def editable_meta_for(name: str, value: Any) -> Dict[str, Any]:
    if isinstance(value, bool):
        return {"type": "bool"}
    if isinstance(value, int):
        return {"type": "int", "min": 0, "max": 500}
    if isinstance(value, float):
        return {"type": "float", "min": 0, "max": 1}
    if name.endswith("_MODE") or name in {"BOT_MODE", "ALPACA_EXECUTION_MODE", "OPTIONS_TRADING_MODE", "CALLS_PUTS_MODE"}:
        options = {
            "BOT_MODE": ["SAFE", "BALANCED", "HUNTER"],
            "ALPACA_EXECUTION_MODE": ["PAPER_SAFE", "LIVE_REVIEW", "LIVE_ENABLED"],
            "OPTIONS_TRADING_MODE": ["SCAN_ONLY", "PAPER_OPTIONS", "TRADE_SIGNAL"],
            "CALLS_PUTS_MODE": ["SIGNAL_ONLY", "PAPER_OPTIONS", "LIVE_OPTIONS"],
            "FRACTIONAL_EXECUTION_MODE": ["OFF", "SMART_FRACTIONAL", "ELITE_FRACTIONAL"],
            "PHASE93_AUTONOMOUS_MODE": ["REVIEW_FIRST", "SCAN_ONLY", "AUTONOMOUS"],
            "PHASE95_1_ELITE_OUTPUT_MODE": ["SUMMARY", "DETAILED"],
            "PMO_AUTONOMOUS_OPTIONS_DECISION_MODE": ["PAPER_ONLY", "SIGNAL_ONLY", "LIVE_REVIEW"],
        }.get(name, [str(value)])
        return {"type": "select", "options": options}
    return {"type": "text"}


for legacy_name, legacy_value in LEGACY_SWITCH_DEFAULTS.items():
    EDITABLE_SETTINGS.setdefault(legacy_name, editable_meta_for(legacy_name, legacy_value))

