def logo_path() -> Optional[Path]:
    for candidate in LOGO_CANDIDATES:
        if candidate.exists() and candidate.stat().st_size > 0:
            return candidate
    return None


def safe_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(value)
    except Exception:
        return default


SETTING_ALIAS_PAIRS = [
    ("ALPACA_PAPER", "PAPER"),
    ("ORDER_AUTOMATION_ENABLED", "ALPACA_ORDER_AUTOMATION"),
    ("PMO_DRY_RUN_ORDERS", "ALPACA_DRY_RUN_MODE"),
    ("PMO_MAX_DAILY_TRADES", "MAX_DAILY_TRADES"),
]


def sync_setting_aliases(settings: Dict[str, Any], changed_name: str = "") -> None:
    """Keep legacy switch names and current PMO names from drifting apart."""
    for primary, alias in SETTING_ALIAS_PAIRS:
        if changed_name == primary and primary in settings:
            settings[alias] = settings[primary]
        elif changed_name == alias and alias in settings:
            settings[primary] = settings[alias]
        elif primary in settings and alias not in settings:
            settings[alias] = settings[primary]
        elif alias in settings and primary not in settings:
            settings[primary] = settings[alias]
        elif primary in settings and alias in settings and not changed_name:
            settings[alias] = settings[primary]


def read_literal_settings_file(path: Path) -> Dict[str, Any]:
    loaded: Dict[str, Any] = {}
    if not path.exists():
        return loaded
    tree = ast.parse(path.read_text(encoding="utf-8"), filename=str(path))
    for node in tree.body:
        target = None
        value_node = None
        if isinstance(node, ast.Assign) and len(node.targets) == 1 and isinstance(node.targets[0], ast.Name):
            target = node.targets[0].id
            value_node = node.value
        elif isinstance(node, ast.AnnAssign) and isinstance(node.target, ast.Name):
            target = node.target.id
            value_node = node.value
        if not target or not target.isupper() or value_node is None:
            continue
        try:
            loaded[target] = ast.literal_eval(value_node)
        except Exception:
            loaded[f"{target}_ERROR"] = "setting value must be a literal"
    return loaded


def load_settings() -> Dict[str, Any]:
    settings = dict(DEFAULT_SETTINGS)
    if SETTINGS_FILE.exists():
        try:
            settings.update(read_literal_settings_file(SETTINGS_FILE))
        except Exception as exc:
            settings["PMO_SETTINGS_ERROR"] = str(exc)

    env_webhook_secret = first_env("TRADINGVIEW_WEBHOOK_SECRET", "PMO_TRADINGVIEW_WEBHOOK_SECRET")
    if env_webhook_secret:
        settings["TRADINGVIEW_WEBHOOK_SECRET"] = env_webhook_secret
    settings["ALPACA_PAPER"] = env_bool("ALPACA_PAPER", bool(settings.get("ALPACA_PAPER", True)))
    sync_setting_aliases(settings, "ALPACA_PAPER")
    return settings


def write_settings(settings: Dict[str, Any]) -> None:
    keys = list(DEFAULT_SETTINGS)
    extras = sorted(k for k in settings if k.isupper() and k not in DEFAULT_SETTINGS and not k.endswith("_ERROR"))
    lines = [
        "# PMO BOT restored local settings",
        "# Secrets belong in .env, not in this file.",
        "",
    ]
    for key in keys + extras:
        if key in settings:
            lines.append(f"{key} = {repr(settings[key])}")
    atomic_write_text(SETTINGS_FILE, "\n".join(lines) + "\n")


def normalize_crypto_symbol(symbol: str) -> str:
    symbol = symbol.strip().upper().replace("-", "/")
    if "/" in symbol:
        return symbol
    known = {"BTC", "ETH", "SOL", "DOGE", "LTC", "BCH", "AVAX", "LINK", "UNI", "AAVE", "MKR"}
    if symbol.endswith("USD") and symbol[:-3] in known:
        return f"{symbol[:-3]}/USD"
    return symbol


def pmo_broker_symbol_key(symbol: Any) -> str:
    clean = normalize_crypto_symbol(str(symbol or "").strip().upper().replace(" ", ""))
    return re.sub(r"[^A-Z0-9]", "", clean)


def pmo_alpaca_order_symbol(symbol: Any, broker_symbol: Any = "") -> str:
    broker_clean = str(broker_symbol or "").strip().upper()
    symbol_clean = normalize_crypto_symbol(str(symbol or "").strip().upper())
    if broker_clean and pmo_broker_symbol_key(broker_clean) == pmo_broker_symbol_key(symbol_clean):
        return broker_clean.replace("/", "") if detect_market(symbol_clean, "AUTO") == "CRYPTO" else broker_clean
    return pmo_broker_symbol_key(symbol_clean) if detect_market(symbol_clean, "AUTO") == "CRYPTO" else symbol_clean


def detect_market(symbol: str, requested: str = "AUTO") -> str:
    requested = str(requested or "AUTO").strip().upper()
    if requested in {"STOCK", "CRYPTO", "OPTION"}:
        return requested
    clean = symbol.strip().upper()
    if "/" in clean or clean.endswith("USD") and len(clean) <= 8:
        return "CRYPTO"
    if re.search(r"\d{6}[CP]\d{8}$", clean):
        return "OPTION"
    return "STOCK"


def pmo_crypto_strategy_profile_from_settings(settings: Optional[Dict[str, Any]] = None) -> Any:
    settings = settings or load_settings()
    if not PMO_CRYPTO_PROFILE_AVAILABLE or CryptoStrategyProfile is None:
        return None
    return CryptoStrategyProfile(
        stop_loss_pct=safe_float(settings.get("PMO_CRYPTO_STOP_LOSS_PCT"), 6.0),
        take_profit_pct=safe_float(settings.get("PMO_CRYPTO_TAKE_PROFIT_PCT"), 10.0),
        trailing_activation_pct=safe_float(settings.get("PMO_CRYPTO_TRAIL_ACTIVATION_PCT"), 5.0),
        trailing_stop_pct=safe_float(settings.get("PMO_CRYPTO_TRAIL_STOP_PCT"), 3.0),
        min_rvol=safe_float(settings.get("PMO_CRYPTO_MIN_RVOL"), 1.2),
        min_score=safe_float(settings.get("PMO_CRYPTO_MIN_SCORE"), 65.0),
        min_score_proven=safe_float(settings.get("PMO_CRYPTO_MIN_SCORE_PROVEN"), 60.0),
        max_hold_minutes=int(max(1, safe_float(settings.get("PMO_CRYPTO_MAX_HOLD_MIN"), 720))),
        max_concurrent=int(max(0, safe_float(settings.get("PMO_CRYPTO_MAX_CONCURRENT"), 3))),
        notional_usd=safe_float(settings.get("PMO_CRYPTO_NOTIONAL_USD"), 40.0),
        notional_proven=safe_float(settings.get("PMO_CRYPTO_NOTIONAL_PROVEN"), 50.0),
        partial_exit_1_pct=safe_float(settings.get("PMO_CRYPTO_PARTIAL_EXIT_1_PCT"), 5.0),
        partial_exit_1_size=safe_float(settings.get("PMO_CRYPTO_PARTIAL_EXIT_1_SIZE"), 0.40),
        partial_exit_2_pct=safe_float(settings.get("PMO_CRYPTO_PARTIAL_EXIT_2_PCT"), 8.0),
        partial_exit_2_size=safe_float(settings.get("PMO_CRYPTO_PARTIAL_EXIT_2_SIZE"), 0.30),
    )


def pmo_crypto_profile_engine(settings: Optional[Dict[str, Any]] = None, reload_journal: bool = False) -> Any:
    global _PMO_CRYPTO_PROFILE_JOURNAL_LOADED, PMO_CRYPTO_PROFILE_ERROR
    settings = settings or load_settings()
    if not settings.get("PMO_CRYPTO_PROFILE_ENABLED", True):
        return None
    if not PMO_CRYPTO_PROFILE_AVAILABLE or _CRYPTO_PROFILE_ENGINE is None:
        return None
    profile = pmo_crypto_strategy_profile_from_settings(settings)
    if profile is not None:
        _CRYPTO_PROFILE_ENGINE._profile = profile
    if reload_journal or not _PMO_CRYPTO_PROFILE_JOURNAL_LOADED:
        try:
            _CRYPTO_PROFILE_ENGINE.load_journal(str(TRADE_JOURNAL_FILE))
            _PMO_CRYPTO_PROFILE_JOURNAL_LOADED = True
            PMO_CRYPTO_PROFILE_ERROR = ""
        except Exception as exc:
            PMO_CRYPTO_PROFILE_ERROR = str(exc)
    return _CRYPTO_PROFILE_ENGINE


def pmo_crypto_bars_from_payload(symbol: str, payload: Optional[Dict[str, Any]] = None, limit: int = 20) -> List[Dict[str, Any]]:
    payload = payload or {}
    bars = payload.get("bars")
    if isinstance(bars, list) and bars:
        return bars[-limit:]
    try:
        return pmo_pattern_prepare_rows(pmo_edge_load_ohlcv_rows(symbol, intraday=True, limit=limit))[-limit:]
    except Exception:
        return []


def pmo_crypto_profile_analysis(
    symbol: Any,
    settings: Optional[Dict[str, Any]] = None,
    bars: Optional[List[Dict[str, Any]]] = None,
    hour_et: Optional[int] = None,
    entry_price: float = 0.0,
) -> Dict[str, Any]:
    settings = settings or load_settings()
    raw_symbol = str(symbol or "").strip().upper()
    normalized = normalize_crypto_symbol(raw_symbol)
    if not raw_symbol:
        return {"ok": False, "enabled": bool(settings.get("PMO_CRYPTO_PROFILE_ENABLED", True)), "error": "missing symbol"}
    if detect_market(normalized, "AUTO") != "CRYPTO":
        return {"ok": True, "enabled": bool(settings.get("PMO_CRYPTO_PROFILE_ENABLED", True)), "ticker": raw_symbol, "is_crypto": False, "recommendation": "USE_EQUITY_PARAMS"}
    engine = pmo_crypto_profile_engine(settings)
    if engine is None:
        return {
            "ok": False,
            "enabled": bool(settings.get("PMO_CRYPTO_PROFILE_ENABLED", True)),
            "ticker": normalized,
            "is_crypto": True,
            "error": PMO_CRYPTO_PROFILE_ERROR or "crypto profile unavailable",
        }
    result = engine.analyze(
        normalized,
        bars=bars or [],
        current_hour_et=int(hour_et if hour_et is not None else now_et().hour),
        entry_price=safe_float(entry_price, 0.0),
    )
    dashboard = result.get_dashboard_dict()
    dashboard.update({
        "ok": True,
        "enabled": True,
        "ticker": normalized,
        "symbol": normalized,
        "recommendation": result.recommendation,
        "symbol_proof": result.symbol_proof,
        "score_modifier": result.score_modifier,
        "journal_loaded": bool(_PMO_CRYPTO_PROFILE_JOURNAL_LOADED),
        "profile_error": PMO_CRYPTO_PROFILE_ERROR,
    })
    return dashboard


def unique_symbols(*sources: Iterable[Any]) -> List[str]:
    symbols: List[str] = []
    for source in sources:
        for symbol in source or []:
            clean = str(symbol).strip().upper()
            if clean and clean not in symbols:
                symbols.append(clean)
    return symbols


def pmo_row_dedupe_key(row: Dict[str, Any], fields: Iterable[str]) -> str:
    parts = []
    for field in fields:
        value = str(row.get(field, "") if isinstance(row, dict) else "").strip().upper()
        parts.append(re.sub(r"\s+", " ", value))
    return "|".join(parts).strip("|")


def pmo_dedupe_rows(rows: Iterable[Dict[str, Any]], fields: Iterable[str], keep: str = "first") -> List[Dict[str, Any]]:
    clean_rows = [row for row in rows or [] if isinstance(row, dict)]
    reverse = str(keep).lower() == "last"
    seen = set()
    unique: List[Dict[str, Any]] = []
    iterator = reversed(clean_rows) if reverse else iter(clean_rows)
    for row in iterator:
        key = pmo_row_dedupe_key(row, fields)
        if not key:
            key = json.dumps(row, sort_keys=True, default=str)
        if key in seen:
            continue
        seen.add(key)
        unique.append(row)
    if reverse:
        unique.reverse()
    return unique


def recent_unique_csv_rows(path: Path, key_fields: Iterable[str], limit: int = 8, scan_limit: int = 500) -> List[Dict[str, Any]]:
    rows = recent_csv_rows(path, max(limit, scan_limit))
    unique_rows = pmo_dedupe_rows(rows, key_fields, keep="last")
    return unique_rows[-limit:]


def slugify(value: Any) -> str:
    clean = re.sub(r"[^a-z0-9]+", "-", str(value).strip().lower()).strip("-")
    return clean or "pmo"


def is_path_inside(child: Path, parent: Path) -> bool:
    try:
        child.resolve(strict=False).relative_to(parent.resolve(strict=False))
        return True
    except Exception:
        return False


def pmo_international_quality_rows(settings: Optional[Dict[str, Any]] = None) -> List[Dict[str, Any]]:
    settings = settings or load_settings()
    raw_rows = settings.get("PMO_INTERNATIONAL_QUALITY_WATCHLIST") or DEFAULT_SETTINGS.get("PMO_INTERNATIONAL_QUALITY_WATCHLIST", [])
    top_10 = set(unique_symbols(settings.get("PMO_INTERNATIONAL_QUALITY_TOP_10") or DEFAULT_SETTINGS.get("PMO_INTERNATIONAL_QUALITY_TOP_10", [])))
    include_higher_risk = bool(settings.get("PMO_INTERNATIONAL_QUALITY_INCLUDE_HIGHER_RISK", True))
    rows: List[Dict[str, Any]] = []
    for item in raw_rows:
        if not isinstance(item, dict):
            continue
        symbol = str(item.get("symbol", "")).strip().upper()
        if not symbol:
            continue
        tier = str(item.get("tier", "CORE_20")).strip().upper() or "CORE_20"
        if tier == "HIGHER_RISK" and not include_higher_risk:
            continue
        execution_mode = str(item.get("execution_mode", "WATCH_ONLY")).strip().upper() or "WATCH_ONLY"
        row = dict(item)
        row.update({
            "symbol": symbol,
            "tier": tier,
            "top_10": symbol in top_10,
            "market": detect_market(symbol, "AUTO"),
            "watchlist_only": True,
            "live_order_unlocked": False,
            "broker_support": "VERIFY_OTC_SUPPORT" if "OTC" in execution_mode else "VERIFY_US_LISTING_SUPPORT",
            "source": "PMO_INTERNATIONAL_QUALITY_WATCHLIST",
        })
        rows.append(row)
    return rows


def pmo_international_quality_watchlist(settings: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    settings = settings or load_settings()
    enabled = bool(settings.get("ENABLE_PMO_INTERNATIONAL_QUALITY_WATCHLIST", True))
    rows = pmo_international_quality_rows(settings)
    symbols = unique_symbols(row.get("symbol") for row in rows)
    core_rows = [row for row in rows if row.get("tier") == "CORE_20"]
    higher_risk_rows = [row for row in rows if row.get("tier") == "HIGHER_RISK"]
    top_rows = [row for row in rows if row.get("top_10")]
    return {
        "ok": True,
        "enabled": enabled,
        "source": "user_supplied_long_term_non_us_quality_watchlist",
        "watchlist_only": True,
        "live_order_unlocked": False,
        "settings_changed_by_endpoint": False,
        "execution_note": "Added to PMO for scanning/research. Live execution remains blocked by PMO proof, broker support, and safety gates.",
        "symbols": symbols,
        "core_20_count": len(core_rows),
        "higher_risk_count": len(higher_risk_rows),
        "top_10": [row.get("symbol") for row in top_rows],
        "allocation_model_pct": settings.get("PMO_INTERNATIONAL_QUALITY_ALLOCATION") or DEFAULT_SETTINGS.get("PMO_INTERNATIONAL_QUALITY_ALLOCATION", {}),
        "rows": rows,
    }


def pmo_market_universe(settings: Dict[str, Any]) -> List[str]:
    if bool(settings.get("ENABLE_PMO_MICRO_ACCOUNT_MODE", False)):
        safe_symbols = settings.get("PMO_MICRO_SAFE_WATCHLIST") or DEFAULT_SETTINGS.get("PMO_MICRO_SAFE_WATCHLIST", [])
        return unique_symbols(safe_symbols)
    sector_symbols = [item["symbol"] for item in SECTOR_ROTATION_SYMBOLS]
    international_symbols: List[str] = []
    if bool(settings.get("ENABLE_PMO_INTERNATIONAL_QUALITY_WATCHLIST", True)):
        international_symbols = [row["symbol"] for row in pmo_international_quality_rows(settings)]
    return unique_symbols(
        settings.get("PMO_WATCHLIST", []),
        settings.get("PMO_AUTO_WATCHLIST_UNIVERSE", []),
        international_symbols,
        sector_symbols,
        ALL_MARKET_WATCHLIST_SYMBOLS,
    )


