def pmo_sync_v112_rows_to_sqlite(rows: Iterable[Dict[str, Any]]) -> Dict[str, Any]:
    synced = 0
    skipped = 0
    errors: List[str] = []
    updated = now_et().isoformat()
    for row in rows or []:
        if not isinstance(row, dict):
            skipped += 1
            continue
        if str(row.get("replay_type", "")).upper() != "PAPER_REPLAY":
            skipped += 1
            continue
        trade_id = str(row.get("trade_id") or row.get("replay_id") or "").strip()
        if not trade_id:
            skipped += 1
            continue
        try:
            storage_sqlite_upsert_paper_outcome(PMO_STORAGE_DB, row, updated)
            synced += 1
        except Exception as exc:
            errors.append(str(exc)[:180])
    return {"ok": not errors, "synced": synced, "skipped": skipped, "errors": errors[:5], "db": str(PMO_STORAGE_DB)}


def csv_append(path: Path, row: Dict[str, Any]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    exists = path.exists()
    fieldnames = list(row.keys())
    existing_rows: List[Dict[str, Any]] = []
    if exists and path.stat().st_size > 0:
        with path.open(newline="", encoding="utf-8", errors="replace") as handle:
            reader = csv.DictReader(handle)
            existing_fieldnames = list(reader.fieldnames or [])
            existing_rows = list(reader)
        fieldnames = existing_fieldnames[:]
        for key in row.keys():
            if key not in fieldnames:
                fieldnames.append(key)
        if fieldnames != existing_fieldnames:
            tmp_path = path.with_name(f".{path.name}.{uuid.uuid4().hex}.tmp")
            with tmp_path.open("w", newline="", encoding="utf-8") as handle:
                writer = csv.DictWriter(handle, fieldnames=fieldnames)
                writer.writeheader()
                for existing_row in existing_rows:
                    writer.writerow(existing_row)
            tmp_path.replace(path)
            exists = True
    with path.open("a", newline="", encoding="utf-8") as handle:
        writer = csv.DictWriter(handle, fieldnames=fieldnames)
        if not exists:
            writer.writeheader()
        writer.writerow(row)
    sqlite_append_event(path, row)


def write_csv_rows(path: Path, rows: List[Dict[str, Any]]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    fieldnames: List[str] = []
    for row in rows:
        for key in row.keys():
            if key not in fieldnames:
                fieldnames.append(key)
    with path.open("w", newline="", encoding="utf-8") as handle:
        writer = csv.DictWriter(handle, fieldnames=fieldnames)
        writer.writeheader()
        for row in rows:
            writer.writerow(row)


def read_json_file(path: Path, default: Any) -> Any:
    if not path.exists():
        return default
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return default


def write_json_file(path: Path, data: Any) -> None:
    atomic_write_text(path, json.dumps(data, indent=2))


def pmo_extract_json_object(text: str) -> Dict[str, Any]:
    clean = str(text or "").strip()
    if clean.startswith("```"):
        clean = re.sub(r"^```(?:json)?", "", clean, flags=re.IGNORECASE).strip()
        clean = re.sub(r"```$", "", clean).strip()
    try:
        parsed = json.loads(clean)
        return parsed if isinstance(parsed, dict) else {}
    except Exception:
        pass
    start = clean.find("{")
    end = clean.rfind("}")
    if start >= 0 and end > start:
        try:
            parsed = json.loads(clean[start:end + 1])
            return parsed if isinstance(parsed, dict) else {}
        except Exception:
            return {}
    return {}


def pmo_claude_call(
    system_prompt: str,
    user_prompt: str,
    max_tokens: int = 400,
    expect_json: bool = False,
    settings: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    settings = settings or {}
    api_key = first_env("ANTHROPIC_API_KEY", "PMO_ANTHROPIC_API_KEY", "CLAUDE_API_KEY")
    if not api_key:
        return {"ok": False, "error": "ANTHROPIC_API_KEY not set in .env", "source": "fallback"}
    model = (
        first_env("PMO_AI_MODEL", "ANTHROPIC_MODEL", "PMOAI_CLAUDE_MODEL")
        or str(settings.get("PMO_AI_MODEL") or settings.get("PMOAI_CLAUDE_MODEL") or PMO_AI_MODEL)
    )
    cache_env = first_env("PMO_CLAUDE_PROMPT_CACHE_ENABLED", "ANTHROPIC_PROMPT_CACHE_ENABLED")
    cache_enabled = (
        str(cache_env).strip().lower() in {"1", "true", "yes", "on"}
        if cache_env
        else bool(settings.get("PMO_CLAUDE_PROMPT_CACHE_ENABLED", True))
    )
    cache_type = str(
        first_env("PMO_CLAUDE_PROMPT_CACHE_TYPE", "ANTHROPIC_PROMPT_CACHE_TYPE")
        or settings.get("PMO_CLAUDE_PROMPT_CACHE_TYPE", "ephemeral")
        or "ephemeral"
    ).strip().lower()
    cache_min_chars = int(safe_float(
        first_env("PMO_CLAUDE_PROMPT_CACHE_MIN_CHARS", "ANTHROPIC_PROMPT_CACHE_MIN_CHARS")
        or settings.get("PMO_CLAUDE_PROMPT_CACHE_MIN_CHARS", 2000),
        2000,
    ))
    timeout_seconds = int(safe_float(
        first_env("PMO_CLAUDE_TIMEOUT_SECONDS", "ANTHROPIC_TIMEOUT_SECONDS")
        or settings.get("PMO_CLAUDE_TIMEOUT_SECONDS", PMO_CLAUDE_TIMEOUT_SECONDS),
        PMO_CLAUDE_TIMEOUT_SECONDS,
    ))
    timeout_seconds = max(20, min(timeout_seconds, 180))
    system_text = str(system_prompt or "")[:8000]
    user_text = str(user_prompt or "")[:30000]
    prompt_chars = len(system_text) + len(user_text)
    cache_enabled = bool(cache_enabled and cache_type == "ephemeral" and prompt_chars >= max(0, cache_min_chars))
    payload = {
        "model": model,
        "max_tokens": int(max(50, max_tokens)),
        "system": system_text,
        "messages": [{"role": "user", "content": user_text}],
    }
    if cache_enabled:
        payload["cache_control"] = {"type": cache_type}
    try:
        headers = {
                "x-api-key": api_key,
                "anthropic-version": "2023-06-01",
                "content-type": "application/json",
        }
        response = requests.post(
            "https://api.anthropic.com/v1/messages",
            headers=headers,
            json=payload,
            timeout=timeout_seconds,
        )
        cache_retry_without_control = False
        if response.status_code == 400 and cache_enabled and "cache_control" in response.text.lower():
            payload.pop("cache_control", None)
            cache_retry_without_control = True
            response = requests.post(
                "https://api.anthropic.com/v1/messages",
                headers=headers,
                json=payload,
                timeout=timeout_seconds,
            )
        response.raise_for_status()
        data = response.json()
        text = "".join(
            str(block.get("text", ""))
            for block in data.get("content", [])
            if isinstance(block, dict) and block.get("type") == "text"
        ).strip()
        usage = data.get("usage", {}) if isinstance(data.get("usage"), dict) else {}
        prompt_cache = {
            "enabled": cache_enabled,
            "type": cache_type if cache_enabled else "",
            "min_chars": cache_min_chars,
            "prompt_chars": prompt_chars,
            "retried_without_cache_control": cache_retry_without_control,
            "cache_creation_input_tokens": usage.get("cache_creation_input_tokens", 0),
            "cache_read_input_tokens": usage.get("cache_read_input_tokens", 0),
        }
        if expect_json:
            parsed = pmo_extract_json_object(text)
            return {
                "ok": bool(parsed),
                "text": text,
                "parsed": parsed,
                "source": "claude" if parsed else "claude_text_only",
                "error": "" if parsed else "Claude response did not parse as JSON",
                "model": model,
                "usage": usage,
                "prompt_cache": prompt_cache,
            }
        return {"ok": True, "text": text, "source": "claude", "model": model, "usage": usage, "prompt_cache": prompt_cache}
    except requests.exceptions.Timeout:
        return {
            "ok": False,
            "error": "Claude API timeout",
            "source": "fallback",
            "model": model,
            "timeout_seconds": timeout_seconds,
        }
    except requests.exceptions.HTTPError as exc:
        body = ""
        try:
            body = exc.response.text if exc.response is not None else ""
        except Exception:
            body = ""
        return {
            "ok": False,
            "error": str(exc)[:240],
            "http_status": getattr(exc.response, "status_code", None),
            "response_body": body[:500],
            "source": "fallback",
            "model": model,
            "prompt_cache": {
                "enabled": cache_enabled,
                "type": cache_type if cache_enabled else "",
                "prompt_chars": prompt_chars,
            },
        }
    except Exception as exc:
        return {"ok": False, "error": str(exc)[:240], "source": "fallback", "model": model}


def pmo_ai_provider_ready(settings: Optional[Dict[str, Any]] = None) -> bool:
    settings = settings or {}
    provider = str(settings.get("PMO_WARP_AI_PROVIDER", "rule_based")).strip().lower()
    return bool(provider == "claude" and first_env("ANTHROPIC_API_KEY", "PMO_ANTHROPIC_API_KEY", "CLAUDE_API_KEY"))


def pmo_report_row_subset(rows: Iterable[Dict[str, Any]], keys: Iterable[str], limit: int = 12) -> List[Dict[str, Any]]:
    compact: List[Dict[str, Any]] = []
    for row in list(rows or [])[: max(0, limit)]:
        if not isinstance(row, dict):
            continue
        item = {key: row.get(key, "") for key in keys if row.get(key, "") not in (None, "")}
        if item:
            compact.append(item)
    return compact


def pmo_letter_grade(score: float) -> str:
    score = safe_float(score, 0)
    if score >= 90:
        return "A"
    if score >= 80:
        return "B"
    if score >= 70:
        return "C"
    if score >= 60:
        return "D"
    return "F"


