def master_pine_source(settings: Optional[Dict[str, Any]] = None) -> str:
    return MASTER_PINE


def ensure_master_pine() -> Path:
    path = master_pine_path()
    content = master_pine_source()
    current = path.read_text(encoding="utf-8", errors="replace") if path.exists() else ""
    if current != content:
        path.write_text(content, encoding="utf-8")
    mirror = PINE_DIR / path.name
    mirror_current = mirror.read_text(encoding="utf-8", errors="replace") if mirror.exists() else ""
    if mirror != path and mirror_current != content:
        mirror.write_text(content, encoding="utf-8")
    return path


def load_receiving_accounts() -> List[Dict[str, Any]]:
    if not RECEIVING_ACCOUNTS_FILE.exists():
        return []
    try:
        data = json.loads(RECEIVING_ACCOUNTS_FILE.read_text(encoding="utf-8"))
        return data if isinstance(data, list) else []
    except Exception:
        return []


def save_receiving_accounts(accounts: List[Dict[str, Any]]) -> None:
    RECEIVING_ACCOUNTS_FILE.write_text(json.dumps(accounts, indent=2), encoding="utf-8")


def public_base_url() -> str:
    raw = first_env("PUBLIC_WEBHOOK_URL")
    if not raw:
        return ""
    base = raw.strip().rstrip("/")
    for suffix in ("/tradingview", "/api/payments/webhook/paypal", "/api/payments/webhook/plaid"):
        if base.lower().endswith(suffix):
            base = base[: -len(suffix)]
    return base.rstrip("/")


def terminal_base_url(settings: Dict[str, Any]) -> str:
    host = str(settings.get("PMO_TERMINAL_HOST", "127.0.0.1") or "127.0.0.1")
    if host in {"0.0.0.0", "::"}:
        host = "127.0.0.1"
    return f"http://{host}:{settings.get('PMO_TERMINAL_PORT', 8090)}"


def tradingview_local_webhook_url(settings: Dict[str, Any]) -> str:
    host = str(settings.get("PMO_TERMINAL_HOST", "127.0.0.1") or "127.0.0.1")
    if host in {"0.0.0.0", "::"}:
        host = "127.0.0.1"
    configured_port = int(settings.get("PMO_TRADINGVIEW_WEBHOOK_PORT") or 0)
    port = configured_port if configured_port > 0 else int(settings.get("PMO_TERMINAL_PORT", 8090))
    return f"http://{host}:{port}/tradingview"


def pmo_tradingview_signal_status(
    settings: Optional[Dict[str, Any]] = None,
    health: Optional[Dict[str, Any]] = None,
    account: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    settings = settings or load_settings()
    account = account or {}
    path = master_pine_path()
    pine_exists = path.exists()
    pine_text = path.read_text(encoding="utf-8", errors="replace") if pine_exists else ""
    pine_stat = path.stat() if pine_exists else None
    public = public_base_url()
    expected_secret = pmo_tradingview_secret(settings)
    recent_rows = recent_csv_rows(CSV_DIR / "pmo_tradingview_alerts.csv", 200)
    last = recent_rows[-1] if recent_rows else {}
    approved_rows = [row for row in recent_rows if csv_truth(row.get("approved"))]
    rejected_rows = [row for row in recent_rows if row and not csv_truth(row.get("approved"))]

    def signal_label(row: Dict[str, Any]) -> str:
        if not row:
            return "None yet"
        parts = [
            str(row.get("timestamp", "")),
            str(row.get("symbol", "")),
            str(row.get("side", "")),
            str(row.get("option_type", "")),
            f"score {row.get('score', '')}",
            str(row.get("score_action") or row.get("execution_status") or ""),
        ]
        return " | ".join(part for part in parts if part)

    payload: Dict[str, Any] = {}
    if last.get("payload"):
        try:
            loaded = json.loads(str(last.get("payload", "{}")))
            payload = loaded if isinstance(loaded, dict) else {}
        except Exception:
            payload = {}
    score = safe_float(last.get("score") or payload.get("score") or payload.get("pmo_score"), 0)
    side = str(last.get("side") or payload.get("side") or "").upper()
    option_type = str(last.get("option_type") or payload.get("option_type") or "").upper()
    prediction_bias = str(
        last.get("prediction_bias")
        or payload.get("prediction_bias")
        or payload.get("prediction")
        or payload.get("bias")
        or "WAIT_NEUTRAL"
    ).upper()
    approved = csv_truth(last.get("approved"))
    live_allowed = csv_truth(last.get("live_order_allowed")) or csv_truth(last.get("broker_order_submitted"))
    alert_mode = str(settings.get("TRADINGVIEW_ALERT_MODE", "SCAN_ONLY"))
    score_action = str(last.get("score_action") or "").upper()
    if not last:
        decision_label = "NO_ALERTS_YET"
    elif live_allowed:
        decision_label = "APPROVED"
    elif alert_mode == "SCAN_ONLY":
        decision_label = "SCAN_ONLY"
    elif "PAPER" in score_action:
        decision_label = "PAPER_ONLY"
    elif approved:
        decision_label = "LIVE_LOCKED"
    else:
        decision_label = "REJECTED"
    health = health or {}
    market_online = pmo_market_data_ready_from_health(health) if health else bool(bot.market_data_status.get("stock_market_data") or bot.market_data_status.get("crypto_market_data"))
    prediction_snapshot = {
        "bias": prediction_bias,
        "bullish": prediction_bias.startswith("BULL") or prediction_bias in {"LONG", "CALL", "CALL_READY"},
        "bearish": prediction_bias.startswith("BEAR") or prediction_bias in {"SHORT", "PUT", "PUT_READY"},
        "neutral": prediction_bias in {"", "WAIT", "WAIT_NEUTRAL", "NEUTRAL", "MIXED"} or not prediction_bias,
        "score": score,
        "rsi": payload.get("rsi") or last.get("rsi") or "",
        "rvol": payload.get("rvol") or payload.get("relative_volume") or last.get("rvol") or "",
        "trend": payload.get("trend") or last.get("trend") or "",
        "macd": payload.get("macd") or last.get("macd") or "",
        "squeeze": payload.get("squeeze") or last.get("squeeze") or "",
        "symbol": str(last.get("symbol") or payload.get("symbol") or "SPY").upper(),
        "timeframe": str(last.get("timeframe") or payload.get("timeframe") or "15"),
        "note": "PMO Prediction Candle is a probability/bias visualization only, not a guarantee.",
    }
    reason = (
        last.get("reason")
        or payload.get("reason")
        or payload.get("message")
        or ("Waiting for the first TradingView alert." if not last else f"Decision from {alert_mode} mode and score action {score_action or 'N/A'}.")
    )
    return {
        "ok": True,
        "pine_file": str(path),
        "pine_exists": pine_exists,
        "pine_size": pine_stat.st_size if pine_stat else 0,
        "last_pine_refresh": datetime.fromtimestamp(pine_stat.st_mtime, ET).isoformat() if pine_stat else "",
        "tradingview_webhook_url": tradingview_local_webhook_url(settings),
        "local_webhook_url": tradingview_local_webhook_url(settings),
        "local_webhook_status": "ONLINE while this PMO Bot server is running",
        "public_webhook_url": f"{public}/tradingview" if public else "",
        "public_webhook_status": "READY" if public else "SET PUBLIC_WEBHOOK_URL / ngrok for TradingView cloud alerts",
        "alert_mode": alert_mode,
        "webhook_secret_status": "CONFIGURED" if expected_secret != "CHANGE_ME_SECRET" else "DEFAULT_CHANGE_REQUIRED",
        "pine_secret_matches_settings": bool(pine_exists and json.dumps(expected_secret) in pine_text),
        "last_alert_received": last.get("timestamp", ""),
        "last_signal_side": side,
        "last_option_type": option_type,
        "last_pmo_score": score,
        "last_prediction_candle_bias": prediction_bias,
        "last_decision": decision_label,
        "last_approved_signal": signal_label(approved_rows[-1] if approved_rows else {}),
        "last_rejected_signal": signal_label(rejected_rows[-1] if rejected_rows else {}),
        "reason": str(reason),
        "last_alert": last,
        "prediction_candle": prediction_snapshot,
        "alpaca_status": account.get("status") or account.get("error") or ("CONNECTED" if bool(bot.api_key and bot.api_secret) else "SETUP REQUIRED"),
        "market_data_status": "ONLINE" if market_online else "SETUP REQUIRED",
        "safety_note": "TradingView never connects directly to Alpaca. PMO Bot must pass paper/dry-run/live, owner approval, duplicate order, buying power, cash lockout, and PDT checks first.",
    }


def payment_webhook_urls(settings: Dict[str, Any]) -> List[Dict[str, str]]:
    local = terminal_base_url(settings)
    public = public_base_url()
    rows = []
    for provider in ("paypal", "plaid"):
        path = f"/api/payments/webhook/{provider}"
        rows.append({
            "provider": provider.upper(),
            "local_url": f"{local}{path}",
            "public_url": f"{public}{path}" if public else "Set PUBLIC_WEBHOOK_URL for public provider callbacks",
            "purpose": "incoming payment event receiver",
        })
    rows.append({
        "provider": "PAYPAL RETURN",
        "local_url": f"{local}/api/payments/paypal/return",
        "public_url": f"{public}/api/payments/paypal/return" if public else "Set PAYPAL_RETURN_URL or PUBLIC_WEBHOOK_URL",
        "purpose": "buyer approval return and capture route",
    })
    return rows


def account_type_matches(accounts: List[Dict[str, Any]], *needles: str) -> bool:
    lowered = [needle.lower() for needle in needles]
    for account in accounts:
        haystack = " ".join([
            str(account.get("account_type", "")),
            str(account.get("nickname", "")),
            str(account.get("destination", "")),
        ]).lower()
        if any(needle in haystack for needle in lowered):
            return True
    return False


def payment_secret_status(*names: str) -> str:
    return "CONFIGURED" if all(first_env(name) for name in names) else "MISSING"


def payment_hub_snapshot(accounts: List[Dict[str, Any]], settings: Dict[str, Any]) -> Dict[str, Any]:
    paypal_api_ready = payment_secret_status("PAYPAL_CLIENT_ID", "PAYPAL_CLIENT_SECRET") == "CONFIGURED"
    plaid_api_ready = payment_secret_status("PLAID_CLIENT_ID", "PLAID_SECRET") == "CONFIGURED"
    stripe_api_ready = bool(first_env("STRIPE_SECRET_KEY") or first_env("STRIPE_PAYMENT_LINK"))
    paypal_saved = account_type_matches(accounts, "paypal")
    stripe_saved = account_type_matches(accounts, "stripe")
    cash_app_saved = account_type_matches(accounts, "cash app", "cashapp", "$")
    invoice_saved = account_type_matches(accounts, "invoice", "bank invoice")
    crypto_saved = account_type_matches(accounts, "crypto", "wallet")
    public_base = public_base_url()
    webhook_public_ready = bool(public_base)
    webhook_verify_ready = bool(first_env("PAYPAL_WEBHOOK_ID"))
    provider_rows = [
        {
            "provider": "PayPal Checkout",
            "direction": "incoming money / outgoing API",
            "status": "READY" if paypal_api_ready or paypal_saved else "NEEDS SETUP",
            "detail": f"API {payment_secret_status('PAYPAL_CLIENT_ID', 'PAYPAL_CLIENT_SECRET')} | saved link {'YES' if paypal_saved else 'NO'} | mode {first_env('PAYPAL_ENV', 'PAYPAL_MODE') or 'sandbox'}",
            "action": "Use API checkout button or store a PayPal payment link.",
        },
        {
            "provider": "PayPal Webhook",
            "direction": "incoming provider callback",
            "status": "READY" if webhook_public_ready and webhook_verify_ready else "PARTIAL" if webhook_public_ready else "NEEDS PUBLIC URL",
            "detail": f"public callback {'YES' if webhook_public_ready else 'NO'} | signature verify {'YES' if webhook_verify_ready else 'NO'}",
            "action": "Add this webhook URL in PayPal and set PAYPAL_WEBHOOK_ID to verify events.",
        },
        {
            "provider": "Plaid Bank Link",
            "direction": "bank-link / ACH setup",
            "status": "READY" if plaid_api_ready else "NEEDS KEYS",
            "detail": f"API {payment_secret_status('PLAID_CLIENT_ID', 'PLAID_SECRET')} | env {first_env('PLAID_ENV') or 'sandbox'}",
            "action": "Use Plaid Auth to link bank accounts, then pair with a payment processor for ACH movement.",
        },
        {
            "provider": "Stripe / Card Link",
            "direction": "incoming card/payment link",
            "status": "READY" if stripe_api_ready or stripe_saved else "OPTIONAL",
            "detail": f"API/link {'CONFIGURED' if stripe_api_ready else 'MISSING'} | saved link {'YES' if stripe_saved else 'NO'}",
            "action": "Store a Stripe Payment Link or add Stripe keys later.",
        },
        {
            "provider": "Cash App / Invoice / Crypto",
            "direction": "incoming manual destination",
            "status": "READY" if cash_app_saved or invoice_saved or crypto_saved else "OPTIONAL",
            "detail": f"cash app {'YES' if cash_app_saved else 'NO'} | invoice {'YES' if invoice_saved else 'NO'} | crypto {'YES' if crypto_saved else 'NO'}",
            "action": "Store public handles, payment links, or invoice destinations only.",
        },
    ]
    return {
        "provider_rows": provider_rows,
        "webhook_rows": payment_webhook_urls(settings),
        "events_file": str(PAYMENT_EVENTS_FILE),
        "paypal_ready": paypal_api_ready or paypal_saved,
        "plaid_ready": plaid_api_ready,
        "public_base_url": public_base,
        "latest_events": recent_csv_rows(PAYMENT_EVENTS_FILE, 8),
        "summary": {
            "saved_destinations": len(accounts),
            "paypal_ready": paypal_api_ready or paypal_saved,
            "plaid_ready": plaid_api_ready,
            "webhook_ready": webhook_public_ready,
        },
    }


def payment_text_has_sensitive_terms(*values: Any) -> bool:
    text = " ".join(str(value or "") for value in values).lower()
    blocked_terms = [
        "password", "passwd", "ssn", "social security", "cvv", "cvc",
        "card number", "routing number", "account number", "broker login",
        "seed phrase", "private key",
    ]
    return any(term in text for term in blocked_terms)


def log_payment_event(
    provider: str,
    event_type: str,
    status: str,
    amount: Any = "",
    currency: str = "USD",
    reference: str = "",
    payer: str = "",
    detail: str = "",
    verified: Any = "",
) -> None:
    row = {field: "" for field in PAYMENT_EVENT_FIELDS}
    row.update({
        "timestamp": now_et().isoformat(),
        "provider": provider,
        "event_type": event_type,
        "status": status,
        "amount": amount,
        "currency": currency,
        "reference": reference,
        "payer": payer,
        "detail": str(detail)[:300],
        "verified": verified,
    })
    csv_append(PAYMENT_EVENTS_FILE, row)


def paypal_api_base() -> str:
    mode = (first_env("PAYPAL_ENV", "PAYPAL_MODE") or "sandbox").strip().lower()
    return "https://api-m.paypal.com" if mode in {"live", "production"} else "https://api-m.sandbox.paypal.com"


def paypal_access_token() -> str:
    client_id = first_env("PAYPAL_CLIENT_ID")
    client_secret = first_env("PAYPAL_CLIENT_SECRET")
    if not client_id or not client_secret:
        raise RuntimeError("PAYPAL_CLIENT_ID and PAYPAL_CLIENT_SECRET are required in .env")
    response = requests.post(
        f"{paypal_api_base()}/v1/oauth2/token",
        auth=(client_id, client_secret),
        data={"grant_type": "client_credentials"},
        timeout=20,
    )
    if response.status_code >= 300:
        raise RuntimeError(f"PayPal auth failed HTTP {response.status_code}: {response.text[:220]}")
    token = response.json().get("access_token")
    if not token:
        raise RuntimeError("PayPal auth did not return an access token")
    return token


def create_paypal_checkout_order(amount: float, memo: str, reference: str, settings: Dict[str, Any]) -> Dict[str, Any]:
    if amount <= 0:
        raise RuntimeError("amount must be greater than zero")
    if amount > 25000:
        raise RuntimeError("amount is above PMO terminal limit")
    token = paypal_access_token()
    base_url = public_base_url() or terminal_base_url(settings)
    return_url = first_env("PAYPAL_RETURN_URL") or f"{base_url}/api/payments/paypal/return"
    cancel_url = first_env("PAYPAL_CANCEL_URL") or f"{base_url}/control"
    reference_id = reference or f"PMO-{int(time.time())}"
    payload = {
        "intent": "CAPTURE",
        "purchase_units": [{
            "reference_id": reference_id,
            "description": memo or "PMO BOT payment",
            "amount": {"currency_code": "USD", "value": f"{amount:.2f}"},
        }],
        "payment_source": {
            "paypal": {
                "experience_context": {
                    "brand_name": first_env("PAYPAL_BRAND_NAME") or "PMO BOT",
                    "landing_page": "LOGIN",
                    "user_action": "PAY_NOW",
                    "return_url": return_url,
                    "cancel_url": cancel_url,
                }
            }
        },
    }
    response = requests.post(
        f"{paypal_api_base()}/v2/checkout/orders",
        headers={"Authorization": f"Bearer {token}", "Content-Type": "application/json"},
        json=payload,
        timeout=25,
    )
    data = response.json() if response.headers.get("content-type", "").startswith("application/json") else {"raw": response.text}
    if response.status_code >= 300:
        raise RuntimeError(f"PayPal order failed HTTP {response.status_code}: {str(data)[:260]}")
    approve_url = ""
    for link in data.get("links", []):
        if link.get("rel") in {"approve", "payer-action"}:
            approve_url = link.get("href", "")
            break
    log_payment_event("PAYPAL", "CREATE_ORDER", data.get("status", "CREATED"), amount=f"{amount:.2f}", reference=data.get("id", reference_id), detail=memo)
    return {"ok": True, "order": data, "approval_url": approve_url, "reference_id": reference_id}


def capture_paypal_order(order_id: str) -> Dict[str, Any]:
    if not order_id:
        raise RuntimeError("missing PayPal order id")
    token = paypal_access_token()
    response = requests.post(
        f"{paypal_api_base()}/v2/checkout/orders/{order_id}/capture",
        headers={"Authorization": f"Bearer {token}", "Content-Type": "application/json"},
        timeout=25,
    )
    data = response.json() if response.headers.get("content-type", "").startswith("application/json") else {"raw": response.text}
    status = data.get("status", f"HTTP {response.status_code}")
    log_payment_event("PAYPAL", "CAPTURE_ORDER", status, reference=order_id, detail=str(data)[:300], verified=response.status_code < 300)
    if response.status_code >= 300:
        raise RuntimeError(f"PayPal capture failed HTTP {response.status_code}: {str(data)[:260]}")
    return {"ok": True, "capture": data}


def verify_paypal_webhook(event: Dict[str, Any], headers: Dict[str, str]) -> Dict[str, Any]:
    webhook_id = first_env("PAYPAL_WEBHOOK_ID")
    if not webhook_id:
        return {"ok": False, "status": "UNVERIFIED", "message": "PAYPAL_WEBHOOK_ID missing"}
    payload = {
        "auth_algo": headers.get("PAYPAL-AUTH-ALGO", ""),
        "cert_url": headers.get("PAYPAL-CERT-URL", ""),
        "transmission_id": headers.get("PAYPAL-TRANSMISSION-ID", ""),
        "transmission_sig": headers.get("PAYPAL-TRANSMISSION-SIG", ""),
        "transmission_time": headers.get("PAYPAL-TRANSMISSION-TIME", ""),
        "webhook_id": webhook_id,
        "webhook_event": event,
    }
    token = paypal_access_token()
    response = requests.post(
        f"{paypal_api_base()}/v1/notifications/verify-webhook-signature",
        headers={"Authorization": f"Bearer {token}", "Content-Type": "application/json"},
        json=payload,
        timeout=20,
    )
    data = response.json() if response.headers.get("content-type", "").startswith("application/json") else {"raw": response.text}
    status = data.get("verification_status", f"HTTP {response.status_code}")
    return {"ok": status == "SUCCESS", "status": status, "detail": data}


def plaid_api_base() -> str:
    env = (first_env("PLAID_ENV") or "sandbox").strip().lower()
    if env == "production":
        return "https://production.plaid.com"
    if env == "development":
        return "https://development.plaid.com"
    return "https://sandbox.plaid.com"


def create_plaid_link_token(settings: Dict[str, Any]) -> Dict[str, Any]:
    client_id = first_env("PLAID_CLIENT_ID")
    secret = first_env("PLAID_SECRET")
    if not client_id or not secret:
        raise RuntimeError("PLAID_CLIENT_ID and PLAID_SECRET are required in .env")
    payload = {
        "client_id": client_id,
        "secret": secret,
        "client_name": first_env("PLAID_CLIENT_NAME") or "PMO BOT",
        "country_codes": ["US"],
        "language": "en",
        "products": ["auth"],
        "user": {"client_user_id": f"pmo-{int(time.time())}"},
    }
    public = public_base_url()
    if public:
        payload["webhook"] = f"{public}/api/payments/webhook/plaid"
    response = requests.post(f"{plaid_api_base()}/link/token/create", json=payload, timeout=25)
    data = response.json() if response.headers.get("content-type", "").startswith("application/json") else {"raw": response.text}
    if response.status_code >= 300:
        log_payment_event("PLAID", "LINK_TOKEN", "FAILED", detail=str(data)[:300], verified=False)
        raise RuntimeError(f"Plaid link token failed HTTP {response.status_code}: {str(data)[:260]}")
    log_payment_event("PLAID", "LINK_TOKEN", "CREATED", reference=data.get("request_id", ""), detail="Plaid Link token created", verified=True)
    return {"ok": True, "plaid": data, "webhook": payload.get("webhook", "")}


def recent_csv_rows(path: Path, limit: int = 8) -> List[Dict[str, Any]]:
    if not path.exists():
        return []
    try:
        with path.open(newline="", encoding="utf-8", errors="replace") as handle:
            rows = list(csv.DictReader(handle))
    except Exception:
        return []
    return rows[-limit:]


def csv_truth(value: Any) -> bool:
    return str(value).strip().lower() in {"1", "true", "yes", "on", "y"}


def parse_pmo_timestamp(value: Any) -> Optional[datetime]:
    text = str(value or "").strip()
    if not text:
        return None
    try:
        clean = text.replace("Z", "+00:00")
        parsed = datetime.fromisoformat(clean)
        if parsed.tzinfo is None:
            parsed = parsed.replace(tzinfo=ET)
        return parsed.astimezone(ET)
    except Exception:
        return None


def recent_window_rows(path: Path, days: int, limit: int = 5000) -> List[Dict[str, Any]]:
    cutoff = now_et() - timedelta(days=max(1, int(days)))
    rows = recent_csv_rows(path, limit)
    kept: List[Dict[str, Any]] = []
    for row in rows:
        timestamp = parse_pmo_timestamp(row.get("timestamp") or row.get("time"))
        if timestamp is None or timestamp >= cutoff:
            kept.append(row)
    return kept


def pmo_dashboard_polish_snapshot(
    settings: Dict[str, Any],
    journal_summary: Dict[str, Any],
    paper_proof: Dict[str, Any],
    regime: Dict[str, Any],
) -> Dict[str, Any]:
    trade_rows = recent_csv_rows(TRADE_JOURNAL_FILE, 5000)
    order_rows = recent_csv_rows(PMO_ORDER_EXECUTION_FILE, 5000)

    closed_rows: List[Dict[str, Any]] = []
    for row in trade_rows:
        status = str(row.get("status") or row.get("result") or row.get("outcome") or "").upper()
        pnl = safe_float(row.get("pnl") or row.get("pnl_usd") or row.get("realized_pnl"), 0)
        if status.startswith("CLOSED") or status in {"WIN", "LOSS", "COMPLETE", "COMPLETED"} or pnl != 0:
            if str(row.get("symbol") or "").upper() == "SYSTEM":
                continue
            closed_rows.append({**row, "_dt": parse_pmo_timestamp(row.get("timestamp") or row.get("time")) or now_et(), "_pnl": pnl})
    closed_rows.sort(key=lambda item: item.get("_dt") or now_et())

    cumulative = 0.0
    equity_curve: List[Dict[str, Any]] = []
    for idx, row in enumerate(closed_rows[-200:], start=max(1, len(closed_rows) - 199)):
        cumulative += safe_float(row.get("_pnl"), 0)
        equity_curve.append({
            "n": idx,
            "timestamp": (row.get("_dt") or now_et()).isoformat(),
            "symbol": row.get("symbol", ""),
            "pnl": round(safe_float(row.get("_pnl"), 0), 4),
            "cumulative_pnl": round(cumulative, 4),
        })

    score_heatmap = []
    for row in recent_csv_rows(PMO_PROOF_DIAGNOSIS_SCORE, 50):
        closed = int(safe_float(row.get("closed"), 0))
        win_rate = safe_float(row.get("win_rate"), 0)
        pf = safe_float(row.get("profit_factor"), 0)
        quality = (
            "EDGE" if closed >= 10 and win_rate >= 0.60 and pf >= 1.25
            else "MIXED" if closed >= 10 and win_rate >= 0.50 and pf >= 1.0
            else "WEAK" if closed else "NO_DATA"
        )
        score_heatmap.append({
            "bucket": row.get("score_bucket") or row.get("bucket") or "",
            "closed": closed,
            "wins": int(safe_float(row.get("wins"), 0)),
            "losses": int(safe_float(row.get("losses"), 0)),
            "win_rate": win_rate,
            "profit_factor": pf,
            "net_pnl": safe_float(row.get("net_pnl"), 0),
            "quality": quality,
            "conclusion": row.get("conclusion", ""),
        })

    clean = paper_proof.get("clean_metrics") if isinstance(paper_proof.get("clean_metrics"), dict) else {}
    metrics = paper_proof.get("metrics") if isinstance(paper_proof.get("metrics"), dict) else {}
    proof_closed = int(safe_float(clean.get("closed_paper_trades", clean.get("clean_closed_paper_trades", paper_proof.get("closed_trades", 0))), 0))
    proof_target = int(safe_float(clean.get("minimum_closed_trades_to_judge", settings.get("PMO_PROOF_MIN_TRADES", 50)), 50))
    proof_progress = {
        "closed": proof_closed,
        "target": proof_target,
        "pct": round(min(1.0, proof_closed / max(1, proof_target)), 4),
        "win_rate": safe_float(clean.get("win_rate", paper_proof.get("win_rate", 0)), 0),
        "profit_factor": safe_float(clean.get("profit_factor", paper_proof.get("profit_factor", 0)), 0),
        "ready": bool(clean.get("positive_allowed") or paper_proof.get("clean_proof_ready")),
        "source": clean.get("source") or paper_proof.get("proof_source") or "UNKNOWN",
        "paper_submissions": int(safe_float(metrics.get("paper_submissions"), 0)),
        "paper_submission_target": int(safe_float(settings.get("PMO_MIN_PAPER_EXECUTOR_SUBMISSIONS", 100), 100)),
    }

    latest_why_not = read_json_file(PMO_WHY_NOT_FILE, {})
    why_rows = latest_why_not.get("rows", []) if isinstance(latest_why_not, dict) and isinstance(latest_why_not.get("rows"), list) else []
    why_text = " ".join(str(item.get("reason") or item.get("blocker") or item.get("detail") or item.get("top_blocker") or "") for item in why_rows[:25]).lower()
    readiness_score = 100
    readiness_hits: List[str] = []
    for label, needle, penalty in [("RVOL", "rvol", 18), ("GAP", "gap", 18), ("ORB", "orb", 18), ("TIME", "09:", 12), ("REGIME", "regime", 18)]:
        if needle in why_text:
            readiness_score -= penalty
            readiness_hits.append(label)
    if not why_rows:
        readiness_score -= 10
        readiness_hits.append("NO_RECENT_WHY_NOT")
    readiness_score = max(0, min(100, readiness_score))

    regime_label = str(regime.get("regime") or "UNKNOWN").upper()
    market_conditions = {
        "regime": regime_label,
        "spy": pmo_regime_cached_price(regime, "SPY"),
        "qqq": pmo_regime_cached_price(regime, "QQQ"),
        "vix_proxy_vxx": pmo_regime_cached_price(regime, "VXX"),
        "breadth": regime.get("breadth", ""),
        "risk_multiplier": regime.get("risk_multiplier", ""),
        "reason": regime.get("reason", ""),
        "status": "RISK_ON" if regime_label in {"BULL", "BULLISH"} else "CAUTION" if regime_label == "MIXED" else "DEFENSIVE",
    }

    def row_key(row: Dict[str, Any]) -> str:
        for field in ("order_id", "source_order_id", "client_order_id", "trade_plan_id", "sync_key"):
            value = str(row.get(field) or "").strip()
            if value:
                return value.split(":")[0].upper()
        return "|".join(str(row.get(field) or "").strip().upper() for field in ("symbol", "side", "score"))

    submitted_orders = [row for row in order_rows if str(row.get("status") or "").upper() in {"SUBMITTED", "FILLED", "PARTIAL_FILLED", "ACCEPTED"}]
    order_keys = {row_key(row) for row in submitted_orders if row_key(row)}
    journal_keys = {row_key(row) for row in trade_rows if row_key(row)}
    orphan_order_keys = sorted(key for key in order_keys if key and key not in journal_keys)
    orphan_journal_keys = sorted(key for key in journal_keys if key and key not in order_keys)[:20]

    component_fields = [
        "relative_volume", "vwap_distance_pct", "market_regime", "gap_signal", "orb_signal",
        "pattern_name", "sentiment_signal", "ml_signal", "edge_signal", "confluence_status",
        "data_collection_tag",
    ]
    score_audit = []
    for row in reversed(order_rows[-80:]):
        symbol = str(row.get("symbol") or "").upper()
        if not symbol:
            continue
        score_audit.append({
            "timestamp": row.get("timestamp", ""),
            "symbol": symbol,
            "status": row.get("status", ""),
            "score": row.get("score", ""),
            "mode": row.get("mode", ""),
            "detail": row.get("detail", ""),
            "components": {field: row.get(field, "") for field in component_fields if row.get(field, "") not in {"", None}},
        })
        if len(score_audit) >= 8:
            break

    build_rows = []
    for row in recent_csv_rows(PMO_BOT_OWNER_COMMANDS_FILE, 12):
        build_rows.append({
            "timestamp": row.get("timestamp", ""),
            "event": row.get("command") or row.get("action") or row.get("status") or "owner_command",
            "detail": row.get("detail") or row.get("message") or row.get("reason") or "",
            "source": "owner_commands",
        })
    for path in [PMO_PAPER_PROOF_FILE, PMO_WHY_NOT_FILE, PMO_LIVE_AI_STATUS_FILE, TRADE_JOURNAL_FILE, PMO_ORDER_EXECUTION_FILE]:
        if path.exists():
            build_rows.append({
                "timestamp": datetime.fromtimestamp(path.stat().st_mtime, ET).isoformat(),
                "event": path.name,
                "detail": f"updated | {path.stat().st_size} bytes",
                "source": "file_mtime",
            })
    build_rows = sorted(build_rows, key=lambda row: row.get("timestamp", ""), reverse=True)[:12]

    return {
        "ok": True,
        "updated": now_et().isoformat(),
        "equity_curve": equity_curve,
        "score_heatmap": score_heatmap,
        "proof_progress": proof_progress,
        "market_conditions": market_conditions,
        "session_readiness": {
            "score": readiness_score,
            "status": "GREEN" if readiness_score >= 75 else "YELLOW" if readiness_score >= 45 else "RED",
            "blocking_factors": readiness_hits,
            "why_not_rows": len(why_rows),
            "note": "Read-only rollup from current Why-Not blockers and active gate context.",
        },
        "journal_reconciliation": {
            "ok": len(orphan_order_keys) == 0,
            "orders": len(submitted_orders),
            "journal_rows": len([row for row in trade_rows if str(row.get("symbol") or "").upper() not in {"", "SYSTEM"}]),
            "orphan_orders": len(orphan_order_keys),
            "orphan_journal_rows": len(orphan_journal_keys),
            "orphan_order_keys": orphan_order_keys[:20],
            "orphan_journal_keys": orphan_journal_keys,
            "note": "Compares submitted broker order IDs/client IDs/plan IDs against trade journal keys.",
        },
        "score_audit": score_audit,
        "build_log": build_rows,
        "source_files": {
            "trade_journal": str(TRADE_JOURNAL_FILE),
            "order_execution": str(PMO_ORDER_EXECUTION_FILE),
            "score_buckets": str(PMO_PROOF_DIAGNOSIS_SCORE),
        },
    }


def load_pmo_learning_memory() -> Dict[str, Any]:
    empty = {
        "ok": False,
        "updated": "",
        "symbols": {},
        "top_symbols": [],
        "summary": {"symbol_count": 0, "source_counts": {}},
        "file": str(PMO_LEARNING_MEMORY_FILE),
    }
    if not PMO_LEARNING_MEMORY_FILE.exists():
        return empty
    try:
        data = json.loads(PMO_LEARNING_MEMORY_FILE.read_text(encoding="utf-8"))
        if isinstance(data, dict):
            data.setdefault("file", str(PMO_LEARNING_MEMORY_FILE))
            data.setdefault("symbols", {})
            data.setdefault("top_symbols", [])
            return data
    except Exception:
        pass
    return empty


def save_pmo_learning_memory(memory: Dict[str, Any]) -> None:
    PMO_LEARNING_MEMORY_FILE.parent.mkdir(parents=True, exist_ok=True)
    PMO_LEARNING_MEMORY_FILE.write_text(json.dumps(memory, indent=2), encoding="utf-8")


def pmo_learning_signal_adjustment(symbol: str, settings: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    settings = settings or load_settings()
    clean = str(symbol or "").strip().upper()
    base = {
        "symbol": clean,
        "watchlist_adjustment": 0.0,
        "execution_adjustment": 0.0,
        "confidence": 0,
        "risk_state": "NO_MEMORY",
        "note": "PMO learning has no memory for this symbol yet.",
    }
    if not clean or not settings.get("ENABLE_PMO_LEARNING_ENGINE", True):
        base["note"] = "PMO learning engine is disabled."
        return base
    memory = load_pmo_learning_memory()
    symbol_memory = memory.get("symbols", {}).get(clean)
    if not isinstance(symbol_memory, dict):
        return base
    execution_adjustment = safe_float(symbol_memory.get("execution_adjustment"), 0)
    if not settings.get("PMO_LEARNING_CAN_RAISE_EXECUTION_SCORE", False):
        execution_adjustment = min(0, execution_adjustment)
    else:
        execution_adjustment = min(execution_adjustment, safe_float(settings.get("PMO_LEARNING_MAX_EXECUTION_BOOST", 0), 0))
    watchlist_adjustment = safe_float(symbol_memory.get("watchlist_adjustment"), 0)
    proof_gate = pmo_positive_learning_gate(settings)
    note = symbol_memory.get("note", "")
    if watchlist_adjustment > 0 and not proof_gate.get("positive_allowed"):
        watchlist_adjustment = 0.0
        note = f"{note} Positive watchlist boost paused: {proof_gate.get('reason')}."
    return {
        "symbol": clean,
        "watchlist_adjustment": watchlist_adjustment,
        "execution_adjustment": execution_adjustment,
        "confidence": int(safe_float(symbol_memory.get("confidence"), 0)),
        "risk_state": symbol_memory.get("risk_state", "WATCH"),
        "note": note,
        "positive_learning_gate": proof_gate,
        "memory": symbol_memory,
    }


def update_pmo_learning_memory(settings: Optional[Dict[str, Any]] = None, record: bool = True) -> Dict[str, Any]:
    settings = settings or load_settings()
    alert_rows = recent_csv_rows(CSV_DIR / "pmo_tradingview_alerts.csv", 2000)
    execution_rows = recent_csv_rows(PMO_ORDER_EXECUTION_FILE, 2000)
    watchlist_rows = recent_csv_rows(AUTO_WATCHLIST_CSV, 2000)
    symbols = sorted({
        str(row.get("symbol", "")).strip().upper()
        for row in alert_rows + execution_rows + watchlist_rows
        if str(row.get("symbol", "")).strip()
    })
    can_raise_execution = bool(settings.get("PMO_LEARNING_CAN_RAISE_EXECUTION_SCORE", False))
    max_execution_boost = safe_float(settings.get("PMO_LEARNING_MAX_EXECUTION_BOOST", 0), 0) if can_raise_execution else 0
    learned_symbols: Dict[str, Dict[str, Any]] = {}
    for symbol in symbols:
        alerts = [row for row in alert_rows if str(row.get("symbol", "")).strip().upper() == symbol]
        executions = [row for row in execution_rows if str(row.get("symbol", "")).strip().upper() == symbol]
        watch_hits = [row for row in watchlist_rows if str(row.get("symbol", "")).strip().upper() == symbol]
        alert_scores = [safe_float(row.get("score"), 0) for row in alerts if str(row.get("score", "")).strip()]
        watch_scores = [safe_float(row.get("score"), 0) for row in watch_hits if str(row.get("score", "")).strip()]
        approved_alerts = sum(1 for row in alerts if csv_truth(row.get("approved")))
        submitted_orders = sum(1 for row in executions if str(row.get("status", "")).upper() == "SUBMITTED")
        failed_orders = sum(1 for row in executions if str(row.get("status", "")).upper() == "FAILED")
        guarded_blocks = [
            row for row in executions
            if str(row.get("status", "")).upper() == "BLOCKED"
            and "ENABLE_ALPACA_ORDER_EXECUTOR is OFF" not in str(row.get("detail", ""))
            and "SIGNAL_ONLY" not in str(row.get("detail", ""))
        ]
        avg_alert_score = round(sum(alert_scores) / len(alert_scores), 2) if alert_scores else 0.0
        avg_watch_score = round(sum(watch_scores) / len(watch_scores), 2) if watch_scores else 0.0
        approval_rate = (approved_alerts / len(alerts)) if alerts else 0.0
        confidence = int(min(100, len(alerts) * 8 + len(watch_hits) * 4 + submitted_orders * 12))
        failure_penalty = failed_orders * 2.0 + len(guarded_blocks) * 0.35
        raw_watch_adjustment = ((avg_watch_score - 70) / 8 if avg_watch_score else 0) + (approval_rate - 0.5) * 5 - failure_penalty
        raw_execution_adjustment = ((avg_alert_score - 75) / 10 if avg_alert_score else 0) + (approval_rate - 0.5) * 4 - failure_penalty
        watchlist_adjustment = round(max(-6, min(8, raw_watch_adjustment)), 2)
        execution_adjustment = round(max(-10, min(max_execution_boost, raw_execution_adjustment)), 2)
        if failed_orders or failure_penalty >= 2:
            risk_state = "COOLDOWN"
            note = "PMO learning sees execution failures or risk blocks; keep this symbol under review."
        elif confidence >= 35 and (avg_alert_score >= 80 or avg_watch_score >= 78) and approval_rate >= 0.5:
            risk_state = "PROMOTE_PAPER"
            note = "PMO learning sees enough positive paper evidence to watch this symbol closely."
        else:
            risk_state = "WATCH"
            note = "PMO learning is still building proof for this symbol."
        learned_symbols[symbol] = {
            "symbol": symbol,
            "alerts": len(alerts),
            "approved_alerts": approved_alerts,
            "approval_rate": round(approval_rate, 3),
            "watchlist_hits": len(watch_hits),
            "submitted_orders": submitted_orders,
            "failed_orders": failed_orders,
            "guarded_blocks": len(guarded_blocks),
            "avg_alert_score": avg_alert_score,
            "avg_watchlist_score": avg_watch_score,
            "watchlist_adjustment": watchlist_adjustment,
            "execution_adjustment": execution_adjustment,
            "confidence": confidence,
            "risk_state": risk_state,
            "note": note,
        }
    top_symbols = sorted(
        learned_symbols.values(),
        key=lambda row: (safe_float(row.get("confidence"), 0), safe_float(row.get("avg_watchlist_score"), 0), safe_float(row.get("avg_alert_score"), 0)),
        reverse=True,
    )[:20]
    memory = {
        "ok": True,
        "updated": now_et().isoformat(),
        "symbols": learned_symbols,
        "top_symbols": top_symbols,
        "summary": {
            "symbol_count": len(learned_symbols),
            "source_counts": {
                "alerts": len(alert_rows),
                "execution_rows": len(execution_rows),
                "watchlist_rows": len(watchlist_rows),
            },
            "execution_boost_policy": "can_raise" if can_raise_execution else "penalty_only",
        },
        "file": str(PMO_LEARNING_MEMORY_FILE),
    }
    save_pmo_learning_memory(memory)
    if record:
        csv_append(PMO_LEARNING_EVENTS_FILE, {
            "timestamp": now_et().isoformat(),
            "symbols": len(learned_symbols),
            "alerts": len(alert_rows),
            "execution_rows": len(execution_rows),
            "watchlist_rows": len(watchlist_rows),
            "policy": memory["summary"]["execution_boost_policy"],
        })
    return memory


def pmo_paper_proof_snapshot(settings: Optional[Dict[str, Any]] = None, record: bool = True) -> Dict[str, Any]:
    settings = settings or load_settings()
    days = int(settings.get("PMO_PAPER_PROOF_DAYS", 30))
    executor_rows = recent_window_rows(PMO_ORDER_EXECUTION_FILE, days, 5000)
    alert_rows = recent_window_rows(CSV_DIR / "pmo_tradingview_alerts.csv", days, 5000)
    plan_rows = recent_window_rows(PMO_TRADE_PLAN_FILE, days, 5000)
    paper_submissions = [
        row for row in executor_rows
        if str(row.get("status", "")).upper() == "SUBMITTED"
        and (csv_truth(row.get("paper")) or str(row.get("mode", "")).upper() == "PAPER_ALPACA")
    ]
    failed_executions = [row for row in executor_rows if str(row.get("status", "")).upper() == "FAILED"]
    blocked_rows = [row for row in executor_rows if str(row.get("status", "")).upper() == "BLOCKED"]
    duplicate_blocks = [row for row in blocked_rows if "duplicate" in str(row.get("detail", "")).lower()]
    protective_blocks = [row for row in blocked_rows if "protective trade plan" in str(row.get("detail", "")).lower()]
    ready_plans = [row for row in plan_rows if csv_truth(row.get("ready"))]
    approved_alerts = [row for row in alert_rows if csv_truth(row.get("approved"))]
    signal_approval_rate = round(len(approved_alerts) / len(alert_rows), 3) if alert_rows else 0.0
    min_submissions = int(settings.get("PMO_MIN_PAPER_EXECUTOR_SUBMISSIONS", 100))
    max_failures = int(settings.get("PMO_MAX_PAPER_FAILED_EXECUTIONS", 0))
    min_approval_rate = safe_float(settings.get("PMO_MIN_PAPER_SIGNAL_APPROVAL_RATE", 0.55), 0.55)
    checks = [
        {
            "name": "Paper executor submissions",
            "ready": len(paper_submissions) >= min_submissions,
            "value": f"{len(paper_submissions)}/{min_submissions}",
            "detail": "Paper executor needs enough successful submissions before live mode.",
        },
        {
            "name": "Failed executor submissions",
            "ready": len(failed_executions) <= max_failures,
            "value": f"{len(failed_executions)}/{max_failures}",
            "detail": "Executor failures must stay within the configured limit.",
        },
        {
            "name": "Signal approval rate",
            "ready": bool(alert_rows) and signal_approval_rate >= min_approval_rate,
            "value": f"{signal_approval_rate:.2%}",
            "detail": f"Minimum approval-rate proof is {min_approval_rate:.2%}.",
        },
        {
            "name": "Duplicate order guard proof",
            "ready": len(duplicate_blocks) == 0,
            "value": str(len(duplicate_blocks)),
            "detail": "Duplicate-order blocks should be zero during the proof window.",
        },
        {
            "name": "Protective plan coverage",
            "ready": len(ready_plans) >= min(3, max(1, len(approved_alerts))),
            "value": f"{len(ready_plans)} ready plan(s)",
            "detail": "PMO needs ready stop/target plans attached to trade decisions.",
        },
    ]
    post_gate_equity_proof = pmo_post_gate_equity_proof_snapshot(settings) if "pmo_post_gate_equity_proof_snapshot" in globals() else {"ready": False, "summary": {}, "next_action": "Post-gate equity proof unavailable."}
    post_gate_summary = post_gate_equity_proof.get("summary", {}) if isinstance(post_gate_equity_proof.get("summary"), dict) else {}
    checks.append({
        "name": "Post-gate equity proof",
        "ready": bool(post_gate_equity_proof.get("ready")),
        "value": f"{int(safe_float(post_gate_summary.get('closed'), 0))}/{int(safe_float(post_gate_summary.get('minimum_closed_trades'), settings.get('PMO_POST_GATE_EQUITY_MIN_CLOSED_TRADES', 20)))}",
        "detail": (
            f"{post_gate_equity_proof.get('status', 'UNKNOWN')} | "
            f"WR {safe_float(post_gate_summary.get('win_rate'), 0):.2%}; "
            f"PF {safe_float(post_gate_summary.get('profit_factor'), 0):.2f}; "
            f"{post_gate_equity_proof.get('next_action', '')}"
        ),
    })
    ready_count = sum(1 for row in checks if row["ready"])
    score = round((ready_count / len(checks)) * 100, 1) if checks else 0
    ready_to_unlock_live = all(row["ready"] for row in checks)
    v112_report = pmo_v112_proof_report(settings, record=False) if "pmo_v112_proof_report" in globals() else {}
    journal_summary = pmo_closed_trade_authority_summary(settings) if "pmo_closed_trade_authority_summary" in globals() else {}
    raw_journal_summary = journal_summary.get("raw_journal_summary") if isinstance(journal_summary.get("raw_journal_summary"), dict) else trade_journal_summary(limit=20)
    clean_metrics = journal_summary.get("clean_metrics") if isinstance(journal_summary.get("clean_metrics"), dict) else pmo_clean_trade_proof_metrics(settings)
    min_clean_trades = max(1, int(safe_float(clean_metrics.get("minimum_closed_trades_to_judge", settings.get("PMO_PROOF_MIN_TRADES", 50)), 50)))
    min_clean_wr = max(0.0001, safe_float(clean_metrics.get("min_win_rate", settings.get("PMO_PROOF_MIN_WIN_RATE", 0.52)), 0.52))
    min_clean_pf = max(0.0001, safe_float(clean_metrics.get("min_profit_factor", settings.get("PMO_PROOF_MIN_PF", 1.25)), 1.25))
    clean_closed = int(safe_float(clean_metrics.get("closed_paper_trades", clean_metrics.get("clean_closed_paper_trades", 0)), 0))
    clean_wr = safe_float(clean_metrics.get("win_rate", 0), 0)
    clean_pf = safe_float(clean_metrics.get("profit_factor", 0), 0)
    clean_proof_ready = bool(clean_metrics.get("positive_allowed"))
    clean_trade_score = min(1.0, clean_closed / min_clean_trades)
    clean_wr_score = min(1.0, clean_wr / min_clean_wr)
    clean_pf_score = min(1.0, clean_pf / min_clean_pf)
    clean_proof_score = round((clean_trade_score + clean_wr_score + clean_pf_score) / 3 * 100, 1)
    if clean_proof_ready:
        clean_proof_score = 100.0
    quality_breaker = pmo_paper_proof_quality_breaker(settings) if "pmo_paper_proof_quality_breaker" in globals() else {"active": False, "blockers": []}
    proof_gaps = [
        {
            "name": row["name"],
            "value": row["value"],
            "detail": row["detail"],
        }
        for row in checks
        if not row["ready"]
    ]
    next_actions: List[str] = []
    if len(paper_submissions) < min_submissions:
        next_actions.append(f"Collect {min_submissions - len(paper_submissions)} more successful PAPER_ALPACA executor submissions after the day hard-stop clears.")
    if not alert_rows:
        next_actions.append("Run TradingView or PMO paper alerts so signal approval rate can be measured.")
    elif signal_approval_rate < min_approval_rate:
        next_actions.append(f"Improve approved alert quality from {signal_approval_rate:.2%} toward {min_approval_rate:.2%}; tighten score/RVOL filters before expanding entries.")
    if len(ready_plans) < min(3, max(1, len(approved_alerts))):
        next_actions.append("Attach ready stop/target plans to every approved paper decision.")
    if safe_float(v112_report.get("summary", {}).get("win_rate"), 0) < safe_float(settings.get("PMO_V112_MIN_PROOF_WIN_RATE", 0.5), 0.5):
        next_actions.append("Keep v112 outcome review active; positive learning boosts remain paused until closed paper replay win rate improves.")
    if quality_breaker.get("active"):
        next_actions.append(quality_breaker.get("next_action") or "Stop new paper entries until proof quality recovers.")
    if not post_gate_equity_proof.get("ready"):
        next_actions.append(post_gate_equity_proof.get("next_action") or "Collect post-gate equity closed trades before live readiness can use equity proof.")
    if not next_actions:
        next_actions.append("Paper proof gates are green; live execution still requires manual live switches and owner confirmation.")
    snapshot = {
        "ok": True,
        "updated": now_et().isoformat(),
        "window_days": days,
        "score": score,
        "ready_count": ready_count,
        "total_checks": len(checks),
        "ready_to_unlock_live": ready_to_unlock_live,
        "status": "LIVE PROOF READY" if ready_to_unlock_live else "PAPER PROOF REQUIRED",
        "recommendation": "Keep PMO in paper/review mode until every proof check is green." if not ready_to_unlock_live else "Paper proof gates are green; live execution still requires manual live switches.",
        "closed_trades": int(safe_float(journal_summary.get("closed_trades"), 0)),
        "win_rate": safe_float(journal_summary.get("win_rate"), 0),
        "profit_factor": safe_float(journal_summary.get("profit_factor"), 0),
        "net_pnl": safe_float(journal_summary.get("net_pnl"), 0),
        "proof_source": journal_summary.get("authority", journal_summary.get("source", settings.get("PMO_PROOF_SOURCE", "REAL_TRADE_JOURNAL_CLEAN_BLOCKLIST"))),
        "clean_proof_ready": clean_proof_ready,
        "clean_proof_score": clean_proof_score,
        "clean_metrics": clean_metrics,
        "post_gate_equity_proof": post_gate_equity_proof,
        "raw_journal_summary": raw_journal_summary,
        "outcome_source": journal_summary.get("source_file", str(TRADE_JOURNAL_FILE)),
        "proof_gaps": proof_gaps,
        "next_actions": next_actions,
        "metrics": {
            "alerts": len(alert_rows),
            "approved_alerts": len(approved_alerts),
            "signal_approval_rate": signal_approval_rate,
            "executor_rows": len(executor_rows),
            "paper_submissions": len(paper_submissions),
            "failed_executions": len(failed_executions),
            "blocked_rows": len(blocked_rows),
            "duplicate_blocks": len(duplicate_blocks),
            "protective_blocks": len(protective_blocks),
            "trade_plans": len(plan_rows),
            "ready_trade_plans": len(ready_plans),
            "v112_paper_replays": v112_report.get("summary", {}).get("paper_replays", 0),
            "v112_would_have_traded": v112_report.get("summary", {}).get("would_have_traded", 0),
            "v112_win_rate": v112_report.get("summary", {}).get("win_rate", 0),
            "v112_analysis_win_rate": v112_report.get("summary", {}).get("analysis_win_rate", 0),
            "v112_blocked_quality": v112_report.get("summary", {}).get("blocked_quality", 0),
            "closed_trades": int(safe_float(journal_summary.get("closed_trades"), 0)),
            "win_rate": safe_float(journal_summary.get("win_rate"), 0),
            "profit_factor": safe_float(journal_summary.get("profit_factor"), 0),
            "net_pnl": safe_float(journal_summary.get("net_pnl"), 0),
            "proof_source": journal_summary.get("authority", journal_summary.get("source", settings.get("PMO_PROOF_SOURCE", "REAL_TRADE_JOURNAL_CLEAN_BLOCKLIST"))),
            "clean_closed_trades": clean_closed,
            "clean_win_rate": clean_wr,
            "clean_profit_factor": clean_pf,
            "clean_net_pnl": safe_float(clean_metrics.get("net_pnl"), 0),
            "clean_proof_score": clean_proof_score,
            "clean_proof_ready": clean_proof_ready,
            "post_gate_equity_closed_trades": int(safe_float(post_gate_summary.get("closed"), 0)),
            "post_gate_equity_win_rate": safe_float(post_gate_summary.get("win_rate"), 0),
            "post_gate_equity_profit_factor": safe_float(post_gate_summary.get("profit_factor"), 0),
            "post_gate_equity_ready": bool(post_gate_equity_proof.get("ready")),
            "raw_closed_trades": int(safe_float(raw_journal_summary.get("closed_trades"), 0)),
            "raw_win_rate": safe_float(raw_journal_summary.get("win_rate"), 0),
            "raw_profit_factor": safe_float(raw_journal_summary.get("profit_factor"), 0),
            "raw_net_pnl": safe_float(raw_journal_summary.get("net_pnl"), 0),
        },
        "checks": checks,
        "latest_plans": recent_csv_rows(PMO_TRADE_PLAN_FILE, 8),
        "latest_executor_rows": recent_csv_rows(PMO_ORDER_EXECUTION_FILE, 8),
        "proof_quality_breaker": quality_breaker,
        "v112": v112_report,
        "file": str(PMO_PAPER_PROOF_FILE),
    }
    if record:
        PMO_PAPER_PROOF_FILE.parent.mkdir(parents=True, exist_ok=True)
        PMO_PAPER_PROOF_FILE.write_text(json.dumps(snapshot, indent=2), encoding="utf-8")
    return snapshot


def load_pmo_quantum_matrix() -> Dict[str, Any]:
    empty = {
        "ok": False,
        "updated": "",
        "mode": "OFF",
        "symbols": {},
        "top_symbols": [],
        "sectors": [],
        "summary": {"symbol_count": 0, "sector_count": 0, "leader_count": 0, "cooldown_count": 0},
        "file": str(PMO_QUANTUM_MATRIX_FILE),
    }
    if not PMO_QUANTUM_MATRIX_FILE.exists():
        return empty
    try:
        data = json.loads(PMO_QUANTUM_MATRIX_FILE.read_text(encoding="utf-8"))
        if isinstance(data, dict):
            data.setdefault("file", str(PMO_QUANTUM_MATRIX_FILE))
            data.setdefault("symbols", {})
            data.setdefault("top_symbols", [])
            data.setdefault("sectors", [])
            return data
    except Exception:
        pass
    return empty


def pmo_quantum_signal_adjustment(symbol: str, settings: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    settings = settings or load_settings()
    clean = str(symbol or "").strip().upper()
    base = {
        "symbol": clean,
        "watchlist_adjustment": 0.0,
        "confidence": 0,
        "quantum_score": 0.0,
        "state": "NO_MATRIX",
        "note": "PMO v108 matrix has not learned this symbol yet.",
    }
    if not clean or not settings.get("ENABLE_PMO_QUANTUM_LEARNING_MATRIX", True) or str(settings.get("PMO_QUANTUM_LEARNING_MODE", "OFF")) == "OFF":
        base["state"] = "OFF"
        base["note"] = "PMO v108 quantum learning matrix is off."
        return base
    matrix = load_pmo_quantum_matrix()
    row = matrix.get("symbols", {}).get(clean)
    if not isinstance(row, dict):
        return base
    confidence = int(safe_float(row.get("confidence"), 0))
    adjustment = safe_float(row.get("watchlist_adjustment"), 0)
    if confidence < int(settings.get("PMO_QUANTUM_MIN_CONFIDENCE_TO_BOOST", 30)) and adjustment > 0:
        adjustment = 0.0
    if settings.get("PMO_QUANTUM_FORCE_PENALTY_ON_FAILURES", True):
        adjustment = min(adjustment, safe_float(row.get("penalty_adjustment"), adjustment))
    proof_gate = pmo_positive_learning_gate(settings)
    note = row.get("note", "")
    if adjustment > 0 and not proof_gate.get("positive_allowed"):
        adjustment = 0.0
        note = f"{note} Positive quantum boost paused: {proof_gate.get('reason')}."
    return {
        "symbol": clean,
        "watchlist_adjustment": adjustment,
        "confidence": confidence,
        "quantum_score": safe_float(row.get("quantum_score"), 0),
        "state": row.get("state", "WATCH"),
        "sector": row.get("sector", ""),
        "note": note,
        "positive_learning_gate": proof_gate,
        "memory": row,
    }


def pmo_quantum_signal_adjustment_v2(symbol: str, settings: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    settings = settings or load_settings()
    clean = str(symbol or "").strip().upper()
    rule_result = pmo_quantum_signal_adjustment(clean, settings)
    if not bool(settings.get("PMO_QUANTUM_AI_INFERENCE", False)):
        return rule_result
    if not first_env("ANTHROPIC_API_KEY", "PMO_ANTHROPIC_API_KEY", "CLAUDE_API_KEY"):
        return rule_result

    matrix = load_pmo_quantum_matrix()
    symbol_data = matrix.get("symbols", {}).get(clean)
    if not isinstance(symbol_data, dict):
        return rule_result
    confidence = int(safe_float(symbol_data.get("confidence"), 0))
    if confidence < int(settings.get("PMO_QUANTUM_MIN_CONFIDENCE_TO_BOOST", 40)):
        return rule_result

    sector_name = pmo_sector_for_symbol(clean) if "pmo_sector_for_symbol" in globals() else str(symbol_data.get("sector", ""))
    sector_data: Dict[str, Any] = {}
    sectors = matrix.get("sectors", [])
    if isinstance(sectors, dict):
        sector_data = sectors.get(sector_name, {}) if isinstance(sectors.get(sector_name, {}), dict) else {}
    elif isinstance(sectors, list):
        for item in sectors:
            if isinstance(item, dict) and str(item.get("name") or item.get("sector") or "").upper() == sector_name.upper():
                sector_data = item
                break

    try:
        system_prompt = (
            "You are PMO Quantum Matrix, a sector-aware paper-trading intelligence layer. "
            "Recommend a conservative watchlist adjustment from -5.0 to +5.0. "
            "Never suggest bypassing safety gates or live locks. Return JSON only."
        )
        user_prompt = (
            f"Symbol: {clean}\n"
            f"Rule result: {json.dumps(rule_result, default=str)[:2500]}\n"
            f"Symbol matrix: {json.dumps(symbol_data, default=str)[:2500]}\n"
            f"Sector: {sector_name}\n"
            f"Sector data: {json.dumps(sector_data, default=str)[:1500]}\n\n"
            'Return JSON: {"adjustment": 0, "confidence": 0, "state": "BOOST|WATCH|PENALIZE|NO_MATRIX", '
            '"sector_momentum": "STRONG|WEAK|NEUTRAL", "reasoning": "one sentence"}'
        )
        ai = pmo_claude_call(system_prompt, user_prompt, max_tokens=220, expect_json=True, settings=settings)
        parsed = ai.get("parsed") if ai.get("ok") else {}
        if not isinstance(parsed, dict) or not parsed:
            return {**rule_result, "ai_provider": "rule_based_fallback", "ai_error": ai.get("error", "Claude unavailable")}
        adjustment = round(max(-5.0, min(5.0, safe_float(parsed.get("adjustment"), 0))), 3)
        proof_gate = pmo_positive_learning_gate(settings)
        if adjustment > 0 and not proof_gate.get("positive_allowed"):
            adjustment = 0.0
        return {
            **rule_result,
            "watchlist_adjustment": adjustment,
            "confidence": int(max(0, min(100, safe_float(parsed.get("confidence"), confidence)))),
            "state": str(parsed.get("state") or rule_result.get("state", "WATCH")),
            "quantum_score": safe_float(parsed.get("confidence"), rule_result.get("quantum_score", 0)),
            "note": f"{parsed.get('reasoning', 'Claude Quantum inference completed.')} Sector: {parsed.get('sector_momentum', 'UNKNOWN')} [Claude Quantum]",
            "ai_provider": "claude",
            "rule_based_adjustment": rule_result.get("watchlist_adjustment", 0),
            "positive_learning_gate": proof_gate,
        }
    except Exception as exc:
        return {**rule_result, "ai_provider": "rule_based_fallback", "ai_error": str(exc)[:120]}


def pmo_quantum_learning_matrix(
    settings: Optional[Dict[str, Any]] = None,
    auto_watchlist: Optional[Dict[str, Any]] = None,
    regime: Optional[Dict[str, Any]] = None,
    record: bool = True,
) -> Dict[str, Any]:
    settings = settings or load_settings()
    mode = str(settings.get("PMO_QUANTUM_LEARNING_MODE", "WATCHLIST_ASSIST"))
    if not settings.get("ENABLE_PMO_QUANTUM_LEARNING_MATRIX", True) or mode == "OFF":
        return {
            "ok": False,
            "updated": now_et().isoformat(),
            "mode": mode,
            "symbols": {},
            "top_symbols": [],
            "sectors": [],
            "summary": {"symbol_count": 0, "sector_count": 0, "leader_count": 0, "cooldown_count": 0, "reason": "PMO quantum learning matrix is disabled."},
            "file": str(PMO_QUANTUM_MATRIX_FILE),
        }
    auto_watchlist = auto_watchlist or load_auto_watchlist()
    regime = regime or {"regime": "UNKNOWN", "risk_multiplier": 1.0, "leaders": [], "laggards": []}
    days = int(settings.get("PMO_QUANTUM_SECTOR_MEMORY_DAYS", 30))
    max_boost = safe_float(settings.get("PMO_QUANTUM_MAX_WATCHLIST_BOOST", 4.0), 4.0)
    min_confidence = int(settings.get("PMO_QUANTUM_MIN_CONFIDENCE_TO_BOOST", 30))
    alert_rows = recent_window_rows(CSV_DIR / "pmo_tradingview_alerts.csv", days, 5000)
    executor_rows = recent_window_rows(PMO_ORDER_EXECUTION_FILE, days, 5000)
    plan_rows = recent_window_rows(PMO_TRADE_PLAN_FILE, days, 5000)
    watch_rows = recent_window_rows(AUTO_WATCHLIST_CSV, days, 5000)
    learning = load_pmo_learning_memory()
    proof = pmo_paper_proof_snapshot(settings, record=False)
    positive_learning_gate = pmo_positive_learning_gate(settings, proof.get("v112", {}))
    sector_symbols = [item["symbol"] for item in SECTOR_ROTATION_SYMBOLS]
    symbols = unique_symbols(
        auto_watchlist.get("symbols", []),
        settings.get("PMO_WATCHLIST", []),
        sector_symbols,
        [row.get("symbol", "") for row in alert_rows],
        [row.get("symbol", "") for row in executor_rows],
        [row.get("symbol", "") for row in plan_rows],
        [row.get("symbol", "") for row in watch_rows],
    )
    learning_symbols = learning.get("symbols", {}) if isinstance(learning.get("symbols"), dict) else {}
    regime_name = str(regime.get("regime", "UNKNOWN")).upper()
    defensive_sectors = {"Utilities", "Consumer Staples", "Healthcare", "Gold Miners", "Real Estate"}
    symbol_rows: Dict[str, Dict[str, Any]] = {}
    sector_buckets: Dict[str, List[Dict[str, Any]]] = {}
    lookup = auto_watchlist_lookup(auto_watchlist)
    for symbol in symbols:
        sector = pmo_sector_for_symbol(symbol)
        auto_row = lookup.get(symbol, {})
        symbol_watch_rows = [row for row in watch_rows if str(row.get("symbol", "")).strip().upper() == symbol]
        symbol_alert_rows = [row for row in alert_rows if str(row.get("symbol", "")).strip().upper() == symbol]
        symbol_exec_rows = [row for row in executor_rows if str(row.get("symbol", "")).strip().upper() == symbol]
        symbol_plan_rows = [row for row in plan_rows if str(row.get("symbol", "")).strip().upper() == symbol]
        watch_scores = [safe_float(row.get("score"), 0) for row in symbol_watch_rows if str(row.get("score", "")).strip()]
        if auto_row.get("score") is not None:
            watch_scores.append(safe_float(auto_row.get("score"), 0))
        avg_watch_score = round(sum(watch_scores) / len(watch_scores), 2) if watch_scores else 0.0
        approved_alerts = sum(1 for row in symbol_alert_rows if csv_truth(row.get("approved")))
        approval_rate = approved_alerts / len(symbol_alert_rows) if symbol_alert_rows else 0.0
        submitted = sum(1 for row in symbol_exec_rows if str(row.get("status", "")).upper() == "SUBMITTED")
        failed = sum(1 for row in symbol_exec_rows if str(row.get("status", "")).upper() == "FAILED")
        blocked = sum(1 for row in symbol_exec_rows if str(row.get("status", "")).upper() == "BLOCKED")
        duplicate_blocks = sum(1 for row in symbol_exec_rows if "duplicate" in str(row.get("detail", "")).lower())
        ready_plans = sum(1 for row in symbol_plan_rows if csv_truth(row.get("ready")))
        learning_row = learning_symbols.get(symbol, {}) if isinstance(learning_symbols.get(symbol, {}), dict) else {}
        learning_confidence = int(safe_float(learning_row.get("confidence"), 0))
        base_confidence = min(100, learning_confidence + len(symbol_watch_rows) * 3 + len(symbol_alert_rows) * 6 + ready_plans * 10 + submitted * 12)
        regime_adjustment = 0.0
        if regime_name == "BULLISH":
            regime_adjustment = 4.0
        elif regime_name == "BEARISH":
            regime_adjustment = -5.0
        elif regime_name == "DEFENSIVE":
            regime_adjustment = 3.0 if sector in defensive_sectors else -2.0
        elif regime_name == "MIXED":
            regime_adjustment = -1.0
        failure_penalty = failed * 12 + duplicate_blocks * 8 + max(0, blocked - submitted) * 1.5
        proof_bonus = 4.0 if proof.get("ready_to_unlock_live") else 0.0
        quantum_score = (
            avg_watch_score * 0.48
            + base_confidence * 0.24
            + approval_rate * 100 * 0.16
            + min(ready_plans, 5) * 3.0
            + min(submitted, 5) * 2.0
            + regime_adjustment
            + proof_bonus
            - failure_penalty
        )
        quantum_score = round(max(0, min(100, quantum_score)), 2)
        penalty_adjustment = round(max(-8, -1 * (failed * 3 + duplicate_blocks * 2 + max(0, blocked - submitted) * 0.4)), 2)
        positive_adjustment = 0.0
        if base_confidence >= min_confidence and quantum_score >= 70:
            positive_adjustment = min(max_boost, (quantum_score - 70) / 6)
        if positive_adjustment > 0 and not positive_learning_gate.get("positive_allowed"):
            positive_adjustment = 0.0
        watchlist_adjustment = round(min(max_boost, positive_adjustment) + penalty_adjustment, 2)
        if failed or duplicate_blocks:
            state = "COOLDOWN"
            note = "PMO v108 sees failures or duplicate blocks; this symbol is penalized until proof improves."
        elif quantum_score >= 82 and base_confidence >= min_confidence:
            state = "QUANTUM_LEADER"
            note = "PMO v108 sees cross-source agreement, sector support, and enough confidence for watchlist priority."
        elif quantum_score >= 68:
            state = "FAST_WATCH"
            note = "PMO v108 sees useful momentum but still wants more proof before heavy execution confidence."
        else:
            state = "BUILD_PROOF"
            note = "PMO v108 is still collecting evidence across alerts, plans, sectors, and execution logs."
        row = {
            "symbol": symbol,
            "sector": sector,
            "state": state,
            "quantum_score": quantum_score,
            "confidence": base_confidence,
            "avg_watch_score": avg_watch_score,
            "approval_rate": round(approval_rate, 3),
            "ready_plans": ready_plans,
            "submitted": submitted,
            "failed": failed,
            "blocked": blocked,
            "duplicate_blocks": duplicate_blocks,
            "regime_alignment": regime_adjustment,
            "watchlist_adjustment": watchlist_adjustment,
            "penalty_adjustment": penalty_adjustment,
            "note": note,
        }
        symbol_rows[symbol] = row
        sector_buckets.setdefault(sector, []).append(row)
    sectors: List[Dict[str, Any]] = []
    for sector, rows in sector_buckets.items():
        if not rows:
            continue
        avg_score = round(sum(safe_float(row.get("quantum_score"), 0) for row in rows) / len(rows), 2)
        leaders = [row for row in rows if row.get("state") in {"QUANTUM_LEADER", "FAST_WATCH"}]
        cooldown = [row for row in rows if row.get("state") == "COOLDOWN"]
        top = sorted(rows, key=lambda row: safe_float(row.get("quantum_score"), 0), reverse=True)[:4]
        sectors.append({
            "sector": sector,
            "quantum_score": avg_score,
            "leaders": len(leaders),
            "cooldown": len(cooldown),
            "symbols": ", ".join(row["symbol"] for row in top),
            "state": "LEADING" if avg_score >= 75 and leaders else "COOLDOWN" if cooldown and avg_score < 60 else "WATCH",
        })
    sectors.sort(key=lambda row: safe_float(row.get("quantum_score"), 0), reverse=True)
    top_symbols = sorted(symbol_rows.values(), key=lambda row: (safe_float(row.get("quantum_score"), 0), safe_float(row.get("confidence"), 0)), reverse=True)[:30]
    matrix = {
        "ok": True,
        "updated": now_et().isoformat(),
        "mode": mode,
        "window_days": days,
        "regime": regime_name,
        "symbols": symbol_rows,
        "top_symbols": top_symbols,
        "sectors": sectors[: int(settings.get("PMO_QUANTUM_TOP_SECTORS", 8))],
        "summary": {
            "symbol_count": len(symbol_rows),
            "sector_count": len(sectors),
            "leader_count": sum(1 for row in symbol_rows.values() if row.get("state") == "QUANTUM_LEADER"),
            "cooldown_count": sum(1 for row in symbol_rows.values() if row.get("state") == "COOLDOWN"),
            "paper_proof_score": proof.get("score", 0),
            "positive_boosts_allowed": bool(positive_learning_gate.get("positive_allowed")),
            "positive_boost_blocked_reason": positive_learning_gate.get("reason", ""),
            "sources": {
                "alerts": len(alert_rows),
                "executor_rows": len(executor_rows),
                "trade_plans": len(plan_rows),
                "watchlist_rows": len(watch_rows),
            },
        },
        "file": str(PMO_QUANTUM_MATRIX_FILE),
    }
    if record:
        PMO_QUANTUM_MATRIX_FILE.parent.mkdir(parents=True, exist_ok=True)
        PMO_QUANTUM_MATRIX_FILE.write_text(json.dumps(matrix, indent=2), encoding="utf-8")
        csv_append(PMO_QUANTUM_EVENTS_FILE, {
            "timestamp": matrix["updated"],
            "mode": mode,
            "symbols": len(symbol_rows),
            "sectors": len(sectors),
            "leaders": matrix["summary"]["leader_count"],
            "cooldown": matrix["summary"]["cooldown_count"],
            "paper_proof_score": matrix["summary"]["paper_proof_score"],
            "regime": regime_name,
        })
    return matrix


PMO_WARP_DESCRIPTION = """
PMO WARP Mode stands for Watch, Analyze, Recommend, Protect.

WARP is a fast intelligence layer inside PMO BOT. It watches system status,
analyzes risk and opportunity, recommends the next best owner action, and
protects the owner by blocking unsafe actions or requiring manual approval.

WARP does not bypass safety. It does not fake results. It does not execute
risky actions without owner approval.
""".strip()


def pmo_warp_default_memory() -> Dict[str, Any]:
    return {
        "version": "PMO_WARP_V109",
        "created_at": now_et().isoformat(),
        "description": PMO_WARP_DESCRIPTION,
        "decisions": [],
        "blocked_terms": [
            "password",
            "private key",
            "seed phrase",
            "ssn",
            "cvv",
            "card number",
            "routing number",
            "account number",
            "fake plays",
            "fake streams",
            "fake traffic",
            "bot traffic",
            "ban evasion",
            "credential stuffing",
            "login automation",
            "scrape private data",
        ],
        "approval_required_actions": [
            "live_trade",
            "place_order",
            "send_payment",
            "refund_payment",
            "cancel_order",
            "route_provider",
            "mark_complete",
            "change_live_setting",
            "delete_data",
            "enable_live_executor",
        ],
    }


def load_pmo_warp_memory() -> Dict[str, Any]:
    if PMO_WARP_MEMORY_FILE.exists():
        try:
            data = json.loads(PMO_WARP_MEMORY_FILE.read_text(encoding="utf-8"))
            if isinstance(data, dict):
                base = pmo_warp_default_memory()
                base.update(data)
                base.setdefault("decisions", [])
                return base
        except Exception:
            pass
    return pmo_warp_default_memory()


def save_pmo_warp_memory(memory: Dict[str, Any]) -> None:
    PMO_WARP_MEMORY_FILE.parent.mkdir(parents=True, exist_ok=True)
    PMO_WARP_MEMORY_FILE.write_text(json.dumps(memory, indent=2), encoding="utf-8")


def pmo_warp_make_id(prefix: str, payload: Dict[str, Any]) -> str:
    raw = json.dumps(payload, sort_keys=True, default=str)
    return f"{prefix}_{uuid.uuid5(uuid.NAMESPACE_DNS, raw).hex[:12]}"


def pmo_warp_redact(value: Any) -> Any:
    sensitive_key_terms = ("password", "secret", "token", "private_key", "seed", "cvv", "routing", "account_number", "card")
    if isinstance(value, dict):
        redacted: Dict[str, Any] = {}
        for key, item in value.items():
            clean_key = str(key).lower().replace("-", "_").replace(" ", "_")
            if any(term in clean_key for term in sensitive_key_terms):
                redacted[key] = "[REDACTED]"
            else:
                redacted[key] = pmo_warp_redact(item)
        return redacted
    if isinstance(value, list):
        return [pmo_warp_redact(item) for item in value[:200]]
    if isinstance(value, str) and len(value) > 240:
        return value[:240] + "...[trimmed]"
    return value


def pmo_warp_safety_check(payload: Dict[str, Any], memory: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    memory = memory or load_pmo_warp_memory()
    text = json.dumps(payload, default=str).lower()
    blocked = [term for term in memory.get("blocked_terms", []) if term in text]
    if blocked:
        return {
            "safe": False,
            "risk_level": 100,
            "blocked_terms": blocked,
            "approval_required": True,
            "reason": "WARP detected unsafe or sensitive data/action terms.",
        }
    action = str(payload.get("action") or payload.get("goal") or "").lower().replace(" ", "_")
    context = payload.get("context") if isinstance(payload.get("context"), dict) else {}
    approval_required = action in set(memory.get("approval_required_actions", []))
    risk_level = 20
    if approval_required:
        risk_level += 45
    for term in ("live_trade", "place_order", "send_payment", "refund_payment", "delete_data", "enable_live_executor"):
        if term.replace("_", " ") in text or term in text:
            risk_level += 15
            approval_required = True
    if context.get("live_mode") is True or context.get("live_executor_enabled") is True:
        risk_level += 25
    if context.get("money_involved") is True:
        risk_level += 20
    if context.get("customer_impact") is True:
        risk_level += 20
    if context.get("broker_order_execution_enabled") is True:
        risk_level += 20
    if context.get("paper_proof_ready") is False:
        risk_level += 10
    risk_level = max(0, min(100, risk_level))
    return {
        "safe": True,
        "risk_level": risk_level,
        "blocked_terms": [],
        "approval_required": approval_required or risk_level >= 60,
        "reason": "Passed WARP safety check.",
    }


