def subscription_tiers() -> List[Dict[str, Any]]:
    tiers = []
    for tier in product_tiers():
        slug = str(tier.get("slug") or slugify(tier.get("name", "tier")))
        env_slug = slug.upper().replace("-", "_")
        paypal_url = first_env(f"PAYPAL_SUBSCRIPTION_URL_{env_slug}")
        stripe_url = first_env(f"STRIPE_SUBSCRIPTION_URL_{env_slug}")
        plan_id = first_env(f"PAYPAL_PLAN_ID_{env_slug}")
        checkout_url = paypal_url or stripe_url
        route = "PayPal hosted subscription" if paypal_url else "Stripe subscription link" if stripe_url else "PayPal plan id" if plan_id else "PMO request form"
        tiers.append({
            **tier,
            "slug": slug,
            "interval": "monthly",
            "paypal_subscription_url": paypal_url,
            "stripe_subscription_url": stripe_url,
            "paypal_plan_id": plan_id,
            "checkout_url": checkout_url,
            "payment_route": route,
            "configured": bool(checkout_url or plan_id),
            "features": [
                "PMO web terminal access",
                "PMO risk and signal dashboards",
                "TradingView/Pine setup support",
            ],
        })
    return tiers


