def load_auto_watchlist() -> Dict[str, Any]:
    if not AUTO_WATCHLIST_FILE.exists():
        return {"ok": False, "updated": "", "symbols": [], "selected": [], "scored": []}
    try:
        data = json.loads(AUTO_WATCHLIST_FILE.read_text(encoding="utf-8"))
        if not isinstance(data, dict):
            return {"ok": False, "updated": "", "symbols": [], "selected": [], "scored": []}
        data["symbols"] = unique_symbols(data.get("symbols", []))
        data["selected"] = pmo_dedupe_rows(data.get("selected", []), ["symbol"], keep="first")
        data["scored"] = pmo_dedupe_rows(data.get("scored", []), ["symbol"], keep="first")
        return data
    except Exception:
        return {"ok": False, "updated": "", "symbols": [], "selected": [], "scored": []}


def auto_watchlist_lookup(auto_watchlist: Dict[str, Any]) -> Dict[str, Dict[str, Any]]:
    lookup: Dict[str, Dict[str, Any]] = {}
    for row in auto_watchlist.get("scored", []) + auto_watchlist.get("selected", []):
        symbol = str(row.get("symbol", "")).upper()
        if symbol:
            lookup[symbol] = row
    return lookup


def sector_rotation_rows(auto_watchlist: Dict[str, Any]) -> List[Dict[str, Any]]:
    lookup = auto_watchlist_lookup(auto_watchlist)
    rows: List[Dict[str, Any]] = []
    for item in SECTOR_ROTATION_SYMBOLS:
        symbol = item["symbol"]
        data = lookup.get(symbol, {})
        score = safe_float(data.get("score"))
        bias = data.get("bias") or "PENDING"
        if not data:
            status = "PENDING LIVE SCAN"
            action = "Run Auto Build Watchlist to score this sector."
        elif score >= 68:
            status = "LEADING"
            action = "PMO watches for continuation and stronger confirmation."
        elif score >= 58:
            status = "WATCHING"
            action = "PMO keeps it active but requires confirmation."
        else:
            status = "DEFENSIVE"
            action = "PMO treats this sector as lower priority."
        rows.append({
            "sector": item["sector"],
            "symbol": symbol,
            "score": round(score, 2) if data else "",
            "bias": bias,
            "price": data.get("price", ""),
            "change_pct": data.get("change_pct", ""),
            "relative_volume": data.get("relative_volume", ""),
            "status": status,
            "action": action,
        })
    return rows


def expanded_watchlist_rows(settings: Dict[str, Any], auto_watchlist: Dict[str, Any]) -> List[Dict[str, Any]]:
    lookup = auto_watchlist_lookup(auto_watchlist)
    symbols = unique_symbols(settings.get("PMO_WATCHLIST", []), auto_watchlist.get("symbols", []), pmo_market_universe(settings))
    rows: List[Dict[str, Any]] = []
    for symbol in symbols[:60]:
        data = lookup.get(symbol, {})
        rows.append({
            "symbol": symbol,
            "market": data.get("market", detect_market(symbol, "AUTO")),
            "score": data.get("score", ""),
            "bias": data.get("bias", "PENDING"),
            "price": data.get("price", ""),
            "feed": data.get("feed", ""),
            "state": "AUTO SELECTED" if symbol in auto_watchlist.get("symbols", []) else "UNIVERSE",
        })
    return rows


