def pmo_micro_execution_guard(
    settings: Dict[str, Any],
    symbol: str,
    market: str = "AUTO",
    positions: Optional[List[Dict[str, Any]]] = None,
    require_proof: bool = True,
) -> Dict[str, Any]:
    if not pmo_micro_mode_enabled(settings):
        return {"ok": True, "enabled": False, "allowed": True, "blockers": []}
    clean_symbol = str(symbol or "").strip().upper()
    clean_market = str(market or detect_market(clean_symbol, "AUTO")).upper()
    if clean_market == "AUTO":
        clean_market = detect_market(clean_symbol, "AUTO")
    data_collection_active = bool(settings.get("DATA_COLLECTION_ACTIVE"))
    safe_symbols = set(pmo_micro_safe_symbols(settings))
    blocked_symbols = pmo_micro_blocked_symbols(settings)
    blockers: List[str] = []
    if clean_market != "STOCK":
        blockers.append(f"Micro Mode allows stock/ETF symbols only; {clean_market} is watch-only")
    if clean_symbol in blocked_symbols or pmo_is_leveraged_etf(clean_symbol, settings):
        blockers.append(f"Micro Mode blocks high-risk leveraged/watch-only symbol {clean_symbol}")
    if safe_symbols and clean_symbol not in safe_symbols and not data_collection_active:
        blockers.append(f"{clean_symbol or 'missing symbol'} is outside the Micro Mode safe watchlist")
    active_positions = []
    for position in positions or []:
        qty = safe_float(position.get("qty"), 0)
        value = safe_float(position.get("market_value"), 0)
        if qty or value:
            active_positions.append(position)
    position_symbols = {str(position.get("symbol", "")).strip().upper() for position in active_positions}
    max_open = int(settings.get("PMO_MICRO_MAX_OPEN_POSITIONS", 1))
    if clean_symbol and clean_symbol in position_symbols:
        blockers.append(f"Micro Mode blocks duplicate entries and averaging down on existing position {clean_symbol}")
    if max_open >= 0 and len(active_positions) >= max_open and clean_symbol not in position_symbols:
        blockers.append(f"Micro Mode max open positions reached: {len(active_positions)}/{max_open}")
    proof_gate = {}
    if require_proof and bool(settings.get("PMO_MICRO_REQUIRE_VERIFIED_WIN_RATE", True)) and not data_collection_active:
        proof_gate = pmo_positive_learning_gate(settings)
        if not proof_gate.get("positive_allowed"):
            blockers.append(f"Micro Mode requires verified closed-paper edge: {proof_gate.get('reason')}")
    return {
        "ok": True,
        "enabled": True,
        "allowed": not blockers,
        "blockers": blockers,
        "symbol": clean_symbol,
        "market": clean_market,
        "safe_watchlist": sorted(safe_symbols),
        "blocked_symbols": sorted(blocked_symbols),
        "active_open_positions": len(active_positions),
        "max_open_positions": max_open,
        "proof_gate": proof_gate,
        "risk_budget": pmo_micro_risk_budget(settings),
        "data_collection_active": data_collection_active,
    }


def pmo_load_drawdown_lock() -> Dict[str, Any]:
    if not PMO_DRAWDOWN_LOCK_FILE.exists():
        return {}
    try:
        data = json.loads(PMO_DRAWDOWN_LOCK_FILE.read_text(encoding="utf-8"))
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}


def pmo_save_drawdown_lock(lock: Dict[str, Any]) -> None:
    PMO_DRAWDOWN_LOCK_FILE.parent.mkdir(parents=True, exist_ok=True)
    PMO_DRAWDOWN_LOCK_FILE.write_text(json.dumps(lock, indent=2), encoding="utf-8")


def pmo_day_drawdown_governor(
    settings: Dict[str, Any],
    account: Optional[Dict[str, Any]] = None,
    symbol: str = "",
    action: str = "NEW_ENTRY",
    record: bool = False,
) -> Dict[str, Any]:
    account = account or {}
    session_date = now_et().date().isoformat()
    symbol = str(symbol or "").strip().upper()
    action = str(action or "NEW_ENTRY").strip().upper()
    enabled = bool(settings.get("ENABLE_PMO_DAY_DRAWDOWN_GOVERNOR", True))
    day_pnl = safe_float(account.get("day_pnl"), 0)
    day_pnl_pct = safe_float(account.get("day_pnl_percent"), 0)
    equity = safe_float(account.get("equity") or account.get("portfolio_value"), 0)
    buying_power = safe_float(account.get("buying_power"), 0)
    account_ok = bool(account.get("ok"))
    if not day_pnl_pct and day_pnl and equity:
        prior_equity = equity - day_pnl
        day_pnl_pct = (day_pnl / prior_equity * 100) if prior_equity else 0
    stale_lock_reset = False
    if PMO_DRAWDOWN_LOCK_FILE.exists():
        try:
            PMO_DRAWDOWN_LOCK_FILE.unlink(missing_ok=True)
            stale_lock_reset = True
        except Exception:
            stale_lock_reset = False
    persistent_freeze = False
    reduce_pct = safe_float(settings.get("PMO_DAY_LOSS_REDUCE_APPROVAL_PCT", 1.0), 1.0)
    leveraged_pct = safe_float(settings.get("PMO_DAY_LOSS_BLOCK_LEVERAGED_ETF_PCT", 1.5), 1.5)
    block_pct = safe_float(settings.get("PMO_DAY_LOSS_BLOCK_NEW_ENTRIES_PCT", 2.0), 2.0)
    review_pct = safe_float(settings.get("PMO_DAY_LOSS_REVIEW_ONLY_PCT", 3.0), 3.0)
    freeze_pct = safe_float(settings.get("PMO_DAY_LOSS_FREEZE_PCT", 4.0), 4.0)
    approval_scale = max(0.0, min(1.0, safe_float(settings.get("PMO_DRAWDOWN_REDUCED_APPROVAL_SCALE", 0.5), 0.5)))
    micro_enabled = pmo_micro_mode_enabled(settings)
    micro_loss_usd = max(0.0, -day_pnl)
    micro_thresholds = {
        "caution_loss_usd": safe_float(settings.get("PMO_MICRO_CAUTION_LOSS_USD", 1.5), 1.5),
        "defensive_loss_usd": safe_float(settings.get("PMO_MICRO_DEFENSIVE_LOSS_USD", 2.5), 2.5),
        "review_only_loss_usd": safe_float(settings.get("PMO_MICRO_REVIEW_ONLY_LOSS_USD", 4.0), 4.0),
        "lockout_loss_usd": safe_float(settings.get("PMO_MICRO_LOCKOUT_LOSS_USD", 6.0), 6.0),
        "max_daily_loss_usd": safe_float(settings.get("PMO_MICRO_MAX_DAILY_LOSS_USD", 6.0), 6.0),
    }
    micro_stage = "CLEAR"
    if micro_enabled and micro_loss_usd >= micro_thresholds["lockout_loss_usd"]:
        micro_stage = "FULL_LOCKOUT"
    elif micro_enabled and micro_loss_usd >= micro_thresholds["review_only_loss_usd"]:
        micro_stage = "REVIEW_ONLY"
    elif micro_enabled and micro_loss_usd >= micro_thresholds["defensive_loss_usd"]:
        micro_stage = "DEFENSIVE"
    elif micro_enabled and micro_loss_usd >= micro_thresholds["caution_loss_usd"]:
        micro_stage = "CAUTION"
    max_drawdown_review_now = bool(enabled and (day_pnl_pct <= -freeze_pct or micro_stage == "FULL_LOCKOUT"))
    freeze_triggered_now = False
    freeze_triggered_at = ""
    freeze_trigger_day_pnl = day_pnl
    freeze_trigger_day_pnl_pct = day_pnl_pct
    freeze_trigger_detail = ""
    level = "NORMAL"
    status = "CLEAR"
    readiness_cap = None
    new_entries_allowed = True
    leveraged_blocked = False
    force_review_only = False
    session_frozen = False
    signal_approval_scale = 1.0
    if not enabled:
        status = "OFF"
    elif max_drawdown_review_now:
        level = "MAX_DRAWDOWN_REVIEW"
        status = "REVIEW_ONLY"
        readiness_cap = 55
        new_entries_allowed = False
        leveraged_blocked = True
        force_review_only = True
        signal_approval_scale = 0.0
    elif micro_enabled and micro_stage == "REVIEW_ONLY":
        level = "MICRO_REVIEW_ONLY"
        status = "REVIEW_ONLY"
        readiness_cap = 55
        new_entries_allowed = False
        leveraged_blocked = True
        force_review_only = True
        signal_approval_scale = 0.0
    elif micro_enabled and micro_stage == "DEFENSIVE":
        level = "MICRO_DEFENSIVE"
        status = "DEFENSIVE"
        readiness_cap = 70
        new_entries_allowed = False
        leveraged_blocked = True
        signal_approval_scale = 0.0
    elif micro_enabled and micro_stage == "CAUTION":
        level = "MICRO_CAUTION"
        status = "CAUTION"
        readiness_cap = 85
        leveraged_blocked = True
        if bool(settings.get("PMO_MICRO_BLOCK_NEW_TRADES_AFTER_CAUTION", True)):
            new_entries_allowed = False
            signal_approval_scale = 0.0
        else:
            signal_approval_scale = approval_scale
    elif day_pnl_pct <= -review_pct:
        level = "REVIEW_ONLY"
        status = "REVIEW_ONLY"
        readiness_cap = 55
        new_entries_allowed = False
        leveraged_blocked = True
        force_review_only = True
        signal_approval_scale = 0.0
    elif day_pnl_pct <= -block_pct:
        level = "BLOCK_NEW_ENTRIES"
        status = "STOP_NEW_TRADES"
        readiness_cap = 70
        new_entries_allowed = False
        leveraged_blocked = True
        signal_approval_scale = 0.0
    elif day_pnl_pct <= -leveraged_pct:
        level = "BLOCK_LEVERAGED_ETFS"
        status = "LEVERAGED_ETF_BLOCK"
        readiness_cap = 85
        leveraged_blocked = True
        signal_approval_scale = approval_scale
    elif day_pnl_pct <= -reduce_pct:
        level = "REDUCE_APPROVAL"
        status = "HALF_THROTTLE"
        readiness_cap = 85
        signal_approval_scale = approval_scale
    elif day_pnl_pct < 0:
        level = "WATCH"
        status = "WATCH"
    symbol_is_leveraged = pmo_is_leveraged_etf(symbol, settings)
    live_ready_allowed = bool(enabled and level in {"NORMAL", "WATCH", "REDUCE_APPROVAL", "BLOCK_LEVERAGED_ETFS"}) or not enabled
    symbol_blocked = enabled and action in PMO_DRAWDOWN_BLOCKED_TRADE_ACTIONS and (
        not new_entries_allowed or (leveraged_blocked and symbol_is_leveraged)
    )
    order_submission_blocked = bool(enabled and (not new_entries_allowed or (leveraged_blocked and symbol_is_leveraged)))
    live_arming_blocked = not bool(live_ready_allowed)
    blockers: List[str] = []
    if symbol_blocked and not new_entries_allowed:
        blockers.append(f"day drawdown governor is {status}; new entries are blocked")
    elif symbol_blocked and symbol_is_leveraged:
        blockers.append(f"day drawdown governor blocks leveraged ETF {symbol}")
    elif enabled and signal_approval_scale < 1:
        blockers.append(f"day drawdown governor reduced new signal approvals to {int(signal_approval_scale * 100)}%")
    if account.get("ok"):
        detail = f"Day P&L ${day_pnl:.2f} / {day_pnl_pct:.2f}% | {status}"
        if micro_enabled:
            detail = f"{detail} | Micro loss ${micro_loss_usd:.2f} | Stage {micro_stage}"
    else:
        detail = f"Account P&L unavailable | {status}"
    if session_frozen:
        freeze_trigger_detail = freeze_trigger_detail or detail
    if session_frozen and persistent_freeze:
        trigger_text = f"freeze trigger ${freeze_trigger_day_pnl:.2f} / {freeze_trigger_day_pnl_pct:.2f}%"
        if freeze_triggered_at:
            trigger_text = f"{trigger_text} at {freeze_triggered_at}"
        detail = f"{detail} ({trigger_text})"
    if stale_lock_reset:
        detail = f"{detail} | removed old persistent drawdown lock file"
    if session_frozen and record:
        seen_at = now_et().isoformat()
        pmo_save_drawdown_lock({
            "session_date": session_date,
            "level": PMO_DRAWDOWN_LEGACY_FREEZE_LEVEL,
            "display_level": PMO_DRAWDOWN_HARD_STOP_NAME,
            "hard_stop_name": PMO_DRAWDOWN_HARD_STOP_NAME,
            "status": status,
            "day_pnl": freeze_trigger_day_pnl,
            "day_pnl_percent": round(freeze_trigger_day_pnl_pct, 4),
            "trigger_day_pnl": freeze_trigger_day_pnl,
            "trigger_day_pnl_percent": round(freeze_trigger_day_pnl_pct, 4),
            "current_day_pnl": day_pnl,
            "current_day_pnl_percent": round(day_pnl_pct, 4),
            "micro_mode": micro_enabled,
            "micro_stage": micro_stage,
            "micro_loss_usd": round(micro_loss_usd, 2),
            "micro_thresholds": micro_thresholds,
            "triggered_at": freeze_triggered_at or seen_at,
            "last_seen_at": seen_at,
            "reset_rule": "Clears automatically when the PMO session date changes, then starts the next session from current broker P&L.",
            "blocked_actions": sorted(PMO_DRAWDOWN_BLOCKED_TRADE_ACTIONS),
            "allowed_actions": PMO_DRAWDOWN_HARD_STOP_ALLOWED_ACTIONS,
            "trigger_detail": freeze_trigger_detail,
            "current_detail": detail,
            "detail": freeze_trigger_detail,
        })
    return {
        "ok": True,
        "enabled": enabled,
        "session_date": session_date,
        "level": level,
        "display_level": PMO_DRAWDOWN_HARD_STOP_NAME if session_frozen else level,
        "hard_stop_name": PMO_DRAWDOWN_HARD_STOP_NAME if session_frozen else "",
        "status": status,
        "day_pnl": round(day_pnl, 2),
        "day_pnl_percent": round(day_pnl_pct, 4),
        "micro_mode": micro_enabled,
        "micro_stage": micro_stage,
        "micro_loss_usd": round(micro_loss_usd, 2),
        "micro_thresholds": micro_thresholds,
        "micro_account_size": safe_float(settings.get("PMO_MICRO_ACCOUNT_SIZE_USD", 200.0), 200.0),
        "readiness_score_cap": readiness_cap,
        "signal_approval_scale": signal_approval_scale,
        "new_entries_allowed": new_entries_allowed,
        "leveraged_etfs_blocked": leveraged_blocked,
        "force_review_only": force_review_only,
        "day_hard_stop": session_frozen,
        "session_frozen": session_frozen,
        "persistent_freeze": persistent_freeze,
        "freeze_triggered_now": freeze_triggered_now,
        "max_drawdown_review_now": max_drawdown_review_now,
        "freeze_triggered_at": freeze_triggered_at if session_frozen else "",
        "freeze_trigger_day_pnl": round(freeze_trigger_day_pnl, 2) if session_frozen else None,
        "freeze_trigger_day_pnl_percent": round(freeze_trigger_day_pnl_pct, 4) if session_frozen else None,
        "symbol": symbol,
        "symbol_is_leveraged_etf": symbol_is_leveraged,
        "symbol_blocked": symbol_blocked,
        "order_submission_blocked": order_submission_blocked,
        "live_arming_blocked": live_arming_blocked,
        "platform_review_allowed": True,
        "dashboard_review_allowed": True,
        "broker_sync_allowed": True,
        "journal_export_allowed": True,
        "learning_reports_allowed": True,
        "paper_analysis_allowed": True,
        "would_have_traded_analysis_allowed": True,
        "penalty_active": bool(enabled and level not in {"NORMAL", "WATCH"}),
        "live_ready_allowed": live_ready_allowed,
        "blockers": blockers,
        "detail": detail,
        "blocked_actions": sorted(PMO_DRAWDOWN_BLOCKED_TRADE_ACTIONS) if order_submission_blocked else [],
        "allowed_actions": PMO_DRAWDOWN_HARD_STOP_ALLOWED_ACTIONS if order_submission_blocked else ["normal_review"],
        "reset_rule": "No persistent drawdown lock is used. Drawdown status follows current broker/account P&L only.",
        "stale_lock_reset": stale_lock_reset,
        "auto_recovered_from_stale_lock": stale_lock_reset,
        "file": str(PMO_DRAWDOWN_LOCK_FILE),
    }


def pmo_drawdown_signal_allowed(symbol: str, score: Any, settings: Dict[str, Any], governor: Dict[str, Any]) -> bool:
    if not governor.get("enabled", True):
        return True
    if governor.get("symbol_blocked"):
        return False
    scale = safe_float(governor.get("signal_approval_scale"), 1.0)
    if scale >= 1.0:
        return True
    if scale <= 0:
        return False
    seed = f"{governor.get('session_date')}|{str(symbol).upper()}|{int(safe_float(score, 0))}"
    bucket = int(hashlib.sha256(seed.encode("utf-8")).hexdigest()[:8], 16) % 100
    return bucket < int(scale * 100)


def pmo_risk_guard_summary(settings: Dict[str, Any]) -> Dict[str, Any]:
    checks = [
        ("ENABLE_BUYING_POWER_GUARD", bool(settings.get("ENABLE_BUYING_POWER_GUARD"))),
        ("ENABLE_CASH_LOCKOUT", bool(settings.get("ENABLE_CASH_LOCKOUT"))),
        ("ENABLE_PDT_PROTECTION_AI", bool(settings.get("ENABLE_PDT_PROTECTION_AI"))),
        ("ENABLE_PMO_DUPLICATE_PHASE_GUARD", bool(settings.get("ENABLE_PMO_DUPLICATE_PHASE_GUARD"))),
    ]
    blockers = [name for name, ready in checks if not ready]
    return {"ready": not blockers, "checks": [{"name": name, "ready": ready} for name, ready in checks], "blockers": blockers}


def pmo_market_data_ready_from_health(health: Dict[str, Any]) -> bool:
    for row in health.get("connections", []):
        if str(row.get("name", "")).lower() == "alpaca market data":
            return bool(row.get("online"))
    total = max(1, int(health.get("total") or 1))
    return int(health.get("online") or 0) >= max(1, int(total * 0.50))


def pmo_smart_trade_limit_snapshot(
    settings: Dict[str, Any],
    health: Optional[Dict[str, Any]] = None,
    regime: Optional[Dict[str, Any]] = None,
    score: Optional[Any] = None,
    account: Optional[Dict[str, Any]] = None,
    symbol: str = "",
) -> Dict[str, Any]:
    health = health or {}
    regime = regime or {}
    account = account or {}
    score_band = pmo_trade_score_band(score if score is not None else 0, settings)
    risk = pmo_risk_guard_summary(settings)
    market_data_online = pmo_market_data_ready_from_health(health) if health else True
    regime_name = str(regime.get("regime") or "UNKNOWN").upper()
    regime_clear = regime_name not in {"", "UNKNOWN"}
    live_context = (
        str(settings.get("PMO_ORDER_EXECUTION_MODE", "SIGNAL_ONLY")).upper() == "LIVE_ALPACA"
        or bool(settings.get("PMO_LIVE_TRADING_ENABLED"))
        or not bool(settings.get("ALPACA_PAPER", True))
    )
    conservative_by_market = {
        "STOCK": int(settings.get("PMO_CONSERVATIVE_MAX_STOCK_TRADES", 6)),
        "CRYPTO": int(settings.get("PMO_CONSERVATIVE_MAX_CRYPTO_TRADES", 4)),
        "OPTION": int(settings.get("PMO_CONSERVATIVE_MAX_OPTION_TRADES", 2)),
    }
    paper_by_market = {
        "STOCK": int(settings.get("PMO_PAPER_MAX_STOCK_TRADES", 10)),
        "CRYPTO": int(settings.get("PMO_PAPER_MAX_CRYPTO_TRADES", 6)),
        "OPTION": int(settings.get("PMO_PAPER_MAX_OPTION_TRADES", 3)),
    }
    live_by_market = {
        "STOCK": int(settings.get("PMO_LIVE_MAX_STOCK_TRADES", 3)),
        "CRYPTO": int(settings.get("PMO_LIVE_MAX_CRYPTO_TRADES", 2)),
        "OPTION": int(settings.get("PMO_LIVE_MAX_OPTION_TRADES", 1)),
    }
    full_size_score = safe_float(settings.get("PMO_SMART_LIMIT_FULL_SIZE_SCORE", 85), 85)
    prerequisites = {
        "smart_limiter_enabled": bool(settings.get("ENABLE_PMO_SMART_TRADE_LIMITER", True)),
        "market_data_online": market_data_online or not bool(settings.get("PMO_SMART_LIMIT_REQUIRE_MARKET_DATA", True)),
        "regime_clear": regime_clear or not bool(settings.get("PMO_SMART_LIMIT_REQUIRE_CLEAR_REGIME", True)),
        "risk_guards_ready": risk["ready"] or not bool(settings.get("PMO_SMART_LIMIT_REQUIRE_RISK_GUARDS", True)),
        "score_strong_enough_for_full_size": (score is None) or safe_float(score, 0) >= full_size_score,
    }
    blockers = [name for name, ok in prerequisites.items() if not ok]
    if live_context:
        limit_mode = "LIVE_CONSERVATIVE"
        effective_daily = int(settings.get("PMO_LIVE_MAX_DAILY_TRADES", 3))
        effective_by_market = live_by_market
        full_paper_limits_active = False
    elif not prerequisites["smart_limiter_enabled"]:
        limit_mode = "SMART_LIMITER_OFF_CONSERVATIVE"
        effective_daily = int(settings.get("PMO_CONSERVATIVE_MAX_DAILY_TRADES", 6))
        effective_by_market = conservative_by_market
        full_paper_limits_active = False
    elif blockers:
        limit_mode = "PAPER_CONSERVATIVE"
        effective_daily = int(settings.get("PMO_CONSERVATIVE_MAX_DAILY_TRADES", 6))
        effective_by_market = conservative_by_market
        full_paper_limits_active = False
    else:
        limit_mode = "PAPER_SMART_EXPANDED"
        effective_daily = int(settings.get("PMO_PAPER_MAX_DAILY_TRADES", 10))
        effective_by_market = paper_by_market
        full_paper_limits_active = True
    drawdown_governor = pmo_day_drawdown_governor(settings, account, symbol=symbol, action="NEW_ENTRY", record=False)
    approval_scale = safe_float(drawdown_governor.get("signal_approval_scale"), 1.0)
    if approval_scale < 1.0:
        if approval_scale <= 0:
            effective_daily = 0
            effective_by_market = {market: 0 for market in effective_by_market}
        else:
            effective_daily = int(max(1, effective_daily * approval_scale))
            effective_by_market = {market: int(max(1, value * approval_scale)) if value > 0 else 0 for market, value in effective_by_market.items()}
        full_paper_limits_active = False
        if "DRAWDOWN" not in limit_mode:
            limit_mode = f"{limit_mode}_DRAWDOWN"
    rebuild_score_gate = pmo_rebuild_score_gate(score, settings) if score is not None else {"enabled": False, "allowed": True, "blockers": []}
    if score is None:
        execution_allowed = True
    elif rebuild_score_gate.get("enabled"):
        execution_allowed = bool(rebuild_score_gate.get("allowed"))
        blockers.extend(rebuild_score_gate.get("blockers", []))
    else:
        execution_allowed = bool(score_band["paper_trade_candidate"])
        if score_band["band"] in {"NO_TRADE", "WATCH_ONLY"}:
            execution_allowed = False
    if drawdown_governor.get("symbol_blocked"):
        execution_allowed = False
        blockers.extend(drawdown_governor.get("blockers", []) or [drawdown_governor.get("detail", "day drawdown governor blocked this entry")])
    market = detect_market(symbol, "AUTO") if symbol else "AUTO"
    micro_guard = pmo_micro_execution_guard(settings, symbol, market, positions=None, require_proof=score is not None)
    if not micro_guard.get("allowed", True):
        execution_allowed = False
        blockers.extend(micro_guard.get("blockers", []))
    if bool(settings.get("PMO_REQUIRE_MARKET_DATA_FOR_EXECUTION", True)) and not market_data_online:
        execution_allowed = False
    if bool(settings.get("PMO_SMART_LIMIT_REQUIRE_CLEAR_REGIME", True)) and not regime_clear:
        execution_allowed = False
    if bool(settings.get("PMO_SMART_LIMIT_REQUIRE_RISK_GUARDS", True)) and not risk["ready"]:
        execution_allowed = False
    return {
        "ok": True,
        "updated": now_et().isoformat(),
        "limit_mode": limit_mode,
        "live_context": live_context,
        "effective_max_daily_trades": effective_daily,
        "effective_by_market": effective_by_market,
        "paper_target_max_daily_trades": int(settings.get("PMO_PAPER_MAX_DAILY_TRADES", 10)),
        "paper_target_by_market": paper_by_market,
        "live_max_daily_trades": int(settings.get("PMO_LIVE_MAX_DAILY_TRADES", 3)),
        "live_by_market": live_by_market,
        "conservative_max_daily_trades": int(settings.get("PMO_CONSERVATIVE_MAX_DAILY_TRADES", 6)),
        "conservative_by_market": conservative_by_market,
        "full_paper_limits_active": full_paper_limits_active,
        "execution_allowed": execution_allowed,
        "blockers": blockers,
        "prerequisites": prerequisites,
        "risk_guards": risk,
        "market_data_online": market_data_online,
        "regime_clear": regime_clear,
        "regime": regime_name,
        "score_band": score_band,
        "rebuild_score_gate": rebuild_score_gate,
        "drawdown_governor": drawdown_governor,
        "micro_guard": micro_guard,
        "account_status": account.get("status") or account.get("error", ""),
        "note": "Higher paper limits activate only when market data, regime, risk guards, and score quality pass. Live uses separate conservative caps.",
    }


