def pmo_why_not_for_row(
    row: Dict[str, Any],
    settings: Dict[str, Any],
    regime: Dict[str, Any],
    account: Optional[Dict[str, Any]] = None,
    health: Optional[Dict[str, Any]] = None,
    live_readiness: Optional[Dict[str, Any]] = None,
    executor: Optional[Dict[str, Any]] = None,
    reconciliation: Optional[Dict[str, Any]] = None,
    paper_proof: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    account = account or {}
    health = health or {}
    live_readiness = live_readiness or {}
    executor = executor or {}
    reconciliation = reconciliation or {}
    paper_proof = paper_proof or {}
    symbol = str(row.get("symbol") or "").upper()
    score = safe_float(row.get("score"))
    score_band = pmo_trade_score_band(score, settings)
    drawdown_governor = pmo_day_drawdown_governor(settings, account, symbol=symbol, action="PAPER_ANALYSIS", record=False)
    min_score = pmo_effective_why_not_min_score(settings)
    rvol = safe_float(row.get("relative_volume"))
    min_rvol = safe_float(settings.get("PMO_WHY_NOT_MIN_RVOL", 1.2), 1.2)
    bias = str(row.get("bias") or "WAIT").upper()
    readiness = calls_puts_readiness(row, settings)
    blockers: List[str] = []
    warnings: List[str] = []
    confirmations: List[str] = []
    if not settings.get("ENABLE_PMO_WHY_NOT_ENGINE", True):
        return {
            "time": row.get("updated", "") or now_et().isoformat(),
            "symbol": symbol or "-",
            "score": row.get("score", ""),
            "bias": bias,
            "readiness": readiness,
            "decision": "WHY-NOT OFF",
            "severity": "OFF",
            "blockers": [],
            "warnings": ["PMO Why-Not Engine is disabled."],
            "confirmations": [],
            "why": "PMO Why-Not Engine is disabled.",
            "next_action": "Turn ENABLE_PMO_WHY_NOT_ENGINE on from the switchboard.",
            "market": row.get("market", detect_market(symbol, "AUTO")) if symbol else "",
            "price": row.get("price", ""),
            "rvol": row.get("relative_volume", ""),
            "regime": regime.get("regime", "UNKNOWN"),
        }
    if not symbol:
        blockers.append("symbol missing")
    elif pmo_is_symbol_blocked(symbol, settings):
        blockers.append(f"symbol blocklist: {symbol} is disabled from new PMO entries")
    if drawdown_governor.get("symbol_blocked"):
        blockers.extend(drawdown_governor.get("blockers", []) or [drawdown_governor.get("detail", "day drawdown governor blocked this setup")])
    elif drawdown_governor.get("penalty_active"):
        warnings.append(drawdown_governor.get("detail", "day drawdown governor is reducing new signal approval"))
    if row.get("ok"):
        confirmations.append("live data OK")
    else:
        blockers.append("live data missing or stale")
    if score >= min_score:
        confirmations.append(f"score {score:g} passed min {min_score:g}")
    else:
        blockers.append(f"score {score:g} below PMO minimum {min_score:g}")
    confirmations.append(f"score band {score_band.get('label')}")
    if bias in {"CALL_BIAS", "PUT_BIAS", "BULLISH", "BEARISH"}:
        confirmations.append(f"directional bias {bias}")
    else:
        blockers.append(f"bias is {bias or 'UNKNOWN'}, no clear calls/puts direction")
    if settings.get("PMO_WHY_NOT_REQUIRE_RVOL", True):
        if rvol >= min_rvol:
            confirmations.append(f"relative volume {rvol:g} passed {min_rvol:g}")
        elif rvol > 0:
            blockers.append(f"relative volume {rvol:g} below {min_rvol:g}")
        elif settings.get("PMO_WHY_NOT_BLOCK_MISSING_RVOL", True):
            blockers.append(f"relative volume missing; PMO requires RVOL >= {min_rvol:g}")
        else:
            warnings.append("relative volume unavailable")
    vwap_check = pmo_vwap_why_not_check(row, settings)
    if vwap_check.get("status") == "BLOCK" and vwap_check.get("blocker"):
        blockers.append(str(vwap_check.get("blocker")))
    elif vwap_check.get("status") == "PASS" and vwap_check.get("confirmation"):
        confirmations.append(str(vwap_check.get("confirmation")))
    elif vwap_check.get("status") == "DATA_REQUIRED" and vwap_check.get("warning"):
        warnings.append(str(vwap_check.get("warning")))
    entry_rebuild_guard = pmo_entry_rebuild_guard(symbol, bias, bias, score, settings, regime=regime, row=row, vwap_check=vwap_check)
    blockers.extend(entry_rebuild_guard.get("blockers", []))
    warnings.extend(entry_rebuild_guard.get("warnings", []))
    confirmations.extend(entry_rebuild_guard.get("confirmations", []))
    discipline_check = pmo_trade_discipline_check(row, settings, regime=regime, account=account, vwap_check=vwap_check, paper_proof=paper_proof)
    if discipline_check.get("status") == "BLOCK":
        blockers.extend(discipline_check.get("blockers", []))
        warnings.extend(discipline_check.get("warnings", [])[:3])
    elif discipline_check.get("status") == "WARN":
        warnings.extend(discipline_check.get("blockers", [])[:2])
        warnings.extend(discipline_check.get("warnings", [])[:3])
    confirmations.extend(discipline_check.get("confirmations", [])[:3])
    change = safe_float(row.get("change_pct"))
    if bias == "CALL_BIAS" and change < 0:
        warnings.append("CALL bias conflicts with negative price move")
    if bias == "PUT_BIAS" and change > 0:
        warnings.append("PUT bias conflicts with positive price move")
    regime_name = str(regime.get("regime") or "UNKNOWN").upper()
    risk_multiplier = safe_float(regime.get("risk_multiplier"), 1.0)
    if regime_name in {"DEFENSIVE", "CHOPPY", "UNKNOWN"} and score < 85:
        blockers.append(f"market regime {regime_name} requires stronger confirmation")
    else:
        confirmations.append(f"market regime {regime_name} risk {risk_multiplier:g}x")
    if not settings.get("ENABLE_BUYING_POWER_GUARD"):
        blockers.append("buying power guard OFF")
    else:
        confirmations.append("buying power guard ON")
    if not settings.get("ENABLE_CASH_LOCKOUT"):
        blockers.append("cash lockout OFF")
    if not settings.get("ENABLE_PDT_PROTECTION_AI"):
        warnings.append("PDT protection OFF")
    if not settings.get("ENABLE_PMO_DUPLICATE_PHASE_GUARD"):
        warnings.append("duplicate signal guard OFF")
    if reconciliation and reconciliation.get("status") != "SYNCED":
        blockers.append("broker reconciliation not synced")
    paper_proof_ready = bool(paper_proof.get("clean_proof_ready") or paper_proof.get("ready_to_unlock_live"))
    if paper_proof and paper_proof_ready:
        confirmations.append(
            f"clean paper proof passed: {int(safe_float(paper_proof.get('closed_trades'), 0))} closed, "
            f"WR {safe_float(paper_proof.get('win_rate'), 0):.1%}, PF {safe_float(paper_proof.get('profit_factor'), 0):.2f}"
        )
    elif paper_proof:
        warnings.append(f"paper proof not complete ({paper_proof.get('score', 0)}%)")
    live_locked = not all([
        settings.get("PMO_LIVE_TRADING_ENABLED"),
        settings.get("PMO_ALLOW_LIVE_TRADING"),
        settings.get("ORDER_AUTOMATION_ENABLED"),
        not settings.get("PMO_DRY_RUN_ORDERS"),
        not settings.get("ALPACA_PAPER"),
    ])
    if live_locked:
        confirmations.append("live execution locked / paper safe")
    elif not executor.get("ready"):
        blockers.append("executor not ready even though live switches are armed")
    if live_readiness and not live_readiness.get("live_ready"):
        warnings.append("live readiness is not approved")
    if score_band.get("extra_confirmation_required"):
        confirmations.append("elite paper score requires extra confirmation")
        trend_text = str(
            row.get("trend")
            or row.get("trend_direction")
            or row.get("prediction_trend")
            or ""
        ).upper()
        if trend_text in {"BULL", "BULLISH", "LONG", "CALL", "BEAR", "BEARISH", "SHORT", "PUT"}:
            confirmations.append(f"trend confirmation {trend_text}")
        elif bias in {"CALL_BIAS", "PUT_BIAS", "BULLISH", "BEARISH"}:
            confirmations.append(f"trend direction inferred from {bias}")
        else:
            blockers.append("elite confirmation missing clear trend direction")
        ema_vwap_text = str(
            row.get("ema_vwap_alignment")
            or row.get("ema_vwap")
            or row.get("vwap_alignment")
            or ""
        ).upper()
        if ema_vwap_text in {"ALIGNED", "BULL", "BULLISH", "LONG", "CALL", "BEAR", "BEARISH", "SHORT", "PUT"}:
            confirmations.append(f"EMA/VWAP alignment {ema_vwap_text}")
        else:
            blockers.append("elite confirmation missing EMA/VWAP alignment")
        rsi_raw = row.get("rsi", row.get("RSI", ""))
        rsi_value = safe_float(rsi_raw, -1)
        rsi_ok = False
        if bias in {"CALL_BIAS", "BULLISH"}:
            rsi_ok = 45 <= rsi_value <= 78
        elif bias in {"PUT_BIAS", "BEARISH"}:
            rsi_ok = 22 <= rsi_value <= 55
        elif rsi_value > 0:
            rsi_ok = 25 <= rsi_value <= 78
        if rsi_ok:
            confirmations.append(f"RSI confirmation {rsi_value:g}")
        else:
            blockers.append("elite confirmation missing RSI confirmation")
        if not drawdown_governor.get("new_entries_allowed", True):
            blockers.append("elite confirmation failed risk guard pass")
        else:
            confirmations.append("risk guard pass")
        if regime_name == "UNKNOWN":
            blockers.append("elite confirmation missing market regime check")
        if not settings.get("ENABLE_CASH_LOCKOUT"):
            blockers.append("elite confirmation failed cash lockout guard")
        else:
            confirmations.append("cash lockout guard pass")
        if not settings.get("ENABLE_PDT_PROTECTION_AI"):
            blockers.append("elite confirmation failed PDT protection pass")
        else:
            confirmations.append("PDT protection pass")
        if settings.get("ENABLE_PMO_DUPLICATE_PHASE_GUARD"):
            duplicate_flag = any(pmo_truthy(row.get(key)) for key in ("duplicate", "duplicate_signal", "duplicate_order"))
            if duplicate_flag:
                blockers.append("elite confirmation failed no duplicate signal")
            else:
                confirmations.append("no duplicate signal")
        else:
            blockers.append("elite confirmation failed duplicate guard pass")
        if live_locked:
            confirmations.append("paper/live mode safety check passed")
        elif not all([settings.get("PMO_ALLOW_LIVE_TRADING"), settings.get("PMO_LIVE_TRADING_ENABLED"), settings.get("ORDER_AUTOMATION_ENABLED")]):
            blockers.append("elite confirmation failed paper/live mode safety check")
    hard_stop_analysis = bool(
        drawdown_governor.get("session_frozen")
        and readiness in {"CALL READY", "PUT READY"}
        and score >= min_score
    )
    blockers = list(dict.fromkeys(str(item) for item in blockers if str(item).strip()))
    warnings = list(dict.fromkeys(str(item) for item in warnings if str(item).strip()))
    confirmations = list(dict.fromkeys(str(item) for item in confirmations if str(item).strip()))
    if blockers:
        decision = "BLOCKED / WHY-NOT"
        severity = "BLOCKED"
        next_action = blockers[0]
    elif hard_stop_analysis:
        decision = "WOULD-HAVE-TRADED / DAY HARD STOP"
        severity = "WATCH"
        next_action = "Analysis only. Do not submit orders until the next session reset and paper proof improves."
    elif readiness in {"CALL READY", "PUT READY"} and score >= min_score:
        decision = "APPROVED FOR PAPER REPLAY"
        severity = "READY"
        next_action = "Paper replay only. Review risk and journal the outcome."
    elif warnings:
        decision = "WAIT / REVIEW"
        severity = "WATCH"
        next_action = warnings[0]
    else:
        decision = "WAIT FOR BETTER SETUP"
        severity = "WATCH"
        next_action = "Wait for stronger data, trend, volume, or bias."
    why_parts = []
    if blockers:
        why_parts.append("Blockers: " + " ; ".join(blockers[:5]))
    if warnings:
        why_parts.append("Warnings: " + " ; ".join(warnings[:4]))
    if confirmations:
        why_parts.append("Confirmed: " + " ; ".join(confirmations[:5]))
    return {
        "time": row.get("updated", "") or now_et().isoformat(),
        "symbol": symbol or "-",
        "score": row.get("score", ""),
        "score_band": score_band.get("band"),
        "score_label": score_band.get("label"),
        "score_action": score_band.get("action"),
        "extra_confirmation_required": bool(score_band.get("extra_confirmation_required")),
        "bias": bias,
        "readiness": readiness,
        "decision": decision,
        "severity": severity,
        "blockers": blockers,
        "warnings": warnings,
        "confirmations": confirmations,
        "why": " | ".join(why_parts) if why_parts else "No PMO signal data available.",
        "next_action": next_action,
        "market": row.get("market", detect_market(symbol, "AUTO")) if symbol else "",
        "price": row.get("price", ""),
        "rvol": row.get("relative_volume", ""),
        "regime": regime_name,
        "vwap_check": vwap_check,
        "vwap": vwap_check.get("vwap", ""),
        "vwap_distance_pct": vwap_check.get("distance_pct", ""),
        "entry_distance_vwap": vwap_check.get("distance_pct", ""),
        "entry_rebuild_guard": entry_rebuild_guard,
        "discipline_check": discipline_check,
        "discipline_status": discipline_check.get("status", ""),
        "discipline_confirmations": discipline_check.get("confirmation_count", 0),
    }


def pmo_why_not_snapshot(
    auto_watchlist: Dict[str, Any],
    settings: Dict[str, Any],
    account: Optional[Dict[str, Any]] = None,
    health: Optional[Dict[str, Any]] = None,
    regime: Optional[Dict[str, Any]] = None,
    live_readiness: Optional[Dict[str, Any]] = None,
    executor: Optional[Dict[str, Any]] = None,
    reconciliation: Optional[Dict[str, Any]] = None,
    paper_proof: Optional[Dict[str, Any]] = None,
    record: bool = False,
) -> Dict[str, Any]:
    regime = regime or {}
    selected = auto_watchlist.get("selected", [])
    if selected:
        rows = [
            pmo_why_not_for_row(row, settings, regime, account, health, live_readiness, executor, reconciliation, paper_proof)
            for row in selected[:30]
        ]
    else:
        rows = [{
            "time": now_et().isoformat(),
            "symbol": "-",
            "score": "-",
            "bias": "WAIT",
            "readiness": "WAIT",
            "decision": "NO SIGNALS",
            "severity": "WATCH",
            "blockers": ["no selected auto-watchlist symbols"],
            "warnings": [],
            "confirmations": ["PMO remains paper-safe"],
            "why": "Run Auto Build Watchlist to create PMO signal decisions.",
            "next_action": "Run Auto Build Watchlist.",
            "market": "",
            "price": "",
            "rvol": "",
            "regime": regime.get("regime", "UNKNOWN"),
        }]
    blocked = [item for item in rows if item.get("severity") == "BLOCKED"]
    ready = [item for item in rows if item.get("severity") == "READY"]
    watch = [item for item in rows if item.get("severity") == "WATCH"]
    summary = {
        "total": len(rows),
        "ready": len(ready),
        "blocked": len(blocked),
        "watch": len(watch),
        "top_blocker": blocked[0]["blockers"][0] if blocked and blocked[0].get("blockers") else "",
        "next_action": "Paper replay ready candidates exist." if ready else blocked[0]["next_action"] if blocked else "Wait for better signal confirmation.",
    }
    snapshot = {
        "ok": True,
        "version": "PMO_V111_WHY_NOT",
        "timestamp": now_et().isoformat(),
        "summary": summary,
        "rows": rows,
        "file": str(PMO_WHY_NOT_FILE),
    }
    if record:
        PMO_WHY_NOT_FILE.write_text(json.dumps(snapshot, indent=2), encoding="utf-8")
        for item in rows[:30]:
            csv_append(PMO_WHY_NOT_EVENTS_FILE, {
                "timestamp": snapshot["timestamp"],
                "symbol": item.get("symbol"),
                "decision": item.get("decision"),
                "severity": item.get("severity"),
                "score": item.get("score"),
                "bias": item.get("bias"),
                "readiness": item.get("readiness"),
                "next_action": item.get("next_action"),
                "why": item.get("why"),
                "vwap": item.get("vwap", ""),
                "vwap_distance_pct": item.get("vwap_distance_pct", ""),
                "entry_distance_vwap": item.get("entry_distance_vwap", ""),
                "vwap_status": (item.get("vwap_check") or {}).get("status", "") if isinstance(item.get("vwap_check"), dict) else "",
            })
    return snapshot


def pmo_why_not_claude_explain(
    blocked_rows: List[Dict[str, Any]],
    regime: Dict[str, Any],
    settings: Optional[Dict[str, Any]] = None,
    max_symbols: int = 3,
) -> List[Dict[str, Any]]:
    settings = settings or load_settings()
    augmented = [dict(row) for row in (blocked_rows or [])]
    if not bool(settings.get("PMO_WHY_NOT_AI_EXPLAIN", True)):
        return augmented
    if not first_env("ANTHROPIC_API_KEY", "PMO_ANTHROPIC_API_KEY", "CLAUDE_API_KEY"):
        for row in augmented:
            row.setdefault("claude_explained", False)
            row.setdefault("claude_error", "ANTHROPIC_API_KEY not set")
        return augmented

    limit = int(max(1, min(10, safe_float(max_symbols, 3))))
    targets = [row for row in augmented if str(row.get("severity", "")).upper() == "BLOCKED"][:limit]
    for row in targets:
        try:
            blockers = row.get("blockers", [])
            warnings = row.get("warnings", [])
            if not isinstance(blockers, list):
                blockers = [str(blockers)]
            if not isinstance(warnings, list):
                warnings = [str(warnings)]
            system_prompt = (
                "You are PMO Why-Not Analyst. Explain why a paper trading signal is blocked. "
                "Use plain English, keep it short, and never suggest bypassing safety gates. "
                "Classify the block as DATA_GAP, QUALITY_GATE, REGIME, or RISK. Return JSON only."
            )
            user_prompt = (
                f"Symbol: {row.get('symbol')}\n"
                f"Score: {row.get('score')}\n"
                f"Bias: {row.get('bias')}\n"
                f"Regime: {regime.get('regime', 'UNKNOWN')}\n"
                f"Blockers: {json.dumps(blockers[:8], default=str)}\n"
                f"Warnings: {json.dumps(warnings[:6], default=str)}\n"
                f"Why: {str(row.get('why', ''))[:1500]}\n\n"
                'Return JSON: {"plain_explanation": "2-3 sentences", '
                '"to_pass": ["specific condition needed"], '
                '"block_type": "DATA_GAP|QUALITY_GATE|REGIME|RISK"}'
            )
            ai = pmo_claude_call(system_prompt, user_prompt, max_tokens=320, expect_json=True, settings=settings)
            parsed = ai.get("parsed") if ai.get("ok") else {}
            if isinstance(parsed, dict) and parsed:
                row["claude_explanation"] = str(parsed.get("plain_explanation", ""))[:800]
                row["claude_to_pass"] = parsed.get("to_pass", []) if isinstance(parsed.get("to_pass"), list) else []
                row["claude_block_type"] = str(parsed.get("block_type", ""))[:40]
                row["claude_explained"] = True
                row["claude_model"] = ai.get("model", PMO_AI_MODEL)
            else:
                row["claude_explained"] = False
                row["claude_error"] = str(ai.get("error", "Claude response unavailable"))[:160]
        except Exception as exc:
            row["claude_explained"] = False
            row["claude_error"] = str(exc)[:160]
    return augmented


def pmo_why_not_snapshot_with_ai(
    auto_watchlist: Dict[str, Any],
    settings: Dict[str, Any],
    account: Optional[Dict[str, Any]] = None,
    health: Optional[Dict[str, Any]] = None,
    regime: Optional[Dict[str, Any]] = None,
    live_readiness: Optional[Dict[str, Any]] = None,
    executor: Optional[Dict[str, Any]] = None,
    reconciliation: Optional[Dict[str, Any]] = None,
    paper_proof: Optional[Dict[str, Any]] = None,
    record: bool = False,
    ai_explain: bool = False,
) -> Dict[str, Any]:
    snapshot = pmo_why_not_snapshot(
        auto_watchlist,
        settings,
        account,
        health,
        regime,
        live_readiness,
        executor,
        reconciliation,
        paper_proof,
        record=False,
    )
    snapshot["ai_explain_requested"] = bool(ai_explain)
    snapshot["ai_provider"] = "rule_based"
    if ai_explain and bool(settings.get("PMO_WHY_NOT_AI_EXPLAIN", True)):
        max_symbols = int(max(1, min(10, safe_float(settings.get("PMO_WHY_NOT_AI_MAX_SYMBOLS", 3), 3))))
        snapshot["rows"] = pmo_why_not_claude_explain(snapshot.get("rows", []), regime or {}, settings, max_symbols=max_symbols)
        snapshot["claude_explanations"] = sum(1 for row in snapshot.get("rows", []) if row.get("claude_explained"))
        snapshot["ai_provider"] = "claude"
    else:
        snapshot["claude_explanations"] = 0

    if record:
        PMO_WHY_NOT_FILE.write_text(json.dumps(snapshot, indent=2), encoding="utf-8")
        for item in snapshot.get("rows", [])[:30]:
            csv_append(PMO_WHY_NOT_EVENTS_FILE, {
                "timestamp": snapshot["timestamp"],
                "symbol": item.get("symbol"),
                "decision": item.get("decision"),
                "severity": item.get("severity"),
                "score": item.get("score"),
                "bias": item.get("bias"),
                "readiness": item.get("readiness"),
                "next_action": item.get("next_action"),
                "why": item.get("why"),
                "vwap": item.get("vwap", ""),
                "vwap_distance_pct": item.get("vwap_distance_pct", ""),
                "entry_distance_vwap": item.get("entry_distance_vwap", ""),
                "vwap_status": (item.get("vwap_check") or {}).get("status", "") if isinstance(item.get("vwap_check"), dict) else "",
                "claude_explanation": item.get("claude_explanation", ""),
                "claude_block_type": item.get("claude_block_type", ""),
            })
    return snapshot


def pmo_v112_direction(row: Dict[str, Any]) -> str:
    text = " ".join(str(row.get(key, "")) for key in ("bias", "readiness", "decision", "paper_action")).upper()
    if "PUT" in text or "SHORT" in text or "BEAR" in text:
        return "SHORT"
    return "LONG"


def pmo_v112_exit_prices(entry_price: float, direction: str, settings: Dict[str, Any]) -> Dict[str, float]:
    stop_pct = max(0.1, safe_float(settings.get("PMO_DEFAULT_STOP_LOSS_PCT", 2.0), 2.0))
    target_pct = max(0.1, safe_float(settings.get("PMO_DEFAULT_TAKE_PROFIT_PCT", 4.0), 4.0))
    trailing_pct = max(0.1, safe_float(settings.get("PMO_DEFAULT_TRAILING_STOP_PCT", 1.5), 1.5))
    trailing_activation_pct = max(0.0, safe_float(settings.get("PMO_TRAILING_ACTIVATION_PROFIT_PCT", 3.0), 3.0))
    if direction == "SHORT":
        stop = entry_price * (1 + stop_pct / 100)
        target = entry_price * (1 - target_pct / 100)
        trailing = entry_price * (1 + trailing_pct / 100)
        trailing_activation = entry_price * (1 - trailing_activation_pct / 100)
    else:
        stop = entry_price * (1 - stop_pct / 100)
        target = entry_price * (1 + target_pct / 100)
        trailing = entry_price * (1 - trailing_pct / 100)
        trailing_activation = entry_price * (1 + trailing_activation_pct / 100)
    return {
        "stop_loss_price": round(stop, 4),
        "take_profit_price": round(target, 4),
        "trailing_watch_price": round(trailing, 4),
        "stop_loss_pct": stop_pct,
        "take_profit_pct": target_pct,
        "trailing_stop_pct": trailing_pct,
        "trailing_activation_profit_pct": trailing_activation_pct,
        "trailing_activation_price": round(trailing_activation, 4),
        "trailing_state": "ARMED_AFTER_PROFIT",
    }


def pmo_v112_score_outcome(row: Dict[str, Any], current_price: float) -> Dict[str, Any]:
    entry = safe_float(row.get("entry_price"), 0)
    stop = safe_float(row.get("stop_loss_price"), 0)
    target = safe_float(row.get("take_profit_price"), 0)
    direction = str(row.get("direction") or "LONG").upper()
    replay_type = str(row.get("replay_type") or "PAPER_REPLAY").upper()
    if entry <= 0 or current_price <= 0:
        return {"outcome": "WAITING_FOR_PRICE", "pnl_pct": 0.0, "quality": "PENDING"}
    if direction == "SHORT":
        pnl_pct = round(((entry - current_price) / entry) * 100, 3)
        target_hit = target > 0 and current_price <= target
        stop_hit = stop > 0 and current_price >= stop
    else:
        pnl_pct = round(((current_price - entry) / entry) * 100, 3)
        target_hit = target > 0 and current_price >= target
        stop_hit = stop > 0 and current_price <= stop
    if replay_type == "BLOCKED_OBSERVATION":
        if stop_hit or pnl_pct <= -abs(safe_float(row.get("stop_loss_pct"), 2.0)):
            return {"outcome": "GOOD_BLOCK", "pnl_pct": pnl_pct, "quality": "GOOD_BLOCK"}
        if target_hit or pnl_pct >= abs(safe_float(row.get("take_profit_pct"), 4.0)):
            return {"outcome": "MISSED_OPPORTUNITY", "pnl_pct": pnl_pct, "quality": "MISSED"}
        return {"outcome": "BLOCK_REVIEW_OPEN", "pnl_pct": pnl_pct, "quality": "INCONCLUSIVE"}
    if target_hit:
        return {"outcome": "TARGET_HIT", "pnl_pct": pnl_pct, "quality": "WIN"}
    if stop_hit:
        return {"outcome": "STOP_HIT", "pnl_pct": pnl_pct, "quality": "LOSS"}
    if pnl_pct > 0:
        return {"outcome": "OPEN_GREEN", "pnl_pct": pnl_pct, "quality": "OPEN"}
    if pnl_pct < 0:
        return {"outcome": "OPEN_RED", "pnl_pct": pnl_pct, "quality": "OPEN"}
    return {"outcome": "OPEN_FLAT", "pnl_pct": pnl_pct, "quality": "OPEN"}


def pmo_v112_load_journal() -> List[Dict[str, Any]]:
    return recent_csv_rows(PMO_V112_REPLAY_JOURNAL_FILE, 5000)


def pmo_truthy(value: Any) -> bool:
    if isinstance(value, bool):
        return value
    return str(value or "").strip().lower() in {"1", "true", "yes", "y", "on", "passed", "ready"}


def pmo_v112_rules_followed(row: Dict[str, Any]) -> bool:
    return pmo_truthy(row.get("rules_followed"))


def pmo_score_range_label(score: Any, settings: Optional[Dict[str, Any]] = None) -> str:
    s = safe_float(score, 0)
    if s >= 93:
        return "93-100 ELITE"
    if s >= 88:
        return "88-92 EXECUTOR"
    if s >= 78:
        return "78-87 PAPER_CANDIDATE"
    if s >= 65:
        return "65-77 WATCH"
    if s >= 50:
        return "50-64 DISCOVERY"
    return "0-49 IGNORE"


def pmo_v112_sync_executor_fills(settings: Dict[str, Any], limit: int = 1000) -> Dict[str, Any]:
    if not settings.get("ENABLE_PMO_V112_PAPER_REPLAY_JOURNAL", True):
        return {"ok": True, "bridged": 0, "skipped": 0, "notes": ["v112 paper replay journal is disabled"]}
    trade_rows = recent_csv_rows(TRADE_JOURNAL_FILE, max(1, limit))
    open_rows = [row for row in trade_rows if str(row.get("status", "")).upper() == "OPEN_FILLED"]
    plan_rows = {
        str(row.get("plan_id", "")).strip(): row
        for row in recent_csv_rows(PMO_TRADE_PLAN_FILE, 5000)
        if str(row.get("plan_id", "")).strip()
    }
    closed_by_order: Dict[str, Dict[str, Any]] = {}
    for row in trade_rows:
        status = str(row.get("status", "")).upper()
        if not status.startswith("CLOSED"):
            continue
        order_id = str(row.get("source_order_id") or row.get("order_id") or "").strip()
        if order_id:
            closed_by_order[order_id] = row

    existing = pmo_v112_load_journal()
    existing_replay_ids = {str(row.get("replay_id", "")).strip() for row in existing if str(row.get("replay_id", "")).strip()}
    existing_order_ids = {
        str(row.get("executor_source_order_id") or row.get("source_order_id") or "").strip()
        for row in existing
        if str(row.get("executor_source_order_id") or row.get("source_order_id") or "").strip()
    }
    bridged = 0
    skipped = 0
    notes: List[str] = []
    rows: List[Dict[str, Any]] = []
    for source in open_rows:
        symbol = str(source.get("symbol", "")).strip().upper()
        if not symbol or symbol == "SYSTEM":
            skipped += 1
            continue
        order_id = str(source.get("source_order_id") or source.get("order_id") or "").strip()
        client_order_id = str(source.get("client_order_id") or "").strip()
        trade_plan_id = str(source.get("trade_plan_id") or "").strip()
        bridge_key = order_id or client_order_id or str(source.get("sync_key") or "").split(":")[0].strip()
        if not bridge_key:
            skipped += 1
            notes.append(f"{symbol}: missing broker order id")
            continue
        replay_id = f"PMO-V112-EXEC-{bridge_key}"
        if replay_id in existing_replay_ids or bridge_key in existing_order_ids:
            skipped += 1
            continue
        entry = safe_float(source.get("entry_price"), 0)
        qty = safe_float(source.get("qty") or source.get("quantity"), 0)
        if entry <= 0:
            skipped += 1
            notes.append(f"{symbol}: missing entry price")
            continue
        plan = plan_rows.get(trade_plan_id, {})
        side_text = str(source.get("side") or plan.get("side") or "").upper()
        direction = "SHORT" if "SHORT" in side_text or side_text == "SELL" else "LONG"
        exits = pmo_v112_exit_prices(entry, direction, settings)
        stop_price = safe_float(plan.get("stop_loss_price"), 0) or exits["stop_loss_price"]
        target_price = safe_float(plan.get("take_profit_price"), 0) or exits["take_profit_price"]
        trailing_price = safe_float(plan.get("trailing_stop_price") or plan.get("trailing_watch_price"), 0) or exits["trailing_watch_price"]
        score = source.get("score") or plan.get("score") or ""
        score_band = pmo_trade_score_band(score, settings)
        closed_row = closed_by_order.get(bridge_key, {})
        exit_price = safe_float(closed_row.get("exit_price"), 0)
        pnl_pct = safe_float(closed_row.get("pnl_pct"), 0)
        pnl_usd = closed_row.get("pnl", "")
        status = "OPEN"
        outcome = "OPEN"
        quality = "OPEN"
        closed_at = ""
        if closed_row:
            closed_status = str(closed_row.get("status", "")).upper()
            closed_at = closed_row.get("timestamp", "")
            if "WIN" in closed_status:
                status = "TARGET_HIT"
                outcome = "TARGET_HIT"
                quality = "WIN"
            elif "LOSS" in closed_status:
                status = "STOP_HIT"
                outcome = "STOP_HIT"
                quality = "LOSS"
            else:
                status = "CLOSED_FLAT"
                outcome = "CLOSED_FLAT"
                quality = "FLAT"
        journal_row = {
            "timestamp": source.get("timestamp") or now_et().isoformat(),
            "replay_id": replay_id,
            "symbol": symbol,
            "market": source.get("market") or detect_market(symbol, "AUTO"),
            "replay_type": "PAPER_REPLAY",
            "direction": direction,
            "side": "SELL_SHORT" if direction == "SHORT" else "BUY_LONG",
            "status": status,
            "score": score,
            "pmo_score": score,
            "score_band": score_band.get("band"),
            "score_range": pmo_score_range_label(score, settings),
            "setup_type": f"{score_band.get('band')}:{direction}",
            "bias": "EXECUTOR_PAPER_FILL",
            "readiness": "EXECUTOR_FILLED",
            "market_regime": "",
            "risk_multiplier": "",
            "entry_price": entry,
            "exit_price": exit_price if exit_price > 0 else "",
            "current_price": exit_price if exit_price > 0 else entry,
            "stop_loss_price": stop_price,
            "take_profit_price": target_price,
            "trailing_watch_price": trailing_price,
            "stop_loss_pct": exits["stop_loss_pct"],
            "take_profit_pct": exits["take_profit_pct"],
            "trailing_stop_pct": exits["trailing_stop_pct"],
            "trailing_activation_profit_pct": exits["trailing_activation_profit_pct"],
            "trailing_activation_price": exits["trailing_activation_price"],
            "trailing_state": exits["trailing_state"],
            "risk_reward": plan.get("risk_reward", ""),
            "qty": qty,
            "quantity": qty,
            "pnl_pct": pnl_pct,
            "profit_loss_pct": pnl_pct,
            "profit_loss_usd": pnl_usd,
            "win_loss_result": quality if quality in {"WIN", "LOSS"} else "",
            "outcome": outcome,
            "quality": quality,
            "rules_followed": True,
            "rule_followed_detail": "Actual PMO executor paper fill bridged into V112 closer.",
            "why": source.get("detail") or "PMO executor paper fill synced from broker journal.",
            "next_action": "V112 closer will refresh target/stop outcome automatically.",
            "reviewed_at": closed_at,
            "closed_at": closed_at,
            "quote_feed": "TRADE_JOURNAL" if closed_row else "",
            "executor_source_order_id": bridge_key,
            "executor_client_order_id": client_order_id,
            "trade_plan_id": trade_plan_id,
            "alpaca_profile": source.get("alpaca_profile", ""),
            "source": "PMO_EXECUTOR_BRIDGE",
        }
        csv_append(PMO_V112_REPLAY_JOURNAL_FILE, journal_row)
        existing_replay_ids.add(replay_id)
        existing_order_ids.add(bridge_key)
        rows.append(journal_row)
        bridged += 1
    return {
        "ok": True,
        "scanned": len(open_rows),
        "bridged": bridged,
        "skipped": skipped,
        "notes": notes[:10],
        "rows": rows[:25],
        "journal_file": str(PMO_V112_REPLAY_JOURNAL_FILE),
    }


def pmo_max_drawdown_from_pnls(pnls: List[float]) -> float:
    cumulative = 0.0
    peak = 0.0
    max_drawdown = 0.0
    for pnl in pnls:
        cumulative += safe_float(pnl, 0)
        peak = max(peak, cumulative)
        max_drawdown = min(max_drawdown, cumulative - peak)
    return round(abs(max_drawdown), 3)


def pmo_v112_log_paper_replays(
    settings: Dict[str, Any],
    auto_watchlist: Dict[str, Any],
    why_not: Optional[Dict[str, Any]] = None,
    limit: Optional[int] = None,
) -> Dict[str, Any]:
    if not settings.get("ENABLE_PMO_V112_PAPER_REPLAY_JOURNAL", True):
        return {"ok": True, "logged": 0, "skipped": ["v112 paper replay journal is disabled"], "rows": []}
    regime_snapshot = bot.market_regime()
    why_not = why_not or pmo_why_not_snapshot(auto_watchlist, settings, regime=regime_snapshot, record=False)
    limit = int(limit or settings.get("PMO_V112_MAX_REPLAY_LOGS_PER_RUN", 10))
    existing = pmo_v112_load_journal()
    open_keys = {
        (str(row.get("symbol", "")).upper(), str(row.get("direction", "")).upper(), str(row.get("replay_type", "")).upper())
        for row in existing
        if str(row.get("status", "")).upper() in {"OPEN", "BLOCK_REVIEW_OPEN", "PAPER_LOGGED", "ANALYSIS_OPEN"}
    }
    ordered = list(why_not.get("rows", []))
    ordered.sort(key=lambda row: 0 if row.get("severity") == "READY" else 1 if "WOULD-HAVE-TRADED" in str(row.get("decision", "")).upper() else 2 if row.get("severity") == "BLOCKED" else 3)
    logged: List[Dict[str, Any]] = []
    skipped: List[str] = []
    for row in ordered:
        if len(logged) >= limit:
            break
        symbol = str(row.get("symbol", "")).upper()
        if not symbol or symbol == "-":
            continue
        severity = str(row.get("severity", "")).upper()
        decision_text = str(row.get("decision", "")).upper()
        would_have_traded = "WOULD-HAVE-TRADED" in decision_text
        if severity not in {"READY", "BLOCKED"} and not would_have_traded:
            continue
        entry = safe_float(row.get("price"), 0)
        if entry <= 0:
            skipped.append(f"{symbol}: no entry price")
            continue
        direction = pmo_v112_direction(row)
        if would_have_traded:
            replay_type = "WOULD_HAVE_TRADED"
        elif severity == "READY":
            replay_type = "PAPER_REPLAY"
        else:
            replay_type = "BLOCKED_OBSERVATION"
        score_band = pmo_trade_score_band(row.get("score"), settings)
        rules_followed = bool(replay_type == "PAPER_REPLAY" and severity == "READY")
        side = "SELL_SHORT" if direction == "SHORT" else "BUY_LONG"
        key = (symbol, direction, replay_type)
        if key in open_keys:
            skipped.append(f"{symbol}: open {replay_type.lower()} already exists")
            continue
        exits = pmo_v112_exit_prices(entry, direction, settings)
        replay_id = f"PMO-V112-{int(time.time() * 1000)}-{symbol}"
        journal_row = {
            "timestamp": now_et().isoformat(),
            "replay_id": replay_id,
            "symbol": symbol,
            "market": row.get("market") or detect_market(symbol, "AUTO"),
            "replay_type": replay_type,
            "direction": direction,
            "side": side,
            "status": "OPEN" if replay_type == "PAPER_REPLAY" else "ANALYSIS_OPEN" if replay_type == "WOULD_HAVE_TRADED" else "BLOCK_REVIEW_OPEN",
            "score": row.get("score", ""),
            "pmo_score": row.get("score", ""),
            "score_band": score_band.get("band"),
            "score_range": pmo_score_range_label(row.get("score"), settings),
            "setup_type": f"{score_band.get('band')}:{direction}",
            "bias": row.get("bias", ""),
            "readiness": row.get("readiness", ""),
            "market_regime": row.get("regime") or regime_snapshot.get("regime", "UNKNOWN"),
            "risk_multiplier": regime_snapshot.get("risk_multiplier", ""),
            "entry_price": entry,
            "exit_price": "",
            "current_price": entry,
            "stop_loss_price": exits["stop_loss_price"],
            "take_profit_price": exits["take_profit_price"],
            "trailing_watch_price": exits["trailing_watch_price"],
            "stop_loss_pct": exits["stop_loss_pct"],
            "take_profit_pct": exits["take_profit_pct"],
            "trailing_stop_pct": exits["trailing_stop_pct"],
            "trailing_activation_profit_pct": exits["trailing_activation_profit_pct"],
            "trailing_activation_price": exits["trailing_activation_price"],
            "trailing_state": exits["trailing_state"],
            "pnl_pct": 0,
            "profit_loss_pct": 0,
            "profit_loss_usd": "",
            "win_loss_result": "",
            "outcome": "OPEN" if replay_type == "PAPER_REPLAY" else "ANALYSIS_OPEN" if replay_type == "WOULD_HAVE_TRADED" else "BLOCK_REVIEW_OPEN",
            "quality": "OPEN",
            "rules_followed": rules_followed,
            "rule_followed_detail": "Why-Not READY paper replay with required score, trend, volume, regime, and safety checks." if rules_followed else "Observation only; not a clean paper trade outcome.",
            "why": row.get("why", ""),
            "next_action": row.get("next_action", ""),
            "reviewed_at": "",
        }
        csv_append(PMO_V112_REPLAY_JOURNAL_FILE, journal_row)
        logged.append(journal_row)
        open_keys.add(key)
        time.sleep(0.001)
    return {
        "ok": True,
        "logged": len(logged),
        "skipped": skipped,
        "rows": logged,
        "journal_file": str(PMO_V112_REPLAY_JOURNAL_FILE),
    }


def pmo_v112_refresh_outcomes(settings: Dict[str, Any], limit: int = 200) -> Dict[str, Any]:
    rows = pmo_v112_load_journal()
    updated = 0
    reviewed: List[Dict[str, Any]] = []
    review_indices = list(range(len(rows) - 1, -1, -1))[:max(1, limit)]
    for index in review_indices:
        row = rows[index]
        status = str(row.get("status", "")).upper()
        if status in {"TARGET_HIT", "STOP_HIT", "GOOD_BLOCK", "MISSED_OPPORTUNITY", "CLOSED_WIN", "CLOSED_LOSS", "CLOSED_FLAT"}:
            reviewed.append(dict(row))
            continue
        symbol = str(row.get("symbol", "")).strip().upper()
        if not symbol or symbol == "-":
            continue
        market = row.get("market") or detect_market(symbol, "AUTO")
        quote = bot.get_latest_price(symbol, market)
        current = safe_float(quote.get("price"), safe_float(row.get("current_price"), 0))
        outcome = pmo_v112_score_outcome(row, current)
        row["current_price"] = current
        row["pnl_pct"] = outcome["pnl_pct"]
        row["profit_loss_pct"] = outcome["pnl_pct"]
        row["outcome"] = outcome["outcome"]
        row["quality"] = outcome["quality"]
        row["status"] = outcome["outcome"]
        row["reviewed_at"] = now_et().isoformat()
        row["quote_feed"] = quote.get("feed", quote.get("error", ""))
        if not row.get("pmo_score"):
            row["pmo_score"] = row.get("score", "")
        if not row.get("score_range"):
            row["score_range"] = pmo_score_range_label(row.get("score"), settings)
        if not row.get("score_band"):
            row["score_band"] = pmo_trade_score_band(row.get("score"), settings).get("band")
        if not row.get("setup_type"):
            row["setup_type"] = f"{row.get('score_band', 'UNKNOWN')}:{row.get('direction', 'UNKNOWN')}"
        if not row.get("side"):
            row["side"] = "SELL_SHORT" if str(row.get("direction", "")).upper() == "SHORT" else "BUY_LONG"
        if outcome["quality"] in {"WIN", "LOSS"}:
            row["exit_price"] = current
            row["closed_at"] = row["reviewed_at"]
            row["win_loss_result"] = outcome["quality"]
            entry = safe_float(row.get("entry_price"), 0)
            qty = safe_float(row.get("qty") or row.get("quantity"), 0)
            if qty > 0 and entry > 0:
                if str(row.get("direction", "")).upper() == "SHORT":
                    row["profit_loss_usd"] = round((entry - current) * qty, 2)
                else:
                    row["profit_loss_usd"] = round((current - entry) * qty, 2)
        updated += 1
        reviewed.append(dict(row))
    write_csv_rows(PMO_V112_REPLAY_JOURNAL_FILE, rows)
    return {
        "ok": True,
        "updated": updated,
        "reviewed": reviewed[:25],
        "journal_file": str(PMO_V112_REPLAY_JOURNAL_FILE),
    }


def pmo_v112_proof_report(settings: Dict[str, Any], record: bool = False) -> Dict[str, Any]:
    rows = pmo_v112_load_journal()
    sqlite_sync = pmo_sync_v112_rows_to_sqlite(rows)
    replay_rows = [row for row in rows if str(row.get("replay_type", "")).upper() == "PAPER_REPLAY"]
    clean_replay_rows = [row for row in replay_rows if pmo_v112_rules_followed(row)]
    analysis_rows = [row for row in rows if str(row.get("replay_type", "")).upper() == "WOULD_HAVE_TRADED"]
    blocked_rows = [row for row in rows if str(row.get("replay_type", "")).upper() == "BLOCKED_OBSERVATION"]
    all_wins = [row for row in replay_rows if str(row.get("quality", "")).upper() == "WIN"]
    all_losses = [row for row in replay_rows if str(row.get("quality", "")).upper() == "LOSS"]
    wins = [row for row in clean_replay_rows if str(row.get("quality", "")).upper() == "WIN"]
    losses = [row for row in clean_replay_rows if str(row.get("quality", "")).upper() == "LOSS"]
    open_rows = [row for row in clean_replay_rows if str(row.get("quality", "")).upper() == "OPEN"]
    analysis_wins = [row for row in analysis_rows if str(row.get("quality", "")).upper() == "WIN"]
    analysis_losses = [row for row in analysis_rows if str(row.get("quality", "")).upper() == "LOSS"]
    analysis_open = [row for row in analysis_rows if str(row.get("quality", "")).upper() == "OPEN"]
    good_blocks = [row for row in blocked_rows if str(row.get("quality", "")).upper() == "GOOD_BLOCK"]
    missed = [row for row in blocked_rows if str(row.get("quality", "")).upper() == "MISSED"]
    all_closed_outcomes = len(all_wins) + len(all_losses)
    closed_outcomes = len(wins) + len(losses)
    try:
        real_journal = trade_journal_summary(limit=500)
    except Exception as exc:
        real_journal = {"ok": False, "closed_trades": 0, "error": str(exc)}
    real_closed = int(safe_float(real_journal.get("closed_trades", 0), 0))
    reconciliation_gap = abs(closed_outcomes - real_closed)
    reconciliation_ok = reconciliation_gap <= 3
    reconciliation = {
        "ok": reconciliation_ok,
        "gap": reconciliation_gap,
        "allowed_gap": 3,
        "v112_closed_paper_trades": closed_outcomes,
        "v112_all_closed_paper_trades": all_closed_outcomes,
        "real_journal_closed_trades": real_closed,
        "real_journal_source": real_journal.get("source_file", str(TRADE_JOURNAL_FILE)),
        "v112_journal_source": str(PMO_V112_REPLAY_JOURNAL_FILE),
        "detail": "V112 and real trade journal closed counts are aligned." if reconciliation_ok else "V112 and real trade journal closed counts differ; review replay rows versus broker-synced closed rows.",
    }
    min_closed_to_judge = int(settings.get("PMO_MICRO_MIN_CLOSED_TRADES_TO_JUDGE", 20)) if pmo_micro_mode_enabled(settings) else int(settings.get("PMO_ASI_MIN_ROWS_TO_APPLY", 5))
    strong_validation_closed = int(settings.get("PMO_MICRO_MIN_CLOSED_TRADES_STRONG_VALIDATION", 50))
    win_rate = round(len(wins) / max(1, len(wins) + len(losses)), 3)
    analysis_win_rate = round(len(analysis_wins) / max(1, len(analysis_wins) + len(analysis_losses)), 3)
    blocked_quality = round(len(good_blocks) / max(1, len(good_blocks) + len(missed)), 3)
    by_symbol: Dict[str, Dict[str, Any]] = {}
    for row in clean_replay_rows:
        symbol = str(row.get("symbol", "")).upper()
        bucket = by_symbol.setdefault(symbol, {"symbol": symbol, "wins": 0, "losses": 0, "open": 0, "avg_pnl": 0.0, "pnl_values": []})
        quality = str(row.get("quality", "")).upper()
        if quality == "WIN":
            bucket["wins"] += 1
        elif quality == "LOSS":
            bucket["losses"] += 1
        else:
            bucket["open"] += 1
        bucket["pnl_values"].append(safe_float(row.get("pnl_pct"), 0))
    symbol_rows = []
    for bucket in by_symbol.values():
        vals = bucket.pop("pnl_values", [])
        bucket["avg_pnl"] = round(sum(vals) / len(vals), 3) if vals else 0
        bucket["proof_score"] = round(bucket["wins"] * 2 - bucket["losses"] + bucket["avg_pnl"], 3)
        symbol_rows.append(bucket)
    by_setup: Dict[str, Dict[str, Any]] = {}
    for row in clean_replay_rows:
        quality = str(row.get("quality", "")).upper()
        if quality not in {"WIN", "LOSS"}:
            continue
        symbol = str(row.get("symbol", "")).upper()
        direction = str(row.get("direction", "") or row.get("side", "") or "UNKNOWN").upper()
        setup_key = str(row.get("setup") or row.get("setup_key") or f"{symbol}:{direction}").upper()
        bucket = by_setup.setdefault(setup_key, {"setup": setup_key, "symbol": symbol, "direction": direction, "wins": 0, "losses": 0, "closed": 0, "win_rate": 0.0})
        bucket["closed"] += 1
        if quality == "WIN":
            bucket["wins"] += 1
        else:
            bucket["losses"] += 1
        bucket["win_rate"] = round(bucket["wins"] / max(1, bucket["wins"] + bucket["losses"]), 3)
    setup_rows = list(by_setup.values())
    best = sorted(symbol_rows, key=lambda item: item.get("proof_score", 0), reverse=True)[:8]
    weakest = sorted(symbol_rows, key=lambda item: item.get("proof_score", 0))[:8]
    best_setup_rows = sorted(setup_rows, key=lambda item: (item.get("win_rate", 0), item.get("closed", 0)), reverse=True)[:8]
    weak_setup_rows = sorted(setup_rows, key=lambda item: (item.get("win_rate", 0), -item.get("closed", 0)))[:8]
    closed_rows = wins + losses
    win_pnls = [max(0.0, safe_float(row.get("pnl_pct"), 0)) for row in wins]
    loss_pnls = [abs(safe_float(row.get("pnl_pct"), 0)) for row in losses]
    gross_win_pct = round(sum(win_pnls), 3)
    gross_loss_pct = round(sum(loss_pnls), 3)
    avg_win_pct = round(gross_win_pct / len(win_pnls), 3) if win_pnls else 0.0
    avg_loss_pct = round(gross_loss_pct / len(loss_pnls), 3) if loss_pnls else 0.0
    profit_factor = round(gross_win_pct / gross_loss_pct, 3) if gross_loss_pct > 0 else 999.0 if gross_win_pct > 0 else 0.0
    expectancy_pct = round(sum(safe_float(row.get("pnl_pct"), 0) for row in closed_rows) / closed_outcomes, 3) if closed_outcomes else 0.0
    closed_pnls = [safe_float(row.get("pnl_pct"), 0) for row in closed_rows]
    max_drawdown_pct = pmo_max_drawdown_from_pnls(closed_pnls)
    avg_winning_score = round(sum(safe_float(row.get("score"), 0) for row in wins) / len(wins), 2) if wins else 0.0
    avg_losing_score = round(sum(safe_float(row.get("score"), 0) for row in losses) / len(losses), 2) if losses else 0.0
    min_profit_factor = safe_float(settings.get("PMO_V112_MIN_PROOF_PROFIT_FACTOR", 1.2), 1.2)
    by_score_range: Dict[str, Dict[str, Any]] = {}
    for row in closed_rows:
        score_range = pmo_score_range_label(row.get("score"), settings)
        bucket = by_score_range.setdefault(score_range, {"score_range": score_range, "wins": 0, "losses": 0, "closed": 0, "avg_pnl": 0.0, "pnl_values": []})
        bucket["closed"] += 1
        if str(row.get("quality", "")).upper() == "WIN":
            bucket["wins"] += 1
        else:
            bucket["losses"] += 1
        bucket["pnl_values"].append(safe_float(row.get("pnl_pct"), 0))
    score_range_rows: List[Dict[str, Any]] = []
    for bucket in by_score_range.values():
        vals = bucket.pop("pnl_values", [])
        bucket["avg_pnl"] = round(sum(vals) / len(vals), 3) if vals else 0.0
        bucket["win_rate"] = round(bucket["wins"] / max(1, bucket["closed"]), 3)
        score_range_rows.append(bucket)
    best_score_ranges = sorted(score_range_rows, key=lambda item: (item.get("avg_pnl", 0), item.get("win_rate", 0), item.get("closed", 0)), reverse=True)[:5]
    worst_score_ranges = sorted(score_range_rows, key=lambda item: (item.get("avg_pnl", 0), -item.get("closed", 0)))[:5]
    if closed_outcomes < min_closed_to_judge:
        threshold_recommendation = "KEEP_40_UNTIL_20_CLEAN_CLOSED_OUTCOMES"
        threshold_detail = f"Only {closed_outcomes}/{min_closed_to_judge} clean closed outcomes are available."
    elif profit_factor < min_profit_factor or expectancy_pct <= 0:
        threshold_recommendation = "MOVE_DISCOVERY_THRESHOLD_TO_50"
        threshold_detail = "Closed-paper proof is not profitable enough; reduce discovery noise before expanding."
    elif losses and avg_losing_score < safe_float(settings.get("PMO_SCORE_MONITOR_MIN", 55), 55):
        threshold_recommendation = "MOVE_DISCOVERY_THRESHOLD_TO_45"
        threshold_detail = "Losses are concentrated in lower discovery/monitor scores."
    else:
        threshold_recommendation = "STAY_AT_40"
        threshold_detail = "Clean closed-paper outcomes support keeping discovery broad while approval remains strict."
    checks = [
        {"name": "Paper replay journal started", "ready": bool(replay_rows), "value": str(len(replay_rows)), "detail": "Log paper replay ideas before live readiness."},
        {"name": "Closed paper outcomes recorded", "ready": bool(wins or losses), "value": str(closed_outcomes), "detail": "Win-rate authority counts closed paper wins/losses only; open rows do not count."},
        {"name": "Clean closed-trade minimum", "ready": closed_outcomes >= min_closed_to_judge, "value": f"{closed_outcomes}/{min_closed_to_judge}", "detail": "Micro Mode waits for clean closed paper trades that followed PMO rules before judging edge."},
        {"name": "Proof win rate", "ready": win_rate >= safe_float(settings.get("PMO_V112_MIN_PROOF_WIN_RATE", 0.5), 0.5) and closed_outcomes >= min_closed_to_judge, "value": f"{win_rate:.2%}", "detail": "Closed paper wins divided by closed wins plus losses."},
        {"name": "Profit factor proof", "ready": profit_factor >= min_profit_factor and closed_outcomes >= min_closed_to_judge, "value": f"{profit_factor:.2f}", "detail": f"Gross winning closed-paper P&L divided by gross losing closed-paper P&L. Minimum {min_profit_factor:.2f}."},
        {"name": "Positive expectancy proof", "ready": expectancy_pct > 0 and closed_outcomes >= min_closed_to_judge, "value": f"{expectancy_pct:.2f}%", "detail": "Average closed-paper P&L must be positive before PMO can claim an edge."},
        {"name": "Blocked trade quality", "ready": blocked_quality >= safe_float(settings.get("PMO_V112_BLOCKED_QUALITY_MIN", 0.6), 0.6) and bool(good_blocks or missed), "value": f"{blocked_quality:.2%}", "detail": "Good blocks divided by good blocks plus missed opportunities."},
    ]
    ready_count = sum(1 for item in checks if item["ready"])
    proof_score = round((ready_count / len(checks)) * 100, 1) if checks else 0
    next_action = "Collect and close clean paper outcomes before changing confidence or live-readiness behavior."
    if closed_outcomes >= min_closed_to_judge and proof_score < 100:
        next_action = "Review weak proof metrics before raising thresholds or confidence."
    elif proof_score >= 100:
        next_action = "Proof is strong; live trading still requires owner arming, broker reconciliation, and safety checks."
    best_setup_name = best_setup_rows[0].get("setup", "") if best_setup_rows else ""
    worst_setup_name = weak_setup_rows[0].get("setup", "") if weak_setup_rows else ""
    validation_summary = {
        "clean_outcomes_collected": closed_outcomes,
        "minimum_clean_outcomes": min_closed_to_judge,
        "progress_label": f"{closed_outcomes}/{min_closed_to_judge}",
        "wins": len(wins),
        "losses": len(losses),
        "win_rate": win_rate,
        "average_win_pct": avg_win_pct,
        "average_loss_pct": avg_loss_pct,
        "profit_factor": profit_factor,
        "max_drawdown_pct": max_drawdown_pct,
        "best_setup": best_setup_name,
        "worst_setup": worst_setup_name,
        "threshold_recommendation": threshold_recommendation,
        "next_action": next_action,
        "sqlite_sync": sqlite_sync,
        "reconciliation": reconciliation,
    }
    report = {
        "ok": True,
        "version": "PMO_V112_PAPER_PROOF_JOURNAL",
        "updated": now_et().isoformat(),
        "proof_score": proof_score,
        "ready_count": ready_count,
        "total_checks": len(checks),
        "status": "PROOF BUILDING" if proof_score < 100 else "PROOF STRONG",
        "summary": {
            "total_rows": len(rows),
            "paper_replays": len(replay_rows),
            "clean_paper_replays": len(clean_replay_rows),
            "would_have_traded": len(analysis_rows),
            "wins": len(wins),
            "losses": len(losses),
            "open": len(open_rows),
            "all_closed_paper_trades": all_closed_outcomes,
            "closed_paper_trades": closed_outcomes,
            "clean_closed_paper_trades": closed_outcomes,
            "real_journal_closed_trades": real_closed,
            "reconciliation_gap": reconciliation_gap,
            "reconciliation_ok": reconciliation_ok,
            "excluded_unclean_closed_paper_trades": max(0, all_closed_outcomes - closed_outcomes),
            "win_rate_authority": "CLOSED_PAPER_TRADES_ONLY",
            "minimum_closed_trades_to_judge": min_closed_to_judge,
            "strong_validation_closed_trades": strong_validation_closed,
            "strong_validation_ready": closed_outcomes >= strong_validation_closed,
            "win_rate": win_rate,
            "gross_win_pct": gross_win_pct,
            "gross_loss_pct": gross_loss_pct,
            "avg_win_pct": avg_win_pct,
            "avg_loss_pct": avg_loss_pct,
            "profit_factor": profit_factor,
            "minimum_profit_factor": min_profit_factor,
            "expectancy_pct": expectancy_pct,
            "max_drawdown_pct": max_drawdown_pct,
            "avg_winning_score": avg_winning_score,
            "avg_losing_score": avg_losing_score,
            "threshold_recommendation": threshold_recommendation,
            "threshold_detail": threshold_detail,
            "best_setup": best_setup_name,
            "worst_setup": worst_setup_name,
            "next_action": next_action,
            "analysis_wins": len(analysis_wins),
            "analysis_losses": len(analysis_losses),
            "analysis_open": len(analysis_open),
            "analysis_win_rate": analysis_win_rate,
            "blocked_observations": len(blocked_rows),
            "good_blocks": len(good_blocks),
            "missed_opportunities": len(missed),
            "blocked_quality": blocked_quality,
        },
        "checks": checks,
        "best_setups": best,
        "weakest_setups": weakest,
        "setup_win_rates": setup_rows,
        "best_setup_win_rates": best_setup_rows,
        "weak_setup_win_rates": weak_setup_rows,
        "score_range_win_rates": score_range_rows,
        "best_score_ranges": best_score_ranges,
        "worst_score_ranges": worst_score_ranges,
        "threshold_recommendation": threshold_recommendation,
        "threshold_detail": threshold_detail,
        "paper_outcome_validation": validation_summary,
        "sqlite_sync": sqlite_sync,
        "reconciliation": reconciliation,
        "latest_rows": pmo_dedupe_rows(rows, ["symbol"], keep="last")[-12:],
        "journal_file": str(PMO_V112_REPLAY_JOURNAL_FILE),
        "report_file": str(PMO_V112_PROOF_REPORT_FILE),
        "recommendation": next_action,
    }
    if record:
        PMO_V112_PROOF_REPORT_FILE.write_text(json.dumps(report, indent=2), encoding="utf-8")
    return report


def pmo_score_model_audit_markdown(timestamp: str, model: str, parsed: Dict[str, Any]) -> str:
    return (
        "# PMO Score Model Audit\n\n"
        f"Generated: {timestamp} | Model: {model}\n\n"
        f"Verdict: {parsed.get('score_model_verdict', 'UNKNOWN')}\n\n"
        f"Inversion cause: {parsed.get('inversion_likely_cause', '-')}\n\n"
        f"Analyst note: {parsed.get('analyst_note', '-')}\n\n"
        "Top fixes:\n"
        + "\n".join(
            f"{index + 1}. [{fix.get('priority', '?')}] {fix.get('fix', '-')} - {fix.get('estimated_impact', '-')}"
            for index, fix in enumerate(parsed.get("top_3_fixes", []))
            if isinstance(fix, dict)
        )
        + "\n\nResearch only. No trades are placed by this report.\n"
    )


def pmo_record_score_model_audit(result: Dict[str, Any], timestamp: str, parsed: Dict[str, Any]) -> Dict[str, Any]:
    model = str(result.get("ai_model") or PMO_AI_MODEL)
    audit_md = pmo_score_model_audit_markdown(timestamp, model, parsed)
    write_json_file(PMO_SCORE_AUDIT_FILE, result)
    atomic_write_text(PMO_SCORE_AUDIT_MD_FILE, audit_md)
    result["audit_file"] = str(PMO_SCORE_AUDIT_FILE)
    result["audit_md_file"] = str(PMO_SCORE_AUDIT_MD_FILE)
    pmo_append_report_archive({
        "timestamp": timestamp,
        "type": "score_model_audit",
        "title": f"Score Model Audit - {parsed.get('score_model_verdict', 'UNKNOWN')}",
        "json_path": str(PMO_SCORE_AUDIT_FILE),
        "md_path": str(PMO_SCORE_AUDIT_MD_FILE),
    })
    return result


def pmo_rule_based_score_model_audit(
    settings: Dict[str, Any],
    timestamp: str,
    v112_report: Dict[str, Any],
    v112_summary: Dict[str, Any],
    closed_rows: List[Dict[str, Any]],
    wins: List[Dict[str, Any]],
    losses: List[Dict[str, Any]],
    avg_win_score: float,
    avg_loss_score: float,
    trade_summary: List[Dict[str, Any]],
    score_band_data: List[Dict[str, Any]],
    ai_error: Optional[Dict[str, Any]] = None,
    record: bool = True,
) -> Dict[str, Any]:
    del v112_report
    diagnosis = {}
    try:
        diagnosis = pmo_paper_proof_diagnosis(settings, record=False)
    except Exception as exc:
        diagnosis = {"ok": False, "error": str(exc)[:180]}
    win_rate = safe_float(v112_summary.get("win_rate", diagnosis.get("win_rate", 0)), 0)
    profit_factor = safe_float(v112_summary.get("profit_factor", diagnosis.get("profit_factor", 0)), 0)
    avg_win_pct = safe_float(v112_summary.get("avg_win_pct", diagnosis.get("avg_win_pct", 0)), 0)
    avg_loss_pct = safe_float(v112_summary.get("avg_loss_pct", diagnosis.get("avg_loss_pct", 0)), 0)
    score_inverted = bool(
        diagnosis.get("score_inverted")
        or (len(wins) >= 5 and len(losses) >= 5 and avg_win_score > 0 and avg_loss_score > 0 and avg_win_score < avg_loss_score)
    )
    band_rows = score_band_data if isinstance(score_band_data, list) else []
    if not band_rows and isinstance(diagnosis.get("score_bucket_results"), list):
        band_rows = diagnosis.get("score_bucket_results", [])

    def band_name(row: Dict[str, Any]) -> str:
        return str(row.get("score_range") or row.get("bucket") or row.get("score_bucket") or row.get("range") or "UNKNOWN")

    def band_count(row: Dict[str, Any]) -> float:
        return safe_float(row.get("closed", row.get("count", 0)), 0)

    def band_score(row: Dict[str, Any]) -> float:
        return (
            safe_float(row.get("profit_factor"), 0) * 2.0
            + safe_float(row.get("win_rate"), 0)
            + safe_float(row.get("avg_pnl", row.get("avg_pnl_pct", 0)), 0) / 100.0
            + min(band_count(row), 20) / 100.0
        )

    usable_bands = [row for row in band_rows if isinstance(row, dict) and band_count(row) > 0]
    best_band = max(usable_bands, key=band_score) if usable_bands else {}
    worst_band = min(usable_bands, key=band_score) if usable_bands else {}
    best_symbols = diagnosis.get("best_symbols", []) if isinstance(diagnosis.get("best_symbols"), list) else []
    worst_symbols = diagnosis.get("worst_symbols", []) if isinstance(diagnosis.get("worst_symbols"), list) else []
    verdict = "REBUILD" if score_inverted or profit_factor < 0.8 else ("RETUNE" if win_rate < 0.52 or profit_factor < 1.3 else "MONITOR")
    min_trades = max(50, int(safe_float(settings.get("PMO_MICRO_MIN_CLOSED_TRADES_STRONG_VALIDATION", 50), 50)))
    recommended_range = band_name(best_band) if best_band else "collect_more_data"
    inversion_note = (
        f"Average winning score {avg_win_score} is below average losing score {avg_loss_score}; high scores are not proving better outcomes."
        if score_inverted else
        "No hard score inversion detected yet, but proof metrics remain below live-readiness requirements."
    )
    parsed = {
        "inversion_likely_cause": inversion_note,
        "features_that_predict_wins": [
            f"Best observed score bucket: {recommended_range}",
            f"Best symbols by closed paper P&L: {', '.join(str(row.get('symbol')) for row in best_symbols[:5]) or 'not enough symbol data'}",
            f"Average win pct {avg_win_pct:.2f} versus average loss pct {avg_loss_pct:.2f}",
        ],
        "features_that_predict_losses": [
            f"Worst observed score bucket: {band_name(worst_band) if worst_band else 'not enough bucket data'}",
            f"Worst symbols by closed paper P&L: {', '.join(str(row.get('symbol')) for row in worst_symbols[:5]) or 'not enough symbol data'}",
            f"Profit factor {profit_factor:.2f} remains below proof target.",
        ],
        "score_band_verdict": {
            "best_band": recommended_range,
            "worst_band": band_name(worst_band) if worst_band else "UNKNOWN",
            "recommended_entry_range": recommended_range,
        },
        "top_3_fixes": [
            {
                "fix": "Keep paper proof quality breaker active until profit factor improves above 0.80, then re-audit before widening entries.",
                "priority": "CRITICAL",
                "estimated_impact": "Stops weak entries from adding more bad proof data.",
            },
            {
                "fix": "Reduce or block the worst symbols from the diagnosis report until their paper PF improves.",
                "priority": "HIGH",
                "estimated_impact": "Removes the largest current symbol-level drag.",
            },
            {
                "fix": "Treat high PMO score as untrusted until 50+ closed trades confirm the score ladder predicts wins.",
                "priority": "HIGH",
                "estimated_impact": "Prevents false confidence from score inversion.",
            },
        ],
        "score_model_verdict": verdict,
        "minimum_trades_before_action": min_trades,
        "analyst_note": "Rule-based fallback audit used because Claude was unavailable or returned invalid output. Live trading remains locked.",
    }
    result = {
        "ok": True,
        "generated": timestamp,
        "research_only": True,
        "ai_model": "rule_based_fallback",
        "ai_ok": False,
        "ai_error": ai_error or {},
        "trade_count_analyzed": len(trade_summary),
        "closed_count": len(closed_rows),
        "wins": len(wins),
        "losses": len(losses),
        "audit": parsed,
        "raw_text": "",
        "data_inputs": {
            "avg_win_score": avg_win_score,
            "avg_loss_score": avg_loss_score,
            "score_bands": band_rows,
            "summary": v112_summary,
            "paper_proof_diagnosis": {
                "closed_outcomes": diagnosis.get("closed_outcomes"),
                "win_rate": diagnosis.get("win_rate"),
                "profit_factor": diagnosis.get("profit_factor"),
                "score_inverted": diagnosis.get("score_inverted"),
            },
        },
        "prompt_cache": (ai_error or {}).get("prompt_cache", {}),
        "safe_next_action": "Do not unlock live trading. Use this rule-based audit until Claude API access is healthy.",
    }
    if record:
        result = pmo_record_score_model_audit(result, timestamp, parsed)
    return result


def pmo_score_model_audit(settings: Optional[Dict[str, Any]] = None, record: bool = True) -> Dict[str, Any]:
    settings = settings or load_settings()
    timestamp = now_et().isoformat()
    if not settings.get("PMO_AI_SCORE_AUDIT_ENABLED", True):
        return {"ok": False, "generated": timestamp, "error": "PMO_AI_SCORE_AUDIT_ENABLED is False."}
    claude_available = bool(first_env("ANTHROPIC_API_KEY", "PMO_ANTHROPIC_API_KEY", "CLAUDE_API_KEY"))
    if not claude_available:
        return {
            "ok": False,
            "generated": timestamp,
            "error": "ANTHROPIC_API_KEY not set in .env. Score audit requires Claude API access.",
            "setup": "Add ANTHROPIC_API_KEY to .env, then POST /api/score/audit with the PMO admin token.",
        }

    v112_report = pmo_v112_proof_report(settings, record=False)
    v112_summary = v112_report.get("summary", {}) if isinstance(v112_report.get("summary"), dict) else {}
    rows = pmo_v112_load_journal()
    closed_rows = [
        row for row in rows
        if str(row.get("replay_type", "")).upper() == "PAPER_REPLAY"
        and str(row.get("quality", "")).upper() in {"WIN", "LOSS"}
    ]
    wins = [row for row in closed_rows if str(row.get("quality", "")).upper() == "WIN"]
    losses = [row for row in closed_rows if str(row.get("quality", "")).upper() == "LOSS"]
    avg_win_score = round(sum(safe_float(row.get("score"), 0) for row in wins) / len(wins), 2) if wins else 0.0
    avg_loss_score = round(sum(safe_float(row.get("score"), 0) for row in losses) / len(losses), 2) if losses else 0.0
    trade_summary = []
    for row in closed_rows[-60:]:
        trade_summary.append({
            "symbol": row.get("symbol", ""),
            "score": safe_float(row.get("score") or row.get("pmo_score"), 0),
            "score_range": row.get("score_range") or pmo_score_range_label(row.get("score"), settings),
            "direction": row.get("direction", ""),
            "quality": row.get("quality", ""),
            "pnl_pct": safe_float(row.get("pnl_pct"), 0),
            "regime": row.get("market_regime") or row.get("regime", ""),
            "rvol": safe_float(row.get("rvol") or row.get("relative_volume"), 0),
            "setup_type": row.get("setup_type") or row.get("setup", ""),
            "vwap_distance_pct": safe_float(row.get("vwap_distance_pct") or row.get("entry_distance_vwap"), 0),
        })
    score_band_data = v112_report.get("score_range_win_rates", [])
    system_prompt = (
        "You are a quantitative trading strategy analyst auditing a paper trading bot score model. "
        "Find score inversion, weak predictors, and concrete retuning actions. Return valid JSON only."
    )
    user_prompt = (
        "Analyze this PMO paper trading score model.\n"
        f"Avg winning score: {avg_win_score}\n"
        f"Avg losing score: {avg_loss_score}\n"
        f"Closed paper rows analyzed: {len(trade_summary)}\n"
        f"Win rate: {safe_float(v112_summary.get('win_rate'), 0):.3f}\n"
        f"Profit factor: {safe_float(v112_summary.get('profit_factor'), 0):.3f}\n"
        f"Avg win pct: {safe_float(v112_summary.get('avg_win_pct'), 0):.3f}\n"
        f"Avg loss pct: {safe_float(v112_summary.get('avg_loss_pct'), 0):.3f}\n\n"
        f"Score band performance:\n{json.dumps(score_band_data, default=str, indent=2)}\n\n"
        f"Closed trade sample:\n{json.dumps(trade_summary, default=str, indent=2)}\n\n"
        "Return only one raw JSON object. Do not wrap it in markdown or a code fence. "
        "Keep string values concise. Return JSON with fields: inversion_likely_cause string, "
        "features_that_predict_wins list, features_that_predict_losses list, "
        "score_band_verdict object with best_band/worst_band/recommended_entry_range, "
        "top_3_fixes list of objects with fix/priority/estimated_impact, "
        "score_model_verdict REBUILD or RETUNE or MONITOR, "
        "minimum_trades_before_action number, analyst_note string."
    )
    audit_max_tokens = int(safe_float(settings.get("PMO_AI_AUDIT_MAX_TOKENS", PMO_AI_AUDIT_MAX_TOKENS), PMO_AI_AUDIT_MAX_TOKENS))
    ai = (
        pmo_claude_call(system_prompt, user_prompt, audit_max_tokens, expect_json=True, settings=settings)
        if claude_available
        else {
            "ok": False,
            "error": "ANTHROPIC_API_KEY not set in .env. Rule-based fallback used.",
            "source": "fallback",
            "model": "rule_based_fallback",
        }
    )
    if not ai.get("ok") or not ai.get("parsed"):
        ai_error = {
            "error": ai.get("error", "Claude score audit failed or returned invalid JSON."),
            "http_status": ai.get("http_status"),
            "response_body": ai.get("response_body", ""),
            "ai_model": ai.get("model", PMO_AI_MODEL),
            "prompt_cache": ai.get("prompt_cache", {}),
            "raw_text": str(ai.get("text", ""))[:1000],
        }
        if settings.get("PMO_SCORE_AUDIT_RULE_BASED_FALLBACK", True):
            return pmo_rule_based_score_model_audit(
                settings,
                timestamp,
                v112_report,
                v112_summary,
                closed_rows,
                wins,
                losses,
                avg_win_score,
                avg_loss_score,
                trade_summary,
                score_band_data,
                ai_error=ai_error,
                record=record,
            )
        return {
            "ok": False,
            "generated": timestamp,
            **ai_error,
        }
    parsed = ai.get("parsed", {})
    result = {
        "ok": True,
        "generated": timestamp,
        "research_only": True,
        "ai_model": ai.get("model", PMO_AI_MODEL),
        "usage": ai.get("usage", {}),
        "prompt_cache": ai.get("prompt_cache", {}),
        "trade_count_analyzed": len(trade_summary),
        "closed_count": len(closed_rows),
        "wins": len(wins),
        "losses": len(losses),
        "audit": parsed,
        "raw_text": ai.get("text", ""),
        "data_inputs": {
            "avg_win_score": avg_win_score,
            "avg_loss_score": avg_loss_score,
            "score_bands": score_band_data,
            "summary": v112_summary,
        },
    }
    if record:
        result = pmo_record_score_model_audit(result, timestamp, parsed)
    return result


def pmo_paper_proof_diagnosis(
    settings: Optional[Dict[str, Any]] = None,
    record: bool = True,
    limit: int = 5000,
) -> Dict[str, Any]:
    """Read-only diagnosis of PMO paper proof quality across the journal files."""
    settings = settings or load_settings()
    timestamp = now_et().isoformat()
    limit = max(50, min(int(safe_float(limit, 5000)), 20000))

    trade_rows = recent_csv_rows(TRADE_JOURNAL_FILE, limit)
    exec_rows = recent_csv_rows(PMO_ORDER_EXECUTION_FILE, limit)
    v112_rows = recent_csv_rows(PMO_V112_REPLAY_JOURNAL_FILE, limit)
    plan_rows = recent_csv_rows(PMO_TRADE_PLAN_FILE, limit)
    approval_rows = recent_csv_rows(PMO_DASHBOARD_TRADE_APPROVAL_FILE, limit)
    backtest_trade_rows = 0
    try:
        for path in (REPORT_DIR / "backtests").rglob("*trades.csv"):
            backtest_trade_rows += len(recent_csv_rows(path, limit))
    except Exception:
        backtest_trade_rows = 0
    open_statuses = {"TARGET_REACHED_OPEN", "STOP_REACHED_OPEN", "OPEN_FILLED", "CLOSE_SUBMITTED", "MAX_HOLD_EXIT_DUE_OPEN"}
    system_statuses = {"JOURNAL_READY", "SYSTEM", "INIT", "INITIALIZED"}
    win_words = ("WIN", "PROFIT", "TAKE_PROFIT", "TARGET_HIT")
    loss_words = ("LOSS", "STOP_LOSS", "STOPPED_OUT", "DRAWDOWN", "DRAWNDOWN")

    def text_value(row: Dict[str, Any], *fields: str) -> str:
        for field in fields:
            value = row.get(field)
            if value not in (None, ""):
                return str(value)
        return ""

    def numeric_value(row: Dict[str, Any], *fields: str, default: Optional[float] = 0.0) -> Optional[float]:
        for field in fields:
            value = row.get(field)
            if value not in (None, ""):
                return safe_float(value, default)
        return default

    def score_bucket(score: float) -> str:
        if score < 55:
            return "0-54"
        if score < 65:
            return "55-64"
        if score < 75:
            return "65-74"
        if score < 85:
            return "75-84"
        return "85+"

    def normalize_exit_reason(row: Dict[str, Any], status: str, pnl: float) -> str:
        raw = text_value(row, "exit_reason", "close_reason", "reason", "detail", "message", "status").upper()
        source = f"{raw} {status}".upper()
        if "STOP" in source:
            return "STOP"
        if "TARGET" in source or "TAKE_PROFIT" in source or "TP" == source.strip():
            return "TARGET"
        if "BROKER_SELL_FILL" in source or "SELL_FILL" in source:
            return "BROKER_SELL_FILL"
        if "TIME" in source or "HOLD" in source:
            return "TIME_EXIT"
        if "MANUAL" in source:
            return "MANUAL"
        if pnl > 0:
            return "WIN_EXIT_UNKNOWN"
        if pnl < 0:
            return "LOSS_EXIT_UNKNOWN"
        return "UNKNOWN"

    def normalize_trade_row(row: Dict[str, Any], source: str) -> Optional[Dict[str, Any]]:
        status = text_value(row, "status", "result", "outcome", "quality", "win_loss_result").strip().upper()
        symbol = text_value(row, "symbol", "ticker").strip().upper()
        if not symbol or symbol == "SYSTEM" or status in system_statuses or status in open_statuses or status.endswith("_OPEN"):
            return None
        pnl = numeric_value(row, "pnl", "pnl_usd", "profit_loss", "profit_loss_usd", "realized_pnl", "net_pnl", default=None)
        quality = text_value(row, "quality", "result", "outcome", "win_loss_result").strip().upper()
        is_win = any(word in status for word in win_words) or any(word in quality for word in win_words) or (pnl is not None and pnl > 0)
        is_loss = (
            any(word in status for word in loss_words)
            or "STOP_HIT" in status
            or any(word in quality for word in loss_words)
            or (pnl is not None and pnl < 0)
        )
        is_closed = (
            status.startswith("CLOSED")
            or status in {"WIN", "LOSS", "COMPLETE", "COMPLETED"}
            or quality in {"WIN", "LOSS"}
            or is_win
            or is_loss
        )
        if not is_closed or not (is_win or is_loss):
            return None
        entry = numeric_value(row, "entry_price", "filled_price", "avg_fill_price", "entry", default=0.0) or 0.0
        exit_price = numeric_value(row, "exit_price", "close_price", "exit", "last_price", default=0.0) or 0.0
        pnl_pct = numeric_value(row, "pnl_pct", "return_pct", "profit_loss_pct", default=None)
        if pnl_pct is None and entry and exit_price:
            pnl_pct = ((exit_price - entry) / entry) * 100.0
        score = numeric_value(row, "score", "pmo_score", "signal_score", default=0.0) or 0.0
        if pnl is None and pnl_pct is not None:
            pnl = pnl_pct
        pnl = pnl if pnl is not None else 0.0
        market = text_value(row, "market", "asset_class") or detect_market(symbol, "AUTO")
        exit_reason = normalize_exit_reason(row, status, pnl)
        source_order_id = text_value(row, "source_order_id", "executor_source_order_id", "order_id")
        client_order_id = text_value(row, "client_order_id", "executor_client_order_id")
        trade_plan_id = text_value(row, "trade_plan_id", "plan_id")
        return {
            "source": source,
            "source_order_id": source_order_id,
            "client_order_id": client_order_id,
            "trade_plan_id": trade_plan_id,
            "timestamp": text_value(row, "timestamp", "time", "submitted_at", "filled_at", "created_at"),
            "closed_at": text_value(row, "closed_at", "exit_timestamp", "reviewed_at"),
            "symbol": symbol,
            "side": text_value(row, "side", "order_side", "direction").upper(),
            "market": market,
            "status": status or quality or "CLOSED",
            "score": round(score, 2),
            "score_bucket": score_bucket(score),
            "entry_price": round(entry, 6),
            "exit_price": round(exit_price, 6),
            "pnl": round(pnl, 4),
            "pnl_pct": round(pnl_pct or 0.0, 4),
            "win": bool(is_win),
            "exit_reason": exit_reason,
            "setup_type": text_value(row, "setup_type", "setup", "strategy", "tag").upper(),
            "market_regime": text_value(row, "market_regime", "regime").upper(),
            "risk_multiplier": numeric_value(row, "risk_multiplier", "risk_mult", default=0.0) or 0.0,
            "rvol": numeric_value(row, "rvol", "relative_volume", default=0.0) or 0.0,
            "sector": text_value(row, "sector") or pmo_sector_for_symbol(symbol),
        }

    closed_trades: List[Dict[str, Any]] = []
    v112_excluded_trades: List[Dict[str, Any]] = []
    closed_by_source: Dict[str, int] = {}
    seen_keys = set()
    for source_name, rows in (("trade_journal", trade_rows),):
        for row in rows:
            trade = normalize_trade_row(row, source_name)
            if not trade:
                continue
            identity = trade.get("source_order_id") or trade.get("client_order_id") or trade.get("trade_plan_id")
            key = (
                identity or trade.get("timestamp") or trade.get("closed_at"),
                trade["symbol"],
                trade["side"],
                trade["entry_price"],
                trade["exit_price"],
                trade["pnl"],
            )
            if key in seen_keys:
                continue
            seen_keys.add(key)
            closed_by_source[source_name] = closed_by_source.get(source_name, 0) + 1
            closed_trades.append(trade)

    for row in v112_rows:
        trade = normalize_trade_row(row, "v112_replay")
        if trade:
            v112_excluded_trades.append(trade)

    total = len(closed_trades)
    wins = [row for row in closed_trades if row["win"]]
    losses = [row for row in closed_trades if not row["win"]]
    v112_wins = [row for row in v112_excluded_trades if row["win"]]
    v112_losses = [row for row in v112_excluded_trades if not row["win"]]
    v112_total = len(v112_excluded_trades)
    v112_gross_profit = sum(max(0.0, safe_float(row.get("pnl"), 0)) for row in v112_wins)
    v112_gross_loss = sum(abs(min(0.0, safe_float(row.get("pnl"), 0))) for row in v112_losses)
    v112_win_rate = round(len(v112_wins) / v112_total, 4) if v112_total else 0.0
    v112_profit_factor = round(v112_gross_profit / v112_gross_loss, 4) if v112_gross_loss else (round(v112_gross_profit, 4) if v112_gross_profit else 0.0)
    n_wins = len(wins)
    n_losses = len(losses)
    gross_profit = sum(max(0.0, safe_float(row.get("pnl"), 0)) for row in wins)
    gross_loss = sum(abs(min(0.0, safe_float(row.get("pnl"), 0))) for row in losses)
    win_rate = round(n_wins / total, 4) if total else 0.0
    profit_factor = round(gross_profit / gross_loss, 4) if gross_loss else (round(gross_profit, 4) if gross_profit else 0.0)
    net_pnl = round(gross_profit - gross_loss, 4)
    avg_win_pnl = round(gross_profit / n_wins, 4) if n_wins else 0.0
    avg_loss_pnl = round(gross_loss / n_losses, 4) if n_losses else 0.0
    avg_win_pct = round(sum(safe_float(row.get("pnl_pct"), 0) for row in wins) / n_wins, 4) if n_wins else 0.0
    avg_loss_pct = round(sum(safe_float(row.get("pnl_pct"), 0) for row in losses) / n_losses, 4) if n_losses else 0.0
    avg_win_score = round(sum(safe_float(row.get("score"), 0) for row in wins) / n_wins, 2) if n_wins else 0.0
    avg_loss_score = round(sum(safe_float(row.get("score"), 0) for row in losses) / n_losses, 2) if n_losses else 0.0
    min_wr = safe_float(settings.get("PMO_V112_MIN_PROOF_WIN_RATE", 0.52), 0.52)
    min_pf = safe_float(settings.get("PMO_V112_MIN_PROOF_PROFIT_FACTOR", 1.3), 1.3)
    proof_passed = bool(total >= 20 and win_rate >= min_wr and profit_factor >= min_pf)

    def aggregate_trade_rows(rows: List[Dict[str, Any]], key_field: str) -> List[Dict[str, Any]]:
        groups: Dict[str, Dict[str, Any]] = {}
        for trade in rows:
            key = str(trade.get(key_field) or "UNKNOWN")
            group = groups.setdefault(key, {
                key_field: key,
                "closed": 0,
                "wins": 0,
                "losses": 0,
                "gross_profit": 0.0,
                "gross_loss": 0.0,
                "score_total": 0.0,
                "pnl_total": 0.0,
                "pnl_pct_total": 0.0,
            })
            pnl = safe_float(trade.get("pnl"), 0)
            group["closed"] += 1
            group["score_total"] += safe_float(trade.get("score"), 0)
            group["pnl_total"] += pnl
            group["pnl_pct_total"] += safe_float(trade.get("pnl_pct"), 0)
            if trade.get("win"):
                group["wins"] += 1
                group["gross_profit"] += max(0.0, pnl)
            else:
                group["losses"] += 1
                group["gross_loss"] += abs(min(0.0, pnl))
        output = []
        for group in groups.values():
            closed = int(group["closed"])
            gross_loss_value = safe_float(group["gross_loss"], 0)
            pf = round(safe_float(group["gross_profit"], 0) / gross_loss_value, 4) if gross_loss_value else (round(safe_float(group["gross_profit"], 0), 4) if safe_float(group["gross_profit"], 0) else 0.0)
            output.append({
                key_field: group[key_field],
                "closed": closed,
                "wins": int(group["wins"]),
                "losses": int(group["losses"]),
                "win_rate": round(safe_float(group["wins"], 0) / closed, 4) if closed else 0.0,
                "profit_factor": pf,
                "net_pnl": round(safe_float(group["pnl_total"], 0), 4),
                "avg_pnl": round(safe_float(group["pnl_total"], 0) / closed, 4) if closed else 0.0,
                "avg_pnl_pct": round(safe_float(group["pnl_pct_total"], 0) / closed, 4) if closed else 0.0,
                "avg_score": round(safe_float(group["score_total"], 0) / closed, 2) if closed else 0.0,
            })
        return output

    symbol_rows = aggregate_trade_rows(closed_trades, "symbol")
    for row in symbol_rows:
        if row["closed"] < 3:
            recommendation = "needs_more_data"
        elif row["net_pnl"] < 0 and (row["profit_factor"] < 0.5 or row["win_rate"] < 0.35):
            recommendation = "block_temporarily"
        elif row["net_pnl"] < 0 or row["profit_factor"] < 0.8:
            recommendation = "reduce_or_watch"
        else:
            recommendation = "paper_test_ok"
        row["recommendation"] = recommendation
        row["sector"] = pmo_sector_for_symbol(str(row.get("symbol") or ""))
    symbol_rows.sort(key=lambda row: (safe_float(row.get("net_pnl"), 0), -safe_float(row.get("closed"), 0)))
    worst_symbols = symbol_rows[:10]
    best_symbols = sorted(symbol_rows, key=lambda row: safe_float(row.get("net_pnl"), 0), reverse=True)[:10]

    bucket_order = ["0-54", "55-64", "65-74", "75-84", "85+"]
    score_bucket_results = []
    bucket_rows = aggregate_trade_rows(closed_trades, "score_bucket")
    by_bucket = {row["score_bucket"]: row for row in bucket_rows}
    for bucket in bucket_order:
        row = by_bucket.get(bucket, {
            "score_bucket": bucket,
            "closed": 0,
            "wins": 0,
            "losses": 0,
            "win_rate": 0.0,
            "profit_factor": 0.0,
            "net_pnl": 0.0,
            "avg_pnl": 0.0,
            "avg_pnl_pct": 0.0,
            "avg_score": 0.0,
        })
        if row["closed"] < 3:
            conclusion = "insufficient_data"
        elif row["profit_factor"] >= min_pf and row["win_rate"] >= min_wr:
            conclusion = "working"
        elif row["profit_factor"] < 0.8 or row["win_rate"] < 0.35:
            conclusion = "weak_or_inverted"
        else:
            conclusion = "monitor"
        score_bucket_results.append({**row, "bucket": bucket, "conclusion": conclusion})

    high_bucket = next((row for row in score_bucket_results if row["bucket"] == "85+"), {})
    lower_best_pf = max(
        (safe_float(row.get("profit_factor"), 0) for row in score_bucket_results if row["bucket"] != "85+" and safe_float(row.get("closed"), 0) >= 3),
        default=0.0,
    )
    score_inverted = bool(
        (n_wins >= 5 and n_losses >= 5 and avg_win_score > 0 and avg_loss_score > 0 and avg_win_score < avg_loss_score)
        or (
            safe_float(high_bucket.get("closed"), 0) >= 3
            and lower_best_pf > safe_float(high_bucket.get("profit_factor"), 0)
            and safe_float(high_bucket.get("profit_factor"), 0) < 0.8
        )
    )

    exit_rows = aggregate_trade_rows(closed_trades, "exit_reason")
    exit_rows.sort(key=lambda row: safe_float(row.get("closed"), 0), reverse=True)
    stop_hits = sum(int(row["closed"]) for row in exit_rows if "STOP" in str(row.get("exit_reason", "")).upper() or "LOSS" in str(row.get("exit_reason", "")).upper())
    target_hits = sum(int(row["closed"]) for row in exit_rows if "TARGET" in str(row.get("exit_reason", "")).upper() or "WIN" in str(row.get("exit_reason", "")).upper())
    tiny_wins = [row for row in wins if 0 < safe_float(row.get("pnl_pct"), 0) < 1.0]
    stop_rate = round(stop_hits / total, 4) if total else 0.0
    target_rate = round(target_hits / total, 4) if total else 0.0
    stop_too_tight = bool(total >= 10 and (stop_rate > 0.6 or (avg_win_pct > 0 and abs(avg_loss_pct) > avg_win_pct * 1.5)))
    exit_quality = {
        "rows": exit_rows,
        "stopped_or_loss_exits": stop_hits,
        "target_or_win_exits": target_hits,
        "stop_hit_rate": stop_rate,
        "target_hit_rate": target_rate,
        "avg_win_pct": avg_win_pct,
        "avg_loss_pct": avg_loss_pct,
        "tiny_wins_under_1pct": len(tiny_wins),
        "stop_too_tight_flag": stop_too_tight,
        "diagnosis": "Exit quality is hurting proof; losses are larger than wins or stop/loss exits dominate." if stop_too_tight else "Exit quality is acceptable enough to keep collecting proof data.",
    }

    bad_trades = []
    for trade in sorted(closed_trades, key=lambda row: safe_float(row.get("pnl"), 0))[:10]:
        reasons = []
        if score_inverted and safe_float(trade.get("score"), 0) >= avg_loss_score:
            reasons.append("high score still lost")
        if safe_float(trade.get("pnl_pct"), 0) <= -3.5:
            reasons.append("large percentage loss")
        if safe_float(trade.get("rvol"), 0) and safe_float(trade.get("rvol"), 0) < 1.0:
            reasons.append("weak relative volume")
        bad_trades.append({
            "timestamp": trade.get("timestamp", ""),
            "symbol": trade.get("symbol", ""),
            "side": trade.get("side", ""),
            "score": trade.get("score", 0),
            "score_bucket": trade.get("score_bucket", ""),
            "pnl": trade.get("pnl", 0),
            "pnl_pct": trade.get("pnl_pct", 0),
            "exit_reason": trade.get("exit_reason", ""),
            "sector": trade.get("sector", ""),
            "loss_reasons": "; ".join(reasons) if reasons else "needs more feature data",
            "block_rule_suggestion": f"Watch or reduce {trade.get('symbol', '')} until symbol PF improves above 0.80",
        })

    best_trades = []
    for trade in sorted(wins, key=lambda row: safe_float(row.get("pnl"), 0), reverse=True)[:10]:
        worked = []
        if score_inverted and safe_float(trade.get("score"), 0) < avg_loss_score:
            worked.append("winner came from lower score range")
        if safe_float(trade.get("pnl_pct"), 0) >= 2.0:
            worked.append("meaningful percentage move")
        if safe_float(trade.get("rvol"), 0) >= 1.5:
            worked.append("strong relative volume")
        best_trades.append({
            "timestamp": trade.get("timestamp", ""),
            "symbol": trade.get("symbol", ""),
            "side": trade.get("side", ""),
            "score": trade.get("score", 0),
            "score_bucket": trade.get("score_bucket", ""),
            "pnl": trade.get("pnl", 0),
            "pnl_pct": trade.get("pnl_pct", 0),
            "exit_reason": trade.get("exit_reason", ""),
            "sector": trade.get("sector", ""),
            "what_worked": "; ".join(worked) if worked else "needs more feature data",
            "look_for_more": bool(safe_float(trade.get("pnl"), 0) > 0),
        })

    recommendations = []
    if profit_factor < 0.8:
        recommendations.append({
            "priority": "CRITICAL",
            "type": "paper_proof_quality",
            "action": f"Keep the paper quality breaker active. Profit factor {profit_factor:.2f} is below 0.80.",
            "estimated_impact": "Prevents the bot from adding more weak proof while exits and score model are repaired.",
        })
    if score_inverted:
        recommendations.append({
            "priority": "CRITICAL",
            "type": "score_model",
            "action": f"Audit score weights. Average winning score {avg_win_score} is not better than losing score {avg_loss_score}.",
            "estimated_impact": "Stops high scores from creating false confidence.",
        })
    if worst_symbols:
        recommendations.append({
            "priority": "HIGH",
            "type": "symbol_damage",
            "action": f"Temporarily block or reduce {', '.join(row['symbol'] for row in worst_symbols[:3])}.",
            "estimated_impact": "Removes the largest symbol-level drag from paper testing.",
        })
    if stop_too_tight:
        recommendations.append({
            "priority": "HIGH",
            "type": "exit_quality",
            "action": "Review stop/target behavior. Winners are too small or loss exits dominate.",
            "estimated_impact": "Improves profit factor without opening more trades.",
        })
    recommendations.append({
        "priority": "ALWAYS",
        "type": "live_safety",
        "action": "Do not unlock live trading. Keep PMO paper-only until closed outcomes meet proof gates.",
        "estimated_impact": "Protects real capital while the paper edge is still unproven.",
    })

    failure_reasons = []
    if win_rate < min_wr:
        failure_reasons.append(f"Win rate {win_rate:.1%} is below {min_wr:.0%}.")
    if profit_factor < min_pf:
        failure_reasons.append(f"Profit factor {profit_factor:.2f} is below {min_pf:.2f}.")
    if score_inverted:
        failure_reasons.append(f"Score model inversion detected: avg win score {avg_win_score}, avg loss score {avg_loss_score}.")
    if stop_too_tight:
        failure_reasons.append("Exit quality is dragging proof metrics.")
    top_failure_reason = failure_reasons[0] if failure_reasons else "Proof gates are not fully diagnosed yet; keep collecting clean closed outcomes."

    files = {
        "json": str(PMO_PROOF_DIAGNOSIS_FILE),
        "symbol_csv": str(PMO_PROOF_DIAGNOSIS_SYM),
        "score_csv": str(PMO_PROOF_DIAGNOSIS_SCORE),
        "exit_csv": str(PMO_PROOF_DIAGNOSIS_EXIT),
        "bad_csv": str(PMO_PROOF_DIAGNOSIS_BAD),
        "best_csv": str(PMO_PROOF_DIAGNOSIS_BEST),
        "recommendations_csv": str(PMO_PROOF_DIAGNOSIS_RECS),
    }
    result = {
        "ok": True,
        "generated": timestamp,
        "research_only": True,
        "closed_outcomes": total,
        "wins": n_wins,
        "losses": n_losses,
        "win_rate": win_rate,
        "profit_factor": profit_factor,
        "net_pnl": net_pnl,
        "avg_win_pnl": avg_win_pnl,
        "avg_loss_pnl": avg_loss_pnl,
        "avg_win_pct": avg_win_pct,
        "avg_loss_pct": avg_loss_pct,
        "avg_win_score": avg_win_score,
        "avg_loss_score": avg_loss_score,
        "score_inverted": score_inverted,
        "proof_passed": proof_passed,
        "proof_min_win_rate": min_wr,
        "proof_min_profit_factor": min_pf,
        "top_failure_reason": top_failure_reason,
        "all_failure_reasons": failure_reasons,
        "source_counts": {
            "trade_journal_rows": len(trade_rows),
            "order_execution_rows": len(exec_rows),
            "v112_rows": len(v112_rows),
            "trade_plan_rows": len(plan_rows),
            "dashboard_approval_rows": len(approval_rows),
            "backtest_trade_rows": backtest_trade_rows,
            "dashboard_blocked_or_order_rows": sum(1 for row in exec_rows if str(row.get("status", "")).upper() in {"BLOCKED", "SUBMITTED"}),
            "closed_by_source": closed_by_source,
            "v112_excluded_from_current_proof": v112_total,
            "closed_used": total,
        },
        "v112_replay_exclusion": {
            "excluded_from_current_proof": True,
            "visible_in_inventory": True,
            "rows": len(v112_rows),
            "closed_outcomes": v112_total,
            "wins": len(v112_wins),
            "losses": len(v112_losses),
            "win_rate": v112_win_rate,
            "profit_factor": v112_profit_factor,
            "reason": (
                "V112 replay is pre-gate historical simulation generated before the blocklist, "
                "opening-slot gate, score model rebuild, and RVOL open-window gate. It remains "
                "visible for transparency but is excluded from current proof."
            ),
        },
        "source_inventory": [
            {"source": "trade_journal", "rows": len(trade_rows), "counts_as_closed_proof": True, "note": "Broker-synced CLOSED_WIN/CLOSED_LOSS outcomes."},
            {"source": "v112_replay", "rows": len(v112_rows), "counts_as_closed_proof": False, "note": "Pre-gate historical replay; visible for diagnosis, excluded from current proof."},
            {"source": "order_execution", "rows": len(exec_rows), "counts_as_closed_proof": False, "note": "Executor attempts; mostly BLOCKED/SUBMITTED, not realized outcomes."},
            {"source": "trade_plans", "rows": len(plan_rows), "counts_as_closed_proof": False, "note": "Generated plans/signals; useful for activity audit, not proof."},
            {"source": "dashboard_approvals", "rows": len(approval_rows), "counts_as_closed_proof": False, "note": "Manual approval attempts; blocked/submitted status only."},
            {"source": "backtest_trades", "rows": backtest_trade_rows, "counts_as_closed_proof": False, "note": "Historical simulator trades; analyze separately from paper/live proof."},
        ],
        "worst_symbols": worst_symbols,
        "best_symbols": best_symbols,
        "score_bucket_results": score_bucket_results,
        "exit_quality": exit_quality,
        "bad_trades": bad_trades,
        "bad_trade_autopsy": bad_trades,
        "best_trades": best_trades,
        "best_trade_dna": best_trades,
        "recommendations": recommendations,
        "safe_next_action": "Do not unlock live trading. Keep PMO paper-only and use this diagnosis to repair score, symbol, and exit quality.",
        "live_unlocked": False,
        "live_trading_changed": False,
        "settings_changed": False,
        "broker_api_called": False,
        "journal_files_modified": False,
        "files": files,
    }
    if record:
        write_json_file(PMO_PROOF_DIAGNOSIS_FILE, result)
        write_csv_rows(PMO_PROOF_DIAGNOSIS_SYM, symbol_rows)
        write_csv_rows(PMO_PROOF_DIAGNOSIS_SCORE, score_bucket_results)
        write_csv_rows(PMO_PROOF_DIAGNOSIS_EXIT, exit_rows)
        write_csv_rows(PMO_PROOF_DIAGNOSIS_BAD, bad_trades)
        write_csv_rows(PMO_PROOF_DIAGNOSIS_BEST, best_trades)
        write_csv_rows(PMO_PROOF_DIAGNOSIS_RECS, recommendations)
    return result


def pmo_positive_learning_gate(settings: Optional[Dict[str, Any]] = None, proof_report: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    settings = settings or load_settings()
    proof_report = proof_report if isinstance(proof_report, dict) else {}
    if not proof_report and "pmo_v112_proof_report" in globals():
        try:
            proof_report = pmo_v112_proof_report(settings, record=False)
        except Exception:
            proof_report = {}
    summary = proof_report.get("summary", {}) if isinstance(proof_report.get("summary"), dict) else {}
    if pmo_micro_mode_enabled(settings):
        min_rows = int(settings.get("PMO_MICRO_MIN_CLOSED_TRADES_TO_JUDGE", settings.get("PMO_ASI_MIN_ROWS_TO_APPLY", 20)))
    else:
        min_rows = int(settings.get("PMO_ASI_MIN_ROWS_TO_APPLY", 5))
    min_win_rate = safe_float(settings.get("PMO_V112_MIN_PROOF_WIN_RATE", 0.5), 0.5)
    paper_replays = int(safe_float(summary.get("clean_paper_replays", summary.get("paper_replays", 0)), 0))
    wins = int(safe_float(summary.get("wins"), 0))
    losses = int(safe_float(summary.get("losses"), 0))
    closed_outcomes = wins + losses
    win_rate = safe_float(summary.get("win_rate"), 0)
    profit_factor = safe_float(summary.get("profit_factor"), 0)
    min_profit_factor = safe_float(settings.get("PMO_V112_MIN_PROOF_PROFIT_FACTOR", 1.2), 1.2)
    expectancy_pct = safe_float(summary.get("expectancy_pct"), 0)
    if paper_replays < min_rows:
        reason = f"needs {min_rows} clean true paper replay rows; current {paper_replays}"
        allowed = False
    elif closed_outcomes < min_rows:
        reason = f"needs {min_rows} closed paper outcomes; current {closed_outcomes}"
        allowed = False
    elif win_rate < min_win_rate:
        reason = f"paper replay win rate {win_rate:.2%} below {min_win_rate:.2%}"
        allowed = False
    elif profit_factor < min_profit_factor:
        reason = f"paper replay profit factor {profit_factor:.2f} below {min_profit_factor:.2f}"
        allowed = False
    elif expectancy_pct <= 0:
        reason = f"paper replay expectancy {expectancy_pct:.2f}% is not positive"
        allowed = False
    else:
        reason = "v112 paper proof supports positive watchlist influence"
        allowed = True
    return {
        "positive_allowed": allowed,
        "reason": reason,
        "paper_replays": paper_replays,
        "closed_outcomes": closed_outcomes,
        "clean_closed_outcomes": int(safe_float(summary.get("clean_closed_paper_trades", closed_outcomes), closed_outcomes)),
        "win_rate": win_rate,
        "min_rows": min_rows,
        "min_win_rate": min_win_rate,
        "profit_factor": profit_factor,
        "min_profit_factor": min_profit_factor,
        "expectancy_pct": expectancy_pct,
        "would_have_traded": int(safe_float(summary.get("would_have_traded"), 0)),
        "analysis_win_rate": safe_float(summary.get("analysis_win_rate"), 0),
    }


def pmo_pre_session_paper_checklist(
    settings: Dict[str, Any],
    account: Dict[str, Any],
    health: Dict[str, Any],
    regime: Dict[str, Any],
    reconciliation: Dict[str, Any],
    live_readiness: Dict[str, Any],
    operations: Dict[str, Any],
    paper_proof: Dict[str, Any],
    v112_proof: Dict[str, Any],
    why_not: Dict[str, Any],
    asi_report: Dict[str, Any],
    quantum_matrix: Dict[str, Any],
    record: bool = False,
    use_ai_context: bool = False,
) -> Dict[str, Any]:
    drawdown_governor = live_readiness.get("drawdown_governor", {}) if isinstance(live_readiness, dict) else {}
    proof_gate = pmo_positive_learning_gate(settings, v112_proof)
    why_summary = why_not.get("summary", {}) if isinstance(why_not.get("summary"), dict) else {}
    proof_metrics = paper_proof.get("metrics", {}) if isinstance(paper_proof.get("metrics"), dict) else {}
    paper_executor_switch_ready = all([
        bool(settings.get("ALPACA_PAPER")),
        bool(settings.get("ENABLE_ALPACA_ORDER_EXECUTOR")),
        str(settings.get("PMO_ORDER_EXECUTION_MODE", "")).upper() == "PAPER_ALPACA",
        bool(settings.get("ORDER_AUTOMATION_ENABLED")),
        not bool(settings.get("PMO_DRY_RUN_ORDERS")),
        not bool(settings.get("PMO_LIVE_TRADING_ENABLED")),
        not bool(settings.get("PMO_ALLOW_LIVE_TRADING")),
    ])
    live_switches_locked = all([
        not bool(settings.get("PMO_LIVE_TRADING_ENABLED")),
        not bool(settings.get("PMO_ALLOW_LIVE_TRADING")),
        bool(settings.get("ALPACA_PAPER")),
    ])
    paper_scan_switches_ready = all([
        bool(settings.get("ALPACA_PAPER")),
        not bool(settings.get("PMO_LIVE_TRADING_ENABLED")),
        not bool(settings.get("PMO_ALLOW_LIVE_TRADING")),
        bool(settings.get("PMO_DRY_RUN_ORDERS")) or not bool(settings.get("ORDER_AUTOMATION_ENABLED")),
    ])
    strict_filters_ready = (
        safe_float(settings.get("PMO_WHY_NOT_MIN_SCORE"), 0) >= safe_float(settings.get("PMO_SCORE_PAPER_ONLY_MIN", 75), 75)
        and safe_float(settings.get("PMO_WHY_NOT_MIN_RVOL"), 0) >= 1.2
        and bool(settings.get("PMO_WHY_NOT_REQUIRE_RVOL", True))
    )
    risk_guards_ready = all([
        settings.get("ENABLE_BUYING_POWER_GUARD"),
        settings.get("ENABLE_CASH_LOCKOUT"),
        settings.get("ENABLE_PDT_PROTECTION_AI"),
        settings.get("ENABLE_PMO_DUPLICATE_PHASE_GUARD"),
        settings.get("ENABLE_PMO_DAY_DRAWDOWN_GOVERNOR", True),
    ])
    operations_ready = safe_float(operations.get("score"), 0) >= 85
    account_ready = bool(account.get("ok")) and bool(account.get("paper", settings.get("ALPACA_PAPER")))
    broker_tradable = bool(account.get("ok")) and bool(account.get("tradable", True))
    paper_funding_ready = bool(account.get("ok")) and (
        safe_float(account.get("equity") or account.get("portfolio_value"), 0) > 0
        or safe_float(account.get("buying_power"), 0) > 0
    )
    market_data_ready = bool(bot.api_key and bot.api_secret and not ALPACA_IMPORT_ERROR)
    order_drawdown_gate_clear = not bool(drawdown_governor.get("order_submission_blocked") or drawdown_governor.get("session_frozen") or drawdown_governor.get("day_hard_stop"))
    paper_analysis_allowed_by_drawdown = bool(drawdown_governor.get("paper_analysis_allowed", True))
    learning_safe = (
        not bool(asi_report.get("live_influence"))
        and not bool(settings.get("PMO_ASI_ALLOW_LIVE_INFLUENCE"))
        and not bool(settings.get("PMO_LEARNING_CAN_RAISE_EXECUTION_SCORE"))
        and not bool(proof_gate.get("positive_allowed"))
    )
    checks = [
        {
            "name": "Order submission drawdown gate",
            "ready": order_drawdown_gate_clear,
            "severity": "order_gate",
            "value": drawdown_governor.get("display_level") or drawdown_governor.get("status", "CLEAR"),
            "detail": drawdown_governor.get("detail", ""),
        },
        {
            "name": "Paper account mode",
            "ready": account_ready,
            "severity": "blocker",
            "value": "PAPER" if account_ready else "NOT READY",
            "detail": account.get("status") if account.get("ok") else account.get("error", "broker snapshot unavailable"),
        },
        {
            "name": "Paper account buying power",
            "ready": paper_funding_ready,
            "severity": "executor",
            "value": f"${safe_float(account.get('buying_power'), 0):.2f}",
            "detail": "Required only for PAPER_ALPACA order collection. Scan-only review and would-have-traded analysis can run without submitting orders.",
        },
        {
            "name": "Broker account tradable",
            "ready": broker_tradable,
            "severity": "executor",
            "value": account.get("status", "UNKNOWN"),
            "detail": "Required only for PAPER_ALPACA order collection. A non-tradable broker account can still be reviewed, reconciled, and used for scan-only analysis.",
        },
        {
            "name": "Live switches locked",
            "ready": live_switches_locked,
            "severity": "blocker",
            "value": "LOCKED" if live_switches_locked else "CHECK SWITCHES",
            "detail": "PMO live master and live permission must remain OFF for paper-only proof.",
        },
        {
            "name": "Paper scan safety switches",
            "ready": paper_scan_switches_ready,
            "severity": "blocker",
            "value": "SCAN SAFE" if paper_scan_switches_ready else "UNSAFE",
            "detail": "Paper scan/review can run with dry-run ON or automation OFF.",
        },
        {
            "name": "Operations board ready",
            "ready": operations_ready,
            "severity": "blocker",
            "value": f"{operations.get('score', 0)}%",
            "detail": operations.get("status", ""),
        },
        {
            "name": "Broker reconciliation usable",
            "ready": reconciliation.get("status") in {"SYNCED", "PAPER_SAFE", "NO_POSITIONS"},
            "severity": "executor",
            "value": reconciliation.get("status", "UNKNOWN"),
            "detail": "Required for broker-submitted paper proof collection. Scan-only review, broker sync, journals, learning reports, and would-have-traded analysis remain available.",
        },
        {
            "name": "Risk guard stack active",
            "ready": risk_guards_ready,
            "severity": "blocker",
            "value": "ON" if risk_guards_ready else "INCOMPLETE",
            "detail": "Buying power, cash, PDT, duplicate, and day drawdown guards should be ON before paper testing.",
        },
        {
            "name": "Market data route ready",
            "ready": market_data_ready,
            "severity": "blocker",
            "value": "READY" if market_data_ready else "CHECK DATA",
            "detail": "Alpaca keys and market-data package must be available before scans.",
        },
        {
            "name": "Strict paper filters active",
            "ready": strict_filters_ready,
            "severity": "blocker",
            "value": f"score>={settings.get('PMO_WHY_NOT_MIN_SCORE')} RVOL>={settings.get('PMO_WHY_NOT_MIN_RVOL')}",
            "detail": "Weak proof state requires a tighter why-not gate.",
        },
        {
            "name": "Positive learning boosts paused",
            "ready": learning_safe,
            "severity": "blocker",
            "value": "PAUSED" if learning_safe else "REVIEW",
            "detail": proof_gate.get("reason", ""),
        },
        {
            "name": "Paper executor collection switches",
            "ready": paper_executor_switch_ready,
            "severity": "executor",
            "value": "READY" if paper_executor_switch_ready else "LOCKED",
            "detail": "Only needed when intentionally collecting PAPER_ALPACA submissions; scan/review can stay dry-run.",
        },
        {
            "name": "Paper proof target",
            "ready": bool(paper_proof.get("ready_to_unlock_live")),
            "severity": "proof",
            "value": f"{paper_proof.get('score', 0)}%",
            "detail": "; ".join(paper_proof.get("next_actions", [])[:2]) or paper_proof.get("recommendation", ""),
        },
        {
            "name": "v112 closed paper outcomes",
            "ready": bool(proof_gate.get("positive_allowed")),
            "severity": "proof",
            "value": f"{proof_gate.get('closed_outcomes', 0)}/{proof_gate.get('min_rows', 5)}",
            "detail": proof_gate.get("reason", ""),
        },
    ]
    blocker_checks = [row for row in checks if row.get("severity") == "blocker"]
    paper_scan_allowed = all(row.get("ready") for row in blocker_checks)
    would_have_traded_analysis_allowed = bool(paper_scan_allowed and paper_analysis_allowed_by_drawdown)
    paper_executor_collection_allowed = bool(paper_scan_allowed and paper_executor_switch_ready and order_drawdown_gate_clear and paper_funding_ready and broker_tradable)
    if not paper_scan_allowed:
        status = "FIX_PRE_SESSION_BLOCKERS"
        first_blocker = next((row for row in blocker_checks if not row.get("ready")), {})
        next_action = first_blocker.get("detail") or first_blocker.get("name") or "Fix pre-session blockers before scanning."
    elif not order_drawdown_gate_clear:
        status = "PAPER_ANALYSIS_READY / ORDER SUBMISSION LOCKED"
        next_action = "Scan-only review, journals, broker sync, learning reports, and would-have-traded analysis are allowed. New paper-order submissions remain locked by the drawdown gate."
    elif not paper_executor_collection_allowed:
        status = "PAPER_SCAN_READY / EXECUTOR COLLECTION LOCKED"
        first_executor_lock = next((row for row in checks if row.get("severity") == "executor" and not row.get("ready")), {})
        next_action = first_executor_lock.get("detail") or "Paper scan/review is allowed. Keep broker paper-order collection locked unless you intentionally switch to PAPER_ALPACA proof collection."
    else:
        status = "PAPER_EXECUTOR_COLLECTION_READY"
        next_action = "Paper-only scan and PAPER_ALPACA proof collection are ready; live trading remains locked."
    score = round((sum(1 for row in checks if row.get("ready")) / len(checks)) * 100, 2) if checks else 0
    payload = {
        "ok": True,
        "updated": now_et().isoformat(),
        "session_date": now_et().date().isoformat(),
        "status": status,
        "score": score,
        "paper_scan_allowed": paper_scan_allowed,
        "would_have_traded_analysis_allowed": would_have_traded_analysis_allowed,
        "order_drawdown_gate_clear": order_drawdown_gate_clear,
        "paper_executor_collection_allowed": paper_executor_collection_allowed,
        "live_trading_allowed": False,
        "research_only": True,
        "live_unlocked": False,
        "next_action": next_action,
        "checks": checks,
        "blockers": [row for row in checks if row.get("severity") == "blocker" and not row.get("ready")],
        "order_locks": [row for row in checks if row.get("severity") == "order_gate" and not row.get("ready")],
        "executor_locks": [row for row in checks if row.get("severity") == "executor" and not row.get("ready")],
        "proof_gaps": paper_proof.get("proof_gaps", []),
        "proof_next_actions": paper_proof.get("next_actions", []),
        "summary": {
            "day_pnl": account.get("day_pnl"),
            "day_pnl_percent": account.get("day_pnl_percent"),
            "drawdown_level": drawdown_governor.get("display_level") or drawdown_governor.get("level"),
            "operations_score": operations.get("score"),
            "paper_proof_score": paper_proof.get("score"),
            "paper_submissions": proof_metrics.get("paper_submissions", 0),
            "paper_submission_target": settings.get("PMO_MIN_PAPER_EXECUTOR_SUBMISSIONS", 100),
            "signal_approval_rate": proof_metrics.get("signal_approval_rate", 0),
            "why_not_ready": why_summary.get("ready", 0),
            "why_not_blocked": why_summary.get("blocked", 0),
            "v112_paper_replays": v112_proof.get("summary", {}).get("paper_replays", 0),
            "v112_win_rate": v112_proof.get("summary", {}).get("win_rate", 0),
            "positive_boosts_allowed": bool(proof_gate.get("positive_allowed")),
            "quantum_positive_boosts_allowed": bool(quantum_matrix.get("summary", {}).get("positive_boosts_allowed")),
        },
        "file": str(PMO_PRE_SESSION_CHECKLIST_FILE),
    }
    pmo_apply_pre_session_context(payload, settings, use_ai=use_ai_context)
    if record:
        PMO_PRE_SESSION_CHECKLIST_FILE.parent.mkdir(parents=True, exist_ok=True)
        PMO_PRE_SESSION_CHECKLIST_FILE.write_text(json.dumps(payload, indent=2), encoding="utf-8")
    return payload


def pmo_micro_mode_snapshot(
    settings: Dict[str, Any],
    account: Dict[str, Any],
    auto_watchlist: Dict[str, Any],
    v112_proof: Dict[str, Any],
    live_readiness: Dict[str, Any],
    broker_reconciliation: Dict[str, Any],
    positions: Optional[List[Dict[str, Any]]] = None,
    regime: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    drawdown = live_readiness.get("drawdown_governor", {}) if isinstance(live_readiness, dict) else {}
    proof_gate = pmo_positive_learning_gate(settings, v112_proof)
    summary = v112_proof.get("summary", {}) if isinstance(v112_proof.get("summary"), dict) else {}
    safe_watchlist = pmo_micro_safe_symbols(settings)
    active_watchlist = unique_symbols(settings.get("PMO_WATCHLIST", []), auto_watchlist.get("symbols", []), safe_watchlist)
    active_positions = []
    for position in positions or []:
        if safe_float(position.get("qty"), 0) or safe_float(position.get("market_value"), 0):
            active_positions.append(position)
    paper_funding_ready = bool(account.get("ok")) and (
        safe_float(account.get("equity") or account.get("portfolio_value"), 0) > 0
        or safe_float(account.get("buying_power"), 0) > 0
    )
    paper_analysis_allowed = bool(settings.get("PMO_MICRO_ALLOW_WOULD_HAVE_TRADED_ANALYSIS", True)) and bool(drawdown.get("paper_analysis_allowed", True))
    new_entries_allowed = bool(drawdown.get("new_entries_allowed", True)) and bool(proof_gate.get("positive_allowed")) and paper_funding_ready
    drawdown_level = drawdown.get("display_level") or drawdown.get("level", "NORMAL")
    decision = (
        "REVIEW_ONLY"
        if drawdown.get("force_review_only") or drawdown.get("order_submission_blocked")
        else "BROKER_FUNDING_REQUIRED"
        if not paper_funding_ready
        else "PROOF_WAIT"
        if not proof_gate.get("positive_allowed")
        else "PAPER_REVIEW_READY"
    )
    if drawdown.get("order_submission_blocked"):
        reason_short = "Drawdown order gate is active. Review and would-have-traded analysis stay available; new entries and live arming are blocked."
    elif drawdown.get("force_review_only"):
        reason_short = "Review-only drawdown stage active. New entries are blocked."
    elif not paper_funding_ready:
        reason_short = "Alpaca paper account has no usable buying power for proof collection."
    elif not proof_gate.get("positive_allowed"):
        reason_short = proof_gate.get("reason", "")
    else:
        reason_short = "Closed-paper proof gate is ready for paper review."
    return {
        "active": pmo_micro_mode_enabled(settings),
        "label": settings.get("PMO_MICRO_MODE_LABEL", "$200 PAPER MICRO MODE"),
        "account_size": safe_float(settings.get("PMO_MICRO_ACCOUNT_SIZE_USD", 200.0), 200.0),
        "equity": round(safe_float(account.get("equity")), 2),
        "buying_power": round(safe_float(account.get("buying_power")), 2),
        "day_pnl": round(safe_float(account.get("day_pnl")), 2),
        "day_pnl_percent": round(safe_float(account.get("day_pnl_percent")), 4),
        "drawdown_status": drawdown.get("status", "CLEAR"),
        "drawdown_level": drawdown_level,
        "drawdown_label": str(drawdown_level).replace("_", " "),
        "micro_stage": drawdown.get("micro_stage", "CLEAR"),
        "micro_loss_usd": drawdown.get("micro_loss_usd", 0),
        "micro_thresholds": drawdown.get("micro_thresholds", {}),
        "new_entries_allowed": new_entries_allowed,
        "paper_analysis_allowed": paper_analysis_allowed,
        "paper_funding_ready": paper_funding_ready,
        "live_master_allowed": False,
        "risk_budget": pmo_micro_risk_budget(settings),
        "max_daily_loss": safe_float(settings.get("PMO_MICRO_MAX_DAILY_LOSS_USD", 6.0), 6.0),
        "max_daily_trades": int(settings.get("PMO_MICRO_MAX_DAILY_TRADES", settings.get("PMO_MAX_DAILY_TRADES", 2))),
        "max_open_positions": int(settings.get("PMO_MICRO_MAX_OPEN_POSITIONS", 1)),
        "open_positions": active_positions,
        "open_position_count": len(active_positions),
        "active_watchlist": active_watchlist,
        "safe_watchlist": safe_watchlist,
        "blocked_symbols": sorted(pmo_micro_blocked_symbols(settings)),
        "broker_reconciliation": broker_reconciliation.get("status", "UNKNOWN") if isinstance(broker_reconciliation, dict) else "UNKNOWN",
        "market_regime": (regime or {}).get("regime", "UNKNOWN"),
        "win_rate": safe_float(summary.get("win_rate"), 0),
        "closed_paper_trades": int(safe_float(summary.get("closed_paper_trades", summary.get("wins", 0) + summary.get("losses", 0)), 0)),
        "min_closed_trades": int(summary.get("minimum_closed_trades_to_judge", settings.get("PMO_MICRO_MIN_CLOSED_TRADES_TO_JUDGE", 20))),
        "strong_validation_closed_trades": int(summary.get("strong_validation_closed_trades", settings.get("PMO_MICRO_MIN_CLOSED_TRADES_STRONG_VALIDATION", 50))),
        "win_rate_authority": summary.get("win_rate_authority", "CLOSED_PAPER_TRADES_ONLY"),
        "proof_gate": proof_gate,
        "decision": decision,
        "decision_label": str(decision).replace("_", " "),
        "reason": drawdown.get("detail") if drawdown.get("penalty_active") else reason_short,
        "reason_short": reason_short,
    }


def pmo_asi_default_memory() -> Dict[str, Any]:
    return {
        "ok": True,
        "version": "PMO_V113_ASI_LEARNING",
        "updated": "",
        "mode": "OBSERVE_ONLY",
        "summary": {
            "row_count": 0,
            "confidence": 0,
            "best_setup": "",
            "weakest_setup": "",
            "symbol_count": 0,
            "sector_count": 0,
        },
        "symbols": {},
        "top_symbols": [],
        "cooldowns": [],
        "sectors": [],
        "setups": [],
        "recommendations": [],
        "file": str(PMO_ASI_MEMORY_FILE),
    }


def load_pmo_asi_memory() -> Dict[str, Any]:
    if PMO_ASI_MEMORY_FILE.exists():
        try:
            data = json.loads(PMO_ASI_MEMORY_FILE.read_text(encoding="utf-8"))
            if isinstance(data, dict):
                base = pmo_asi_default_memory()
                base.update(data)
                base.setdefault("symbols", {})
                base.setdefault("top_symbols", [])
                base.setdefault("cooldowns", [])
                base.setdefault("sectors", [])
                base.setdefault("setups", [])
                base.setdefault("recommendations", [])
                return base
        except Exception:
            pass
    return pmo_asi_default_memory()


def save_pmo_asi_memory(memory: Dict[str, Any]) -> None:
    PMO_ASI_MEMORY_FILE.parent.mkdir(parents=True, exist_ok=True)
    PMO_ASI_MEMORY_FILE.write_text(json.dumps(memory, indent=2), encoding="utf-8")


def pmo_asi_signal_adjustment(symbol: str, settings: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    settings = settings or load_settings()
    clean = str(symbol or "").strip().upper()
    base = {
        "symbol": clean,
        "watchlist_adjustment": 0.0,
        "confidence": 0,
        "state": "NO_ASI",
        "note": "PMO ASI has not learned this symbol yet.",
    }
    if not clean or not settings.get("ENABLE_PMO_ASI_LEARNING", True):
        base["state"] = "OFF"
        base["note"] = "PMO ASI Learning is off."
        return base
    memory = load_pmo_asi_memory()
    row = memory.get("symbols", {}).get(clean)
    if not isinstance(row, dict):
        return base
    min_rows = int(settings.get("PMO_MICRO_MIN_CLOSED_TRADES_TO_JUDGE", settings.get("PMO_ASI_MIN_ROWS_TO_APPLY", 20))) if pmo_micro_mode_enabled(settings) else int(settings.get("PMO_ASI_MIN_ROWS_TO_APPLY", 5))
    if settings.get("PMO_ASI_REQUIRE_V112_PROOF", True) and int(memory.get("summary", {}).get("row_count", 0)) < min_rows:
        return {
            **base,
            "confidence": int(memory.get("summary", {}).get("confidence", 0)),
            "state": "WAIT_FOR_PROOF",
            "note": f"PMO ASI waiting for at least {min_rows} v112 proof rows.",
        }
    adjustment = safe_float(row.get("watchlist_adjustment"), 0)
    max_boost = safe_float(settings.get("PMO_ASI_MAX_SCORE_BOOST", 5.0), 5.0)
    adjustment = round(max(-max_boost, min(max_boost, adjustment)), 3)
    state = row.get("state", "WATCH")
    note = row.get("note", "PMO ASI paper-proof adjustment.")
    proof_gate = pmo_positive_learning_gate(settings, memory.get("proof_report", {}))
    if adjustment > 0 and not proof_gate.get("positive_allowed"):
        adjustment = 0.0
        state = "WAIT_FOR_PROOF" if state == "BOOST" else state
        note = f"{note} Positive ASI boost paused: {proof_gate.get('reason')}."
    if not settings.get("PMO_ASI_ALLOW_LIVE_INFLUENCE", False):
        note = f"{note} Live influence locked."
    return {
        "symbol": clean,
        "watchlist_adjustment": adjustment,
        "confidence": row.get("confidence", memory.get("summary", {}).get("confidence", 0)),
        "state": state,
        "note": note,
        "positive_learning_gate": proof_gate,
    }


def pmo_asi_signal_adjustment_v2(symbol: str, settings: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    settings = settings or load_settings()
    clean = str(symbol or "").strip().upper()
    rule_result = pmo_asi_signal_adjustment(clean, settings)
    if not bool(settings.get("PMO_ASI_AI_INFERENCE", False)):
        return rule_result
    if not first_env("ANTHROPIC_API_KEY", "PMO_ANTHROPIC_API_KEY", "CLAUDE_API_KEY"):
        return rule_result

    memory = load_pmo_asi_memory()
    symbol_data = memory.get("symbols", {}).get(clean)
    if not isinstance(symbol_data, dict):
        return rule_result
    min_rows = int(settings.get("PMO_MICRO_MIN_CLOSED_TRADES_TO_JUDGE", settings.get("PMO_ASI_MIN_ROWS_TO_APPLY", 30))) if pmo_micro_mode_enabled(settings) else int(settings.get("PMO_ASI_MIN_ROWS_TO_APPLY", 30))
    row_count = int(safe_float(memory.get("summary", {}).get("row_count", 0), 0))
    if row_count < min_rows:
        return rule_result

    try:
        system_prompt = (
            "You are PMO ASI, an adaptive paper-trade signal intelligence layer. "
            "Recommend a conservative watchlist adjustment from -5.0 to +5.0. "
            "Only boost with strong paper-proof evidence. Never suggest bypassing safety gates. Return JSON only."
        )
        user_prompt = (
            f"Symbol: {clean}\n"
            f"Rule result: {json.dumps(rule_result, default=str)[:2500]}\n"
            f"Symbol ASI memory: {json.dumps(symbol_data, default=str)[:2500]}\n"
            f"ASI summary: {json.dumps(memory.get('summary', {}), default=str)[:1500]}\n\n"
            'Return JSON: {"adjustment": 0, "confidence": 0, '
            '"state": "BOOST|WATCH|PENALIZE|WAIT_FOR_PROOF", "reasoning": "one sentence"}'
        )
        ai = pmo_claude_call(system_prompt, user_prompt, max_tokens=220, expect_json=True, settings=settings)
        parsed = ai.get("parsed") if ai.get("ok") else {}
        if not isinstance(parsed, dict) or not parsed:
            return {**rule_result, "ai_provider": "rule_based_fallback", "ai_error": ai.get("error", "Claude unavailable")}
        max_boost = safe_float(settings.get("PMO_ASI_MAX_SCORE_BOOST", 5.0), 5.0)
        adjustment = round(max(-max_boost, min(max_boost, safe_float(parsed.get("adjustment"), 0))), 3)
        proof_gate = pmo_positive_learning_gate(settings, memory.get("proof_report", {}))
        if adjustment > 0 and not proof_gate.get("positive_allowed"):
            adjustment = 0.0
        return {
            **rule_result,
            "watchlist_adjustment": adjustment,
            "confidence": int(max(0, min(100, safe_float(parsed.get("confidence"), 50)))),
            "state": str(parsed.get("state") or rule_result.get("state", "WATCH")),
            "note": f"{parsed.get('reasoning', 'Claude ASI inference completed.')} [Claude ASI]",
            "ai_provider": "claude",
            "rule_based_adjustment": rule_result.get("watchlist_adjustment", 0),
            "positive_learning_gate": proof_gate,
        }
    except Exception as exc:
        return {**rule_result, "ai_provider": "rule_based_fallback", "ai_error": str(exc)[:120]}


def pmo_asi_learning_report(settings: Optional[Dict[str, Any]] = None, record: bool = True) -> Dict[str, Any]:
    settings = settings or load_settings()
    mode = str(settings.get("PMO_ASI_MODE", "OBSERVE_ONLY"))
    if not settings.get("ENABLE_PMO_ASI_LEARNING", True):
        memory = pmo_asi_default_memory()
        memory.update({
            "ok": False,
            "updated": now_et().isoformat(),
            "mode": mode,
            "summary": {"row_count": 0, "confidence": 0, "best_setup": "", "weakest_setup": "", "symbol_count": 0, "sector_count": 0, "reason": "PMO ASI Learning is disabled."},
        })
        return memory
    rows = pmo_v112_load_journal()
    max_boost = safe_float(settings.get("PMO_ASI_MAX_SCORE_BOOST", 5.0), 5.0)
    min_rows = int(settings.get("PMO_MICRO_MIN_CLOSED_TRADES_TO_JUDGE", settings.get("PMO_ASI_MIN_ROWS_TO_APPLY", 20))) if pmo_micro_mode_enabled(settings) else int(settings.get("PMO_ASI_MIN_ROWS_TO_APPLY", 5))
    symbol_buckets: Dict[str, Dict[str, Any]] = {}
    sector_buckets: Dict[str, Dict[str, Any]] = {}
    setup_buckets: Dict[str, Dict[str, Any]] = {}

    def bucket_for(target: Dict[str, Dict[str, Any]], key: str) -> Dict[str, Any]:
        clean_key = key or "UNKNOWN"
        return target.setdefault(clean_key, {
            "name": clean_key,
            "rows": 0,
            "wins": 0,
            "losses": 0,
            "open": 0,
            "good_blocks": 0,
            "missed": 0,
            "pnl_values": [],
            "avg_pnl": 0.0,
            "score": 0.0,
        })

    for row in rows:
        symbol = str(row.get("symbol", "")).strip().upper()
        if not symbol or symbol == "-":
            continue
        sector = pmo_sector_for_symbol(symbol)
        setup = " | ".join([
            str(row.get("replay_type") or "PAPER"),
            str(row.get("direction") or "LONG"),
            str(row.get("bias") or "BIAS"),
            str(row.get("readiness") or "READINESS"),
        ])
        quality = str(row.get("quality", "")).upper()
        pnl = safe_float(row.get("pnl_pct"), 0)
        for bucket in (bucket_for(symbol_buckets, symbol), bucket_for(sector_buckets, sector), bucket_for(setup_buckets, setup)):
            bucket["rows"] += 1
            bucket["pnl_values"].append(pnl)
            if quality == "WIN":
                bucket["wins"] += 1
            elif quality == "LOSS":
                bucket["losses"] += 1
            elif quality == "GOOD_BLOCK":
                bucket["good_blocks"] += 1
            elif quality == "MISSED":
                bucket["missed"] += 1
            else:
                bucket["open"] += 1

    def finalize_bucket(bucket: Dict[str, Any]) -> Dict[str, Any]:
        vals = bucket.pop("pnl_values", [])
        avg_pnl = round(sum(vals) / len(vals), 3) if vals else 0.0
        proof_score = round(
            (bucket["wins"] * 2.0)
            - (bucket["losses"] * 2.25)
            + (bucket["good_blocks"] * 1.2)
            - (bucket["missed"] * 1.75)
            + (avg_pnl * 0.35),
            3,
        )
        bucket["avg_pnl"] = avg_pnl
        bucket["score"] = proof_score
        bucket["win_rate"] = round(bucket["wins"] / max(1, bucket["wins"] + bucket["losses"]), 3)
        bucket["blocked_quality"] = round(bucket["good_blocks"] / max(1, bucket["good_blocks"] + bucket["missed"]), 3)
        return bucket

    symbol_rows = [finalize_bucket(dict(bucket)) for bucket in symbol_buckets.values()]
    sector_rows = [finalize_bucket(dict(bucket)) for bucket in sector_buckets.values()]
    setup_rows = [finalize_bucket(dict(bucket)) for bucket in setup_buckets.values()]
    symbol_rows.sort(key=lambda item: item.get("score", 0), reverse=True)
    sector_rows.sort(key=lambda item: item.get("score", 0), reverse=True)
    setup_rows.sort(key=lambda item: item.get("score", 0), reverse=True)

    symbols: Dict[str, Dict[str, Any]] = {}
    for item in symbol_rows:
        raw_adj = item.get("score", 0) / 2.0
        if settings.get("PMO_ASI_COOLDOWN_LOSERS", True) and item.get("losses", 0) > item.get("wins", 0):
            raw_adj -= 1.5
        adjustment = round(max(-max_boost, min(max_boost, raw_adj)), 3)
        state = "BOOST" if adjustment >= 0.75 else "COOLDOWN" if adjustment <= -0.75 else "WATCH"
        symbols[item["name"]] = {
            "symbol": item["name"],
            "watchlist_adjustment": adjustment,
            "state": state,
            "confidence": min(100, 35 + item.get("rows", 0) * 8),
            "wins": item.get("wins", 0),
            "losses": item.get("losses", 0),
            "good_blocks": item.get("good_blocks", 0),
            "missed": item.get("missed", 0),
            "avg_pnl": item.get("avg_pnl", 0),
            "note": f"ASI {state}: {item.get('wins',0)}W/{item.get('losses',0)}L, avg {item.get('avg_pnl',0)}%, block quality {item.get('blocked_quality',0):.2%}.",
        }
    best_setup = setup_rows[0]["name"] if setup_rows else ""
    weakest_setup = setup_rows[-1]["name"] if setup_rows else ""
    confidence = min(100, int((len(rows) / max(1, min_rows)) * 40) + min(40, len(symbol_rows) * 4))
    recommendations: List[str] = []
    proof = pmo_v112_proof_report(settings, record=False)
    positive_learning_gate = pmo_positive_learning_gate(settings, proof)
    win_rate = safe_float(proof.get("summary", {}).get("win_rate"), 0)
    blocked_quality = safe_float(proof.get("summary", {}).get("blocked_quality"), 0)
    if len(rows) < min_rows:
        recommendations.append(f"Collect at least {min_rows} v112 proof rows before applying ASI adjustments.")
    if win_rate < safe_float(settings.get("PMO_V112_MIN_PROOF_WIN_RATE", 0.5), 0.5):
        recommendations.append("Raise PMO_WHY_NOT_MIN_SCORE or require stronger RVOL until paper win rate improves.")
    if blocked_quality < safe_float(settings.get("PMO_V112_BLOCKED_QUALITY_MIN", 0.6), 0.6):
        recommendations.append("Review missed blocked trades; current blockers may be too strict for some setups.")
    if sector_rows:
        recommendations.append(f"Watch strongest ASI sector: {sector_rows[0]['name']} ({sector_rows[0]['score']}).")
    cooldowns = [row for row in symbols.values() if row.get("state") == "COOLDOWN"]
    if cooldowns:
        recommendations.append(f"Cooldown {len(cooldowns)} symbol(s) with weak paper proof.")
    if not positive_learning_gate.get("positive_allowed"):
        recommendations.append(f"Positive ASI/learning boosts paused: {positive_learning_gate.get('reason')}.")
    if not recommendations:
        recommendations.append("ASI memory is balanced. Keep collecting paper proof before expanding influence.")
    memory = {
        "ok": True,
        "version": "PMO_V113_ASI_LEARNING",
        "updated": now_et().isoformat(),
        "mode": mode,
        "live_influence": bool(settings.get("PMO_ASI_ALLOW_LIVE_INFLUENCE", False)),
        "paper_safe_note": "ASI is paper/review focused. It cannot arm live trading or place orders.",
        "summary": {
            "row_count": len(rows),
            "confidence": confidence,
            "best_setup": best_setup,
            "weakest_setup": weakest_setup,
            "symbol_count": len(symbols),
            "sector_count": len(sector_rows),
            "boost_count": sum(1 for row in symbols.values() if row.get("state") == "BOOST"),
            "cooldown_count": len(cooldowns),
            "win_rate": win_rate,
            "blocked_quality": blocked_quality,
            "positive_boosts_allowed": bool(positive_learning_gate.get("positive_allowed")),
        },
        "symbols": symbols,
        "top_symbols": list(symbols.values())[:12],
        "cooldowns": cooldowns[:12],
        "sectors": sector_rows[:12],
        "setups": setup_rows[:12],
        "recommendations": recommendations,
        "positive_learning_gate": positive_learning_gate,
        "proof_report": {
            "proof_score": proof.get("proof_score", 0),
            "status": proof.get("status", ""),
            "summary": proof.get("summary", {}),
        },
        "file": str(PMO_ASI_MEMORY_FILE),
    }
    if record:
        save_pmo_asi_memory(memory)
        csv_append(PMO_ASI_EVENTS_FILE, {
            "timestamp": memory["updated"],
            "row_count": len(rows),
            "confidence": confidence,
            "boost_count": memory["summary"]["boost_count"],
            "cooldown_count": memory["summary"]["cooldown_count"],
            "best_setup": best_setup,
            "weakest_setup": weakest_setup,
            "recommendation": " | ".join(recommendations[:3]),
        })
    return memory


def pmo_asi_apply_to_watchlist(settings: Dict[str, Any]) -> Dict[str, Any]:
    report = pmo_asi_learning_report(settings, record=True)
    auto_watchlist = load_auto_watchlist()
    if not auto_watchlist.get("ok") and not auto_watchlist.get("selected"):
        return {"ok": False, "message": "Auto watchlist is empty. Build the watchlist before applying ASI.", "asi_report": report}
    min_rows = int(settings.get("PMO_MICRO_MIN_CLOSED_TRADES_TO_JUDGE", settings.get("PMO_ASI_MIN_ROWS_TO_APPLY", 20))) if pmo_micro_mode_enabled(settings) else int(settings.get("PMO_ASI_MIN_ROWS_TO_APPLY", 5))
    if settings.get("PMO_ASI_REQUIRE_V112_PROOF", True) and int(report.get("summary", {}).get("row_count", 0)) < min_rows:
        return {"ok": False, "message": "ASI needs more v112 proof rows before applying watchlist adjustments.", "asi_report": report}
    positive_gate = report.get("positive_learning_gate", {})
    symbols = report.get("symbols", {})

    def adjust_row(row: Dict[str, Any]) -> Dict[str, Any]:
        symbol = str(row.get("symbol", "")).upper()
        learned = symbols.get(symbol, {})
        adjustment = safe_float(learned.get("watchlist_adjustment"), 0)
        if adjustment > 0 and not positive_gate.get("positive_allowed"):
            adjustment = 0.0
        base_score = safe_float(row.get("score"), 0)
        row["asi_adjustment"] = adjustment
        row["asi_adjusted_score"] = round(max(0, min(100, base_score + adjustment)), 2)
        row["asi_state"] = learned.get("state", "NO_ASI")
        row["asi_note"] = learned.get("note", "No ASI paper-proof adjustment.")
        return row

    scored = [adjust_row(dict(row)) for row in auto_watchlist.get("scored", [])]
    selected = [adjust_row(dict(row)) for row in auto_watchlist.get("selected", [])]
    selected.sort(key=lambda row: safe_float(row.get("asi_adjusted_score"), safe_float(row.get("score"), 0)), reverse=True)
    scored.sort(key=lambda row: safe_float(row.get("asi_adjusted_score"), safe_float(row.get("score"), 0)), reverse=True)
    auto_watchlist["scored"] = scored
    auto_watchlist["selected"] = selected
    auto_watchlist["symbols"] = [row.get("symbol") for row in selected if row.get("symbol")]
    auto_watchlist["asi_applied_at"] = now_et().isoformat()
    auto_watchlist["asi_mode"] = settings.get("PMO_ASI_MODE")
    auto_watchlist["asi_positive_boosts_allowed"] = bool(positive_gate.get("positive_allowed"))
    auto_watchlist["asi_note"] = "Paper-safe ASI adjustments applied to watchlist scores only. Positive boosts stay paused until v112 paper proof improves. Live trading remains locked by master gates."
    AUTO_WATCHLIST_FILE.write_text(json.dumps(auto_watchlist, indent=2), encoding="utf-8")
    for row in selected[:25]:
        csv_append(PMO_ASI_APPLIED_FILE, {
            "timestamp": auto_watchlist["asi_applied_at"],
            "symbol": row.get("symbol"),
            "base_score": row.get("score"),
            "asi_adjustment": row.get("asi_adjustment"),
            "asi_adjusted_score": row.get("asi_adjusted_score"),
            "asi_state": row.get("asi_state"),
            "asi_note": row.get("asi_note"),
        })
    return {
        "ok": True,
        "applied": len(selected),
        "auto_watchlist": auto_watchlist,
        "asi_report": report,
        "positive_learning_gate": positive_gate,
        "applied_file": str(PMO_ASI_APPLIED_FILE),
    }


def signal_decision_timeline(
    auto_watchlist: Dict[str, Any],
    settings: Dict[str, Any],
    regime: Dict[str, Any],
    account: Optional[Dict[str, Any]] = None,
    health: Optional[Dict[str, Any]] = None,
    live_readiness: Optional[Dict[str, Any]] = None,
    executor: Optional[Dict[str, Any]] = None,
    reconciliation: Optional[Dict[str, Any]] = None,
    paper_proof: Optional[Dict[str, Any]] = None,
) -> List[Dict[str, Any]]:
    rows: List[Dict[str, Any]] = []
    for row in auto_watchlist.get("selected", [])[:20]:
        why = pmo_why_not_for_row(row, settings, regime, account, health, live_readiness, executor, reconciliation, paper_proof)
        rows.append({
            "time": why.get("time", ""),
            "symbol": why.get("symbol", ""),
            "score": why.get("score", ""),
            "bias": why.get("bias", ""),
            "readiness": why.get("readiness", ""),
            "decision": why.get("decision", ""),
            "why": why.get("why", ""),
            "next_action": why.get("next_action", ""),
            "blocker_count": len(why.get("blockers", [])),
            "warning_count": len(why.get("warnings", [])),
        })
    return rows or [{
        "time": now_et().isoformat(),
        "symbol": "-",
        "score": "-",
        "bias": "WAIT",
        "readiness": "WAIT",
        "decision": "NO SIGNALS",
        "why": "Run Auto Build Watchlist to create PMO decisions.",
        "next_action": "Run Auto Build Watchlist.",
        "blocker_count": 1,
        "warning_count": 0,
    }]


def trade_replay_rows(auto_watchlist: Dict[str, Any], settings: Dict[str, Any], account: Optional[Dict[str, Any]] = None) -> List[Dict[str, Any]]:
    rows: List[Dict[str, Any]] = []
    account = account or {}
    automation_locked = not all([
        settings.get("PMO_LIVE_TRADING_ENABLED"),
        settings.get("PMO_ALLOW_LIVE_TRADING"),
        settings.get("ORDER_AUTOMATION_ENABLED"),
        not settings.get("PMO_DRY_RUN_ORDERS"),
    ])
    for row in auto_watchlist.get("selected", [])[:15]:
        symbol = str(row.get("symbol", "")).strip().upper()
        drawdown_governor = pmo_day_drawdown_governor(settings, account, symbol=symbol, action="PAPER_ANALYSIS", record=False)
        readiness = calls_puts_readiness(row, settings)
        order_gate_locked = bool(drawdown_governor.get("order_submission_blocked") or drawdown_governor.get("session_frozen"))
        throttled_by_drawdown = (
            readiness in {"CALL READY", "PUT READY"}
            and drawdown_governor.get("penalty_active")
            and not pmo_drawdown_signal_allowed(symbol, row.get("score"), settings, drawdown_governor)
        )
        if order_gate_locked and readiness == "CALL READY":
            paper_action = "WOULD-HAVE-TRADED CALL / ORDER GATE"
        elif order_gate_locked and readiness == "PUT READY":
            paper_action = "WOULD-HAVE-TRADED PUT / ORDER GATE"
        elif order_gate_locked:
            paper_action = "ORDER GATE / REVIEW"
        elif drawdown_governor.get("force_review_only"):
            paper_action = "REVIEW ONLY"
        elif drawdown_governor.get("symbol_blocked"):
            paper_action = "NO TRADE"
        elif throttled_by_drawdown:
            paper_action = "THROTTLED / REVIEW"
        elif readiness == "CALL READY":
            paper_action = "PAPER CALL / LONG TEST"
        elif readiness == "PUT READY":
            paper_action = "PAPER PUT / SHORT TEST"
        elif readiness == "WATCH":
            paper_action = "WATCH ONLY"
        else:
            paper_action = "NO TRADE"
        rows.append({
            "symbol": row.get("symbol", ""),
            "paper_action": paper_action,
            "score": row.get("score", ""),
            "bias": row.get("bias", ""),
            "entry_logic": "trend + score + relative volume + PMO gate confirmation",
            "risk_logic": "day drawdown governor, max loss model, buying power guard, duplicate guard, PDT guard",
            "order_state": "LOCKED" if automation_locked else "LIVE GATED",
            "reason": drawdown_governor.get("detail") if drawdown_governor.get("penalty_active") else row.get("reason", ""),
        })
    return rows or [{
        "symbol": "-",
        "paper_action": "NO REPLAY",
        "score": "-",
        "bias": "WAIT",
        "entry_logic": "No symbols selected.",
        "risk_logic": "PMO remains paper-safe.",
        "order_state": "LOCKED",
        "reason": "Run Auto Build Watchlist first.",
    }]


def connection_map_rows(health: Dict[str, Any]) -> List[Dict[str, Any]]:
    rows = []
    for item in health.get("connections", []):
        status = "ONLINE" if item.get("online") else "OFFLINE"
        action = "No action needed." if item.get("online") else "Check credentials, process, URL, or local file path."
        rows.append({
            "node": item.get("name", ""),
            "direction": item.get("direction", "local"),
            "status": status,
            "detail": item.get("detail", ""),
            "action": action,
        })
    return rows


def watchlist_lab_rows(settings: Dict[str, Any], auto_watchlist: Dict[str, Any]) -> List[Dict[str, Any]]:
    lookup = auto_watchlist_lookup(auto_watchlist)
    rows = []
    for symbol in unique_symbols(auto_watchlist.get("symbols", []), settings.get("PMO_WATCHLIST", []), pmo_market_universe(settings))[:100]:
        data = lookup.get(symbol, {})
        rows.append({
            "symbol": symbol,
            "market": data.get("market", detect_market(symbol, "AUTO")),
            "sector": pmo_sector_for_symbol(symbol),
            "score": data.get("score", ""),
            "bias": data.get("bias", "PENDING"),
            "price": data.get("price", ""),
            "move": data.get("change_pct", ""),
            "rvol": data.get("relative_volume", ""),
            "trend": "UP" if safe_float(data.get("change_pct")) > 0 else "DOWN" if data else "PENDING",
            "calls_puts": calls_puts_readiness(data, settings) if data else "PENDING",
            "state": "AUTO SELECTED" if symbol in auto_watchlist.get("symbols", []) else "UNIVERSE",
        })
    return rows


def latest_system_review() -> Dict[str, Any]:
    if not SYSTEM_REVIEW_FILE.exists():
        return {"ok": False, "report_text": "No PMO BOT system review has run yet.", "score": None}
    try:
        data = json.loads(SYSTEM_REVIEW_FILE.read_text(encoding="utf-8"))
        return data if isinstance(data, dict) else {"ok": False, "report_text": "System review file is not readable.", "score": None}
    except Exception as exc:
        return {"ok": False, "report_text": f"System review file error: {exc}", "score": None}


def list_code_inventory() -> Dict[str, Any]:
    py_files = list(PMO_DIR.glob("*.py"))
    bat_files = list(PMO_ROOT.glob("*.bat")) + list(PMO_DIR.glob("*.bat"))
    pine_files = list(PMO_ROOT.glob("*.pine")) + list(PMO_DIR.glob("*.pine")) + list(PINE_DIR.glob("*.pine"))
    return {
        "python_files": len(py_files),
        "bat_files": len(bat_files),
        "pine_files": len(pine_files),
        "pmo_bot_size": (PMO_DIR / "pmo_bot.py").stat().st_size if (PMO_DIR / "pmo_bot.py").exists() else 0,
    }


def run_system_review_scan(command_text: str = "", use_ai: bool = False) -> Dict[str, Any]:
    settings = load_settings()
    bot.settings = settings
    account = bot.account_snapshot()
    health = bot.connection_check()
    regime = pmo_market_regime_snapshot(bot, fresh=True)
    auto_watchlist = load_auto_watchlist()
    inventory = list_code_inventory()
    positions = open_positions()
    score = 100
    strongest: List[str] = []
    weakest: List[str] = []
    critical: List[str] = []
    risk_problems: List[str] = []
    trading_tightening: List[str] = []
    cleanup: List[str] = []
    fixes: List[str] = []

    if account.get("ok"):
        strongest.append("Alpaca broker account is reachable and returning equity, buying power, and status.")
    else:
        score -= 22
        critical.append(f"Alpaca broker account is not reachable: {account.get('error')}")

    online_ratio = (health.get("online", 0) / health.get("total", 1)) if health.get("total") else 0
    if online_ratio >= 0.8:
        strongest.append(f"Incoming/outgoing connection layer is mostly online: {health.get('online')}/{health.get('total')}.")
    else:
        score -= 12
        weakest.append(f"Connection layer is weak: {health.get('online')}/{health.get('total')} online.")

    offline_connections = [item for item in health.get("connections", []) if not item.get("online")]
    if offline_connections:
        score -= min(14, len(offline_connections) * 2)
        for item in offline_connections[:5]:
            weakest.append(f"{item.get('name')} is offline or incomplete: {item.get('detail')}")

    safety_switches = [
        ("ENABLE_BUYING_POWER_GUARD", "Buying power guard"),
        ("ENABLE_CASH_LOCKOUT", "Cash lockout"),
        ("ENABLE_PDT_PROTECTION_AI", "PDT protection"),
        ("BLOCK_ORDERS_WHEN_PDT_RESTRICTED", "PDT order block"),
        ("ENABLE_PMO_DUPLICATE_PHASE_GUARD", "Duplicate phase guard"),
        ("ENABLE_PHASE95_3_DUPLICATE_NO_TRADE_SUPPRESSION", "Duplicate no-trade suppression"),
        ("ENABLE_PMO_SECTOR_TRADE_LIMITS", "Sector trade limits"),
    ]
    for key, label in safety_switches:
        if settings.get(key):
            strongest.append(f"{label} is enabled.")
        else:
            score -= 7
            risk_problems.append(f"{label} is disabled.")

    if settings.get("PMO_LIVE_TRADING_ENABLED") and settings.get("PMO_DRY_RUN_ORDERS"):
        score -= 14
        critical.append("Live master is enabled while dry-run orders are still enabled. That is a live-mode conflict.")
    if settings.get("ORDER_AUTOMATION_ENABLED") and not settings.get("PMO_LIVE_TRADING_ENABLED"):
        score -= 10
        critical.append("Order automation is enabled while PMO live master is not armed.")
    if not settings.get("ORDER_AUTOMATION_ENABLED"):
        weakest.append("Order automation is disabled, which is safe for demo but not live-execution ready.")
    if settings.get("TRADINGVIEW_WEBHOOK_SECRET") == "CHANGE_ME_SECRET":
        score -= 6
        risk_problems.append("TradingView webhook secret is still the default value.")
    if settings.get("TRADINGVIEW_ALERT_MODE") != "TRADE_SIGNAL":
        trading_tightening.append("TradingView is in SCAN_ONLY mode, so alerts will not become trade signals.")
    if settings.get("OPTIONS_ORDER_ENABLED") and settings.get("OPTIONS_EXECUTION_MODE") == "LIVE_OPTIONS":
        strongest.append("Options execution mode is configured for live options.")
    else:
        trading_tightening.append("Options/calls/puts logic is currently signal-first, not live options execution.")

    if auto_watchlist.get("symbols"):
        strongest.append(f"PMO Auto Watchlist AI has {len(auto_watchlist.get('symbols', []))} active symbols from its latest scan.")
    else:
        score -= 6
        weakest.append("Auto Watchlist AI has not generated a saved symbol list yet.")
        fixes.append("Run Auto Build Watchlist so PMO ranks symbols from live data before scanning.")

    if regime.get("regime") == "UNKNOWN":
        score -= 5
        trading_tightening.append(f"Market regime is UNKNOWN: {regime.get('reason')}")
    else:
        strongest.append(f"Market regime is returning {regime.get('regime')} with risk multiplier {regime.get('risk_multiplier')}x.")

    if inventory["pmo_bot_size"] > 250_000:
        cleanup.append("pmo_bot.py is large enough that engines should be split into modules.")
    else:
        cleanup.append("Keep pmo_bot.py organized by engine sections as more phases are restored.")
    if inventory["pine_files"] == 0:
        score -= 4
        cleanup.append("No Pine files detected; TradingView signal source needs a Pine script.")
    else:
        strongest.append(f"{inventory['pine_files']} Pine file(s) are available for TradingView.")

    if not latest_system_review().get("ok"):
        cleanup.append("No previous system review existed before this scan.")
    if not positions:
        strongest.append("No open Alpaca positions were returned, reducing immediate unmanaged-position risk.")

    trading_tightening.extend([
        "Sniper entries should require trend, volume, liquidity, regime, and duplicate-signal agreement before approval.",
        "Stop-loss, take-profit, and trailing-stop rules should be written to the trade journal for every approved alert.",
        "News protection should block fresh entries during high-risk headline windows or unknown source-bias states.",
    ])
    fixes.extend([
        "Use one decision bus per scan cycle so Phase 130/135/150 decisions are cached and not recomputed inside loops.",
        "Require live market data success before any trade approval can move past PMO risk gates.",
        "Keep live trading locked until paper logs prove no duplicate orders, no bad webhook retries, and no missing exits.",
        "Persist every rejected trade with the exact failed gate so false signals and missed entries can be tuned.",
    ])

    score = int(max(1, min(100, round(score))))
    if score >= 88 and not settings.get("PMO_LIVE_TRADING_ENABLED"):
        recommendation = "Ready for demo and paper/live-data testing. More paper validation is required before live orders."
    elif score >= 88:
        recommendation = "Ready for controlled live testing only if order size, kill switches, and duplicate-order logs are verified."
    elif score >= 75:
        recommendation = "Ready for demo, but more development is needed before live trading."
    else:
        recommendation = "More development required before demo or live testing."

    strongest_lines = [f"- {item}" for item in strongest[:12]] or ["- No strong areas detected by this scan."]
    weakest_lines = [f"- {item}" for item in weakest[:12]] or ["- No major weak areas detected by this scan."]
    critical_lines = [f"- {item}" for item in critical[:12]] or ["- No critical live-order logic conflict detected by this scan."]
    risk_lines = [f"- {item}" for item in risk_problems[:12]] or ["- Core risk switches are enabled."]
    tighten_lines = [f"- {item}" for item in trading_tightening[:12]] or ["- No immediate tightening item detected."]
    cleanup_lines = [f"- {item}" for item in cleanup[:12]] or ["- No cleanup item detected."]
    fix_lines = [f"- {item}" for item in fixes[:12]] or ["- No immediate fix item detected."]
    report_lines = [
        "PMO BOT SYSTEM REVIEW AND OPTIMIZATION SCAN",
        f"Updated: {now_et().isoformat()}",
        "",
        f"1. PMO BOT health score: {score}/100",
        "",
        "2. Strongest parts of the bot:",
        *strongest_lines,
        "",
        "3. Weakest parts of the bot:",
        *weakest_lines,
        "",
        "4. Critical bugs or logic conflicts:",
        *critical_lines,
        "",
        "5. Risk management problems:",
        *risk_lines,
        "",
        "6. Trading logic that needs to be tightened:",
        *tighten_lines,
        "",
        "7. Code sections that need cleanup:",
        *cleanup_lines,
        "",
        "8. Best fixes to improve live trading performance:",
        *fix_lines,
        "",
        "9. Final recommendation:",
        f"- {recommendation}",
    ]
    payload = {
        "ok": True,
        "score": score,
        "grade": pmo_letter_grade(score),
        "updated": now_et().isoformat(),
        "prompt": command_text or SYSTEM_REVIEW_PROMPT,
        "headline": recommendation,
        "research_only": True,
        "live_unlocked": False,
        "strongest": strongest,
        "weakest": weakest,
        "critical": critical,
        "critical_problems": critical,
        "risk_problems": risk_problems,
        "trading_tightening": trading_tightening,
        "cleanup": cleanup,
        "fixes": fixes,
        "prioritized_fix_list": fixes[:8],
        "recommendation": recommendation,
        "report_text": "\n".join(report_lines),
        "ai_assisted": False,
        "ai_provider": "rule_based",
        "ai_error": "",
    }
    if use_ai and bool(settings.get("PMO_AI_SYSTEM_REVIEW_ENABLED", True)):
        context = pmo_ai_research_context(settings, health=health, regime=regime, account=account, limit=16)
        context["system_review_rule_based"] = {
            "score": score,
            "grade": payload["grade"],
            "strongest": strongest[:10],
            "weakest": weakest[:10],
            "critical": critical[:10],
            "risk_problems": risk_problems[:10],
            "fixes": fixes[:10],
            "code_inventory": inventory,
            "open_positions": len(positions),
        }
        if pmo_ai_provider_ready(settings):
            ai = pmo_claude_call(
                "You are PMO Bot's senior reliability and trading-safety reviewer. Return JSON only. "
                "Grade the system honestly from A to F. Never recommend live unlocks.",
                "Return JSON with keys: grade, headline, critical_problems, working_well, prioritized_fix_list, "
                "safety_problems, trading_logic_problems, dashboard_problems, final_readiness_score, rationale. "
                "PMO context:\n" + json.dumps(context, default=str, indent=2),
                int(safe_float(settings.get("PMO_AI_AUDIT_MAX_TOKENS", PMO_AI_AUDIT_MAX_TOKENS), PMO_AI_AUDIT_MAX_TOKENS)),
                expect_json=True,
                settings=settings,
            )
            if ai.get("ok") and isinstance(ai.get("parsed"), dict):
                pmo_merge_ai_research_fields(
                    payload,
                    ai.get("parsed", {}),
                    [
                        "grade", "headline", "critical_problems", "working_well", "prioritized_fix_list",
                        "safety_problems", "trading_logic_problems", "dashboard_problems",
                        "final_readiness_score", "rationale",
                    ],
                )
                payload.update({"ai_assisted": True, "ai_provider": "claude", "ai_model": ai.get("model", PMO_AI_MODEL), "ai_usage": ai.get("usage", {})})
            else:
                payload["ai_error"] = ai.get("error", "Claude system review unavailable")
        else:
            payload["ai_error"] = "Claude provider not ready; using rule-based system review."
    SYSTEM_REVIEW_FILE.write_text(json.dumps(payload, indent=2), encoding="utf-8")
    return payload


def build_live_data_snapshot() -> Dict[str, Any]:
    settings = load_settings()
    account = bot.account_snapshot()
    regime = bot.market_regime()
    health = bot.connection_check()
    auto_watchlist = load_auto_watchlist()
    positions = open_positions()
    reconciliation = broker_reconciliation_snapshot(settings, account, positions)
    live_readiness = live_readiness_snapshot(settings, account, health, regime, reconciliation)
    decision_bus = pmo_decision_bus_snapshot(settings, account, health, regime, auto_watchlist, reconciliation, live_readiness, record=False)
    scorecard = decision_bus.get("scorecard", paper_validation_scorecard(auto_watchlist, settings, account=account))
    rows = [
        {"metric": "Account Equity", "value": account.get("equity"), "detail": account.get("status") or account.get("error", "")},
        {"metric": "Buying Power", "value": account.get("buying_power"), "detail": "Alpaca account buying power"},
        {"metric": "Day P&L", "value": account.get("day_pnl"), "detail": f"{account.get('day_pnl_percent', 0):.2f}%"},
        {"metric": "PMO Drawdown Governor", "value": live_readiness.get("drawdown_governor", {}).get("status", "CLEAR"), "detail": live_readiness.get("drawdown_governor", {}).get("detail", "")},
        {"metric": "Market Regime", "value": regime.get("regime"), "detail": regime.get("reason", "")},
        {"metric": "Connections", "value": f"{health.get('online')}/{health.get('total')}", "detail": "incoming/outgoing/local"},
        {"metric": "Auto Watchlist", "value": len(auto_watchlist.get("symbols", [])), "detail": ", ".join(auto_watchlist.get("symbols", [])[:8])},
        {"metric": "v106 Paper Score", "value": f"{scorecard.get('score', 0)}%", "detail": scorecard.get("mode", "")},
        {"metric": "v106 Decision Bus", "value": decision_bus.get("execution_decision", ""), "detail": decision_bus.get("session_id", "")},
        {"metric": "TradingView Mode", "value": settings.get("TRADINGVIEW_ALERT_MODE"), "detail": "alert handling mode"},
        {"metric": "Live Master", "value": settings.get("PMO_LIVE_TRADING_ENABLED"), "detail": "PMO live signal approval master switch"},
    ]
    for row in rows:
        csv_append(LIVE_DATA_SNAPSHOT_FILE, {"timestamp": now_et().isoformat(), **row})
    return {"ok": True, "updated": now_et().isoformat(), "rows": rows, "account": account, "regime": regime, "health": health, "auto_watchlist": auto_watchlist}


def pmo_public_setting_value(key: str, value: Any) -> Any:
    clean_key = str(key or "").upper()
    if any(token in clean_key for token in ("SECRET", "TOKEN", "KEY", "PASSWORD")):
        return "CONFIGURED" if value else "MISSING"
    return value


def pmo_unique_text(values: Iterable[Any]) -> List[str]:
    rows: List[str] = []
    for value in values or []:
        text = str(value).strip()
        if text and text not in rows:
            rows.append(text)
    return rows


def pmo_setting_diff(before: Dict[str, Any], after: Dict[str, Any], keys: Optional[Iterable[str]] = None) -> List[Dict[str, Any]]:
    selected = list(keys) if keys is not None else sorted(set(before) | set(after))
    rows: List[Dict[str, Any]] = []
    for key in selected:
        if before.get(key) != after.get(key):
            rows.append({
                "setting": key,
                "before": pmo_public_setting_value(key, before.get(key)),
                "after": pmo_public_setting_value(key, after.get(key)),
            })
    return rows


def pmo_sync_core_safety_aliases(settings: Dict[str, Any]) -> None:
    for name in ("ALPACA_PAPER", "ORDER_AUTOMATION_ENABLED", "PMO_DRY_RUN_ORDERS"):
        sync_setting_aliases(settings, name)


