def pmo_safety_mode_snapshot(settings: Dict[str, Any], paper_proof: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    markets = [str(item).upper() for item in (settings.get("PMO_EXECUTOR_ALLOWED_MARKETS") or [])]
    max_trades = dict(settings.get("PMO_MAX_TRADES_BY_MARKET", {}) or {})
    live_enabled = bool(settings.get("PMO_LIVE_TRADING_ENABLED", False))
    live_allowed = bool(settings.get("PMO_ALLOW_LIVE_TRADING", False))
    alpaca_paper = bool(settings.get("ALPACA_PAPER", True))
    automation = bool(settings.get("ORDER_AUTOMATION_ENABLED", False))
    dry_run = bool(settings.get("PMO_DRY_RUN_ORDERS", True))
    executor_on = bool(settings.get("ENABLE_ALPACA_ORDER_EXECUTOR", False))
    execution_mode = str(settings.get("PMO_ORDER_EXECUTION_MODE", "SIGNAL_ONLY")).upper()
    crypto_live = bool(settings.get("ENABLE_PMO_CRYPTO_LIVE_TRADING", False))
    crypto_paper = bool(settings.get("ENABLE_PMO_CRYPTO_PAPER_TRADING", False))
    crypto_executor = bool(settings.get("ENABLE_PMO_CRYPTO_EXECUTOR", False))
    crypto_research = bool(settings.get("PMO_CRYPTO_RESEARCH_ONLY", True))
    proof_ready = bool((paper_proof or {}).get("ready_to_unlock_live", False))
    proof_quality_breaker = (paper_proof or {}).get("proof_quality_breaker") if isinstance((paper_proof or {}).get("proof_quality_breaker"), dict) else {}
    proof_quality_blocked = bool(proof_quality_breaker.get("active"))
    mismatches: List[str] = []
    if not alpaca_paper and not live_enabled and not live_allowed:
        mismatches.append("ALPACA_PAPER is False while live trading flags are locked.")
    if execution_mode == "LIVE_ALPACA" and not live_enabled:
        mismatches.append("PMO_ORDER_EXECUTION_MODE is LIVE_ALPACA while PMO_LIVE_TRADING_ENABLED is False.")
    if automation and not executor_on:
        mismatches.append("ORDER_AUTOMATION_ENABLED is True while ENABLE_ALPACA_ORDER_EXECUTOR is False.")
    if not dry_run and execution_mode == "SIGNAL_ONLY":
        mismatches.append("PMO_DRY_RUN_ORDERS is False while execution mode is SIGNAL_ONLY.")
    if "CRYPTO" in markets and not (crypto_live or crypto_paper or crypto_executor):
        mismatches.append("CRYPTO is in PMO_EXECUTOR_ALLOWED_MARKETS while crypto paper/live/executor switches are off.")
    if live_enabled and not proof_ready:
        mismatches.append("PMO_LIVE_TRADING_ENABLED is True before paper proof is ready.")
    stock_only = markets == ["STOCK"] or set(markets) == {"STOCK"}
    paper_safe = (
        alpaca_paper and not live_enabled and not live_allowed and not automation and dry_run and
        not executor_on and execution_mode == "SIGNAL_ONLY" and stock_only and
        not crypto_live and not crypto_paper and not crypto_executor
    )
    paper_executor = (
        alpaca_paper and not live_enabled and not live_allowed and automation and not dry_run and
        executor_on and execution_mode == "PAPER_ALPACA" and stock_only and
        not crypto_live and not crypto_paper and not crypto_executor
    )
    crypto_research_only = crypto_research and not crypto_live and not crypto_paper and not crypto_executor and "CRYPTO" not in markets
    if mismatches or live_enabled or live_allowed or execution_mode == "LIVE_ALPACA":
        state = "SAFETY_MISMATCH"
        label = "SAFETY MISMATCH"
        badge_class = "bad"
        state_line = "PMO safety mismatch detected: review settings before continuing."
    elif paper_executor and proof_quality_blocked:
        state = "PAPER_PROOF_REVIEW"
        label = "PAPER PROOF REVIEW"
        badge_class = "warn"
        state_line = "PMO paper executor is armed, but new paper entries are blocked by the proof-quality breaker. Sync/close trades and review losers."
    elif paper_executor:
        state = "PAPER_EXECUTOR_COLLECTION"
        label = "PAPER EXECUTOR COLLECTION"
        badge_class = "warn"
        state_line = "PMO is currently in PAPER EXECUTOR COLLECTION mode: paper Alpaca orders may be submitted, but live trading remains locked."
    elif paper_safe:
        state = "PAPER_SAFE"
        label = "PAPER SAFE / SIGNAL ONLY / STOCK ONLY"
        badge_class = "ok"
        state_line = "PMO is currently in PAPER SAFE mode: scanning and reviewing only. No broker orders will be submitted."
    elif crypto_research_only:
        state = "CRYPTO_RESEARCH_ONLY"
        label = "CRYPTO RESEARCH ONLY"
        badge_class = "info"
        state_line = "PMO crypto execution is off. Crypto monitoring and research may remain available."
    else:
        state = "REVIEW_REQUIRED"
        label = "REVIEW REQUIRED"
        badge_class = "warn"
        state_line = "PMO safety state is mixed. Review settings before continuing."
    badges = [
        {"label": "Alpaca Paper Mode", "value": alpaca_paper, "class": "ok" if alpaca_paper else "bad"},
        {"label": "Live Trading Locked", "value": not live_enabled and not live_allowed, "class": "ok" if not live_enabled and not live_allowed else "bad"},
        {"label": "Order Automation", "value": automation, "class": "warn" if automation else "info"},
        {"label": "Dry Run Orders", "value": dry_run, "class": "ok" if dry_run else "warn"},
        {"label": "Alpaca Executor", "value": executor_on, "class": "warn" if executor_on else "info"},
        {"label": "Execution Mode", "value": execution_mode, "class": "info" if execution_mode == "SIGNAL_ONLY" else "warn" if execution_mode == "PAPER_ALPACA" else "bad"},
        {"label": "Executor Markets", "value": ", ".join(markets) if markets else "-", "class": "ok" if stock_only else "warn"},
        {"label": "Crypto Live", "value": crypto_live, "class": "bad" if crypto_live else "ok"},
        {"label": "Crypto Paper", "value": crypto_paper, "class": "warn" if crypto_paper else "ok"},
        {"label": "Proof Quality", "value": "BLOCKED" if proof_quality_blocked else "CLEAR", "class": "bad" if proof_quality_blocked else "ok"},
        {"label": "Current Safety State", "value": label, "class": badge_class},
    ]
    values = [{"setting": key, "value": pmo_public_setting_value(key, settings.get(key))} for key in PMO_SAFETY_MODE_KEYS if key in settings]
    return {
        "state": state,
        "label": label,
        "badge_class": badge_class,
        "state_line": state_line,
        "mismatches": mismatches,
        "badges": badges,
        "values": values,
        "safe_baseline_label": "PAPER SAFE / SIGNAL ONLY / STOCK ONLY",
        "proof_ready": proof_ready,
        "proof_quality_breaker": proof_quality_breaker,
        "updated": now_et().isoformat(),
    }


def pmo_apply_safety_preset(payload: Dict[str, Any], apply_change: bool = True) -> Dict[str, Any]:
    preset = str(payload.get("preset", "")).strip().upper()
    preset_map = {
        "PAPER_SAFE": ("PAPER_SAFE", "PMO PAPER SAFE", pmo_apply_paper_safe_settings),
        "PAPER_EXECUTOR_COLLECTION": ("STOCK_PAPER_EXECUTOR_COLLECTION", "PMO PAPER EXECUTOR ONLY", pmo_apply_stock_paper_executor_settings),
        "CRYPTO_RESEARCH_ONLY": ("CRYPTO_RESEARCH_ONLY", "", pmo_apply_crypto_research_only_settings),
    }
    if preset not in preset_map:
        raise ValueError("Unsupported PMO safety preset.")
    mode_name, phrase, apply_func = preset_map[preset]
    confirm_text = str(payload.get("confirm_text", "")).strip().upper()
    if phrase and confirm_text != phrase:
        raise ValueError(f"Type {phrase} to continue.")
    settings = load_settings()
    before = dict(settings)
    result = apply_func(settings)
    diff = result.get("diff", pmo_setting_diff(before, settings))
    audit = {"ok": True, "mode": mode_name, "diff": diff, "preview": True}
    if apply_change:
        write_settings(settings)
        bot.reload()
        audit = pmo_save_mode_change(mode_name, before, settings)
    return {
        "ok": True,
        "applied": apply_change,
        "preset": preset,
        "mode": mode_name,
        "warning": "This enables paper Alpaca order submission only. Live trading remains locked." if preset == "PAPER_EXECUTOR_COLLECTION" else "",
        "result": result,
        "diff": diff,
        "audit": audit,
        "safety": pmo_safety_mode_snapshot(settings, pmo_paper_proof_snapshot(settings, record=False)),
    }


