def pmo_cms_module_registry(settings: Optional[Dict[str, Any]] = None) -> List[Dict[str, Any]]:
    settings = settings or load_settings()
    manual = pmo_cms_manual_modules()
    protected = set(PMO_ADMIN_REQUIRED_POST_PATHS)
    report_names = {Path(row.get("path", "")).name: row for row in pmo_report_file_rows()}
    modules: List[Dict[str, Any]] = []
    for seed in pmo_cms_known_module_seeds():
        prefixes = seed.get("setting_prefixes", [])
        setting_keys = [key for key in settings if any(key == prefix or key.startswith(prefix) for prefix in prefixes)]
        enabled_keys = [key for key in setting_keys if isinstance(settings.get(key), bool) and settings.get(key)]
        disabled_keys = [key for key in setting_keys if isinstance(settings.get(key), bool) and not settings.get(key)]
        endpoints = list(seed.get("endpoints", []))
        admin_required = any(endpoint in protected for endpoint in endpoints)
        existing_reports = [path for path in seed.get("reports", []) if Path(path).exists() or Path(path).name in report_names]
        status = "disabled" if setting_keys and not enabled_keys and disabled_keys else "healthy"
        if seed.get("safety_level") in {"LIVE_LOCKED", "LIVE_LOCK"} and bool(settings.get("PMO_LIVE_TRADING_ENABLED", False)):
            status = "blocked"
        if not existing_reports and seed.get("category") in {"Reports", "Paper Proof"}:
            status = "warning"
        module = {
            "id": seed["id"],
            "module": seed["name"],
            "category": seed["category"],
            "enabled": bool(enabled_keys) or seed["id"] in {"core_safety", "reports", "dashboard_layout"},
            "setting_keys": setting_keys[:16],
            "related_api_endpoints": endpoints,
            "dashboard_section": seed.get("section", ""),
            "report_log_files": existing_reports[:8],
            "safety_level": seed.get("safety_level", "REVIEW"),
            "admin_required": admin_required,
            "status": status,
            "notes": seed.get("notes", ""),
            "open_section": seed.get("section", ""),
        }
        override = manual.get(seed["id"], {}) if isinstance(manual.get(seed["id"], {}), dict) else {}
        module.update({k: v for k, v in override.items() if k in {"notes", "dashboard_section", "category", "module"}})
        modules.append(module)
    return modules


def pmo_cms_status_snapshot(settings: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    pmo_cms_ensure_storage()
    settings = settings or load_settings()
    modules = pmo_cms_module_registry(settings)
    reports = pmo_report_file_rows()
    paper_proof = pmo_paper_proof_snapshot(settings, record=False)
    safety = pmo_safety_mode_snapshot(settings, paper_proof)
    layout = load_pmo_dashboard_layout()
    latest_audit = recent_csv_rows(PMO_CMS_AUDIT_FILE, 1)
    admin_security = pmo_admin_security_state()
    warning = "No current CMS warning"
    for module in modules:
        if module.get("status") in {"warning", "blocked"}:
            warning = f"{module.get('module')}: {module.get('status')}"
            break
    return {
        "total_modules": len(modules),
        "enabled_modules": sum(1 for module in modules if module.get("enabled")),
        "disabled_modules": sum(1 for module in modules if not module.get("enabled")),
        "safety_state": safety.get("label"),
        "paper_live_state": f"paper={settings.get('ALPACA_PAPER')} live={settings.get('PMO_LIVE_TRADING_ENABLED')}",
        "active_dashboard_layout": layout.get("name", "PMO Bot Control Layout"),
        "latest_report_count": len(reports),
        "latest_proof_status": paper_proof.get("status") or ("READY" if paper_proof.get("ready_to_unlock_live") else "COLLECTING"),
        "latest_system_warning": warning,
        "last_cms_save_time": latest_audit[-1].get("timestamp") if latest_audit else "",
        "admin_token_configured": bool(admin_security.get("configured")),
        "protected_post_route_count": len(PMO_ADMIN_REQUIRED_POST_PATHS),
        "storage_files": {
            "modules": str(PMO_CMS_MODULES_FILE),
            "layout": str(PMO_CMS_LAYOUT_FILE),
            "content": str(PMO_CMS_CONTENT_FILE),
            "audit": str(PMO_CMS_AUDIT_FILE),
        },
    }


def pmo_cms_report_library() -> Dict[str, Any]:
    rows = pmo_report_file_rows()
    related = []
    for row in rows:
        name = row.get("name", "")
        module = "Reports"
        lowered = name.lower()
        if "proof" in lowered or "v112" in lowered:
            module = "Proof CMS"
        elif "asi" in lowered:
            module = "ASI Learning"
        elif "quantum" in lowered:
            module = "Quantum Learning"
        elif "warp" in lowered:
            module = "WARP"
        elif "tradingview" in lowered or name.endswith(".pine"):
            module = "TradingView"
        elif "button" in lowered or "audit" in lowered:
            module = "Logs/Audit"
        row["related_module"] = module
        row["download_safe"] = Path(row.get("path", "")).suffix.lower() in {".csv", ".json", ".html", ".txt", ".pine", ".log"}
        related.append(row)
    return {"reports": related, "count": len(related), "file_roots": [str(REPORT_DIR), str(CSV_DIR), str(PINE_DIR)]}


def pmo_cms_audit_snapshot() -> Dict[str, Any]:
    rows = list(reversed(recent_csv_rows(PMO_CMS_AUDIT_FILE, 80)))
    button_events = list(reversed(recent_csv_rows(PMO_BOT_BUTTON_AUDIT_FILE, 40)))
    mode_changes = list(reversed(recent_csv_rows(PMO_MODE_CHANGE_EVENTS_FILE, 40)))
    return {
        "cms_audit": rows,
        "button_events": button_events,
        "safety_mode_changes": mode_changes,
        "warnings_first": [row for row in rows if str(row.get("status", "")).upper() not in {"OK", "COMPLETE", "SUCCESS"}][:20],
        "files": {
            "cms_audit": str(PMO_CMS_AUDIT_FILE),
            "button_audit": str(PMO_BOT_BUTTON_AUDIT_FILE),
            "mode_changes": str(PMO_MODE_CHANGE_EVENTS_FILE),
        },
    }


def pmo_save_mode_change(mode: str, before: Dict[str, Any], after: Dict[str, Any]) -> Dict[str, Any]:
    diff = pmo_setting_diff(before, after)
    csv_append(PMO_MODE_CHANGE_EVENTS_FILE, {
        "timestamp": now_et().isoformat(),
        "mode": mode,
        "changed_count": len(diff),
        "changed_settings": ", ".join(item["setting"] for item in diff[:40]),
        "safe_note": "Mode changes are audited with secret values redacted.",
    })
    return {"ok": True, "mode": mode, "diff": diff, "file": str(PMO_MODE_CHANGE_EVENTS_FILE)}


def pmo_market_session_now() -> Dict[str, Any]:
    current = now_et()
    minutes = current.hour * 60 + current.minute
    weekday = current.weekday()
    if weekday >= 5:
        session = "WEEKEND"
        equity_open = False
    elif 4 * 60 <= minutes < 9 * 60 + 30:
        session = "PRE_MARKET"
        equity_open = False
    elif 9 * 60 + 30 <= minutes < 16 * 60:
        session = "REGULAR"
        equity_open = True
    elif 16 * 60 <= minutes < 20 * 60:
        session = "AFTER_HOURS"
        equity_open = False
    else:
        session = "OVERNIGHT"
        equity_open = False
    return {
        "ok": True,
        "timestamp": current.isoformat(),
        "session": session,
        "weekday": current.strftime("%A"),
        "equity_regular_open": equity_open,
        "crypto_24_7": True,
        "note": "Extended-hours equities stay research or guarded paper-only unless the dedicated PMO switch is enabled.",
    }


