def pmo_all_day_runner_status(
    settings: Dict[str, Any],
    account: Dict[str, Any],
    health: Dict[str, Any],
    regime: Dict[str, Any],
    live_readiness: Dict[str, Any],
    executor: Dict[str, Any],
    paper_proof: Dict[str, Any],
    why_not: Dict[str, Any],
    crypto_status: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    session = pmo_market_session_now()
    blockers: List[str] = []
    if not settings.get("ALPACA_PAPER", True):
        blockers.append("ALPACA_PAPER is not True")
    if settings.get("PMO_LIVE_TRADING_ENABLED") or settings.get("PMO_ALLOW_LIVE_TRADING"):
        blockers.append("live trading switches are not locked")
    if not settings.get("ENABLE_PMO_ALWAYS_ON_WATCHTOWER", True):
        blockers.append("ENABLE_PMO_ALWAYS_ON_WATCHTOWER is OFF")
    if not health.get("online"):
        blockers.append("connection health is not online")
    if not executor.get("ready"):
        blockers.extend(executor.get("blockers", [])[:3] if isinstance(executor.get("blockers"), list) else ["executor is not ready"])
    if settings.get("PMO_DRY_RUN_ORDERS", True):
        blockers.append("PMO_DRY_RUN_ORDERS is ON, so no paper broker submissions are made")
    next_action = "Review signals and keep collecting proof."
    if blockers:
        next_action = "Open Quick Safety Controls and review the blocked paper-trading gates."
    elif not paper_proof.get("ready_to_unlock_live"):
        next_action = "Keep paper executor collection running until proof minimums are met."
    return {
        "ok": True,
        "updated": now_et().isoformat(),
        "session": session,
        "runner_mode": "WATCHTOWER_ON" if settings.get("ENABLE_PMO_ALWAYS_ON_WATCHTOWER", True) else "WATCHTOWER_OFF",
        "scan_interval_minutes": settings.get("PMO_WATCHTOWER_SCAN_INTERVAL_MINUTES", 15),
        "paper_safe": bool(settings.get("ALPACA_PAPER")) and not bool(settings.get("PMO_LIVE_TRADING_ENABLED")),
        "executor_ready": bool(executor.get("ready")),
        "paper_proof_ready": bool(paper_proof.get("ready_to_unlock_live")),
        "why_not_blocked": (why_not.get("summary") or {}).get("blocked", 0),
        "crypto_mode": (crypto_status or {}).get("mode", "UNKNOWN"),
        "account_status": account.get("status") or account.get("error", "UNKNOWN"),
        "regime": regime.get("regime", "UNKNOWN"),
        "live_readiness_score": live_readiness.get("score", 0),
        "blockers": pmo_unique_text(blockers),
        "next_action": next_action,
    }


def pmo_crypto_symbols(settings: Dict[str, Any], limit: Optional[int] = None) -> List[str]:
    symbols = unique_symbols(settings.get("PMO_CRYPTO_WATCHLIST", []), settings.get("PMO_CRYPTO_DISCOVERY_UNIVERSE", []))
    crypto_symbols = [normalize_crypto_symbol(symbol) for symbol in symbols if detect_market(str(symbol), "AUTO") == "CRYPTO"]
    if limit:
        return crypto_symbols[:max(1, int(limit))]
    return crypto_symbols


def pmo_crypto_watchlist_rows(settings: Dict[str, Any], limit: Optional[int] = None) -> List[Dict[str, Any]]:
    rows: List[Dict[str, Any]] = []
    for symbol in pmo_crypto_symbols(settings, limit=limit or 8):
        try:
            bot.settings = settings
            row = bot.score_watchlist_symbol(symbol)
            row["symbol"] = normalize_crypto_symbol(str(row.get("symbol") or symbol))
        except Exception as exc:
            row = {
                "symbol": symbol,
                "market": "CRYPTO",
                "score": 0,
                "score_band": "DATA_OFFLINE",
                "price": None,
                "feed": "FAILED",
                "ok": False,
                "reason": str(exc),
                "updated": now_et().isoformat(),
            }
        rows.append(row)
    return rows


def pmo_crypto_live_price_rows(settings: Dict[str, Any], limit: Optional[int] = None) -> List[Dict[str, Any]]:
    rows: List[Dict[str, Any]] = []
    for symbol in pmo_crypto_symbols(settings, limit=limit or 8):
        try:
            bot.settings = settings
            data = bot.get_latest_price(symbol, "CRYPTO")
            ok = bool(data.get("ok"))
            row = {
                "symbol": normalize_crypto_symbol(str(data.get("symbol") or symbol)),
                "market": "CRYPTO",
                "score": 60 if ok else 0,
                "score_band": "LIVE_DATA" if ok else "DATA_OFFLINE",
                "score_label": "Live crypto feed" if ok else "No live crypto feed",
                "score_range": "60" if ok else "0",
                "score_action": "WATCH" if ok else "WAIT",
                "extra_confirmation_required": True,
                "price": data.get("price"),
                "feed": data.get("feed", ""),
                "bias": "WATCH",
                "change_pct": 0,
                "relative_volume": 0,
                "quantum_score": 0,
                "quantum_state": "NOT_SCORED_FAST_FEED",
                "asi_adjustment": 0,
                "asi_state": "NOT_SCORED_FAST_FEED",
                "rows": 0,
                "ok": ok,
                "reason": "Live WebSocket crypto price" if str(data.get("feed", "")).startswith("CRYPTO_WS_") else (data.get("error") or "Live crypto price"),
                "updated": data.get("timestamp") or now_et().isoformat(),
            }
        except Exception as exc:
            row = {
                "symbol": symbol,
                "market": "CRYPTO",
                "score": 0,
                "score_band": "DATA_OFFLINE",
                "price": None,
                "feed": "FAILED",
                "ok": False,
                "reason": str(exc),
                "updated": now_et().isoformat(),
            }
        rows.append(row)
    return rows


def pmo_crypto_ws_monitor(settings: Optional[Dict[str, Any]] = None, restart_if_needed: bool = False) -> Dict[str, Any]:
    settings = settings or load_settings()
    if "bot" not in globals() or not hasattr(bot, "crypto_ws"):
        return {"enabled": False, "available": False, "connected": False, "age_seconds": None, "needs_restart": False, "restart": {"attempted": False}}
    status = bot.crypto_ws.status_snapshot()
    enabled = bool(settings.get("ENABLE_PMO_CRYPTO_WEBSOCKET_FEEDS", True))
    connected = bool(status.get("connected"))
    cached_symbols = status.get("cached_symbols") if isinstance(status.get("cached_symbols"), list) else []
    max_age = safe_float(settings.get("PMO_CRYPTO_WS_MAX_PRICE_AGE_SECONDS", 20), 20)
    age_seconds: Optional[float] = None
    last_update = status.get("last_update")
    if last_update:
        try:
            parsed = datetime.fromisoformat(str(last_update).replace("Z", "+00:00"))
            if parsed.tzinfo is None:
                parsed = parsed.replace(tzinfo=ET)
            age_seconds = max(0.0, (now_et() - parsed.astimezone(ET)).total_seconds())
        except Exception:
            age_seconds = None
    stale = age_seconds is None or age_seconds > max_age
    needs_restart = bool(enabled and (not connected or not cached_symbols or stale))
    restart: Dict[str, Any] = {"attempted": False}
    if restart_if_needed and needs_restart:
        symbols = [
            normalize_crypto_symbol(symbol)
            for symbol in unique_symbols(settings.get("PMO_CRYPTO_WATCHLIST", []), settings.get("PMO_CRYPTO_DISCOVERY_UNIVERSE", []))
            if detect_market(str(symbol), "AUTO") == "CRYPTO"
        ]
        provider_order = bot.crypto_ws.provider_order()
        active_provider = str(status.get("active_provider") or "").lower()
        rotated_order = list(provider_order)
        if active_provider in rotated_order:
            index = rotated_order.index(active_provider)
            rotated_order = rotated_order[index + 1:] + rotated_order[:index + 1]
        replacement_settings = dict(settings)
        replacement_settings["PMO_CRYPTO_WS_PROVIDER_ORDER"] = rotated_order or provider_order
        try:
            bot.crypto_ws.stop()
        except Exception:
            pass
        bot.crypto_ws = PMOCryptoWebSocketFeed(replacement_settings)
        bot.crypto_ws.start(symbols)
        restart = {"attempted": True, "symbols": symbols, "reason": "connected=false/cache-empty/stale", "provider_order": replacement_settings["PMO_CRYPTO_WS_PROVIDER_ORDER"]}
        status = bot.crypto_ws.status_snapshot()
    return {
        **status,
        "enabled": enabled,
        "age_seconds": age_seconds,
        "max_age_seconds": max_age,
        "stale": stale,
        "needs_restart": needs_restart,
        "restart": restart,
    }


def pmo_crypto_proof_snapshot(settings: Optional[Dict[str, Any]] = None, record: bool = False) -> Dict[str, Any]:
    settings = settings or load_settings()
    orders = recent_csv_rows(PMO_CRYPTO_ORDER_EXECUTION_FILE, 5000)
    replay = recent_csv_rows(PMO_CRYPTO_REPLAY_JOURNAL_FILE, 5000)
    submitted = [row for row in orders if str(row.get("status", "")).upper() == "SUBMITTED"]
    failed = [row for row in orders if str(row.get("status", "")).upper() == "FAILED"]
    closed = [row for row in replay if str(row.get("status", "")).upper() in {"CLOSED", "COMPLETE", "WIN", "LOSS"}]
    pnl_values = [safe_float(row.get("pnl_pct") or row.get("pnl") or row.get("pnl_usd"), 0) for row in closed]
    wins = [value for value in pnl_values if value > 0]
    losses = [abs(value) for value in pnl_values if value < 0]
    win_rate = round(len(wins) / len(pnl_values), 4) if pnl_values else 0
    profit_factor = round(sum(wins) / sum(losses), 4) if losses and sum(losses) > 0 else (round(sum(wins), 4) if wins else 0)
    risk_rewards = [safe_float(row.get("risk_reward"), 0) for row in closed if safe_float(row.get("risk_reward"), 0) > 0]
    avg_rr = round(sum(risk_rewards) / len(risk_rewards), 4) if risk_rewards else 0
    requirements = {
        "min_submissions": int(safe_float(settings.get("PMO_MIN_CRYPTO_PAPER_EXECUTOR_SUBMISSIONS"), 20)),
        "min_closed_trades": int(safe_float(settings.get("PMO_MIN_CRYPTO_CLOSED_PAPER_TRADES"), 30)),
        "max_failed_executions": int(safe_float(settings.get("PMO_MAX_CRYPTO_FAILED_EXECUTIONS"), 0)),
        "min_win_rate": safe_float(settings.get("PMO_MIN_CRYPTO_PROOF_WIN_RATE"), 0.52),
        "min_profit_factor": safe_float(settings.get("PMO_MIN_CRYPTO_PROOF_PROFIT_FACTOR"), 1.25),
        "min_avg_risk_reward": safe_float(settings.get("PMO_MIN_CRYPTO_AVG_RISK_REWARD"), 1.5),
    }
    checks = [
        {"name": "paper submissions", "ready": len(submitted) >= requirements["min_submissions"], "value": len(submitted), "required": requirements["min_submissions"]},
        {"name": "closed paper trades", "ready": len(closed) >= requirements["min_closed_trades"], "value": len(closed), "required": requirements["min_closed_trades"]},
        {"name": "failed executions", "ready": len(failed) <= requirements["max_failed_executions"], "value": len(failed), "required": requirements["max_failed_executions"]},
        {"name": "win rate", "ready": win_rate >= requirements["min_win_rate"], "value": win_rate, "required": requirements["min_win_rate"]},
        {"name": "profit factor", "ready": profit_factor >= requirements["min_profit_factor"], "value": profit_factor, "required": requirements["min_profit_factor"]},
        {"name": "average risk reward", "ready": avg_rr >= requirements["min_avg_risk_reward"], "value": avg_rr, "required": requirements["min_avg_risk_reward"]},
    ]
    ready = all(item["ready"] for item in checks)
    payload = {
        "ok": True,
        "updated": now_et().isoformat(),
        "ready_to_unlock_live_crypto": ready,
        "status": "PROOF_READY" if ready else "PROOF_LOCKED",
        "requirements": requirements,
        "checks": checks,
        "summary": {
            "submitted": len(submitted),
            "failed": len(failed),
            "closed": len(closed),
            "wins": len(wins),
            "losses": len(losses),
            "win_rate": win_rate,
            "profit_factor": profit_factor,
            "avg_risk_reward": avg_rr,
        },
        "files": {
            "orders": str(PMO_CRYPTO_ORDER_EXECUTION_FILE),
            "replay": str(PMO_CRYPTO_REPLAY_JOURNAL_FILE),
            "report": str(PMO_CRYPTO_PROOF_REPORT_FILE),
        },
    }
    if record:
        write_json_file(PMO_CRYPTO_PROOF_REPORT_FILE, payload)
    return payload


def pmo_crypto_status_snapshot(settings: Optional[Dict[str, Any]] = None, record: bool = False) -> Dict[str, Any]:
    settings = settings or load_settings()
    proof = pmo_crypto_proof_snapshot(settings, record=False)
    rows = pmo_crypto_live_price_rows(settings, limit=5) if settings.get("ENABLE_PMO_CRYPTO_MARKET_DATA", True) else []
    blockers: List[str] = []
    if not settings.get("ENABLE_PMO_CRYPTO_MARKET_DATA", True):
        blockers.append("ENABLE_PMO_CRYPTO_MARKET_DATA is OFF")
    if not settings.get("ENABLE_PMO_CRYPTO_PAPER_TRADING", False):
        blockers.append("ENABLE_PMO_CRYPTO_PAPER_TRADING is OFF")
    if not settings.get("ENABLE_PMO_CRYPTO_EXECUTOR", False):
        blockers.append("ENABLE_PMO_CRYPTO_EXECUTOR is OFF")
    if "CRYPTO" not in {str(item).upper() for item in settings.get("PMO_EXECUTOR_ALLOWED_MARKETS", [])}:
        blockers.append("CRYPTO is not in PMO_EXECUTOR_ALLOWED_MARKETS")
    if settings.get("PMO_CRYPTO_RESEARCH_ONLY", True):
        blockers.append("PMO_CRYPTO_RESEARCH_ONLY is ON")
    if not settings.get("ALPACA_PAPER", True):
        blockers.append("ALPACA_PAPER must be True for crypto paper mode")
    if settings.get("PMO_LIVE_TRADING_ENABLED") or settings.get("PMO_ALLOW_LIVE_TRADING") or settings.get("ENABLE_PMO_CRYPTO_LIVE_TRADING"):
        blockers.append("live switches must stay OFF for crypto paper mode")
    if str(settings.get("PMO_ORDER_EXECUTION_MODE", "SIGNAL_ONLY")) != "PAPER_ALPACA":
        blockers.append("PMO_ORDER_EXECUTION_MODE is not PAPER_ALPACA")
    mode = "CRYPTO_RESEARCH_ONLY" if settings.get("PMO_CRYPTO_RESEARCH_ONLY", True) else "CRYPTO_PAPER_LOCKED"
    if not blockers:
        mode = "CRYPTO_PAPER_READY"
    payload = {
        "ok": True,
        "updated": now_et().isoformat(),
        "mode": mode,
        "market_data_enabled": bool(settings.get("ENABLE_PMO_CRYPTO_MARKET_DATA", True)),
        "websocket_feeds": pmo_crypto_ws_monitor(settings, restart_if_needed=False) if "bot" in globals() else {},
        "watchlist_enabled": bool(settings.get("ENABLE_PMO_CRYPTO_WATCHLIST", True)),
        "executor_enabled": bool(settings.get("ENABLE_PMO_CRYPTO_EXECUTOR", False)),
        "paper_trading_enabled": bool(settings.get("ENABLE_PMO_CRYPTO_PAPER_TRADING", False)),
        "live_trading_enabled": bool(settings.get("ENABLE_PMO_CRYPTO_LIVE_TRADING", False)),
        "allowed_markets": settings.get("PMO_EXECUTOR_ALLOWED_MARKETS", []),
        "max_notional": settings.get("PMO_CRYPTO_MAX_NOTIONAL_USD", 10.0),
        "min_score": settings.get("PMO_CRYPTO_MIN_SCORE", 85),
        "proof": proof,
        "top_symbols": rows,
        "blockers": pmo_unique_text(blockers),
        "next_action": "Run crypto Why-Not, then enable crypto paper only if every paper guard is intentional." if blockers else "Crypto paper executor can submit only after signal, score, risk, and Alpaca paper gates pass.",
    }
    if record:
        write_json_file(PMO_CRYPTO_PROOF_REPORT_FILE, payload)
    return payload


def pmo_crypto_why_not_snapshot(settings: Optional[Dict[str, Any]] = None, record: bool = False) -> Dict[str, Any]:
    settings = settings or load_settings()
    rows = []
    min_score = safe_float(settings.get("PMO_CRYPTO_MIN_SCORE"), 85)
    for row in pmo_crypto_watchlist_rows(settings, limit=12):
        blockers: List[str] = []
        score = safe_float(row.get("score"), 0)
        if not row.get("ok"):
            blockers.append(row.get("reason") or "crypto market data unavailable")
        if score < min_score:
            blockers.append(f"score {score:g} is below PMO_CRYPTO_MIN_SCORE {min_score:g}")
        if not settings.get("ENABLE_PMO_CRYPTO_PAPER_TRADING", False):
            blockers.append("ENABLE_PMO_CRYPTO_PAPER_TRADING is OFF")
        if not settings.get("ENABLE_PMO_CRYPTO_EXECUTOR", False):
            blockers.append("ENABLE_PMO_CRYPTO_EXECUTOR is OFF")
        if settings.get("PMO_CRYPTO_RESEARCH_ONLY", True):
            blockers.append("PMO_CRYPTO_RESEARCH_ONLY is ON")
        if str(settings.get("PMO_ORDER_EXECUTION_MODE", "SIGNAL_ONLY")) != "PAPER_ALPACA":
            blockers.append("PMO_ORDER_EXECUTION_MODE is not PAPER_ALPACA")
        if settings.get("PMO_DRY_RUN_ORDERS", True):
            blockers.append("PMO_DRY_RUN_ORDERS is ON")
        if "CRYPTO" not in {str(item).upper() for item in settings.get("PMO_EXECUTOR_ALLOWED_MARKETS", [])}:
            blockers.append("CRYPTO not allowed in PMO_EXECUTOR_ALLOWED_MARKETS")
        decision = "PAPER_READY" if not blockers else "BLOCKED"
        output = {
            "timestamp": now_et().isoformat(),
            "symbol": row.get("symbol"),
            "score": score,
            "price": row.get("price"),
            "feed": row.get("feed"),
            "decision": decision,
            "blockers": blockers,
            "next_action": "Paper crypto signal can be reviewed." if decision == "PAPER_READY" else blockers[0],
        }
        rows.append(output)
        if record:
            csv_append(PMO_CRYPTO_SIGNALS_FILE, {
                **{k: v for k, v in output.items() if k != "blockers"},
                "blockers": " | ".join(blockers),
            })
    summary = {
        "total": len(rows),
        "ready": len([row for row in rows if row["decision"] == "PAPER_READY"]),
        "blocked": len([row for row in rows if row["decision"] != "PAPER_READY"]),
    }
    return {"ok": True, "updated": now_et().isoformat(), "summary": summary, "rows": rows, "file": str(PMO_CRYPTO_SIGNALS_FILE)}


def pmo_v207_clean_symbol(symbol: Any) -> str:
    clean = str(symbol or "").strip().upper()
    if not clean or clean in {"-", "NONE", "NAN", "NULL"}:
        return ""
    return normalize_crypto_symbol(clean) if detect_market(clean, "AUTO") == "CRYPTO" else clean


def pmo_v207_add_symbol_source(source_map: Dict[str, Dict[str, Any]], symbol: Any, source: str, detail: str = "") -> None:
    clean = pmo_v207_clean_symbol(symbol)
    if not clean:
        return
    row = source_map.setdefault(clean, {"symbol": clean, "sources": [], "source_details": []})
    if source and source not in row["sources"]:
        row["sources"].append(source)
    if detail:
        detail_text = str(detail).strip()
        if detail_text and detail_text not in row["source_details"]:
            row["source_details"].append(detail_text[:240])


def pmo_v207_recent_symbol_sources(settings: Dict[str, Any], auto_watchlist: Dict[str, Any]) -> Dict[str, Dict[str, Any]]:
    source_map: Dict[str, Dict[str, Any]] = {}
    for symbol in settings.get("PMO_WATCHLIST", []):
        pmo_v207_add_symbol_source(source_map, symbol, "PMO_WATCHLIST", "locked settings watchlist")
    for symbol in settings.get("PMO_AUTO_WATCHLIST_UNIVERSE", []):
        pmo_v207_add_symbol_source(source_map, symbol, "PMO_AUTO_WATCHLIST_UNIVERSE", "locked auto-watchlist universe")
    for symbol in auto_watchlist.get("symbols", []):
        pmo_v207_add_symbol_source(source_map, symbol, "AUTO_WATCHLIST_SELECTED", f"auto selected {auto_watchlist.get('updated', '')}")
    for row in auto_watchlist.get("selected", []) + auto_watchlist.get("scored", []):
        pmo_v207_add_symbol_source(source_map, row.get("symbol"), "AUTO_WATCHLIST_SCORE", f"score={row.get('score', '')} bias={row.get('bias', '')}")
    for item in SECTOR_ROTATION_SYMBOLS:
        pmo_v207_add_symbol_source(source_map, item.get("symbol"), "SECTOR_ROTATION", item.get("sector", "sector ETF"))
    for symbol in pmo_market_universe(settings):
        pmo_v207_add_symbol_source(source_map, symbol, "PMO_MARKET_UNIVERSE", "active scan universe")
    for symbol in pmo_crypto_symbols(settings, limit=40):
        pmo_v207_add_symbol_source(source_map, symbol, "CRYPTO_WATCHLIST", "crypto data/research universe")
    for position in open_positions():
        pmo_v207_add_symbol_source(source_map, position.get("symbol"), "BROKER_POSITION", f"qty={position.get('qty', '')} unrealized={position.get('unrealized_pl', '')}")
    for order in open_orders_snapshot():
        pmo_v207_add_symbol_source(source_map, order.get("symbol"), "BROKER_OPEN_ORDER", f"{order.get('side', '')} {order.get('status', '')}")
    csv_sources = [
        (AUTO_WATCHLIST_CSV, "AUTO_WATCHLIST_HISTORY"),
        (PMO_ORDER_EXECUTION_FILE, "ORDER_EXECUTION_JOURNAL"),
        (PMO_CRYPTO_ORDER_EXECUTION_FILE, "CRYPTO_EXECUTION_JOURNAL"),
        (PMO_TRADE_PLAN_FILE, "TRADE_PLAN_JOURNAL"),
        (TRADE_JOURNAL_FILE, "TRADE_JOURNAL"),
        (PMO_V112_REPLAY_JOURNAL_FILE, "V112_REPLAY_JOURNAL"),
        (PMO_WHY_NOT_EVENTS_FILE, "WHY_NOT_EVENTS"),
        (PMO_LEARNING_EVENTS_FILE, "LEARNING_EVENTS"),
        (PMO_QUANTUM_EVENTS_FILE, "QUANTUM_EVENTS"),
        (PMO_ASI_EVENTS_FILE, "ASI_EVENTS"),
    ]
    for path, source_name in csv_sources:
        for row in recent_csv_rows(path, 250):
            symbol = row.get("symbol") or row.get("ticker") or row.get("asset")
            detail_parts = [
                row.get("decision") or row.get("status") or row.get("action") or "",
                f"score={row.get('score') or row.get('pmo_score')}" if row.get("score") or row.get("pmo_score") else "",
            ]
            pmo_v207_add_symbol_source(source_map, symbol, source_name, " ".join(part for part in detail_parts if part))
    return source_map


def pmo_v207_watchlist_intelligence_snapshot(settings: Optional[Dict[str, Any]] = None, record: bool = False, limit: int = 120) -> Dict[str, Any]:
    settings = settings or load_settings()
    auto_watchlist = load_auto_watchlist()
    account = bot.account_snapshot()
    health = bot.connection_check()
    regime = bot.market_regime()
    positions = open_positions()
    reconciliation = broker_reconciliation_snapshot(settings, account, positions)
    live_readiness = live_readiness_snapshot(settings, account, health, regime, reconciliation)
    executor = bot.executor_status()
    paper_proof = pmo_paper_proof_snapshot(settings, record=False)
    why_not = pmo_why_not_snapshot(
        auto_watchlist,
        settings,
        account,
        health,
        regime,
        live_readiness,
        executor,
        reconciliation,
        paper_proof,
        record=False,
    )
    why_not_lookup = {pmo_v207_clean_symbol(row.get("symbol")): row for row in why_not.get("rows", []) if pmo_v207_clean_symbol(row.get("symbol"))}
    source_map = pmo_v207_recent_symbol_sources(settings, auto_watchlist)
    lookup = auto_watchlist_lookup(auto_watchlist)
    position_lookup = {pmo_v207_clean_symbol(row.get("symbol")): row for row in positions if pmo_v207_clean_symbol(row.get("symbol"))}
    order_lookup = {pmo_v207_clean_symbol(row.get("symbol")): row for row in open_orders_snapshot() if pmo_v207_clean_symbol(row.get("symbol"))}
    allowed_markets = {str(item).upper() for item in settings.get("PMO_EXECUTOR_ALLOWED_MARKETS", [])}
    rows: List[Dict[str, Any]] = []
    for symbol, source_info in sorted(source_map.items()):
        if len(rows) >= max(10, int(limit)):
            break
        market = detect_market(symbol, "AUTO")
        scored = lookup.get(symbol)
        if not scored:
            try:
                scored = bot.score_watchlist_symbol(symbol)
            except Exception as exc:
                scored = {
                    "symbol": symbol,
                    "market": market,
                    "score": 0,
                    "score_band": "DATA_OFFLINE",
                    "score_label": "Data unavailable",
                    "bias": "WAIT",
                    "price": None,
                    "feed": "FAILED",
                    "ok": False,
                    "reason": str(exc),
                    "relative_volume": 0,
                    "change_pct": 0,
                    "updated": now_et().isoformat(),
                }
        score = safe_float(scored.get("score"), 0)
        band = pmo_trade_score_band(score, settings)
        why_row = why_not_lookup.get(symbol, {})
        learning = pmo_learning_signal_adjustment(symbol, settings)
        quantum = pmo_quantum_signal_adjustment_v2(symbol, settings)
        asi = pmo_asi_signal_adjustment_v2(symbol, settings)
        sector = pmo_sector_for_symbol(symbol)
        regime_name = str(regime.get("regime") or "UNKNOWN").upper()
        bias = str(scored.get("bias") or "WAIT")
        defensive_symbols = {"SH", "PSQ", "DOG", "RWM", "TLT", "GLD", "XLP", "XLU", "XLV"}
        if market == "CRYPTO":
            regime_alignment = "CRYPTO_CONTEXT"
        elif regime_name == "DEFENSIVE" and (symbol in defensive_symbols or sector in {"Utilities", "Consumer Staples", "Healthcare"}):
            regime_alignment = "ALIGNED"
        elif regime_name == "BULLISH" and bias == "CALL_BIAS":
            regime_alignment = "ALIGNED"
        elif regime_name in {"BEARISH", "DEFENSIVE"} and bias == "CALL_BIAS":
            regime_alignment = "NEEDS_CONFIRMATION"
        else:
            regime_alignment = "WATCH"
        blockers = why_row.get("blockers", []) if isinstance(why_row.get("blockers", []), list) else []
        rows.append({
            "timestamp": now_et().isoformat(),
            "symbol": symbol,
            "market": market,
            "sector": sector,
            "score": round(score, 2),
            "score_band": band.get("band") or scored.get("score_band", ""),
            "score_action": band.get("action") or scored.get("score_action", ""),
            "bias": bias,
            "readiness": why_row.get("readiness") or calls_puts_readiness(scored, settings),
            "why_not_decision": why_row.get("decision", "NOT_REVIEWED"),
            "blockers": blockers,
            "price": scored.get("price"),
            "change_pct": scored.get("change_pct", ""),
            "relative_volume": scored.get("relative_volume", ""),
            "feed": scored.get("feed", ""),
            "feed_online": bool(scored.get("ok")),
            "regime": regime_name,
            "regime_alignment": regime_alignment,
            "sources": source_info.get("sources", []),
            "source_details": source_info.get("source_details", [])[:8],
            "learning_adjustment": learning.get("watchlist_adjustment", 0),
            "learning_state": learning.get("risk_state", "NO_MEMORY"),
            "quantum_score": quantum.get("quantum_score", 0),
            "quantum_state": quantum.get("state", "NO_MATRIX"),
            "asi_adjustment": asi.get("watchlist_adjustment", 0),
            "asi_state": asi.get("state", "NO_ASI"),
            "in_position": symbol in position_lookup,
            "open_order": symbol in order_lookup,
            "executor_market_allowed": market in allowed_markets,
            "information_feeds": pmo_unique_text(source_info.get("sources", []) + ["LIVE_PRICE", "BAR_DATA", "WHY_NOT", "LEARNING", "QUANTUM", "ASI", "REGIME", "BROKER_CONTEXT"]),
            "next_action": why_row.get("next_action") or "Keep feeding PMO with live data, learning records, and broker context; execution still follows locked settings.",
        })
    rows.sort(key=lambda row: (bool(row.get("feed_online")), safe_float(row.get("score"), 0), len(row.get("sources", []))), reverse=True)
    summary = {
        "total_symbols": len(rows),
        "feed_online": len([row for row in rows if row.get("feed_online")]),
        "stocks": len([row for row in rows if row.get("market") == "STOCK"]),
        "crypto": len([row for row in rows if row.get("market") == "CRYPTO"]),
        "options": len([row for row in rows if row.get("market") == "OPTION"]),
        "ready_or_watch": len([row for row in rows if str(row.get("why_not_decision", "")).upper() not in {"BLOCKED", "NO SIGNALS"}]),
        "broker_positions": len([row for row in rows if row.get("in_position")]),
        "broker_open_orders": len([row for row in rows if row.get("open_order")]),
        "regime": regime.get("regime", "UNKNOWN"),
        "settings_frozen": True,
        "settings_note": "v207 watchlist intelligence reads locked settings and writes only report/journal output.",
    }
    payload = {
        "ok": True,
        "version": "PMO_V207_WATCHLIST_INTELLIGENCE",
        "updated": now_et().isoformat(),
        "summary": summary,
        "settings_respected": {
            "order_execution_mode": settings.get("PMO_ORDER_EXECUTION_MODE"),
            "alpaca_paper": bool(settings.get("ALPACA_PAPER")),
            "dry_run_orders": bool(settings.get("PMO_DRY_RUN_ORDERS")),
            "order_automation_enabled": bool(settings.get("ORDER_AUTOMATION_ENABLED")),
            "allowed_markets": settings.get("PMO_EXECUTOR_ALLOWED_MARKETS", []),
            "live_trading_enabled": bool(settings.get("PMO_LIVE_TRADING_ENABLED")),
        },
        "source_counts": {source: len([row for row in rows if source in row.get("sources", [])]) for source in sorted({source for row in rows for source in row.get("sources", [])})},
        "rows": rows,
        "files": {
            "json": str(PMO_V207_WATCHLIST_INTELLIGENCE_FILE),
            "csv": str(PMO_V207_WATCHLIST_INTELLIGENCE_CSV),
        },
    }
    if record:
        write_json_file(PMO_V207_WATCHLIST_INTELLIGENCE_FILE, payload)
        csv_rows = []
        for row in rows:
            csv_rows.append({
                **{key: value for key, value in row.items() if key not in {"sources", "source_details", "blockers", "information_feeds"}},
                "sources": " | ".join(row.get("sources", [])),
                "source_details": " | ".join(row.get("source_details", [])),
                "blockers": " | ".join(str(item) for item in row.get("blockers", [])),
                "information_feeds": " | ".join(row.get("information_feeds", [])),
            })
        write_csv_rows(PMO_V207_WATCHLIST_INTELLIGENCE_CSV, csv_rows)
        pmo_append_report_archive({
            "timestamp": payload["updated"],
            "type": "PMO_V207_WATCHLIST_INTELLIGENCE",
            "title": "PMO v207 Watchlist Intelligence",
            "path": str(PMO_V207_WATCHLIST_INTELLIGENCE_FILE),
            "summary": summary,
        })
    return payload


def pmo_append_report_archive(entry: Dict[str, Any]) -> Dict[str, Any]:
    archive = read_json_file(PMO_REPORT_ARCHIVE_FILE, {"items": []})
    items = archive.get("items", []) if isinstance(archive, dict) else []
    items.append(entry)
    archive = {"ok": True, "updated": now_et().isoformat(), "items": items[-200:]}
    write_json_file(PMO_REPORT_ARCHIVE_FILE, archive)
    return archive


