def pmo_sentiment_status(settings: Optional[Dict[str, Any]] = None, force: bool = False) -> Dict[str, Any]:
    settings = settings or load_settings()
    if not bool(settings.get("ENABLE_PMO_SENTIMENT_ENGINE", True)):
        return {
            "ok": True,
            "enabled": False,
            "available": PMO_SENTIMENT_ENGINE_AVAILABLE,
            "signal": "OFF",
            "score": 0,
            "journal": {},
            "error": "",
        }
    if not PMO_SENTIMENT_ENGINE_AVAILABLE or _SENTIMENT_ENGINE is None:
        return {
            "ok": False,
            "enabled": True,
            "available": False,
            "signal": "UNAVAILABLE",
            "score": 0,
            "journal": {},
            "error": PMO_SENTIMENT_ENGINE_ERROR or "sentiment engine unavailable",
        }
    try:
        result = _SENTIMENT_ENGINE.read(force=force)
        dashboard = result.get_dashboard_dict()
        journal = result.get_journal_dict()
        return {
            "ok": True,
            "enabled": True,
            "available": True,
            **dashboard,
            "journal": journal,
            "error": result.error or "",
        }
    except Exception as exc:
        return {
            "ok": False,
            "enabled": True,
            "available": True,
            "signal": "ERROR",
            "score": 0,
            "journal": {},
            "error": str(exc)[:180],
        }


def pmo_init_ml_engine(settings: Optional[Dict[str, Any]] = None, force: bool = False) -> Dict[str, Any]:
    settings = settings or load_settings()
    if not bool(settings.get("ENABLE_PMO_ML_ENGINE", True)):
        return {"ok": True, "enabled": False, "available": PMO_ML_ENGINE_AVAILABLE, "trained": False, "training_trades": 0, "error": ""}
    if not PMO_ML_ENGINE_AVAILABLE or _ML_ENGINE is None:
        return {"ok": False, "enabled": True, "available": False, "trained": False, "training_trades": 0, "error": PMO_ML_ENGINE_ERROR or "ML engine unavailable"}
    try:
        if force or not bool(getattr(_ML_ENGINE, "is_trained", False)):
            exclude_blocklist = bool(settings.get("PMO_ML_EXCLUDE_BLOCKLIST", settings.get("PMO_CUSTOM_MODEL_EXCLUDE_BLOCKLIST", True)))
            training_source: Any = pmo_closed_trade_rows_for_learning(settings, exclude_blocklist=exclude_blocklist) if exclude_blocklist else str(TRADE_JOURNAL_FILE)
            _ML_ENGINE.train(training_source)
        return {
            "ok": True,
            "enabled": True,
            "available": True,
            "trained": bool(getattr(_ML_ENGINE, "is_trained", False)),
            "training_trades": int(getattr(_ML_ENGINE, "training_trades", 0) or 0),
            "training_filter": "EXCLUDE_SYMBOL_BLOCKLIST" if bool(settings.get("PMO_ML_EXCLUDE_BLOCKLIST", settings.get("PMO_CUSTOM_MODEL_EXCLUDE_BLOCKLIST", True))) else "ALL_CLOSED_TRADES",
            "excluded_symbols": sorted(pmo_symbol_blocklist(settings)) if bool(settings.get("PMO_ML_EXCLUDE_BLOCKLIST", settings.get("PMO_CUSTOM_MODEL_EXCLUDE_BLOCKLIST", True))) else [],
            "confidence": (
                "HIGH" if int(getattr(_ML_ENGINE, "training_trades", 0) or 0) >= 200
                else "MEDIUM" if int(getattr(_ML_ENGINE, "training_trades", 0) or 0) >= 100
                else "LOW"
            ),
            "error": "",
        }
    except Exception as exc:
        return {"ok": False, "enabled": True, "available": True, "trained": False, "training_trades": int(getattr(_ML_ENGINE, "training_trades", 0) or 0), "training_filter": "ERROR", "error": str(exc)[:180]}


def pmo_ml_prediction_status(settings: Optional[Dict[str, Any]] = None, features: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    settings = settings or load_settings()
    init = pmo_init_ml_engine(settings, force=False)
    if not init.get("ok") or not init.get("trained") or not _ML_ENGINE:
        return {
            "ok": bool(init.get("ok")),
            "enabled": bool(init.get("enabled", True)),
            "available": bool(init.get("available", False)),
            "model_ready": False,
            "training_trades": init.get("training_trades", 0),
            "signal": "NEUTRAL",
            "win_prob": 50.0,
            "confidence": "LOW",
            "warning": init.get("error") or "ML model not trained yet.",
            "journal": {},
        }
    try:
        default_features = {
            "pmo_score": 70,
            "pattern_score_mod": 0,
            "sentiment_score": 0,
            "nlp_score": 0,
            "rvol": 1.5,
            "vwap_position": 0,
            "hold_time_min": 60,
            "entry_hour": now_et().hour,
            "day_of_week": now_et().weekday(),
            "score_band": 0,
        }
        default_features.update(features or {})
        result = _ML_ENGINE.predict(default_features)
        return {
            "ok": True,
            "enabled": True,
            "available": True,
            **result.get_dashboard_dict(),
            "journal": result.get_journal_dict(),
            "training_filter": init.get("training_filter", ""),
            "excluded_symbols": init.get("excluded_symbols", []),
        }
    except Exception as exc:
        return {
            "ok": False,
            "enabled": True,
            "available": True,
            "model_ready": False,
            "training_trades": init.get("training_trades", 0),
            "signal": "ERROR",
            "win_prob": 50.0,
            "confidence": "LOW",
            "warning": str(exc)[:180],
            "journal": {},
        }


def pmo_ai_engine_candidate_snapshot(
    settings: Optional[Dict[str, Any]] = None,
    *,
    score: float = 70,
    pattern: Optional[Dict[str, Any]] = None,
    sentiment: Optional[Dict[str, Any]] = None,
    rvol: float = 1.0,
    vwap_position: float = 0.0,
) -> Dict[str, Any]:
    settings = settings or load_settings()
    if isinstance(sentiment, dict):
        sentiment_data = sentiment
    elif (
        bool(settings.get("ENABLE_PMO_SENTIMENT_ENGINE", True))
        and PMO_SENTIMENT_ENGINE_AVAILABLE
        and _SENTIMENT_ENGINE is not None
        and bool(getattr(_SENTIMENT_ENGINE, "_is_cache_valid", lambda: False)())
    ):
        sentiment_data = pmo_sentiment_status(settings, force=False)
    else:
        sentiment_data = {
            "ok": True,
            "enabled": bool(settings.get("ENABLE_PMO_SENTIMENT_ENGINE", True)),
            "available": PMO_SENTIMENT_ENGINE_AVAILABLE,
            "signal": "NEUTRAL",
            "score": 0,
            "journal": {},
            "error": "sentiment not cached; refresh /api/ai-engines/status",
        }
    pattern = pattern or {}
    features = {
        "pmo_score": safe_float(score, 70),
        "pattern_score_mod": safe_float(pattern.get("pattern_score_mod"), 0),
        "sentiment_score": safe_float(sentiment_data.get("score"), 0),
        "rvol": safe_float(rvol, 1.0),
        "vwap_position": safe_float(vwap_position, 0),
        "hold_time_min": 60,
        "entry_hour": now_et().hour,
        "day_of_week": now_et().weekday(),
        "score_band": 0 if safe_float(score, 0) < 75 else (1 if safe_float(score, 0) < 85 else 2),
    }
    ml_data = pmo_ml_prediction_status(settings, features)
    return {
        "sentiment": sentiment_data,
        "ml": ml_data,
        "features": features,
        "score_influence": False,
        "orders_placed": False,
        "live_trading_changed": False,
    }


def pmo_ai_engines_status(settings: Optional[Dict[str, Any]] = None, force_sentiment: bool = False, retrain_ml: bool = False) -> Dict[str, Any]:
    settings = settings or load_settings()
    sentiment = pmo_sentiment_status(settings, force=force_sentiment)
    if retrain_ml:
        pmo_init_ml_engine(settings, force=True)
    ml = pmo_ml_prediction_status(settings, {"sentiment_score": safe_float(sentiment.get("score"), 0)})
    payload = {
        "ok": True,
        "updated": now_et().isoformat(),
        "mode": "OBSERVE_ONLY",
        "sentiment": sentiment,
        "ml": ml,
        "nlp": {
            "ok": False,
            "available": False,
            "enabled": False,
            "signal": "NOT_INSTALLED",
            "note": "pmo_nlp_engine.py was not included in this attachment batch.",
        },
        "safety": {
            "score_influence": bool(settings.get("PMO_ML_ALLOW_SCORE_INFLUENCE", False)) and False,
            "orders_placed": False,
            "live_trading_changed": False,
            "live_unlocked": False,
        },
    }
    try:
        write_json_file(REPORT_DIR / "pmo_ai_engines_status.json", payload)
    except Exception:
        pass
    return payload


