def pmo_ensure_intelligence_bundle_loaded(force: bool = False) -> Dict[str, Any]:
    global _intelligence_bundle_loaded, _intelligence_bundle_loaded_rows
    if not PMO_INTELLIGENCE_BUNDLE_AVAILABLE or _INTELLIGENCE_BUNDLE is None:
        return {"ok": False, "loaded": False, "rows": 0, "error": PMO_INTELLIGENCE_BUNDLE_ERROR or "Intelligence bundle unavailable."}
    if _intelligence_bundle_loaded and not force:
        return {"ok": True, "loaded": True, "rows": _intelligence_bundle_loaded_rows, "error": ""}
    try:
        rows = int(_INTELLIGENCE_BUNDLE.load_journal(str(TRADE_JOURNAL_FILE)) or 0)
        _intelligence_bundle_loaded = True
        _intelligence_bundle_loaded_rows = rows
        return {"ok": True, "loaded": True, "rows": rows, "error": ""}
    except Exception as exc:
        _intelligence_bundle_loaded = False
        _intelligence_bundle_loaded_rows = 0
        return {"ok": False, "loaded": False, "rows": 0, "error": str(exc)[:180]}


def pmo_intelligence_prepare_rows(rows: Iterable[Dict[str, Any]]) -> List[Dict[str, Any]]:
    prepared: List[Dict[str, Any]] = []
    for row in rows or []:
        close = safe_float(row.get("close") or row.get("c"), 0)
        if close <= 0:
            continue
        timestamp = row.get("datetime") or row.get("date") or row.get("timestamp") or row.get("time") or row.get("t") or ""
        prepared.append({
            "datetime": timestamp,
            "date": timestamp,
            "open": safe_float(row.get("open") or row.get("o"), close),
            "high": safe_float(row.get("high") or row.get("h"), close),
            "low": safe_float(row.get("low") or row.get("l"), close),
            "close": close,
            "volume": safe_float(row.get("volume") or row.get("v"), 0),
        })
    return prepared


def pmo_analyze_intelligence_bundle(
    symbol: str,
    trade_direction: str,
    settings: Optional[Dict[str, Any]] = None,
    *,
    score: float = 0.0,
    rvol: float = 1.0,
    regime: str = "MIXED",
    pattern: Optional[Dict[str, Any]] = None,
    refresh_journal: bool = False,
) -> Dict[str, Any]:
    global _latest_intelligence_bundle_result, _latest_intelligence_bundle_journal
    settings = settings or load_settings()
    if not bool(settings.get("PMO_INTELLIGENCE_ENABLED", True)):
        return pmo_intelligence_bundle_empty("OFF", "PMO_INTELLIGENCE_ENABLED is false.")
    if not bool(settings.get("PMO_INTELLIGENCE_READ_ONLY", True)):
        # Fail closed: this layer is approved only as read-only research.
        return pmo_intelligence_bundle_empty("LOCKED", "PMO_INTELLIGENCE_READ_ONLY must stay true before bundle analysis runs.")
    if not PMO_INTELLIGENCE_BUNDLE_AVAILABLE or _INTELLIGENCE_BUNDLE is None:
        return pmo_intelligence_bundle_empty("UNAVAILABLE", PMO_INTELLIGENCE_BUNDLE_ERROR or "Intelligence bundle unavailable.")
    load_state = pmo_ensure_intelligence_bundle_loaded(force=refresh_journal)
    now = now_et()
    clean_symbol = str(symbol or "").strip().upper()
    try:
        lookback = int(max(20, safe_float(settings.get("PMO_INTRADAY_BARS_LOOKBACK", 78), 78)))
        intraday_rows = pmo_intelligence_prepare_rows(pmo_edge_load_ohlcv_rows(clean_symbol, intraday=True, limit=lookback))
        daily_rows = pmo_intelligence_prepare_rows(pmo_edge_load_ohlcv_rows(clean_symbol, intraday=False, limit=30))
        pattern_name = ""
        if isinstance(pattern, dict):
            pattern_name = str(pattern.get("pattern_name") or "").strip()
            if pattern_name.upper() in {"NONE", "NO_PATTERN"}:
                pattern_name = ""
        result = _INTELLIGENCE_BUNDLE.analyze(
            ticker=clean_symbol,
            bars=intraday_rows,
            daily_bars=daily_rows,
            regime=str(regime or "MIXED").upper(),
            rvol=safe_float(rvol, 1.0),
            score=safe_float(score, 0.0),
            day_of_week=now.weekday(),
            pattern_name=pattern_name or None,
            trade_direction=str(trade_direction or "long").lower(),
            today=now.date(),
            current_hour_et=now.hour,
            current_minute=now.minute,
            blocklist=pmo_symbol_blocklist(settings),
        )
        journal = result.get_journal_dict()
        dashboard = result.get_dashboard_dict()
        payload = {
            "ok": True,
            "enabled": True,
            "available": True,
            "status": "READY",
            "symbol": clean_symbol,
            "updated": now.isoformat(),
            "read_only": True,
            "score_influence": False,
            "orders_placed": False,
            "live_unlocked": False,
            "settings_changed": False,
            "journal_loaded": bool(load_state.get("loaded")),
            "journal_loaded_rows": int(load_state.get("rows", 0) or 0),
            "intraday_rows": len(intraday_rows),
            "daily_rows": len(daily_rows),
            "dashboard": dashboard,
            "journal": journal,
            "combined": dashboard.get("combined", {}),
            "error": "",
        }
        _latest_intelligence_bundle_result = payload
        _latest_intelligence_bundle_journal = journal
        return payload
    except Exception as exc:
        payload = pmo_intelligence_bundle_empty("ERROR", f"Intelligence bundle error: {str(exc)[:140]}")
        payload.update({"enabled": True, "symbol": clean_symbol, "updated": now.isoformat(), "error": str(exc)[:180]})
        _latest_intelligence_bundle_result = payload
        _latest_intelligence_bundle_journal = payload.get("journal", {})
        return payload


def pmo_latest_intelligence_bundle_snapshot(settings: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    settings = settings or load_settings()
    if not bool(settings.get("PMO_INTELLIGENCE_ENABLED", True)):
        return pmo_intelligence_bundle_empty("OFF", "PMO_INTELLIGENCE_ENABLED is false.")
    if _latest_intelligence_bundle_result:
        return dict(_latest_intelligence_bundle_result)
    payload = pmo_intelligence_bundle_empty("WAITING", "No scored signal has run through the intelligence bundle yet.")
    payload.update({
        "enabled": True,
        "available": PMO_INTELLIGENCE_BUNDLE_AVAILABLE,
        "journal_loaded_rows": _intelligence_bundle_loaded_rows,
        "journal_loaded": _intelligence_bundle_loaded,
    })
    return payload


