    "/api/all-day/watchtower/start",
    "/api/safety/preset",
    "/api/safety/paper-safe",
    "/api/safety/stock-paper-executor",
    "/api/crypto/paper/enable",
    "/api/crypto/research-only",
    "/api/score/audit",
    "/api/regime/advisor",
    "/api/intelligence/email-latest",
    "/api/custom-model/train",
