MOBILE_STATUS_TEMPLATE = """
<!doctype html>
<html>
<head>
    <title>PMO BOT Mobile Status</title>
    <meta name="viewport" content="width=device-width, initial-scale=1">
    <style>
        :root { color-scheme:dark; --bg:#05070a; --panel:#101722; --panel2:#0b111a; --line:#26364a; --text:#edf4ff; --muted:#9fb3c8; --green:#00ff9d; --red:#ff5c7a; --yellow:#ffd166; --blue:#7ab7ff; }
        * { box-sizing:border-box; }
        body { margin:0; background:var(--bg); color:var(--text); font-family:Arial, sans-serif; }
        header { padding:16px; background:var(--panel2); border-bottom:1px solid var(--line); display:flex; gap:12px; align-items:center; }
        .logo { width:58px; height:58px; object-fit:contain; flex-shrink:0; }
        h1 { margin:0; font-size:24px; letter-spacing:0; }
        h2 { margin:0 0 10px 0; font-size:18px; letter-spacing:0; }
        h3 { margin:0 0 8px 0; font-size:15px; letter-spacing:0; }
        main { padding:12px; display:grid; gap:12px; }
        .card { background:var(--panel); border:1px solid var(--line); border-radius:8px; padding:14px; }
        .hero { border-color:rgba(0,255,157,.45); }
        .grid { display:grid; grid-template-columns:1fr 1fr; gap:10px; }
        .metric { font-size:27px; font-weight:bold; margin-top:4px; overflow-wrap:anywhere; }
        .label, .muted { color:var(--muted); font-size:12px; line-height:1.4; }
        .green { color:var(--green); } .red { color:var(--red); } .yellow { color:var(--yellow); } .blue { color:var(--blue); }
        .pill { display:inline-flex; border:1px solid #34475f; border-radius:6px; padding:5px 7px; margin:3px 3px 0 0; font-size:12px; background:#172130; color:#eaf2ff; }
        .pill.ok { border-color:rgba(0,255,157,.55); color:#bfffe8; }
        .pill.bad { border-color:rgba(255,92,122,.55); color:#ffd3dc; }
        table { width:100%; border-collapse:collapse; font-size:12px; }
        th, td { border-bottom:1px solid var(--line); padding:7px 4px; text-align:left; vertical-align:top; }
        th { color:#dbe9fa; }
        footer { padding:14px; color:var(--muted); font-size:12px; text-align:center; }
        @media(max-width:520px) { .grid { grid-template-columns:1fr; } header { align-items:flex-start; } h1 { font-size:21px; } .metric { font-size:24px; } }
    </style>
</head>
<body>
<header>
    <img class="logo" src="/logo.png?v={{ logo_version }}" alt="PMO BOT">
    <div>
        <h1>PMO BOT Mobile</h1>
        <div class="muted">Read-only status | {{ now }} ET</div>
        <span class="pill {{ 'ok' if settings.ALPACA_PAPER else 'bad' }}">Paper {{ settings.ALPACA_PAPER }}</span>
        <span class="pill {{ 'ok' if not settings.PMO_LIVE_TRADING_ENABLED else 'bad' }}">Live Master {{ 'ON' if settings.PMO_LIVE_TRADING_ENABLED else 'OFF' }}</span>
    </div>
</header>
<main>
    <section class="card hero">
        <h2>Operations Readiness</h2>
        <div class="grid">
            <div><div class="label">Operation Score</div><div class="metric {{ 'green' if operations.score >= 100 else 'yellow' if operations.score >= 85 else 'red' }}">{{ operations.score }}%</div></div>
            <div><div class="label">Status</div><div class="metric {{ 'green' if operations.score >= 100 else 'yellow' if operations.score >= 85 else 'red' }}">{{ operations.status }}</div></div>
            <div><div class="label">Green Checks</div><div class="metric blue">{{ operations.ready_count }}/{{ operations.total }}</div></div>
            <div><div class="label">Connections</div><div class="metric">{{ health.online }}/{{ health.total }}</div></div>
        </div>
        <div class="muted" style="margin-top:10px;">{{ operations.recommendation }}</div>
    </section>

    <section class="card">
        <h2>Live Ops Dashboard</h2>
        <div class="grid">
            <div><div class="label">PMO State</div><div class="metric {{ 'green' if live_ops.live_ready else 'yellow' }}">{{ live_ops.mode }}</div></div>
            <div><div class="label">Open Positions</div><div class="metric blue">{{ live_ops.positions }}</div></div>
            <div><div class="label">Buying Power Used</div><div class="metric yellow">{{ live_ops.buying_power_used_pct }}%</div></div>
            <div><div class="label">Market Regime</div><div class="metric">{{ regime.regime }}</div></div>
        </div>
        <div class="muted" style="margin-top:10px;">Emergency safe state: {{ live_ops.emergency_state }}</div>
    </section>

    <section class="card">
        <h2>Broker Reconciliation</h2>
        <div class="grid">
            <div><div class="label">Reconciliation</div><div class="metric {{ 'green' if reconciliation.status == 'SYNCED' else 'red' }}">{{ reconciliation.status }}</div></div>
            <div><div class="label">Open Orders</div><div class="metric yellow">{{ reconciliation.open_orders_count }}</div></div>
            <div><div class="label">Positions</div><div class="metric blue">{{ reconciliation.positions_count }}</div></div>
            <div><div class="label">Updated</div><div class="metric blue">{{ reconciliation.updated[:10] }}</div></div>
        </div>
        <div class="muted" style="margin-top:10px;">{{ reconciliation.recommendation }}</div>
    </section>

    <section class="card">
        <h3>Operations Checks</h3>
        <table>
            <tr><th>Check</th><th>Status</th></tr>
            {% for row in operations.checks[:10] %}
            <tr><td>{{ row.name }}</td><td class="{{ 'green' if row.ready else 'red' }}">{{ 'READY' if row.ready else 'FIX' }}</td></tr>
            {% endfor %}
        </table>
    </section>

    <section class="card">
        <h3>Broker Checks</h3>
        <table>
            <tr><th>Check</th><th>Status</th><th>Action</th></tr>
            {% for row in reconciliation.checks %}
            <tr><td>{{ row.name }}</td><td class="{{ 'green' if row.status == 'OK' else 'red' if row.status in ['BLOCK', 'OFFLINE'] else 'yellow' }}">{{ row.status }}</td><td>{{ row.action }}</td></tr>
            {% endfor %}
        </table>
    </section>

    <section class="card">
        <h3>Watchlist Snapshot</h3>
        <table>
            <tr><th>Symbol</th><th>Score</th><th>Bias</th></tr>
            {% for row in watchlist_rows[:8] %}
            <tr><td>{{ row.symbol }}</td><td>{{ row.score }}</td><td>{{ row.bias }}</td></tr>
            {% else %}
            <tr><td colspan="3">Run Auto Build Watchlist from the desktop dashboard.</td></tr>
            {% endfor %}
        </table>
    </section>
</main>
<footer>Read-only mobile view. Full PMO controls stay on the desktop dashboard.</footer>
</body>
</html>
"""


SUBSCRIPTION_TEMPLATE = """
<!doctype html>
<html>
<head>
    <title>PMO Bot Subscription Center</title>
    <meta name="viewport" content="width=device-width, initial-scale=1">
    {% if paypal_sdk_ready %}
    <script src="https://www.paypal.com/sdk/js?client-id={{ subscription_hub.paypal_client_id }}&vault=true&intent=subscription"></script>
    {% endif %}
    <style>
        :root { color-scheme:dark; --bg:#05070a; --panel:#101722; --panel2:#0b111a; --line:#26364a; --text:#edf4ff; --muted:#9fb3c8; --green:#00ff9d; --red:#ff5c7a; --yellow:#ffd166; --blue:#7ab7ff; }
        * { box-sizing:border-box; }
        body { margin:0; background:var(--bg); color:var(--text); font-family:Arial, sans-serif; }
        header { padding:22px 24px; background:var(--panel2); border-bottom:1px solid var(--line); display:grid; grid-template-columns:minmax(280px,1fr) auto; gap:16px; align-items:center; }
        .brand { display:flex; align-items:center; gap:16px; min-width:0; }
        .logo { width:104px; height:104px; object-fit:contain; flex-shrink:0; filter:drop-shadow(0 0 14px rgba(0,255,157,.22)); }
        h1 { margin:0 0 6px 0; font-size:34px; letter-spacing:0; }
        h2 { margin:0 0 10px 0; font-size:20px; letter-spacing:0; }
        h3 { margin:0 0 8px 0; font-size:16px; letter-spacing:0; }
        .tagline { color:var(--green); font-size:12px; font-weight:bold; margin-bottom:8px; }
        .muted { color:var(--muted); font-size:12px; line-height:1.45; }
        main { padding:18px; display:grid; gap:14px; }
        .grid { display:grid; grid-template-columns:repeat(auto-fit,minmax(230px,1fr)); gap:14px; }
        .wide-grid { display:grid; grid-template-columns:repeat(auto-fit,minmax(320px,1fr)); gap:14px; }
        .card { background:var(--panel); border:1px solid var(--line); border-radius:8px; padding:16px; min-width:0; }
        .tier-card { display:flex; flex-direction:column; gap:8px; }
        .metric { font-size:30px; font-weight:bold; margin-top:6px; overflow-wrap:anywhere; }
        .green { color:var(--green); } .red { color:var(--red); } .yellow { color:var(--yellow); } .blue { color:var(--blue); }
        .pill { display:inline-block; border:1px solid #34475f; border-radius:6px; padding:5px 8px; margin:3px; font-size:12px; background:#172130; color:#eaf2ff; text-decoration:none; }
        .pill.ok { border-color:rgba(0,255,157,.55); color:#bfffe8; }
        .pill.bad { border-color:rgba(255,92,122,.55); color:#ffd3dc; }
        .row { display:flex; gap:8px; flex-wrap:wrap; align-items:center; }
        button, input, select, textarea, a.button-link { background:#172130; border:1px solid #34475f; color:var(--text); border-radius:6px; padding:9px; font:inherit; text-decoration:none; }
        button, a.button-link { cursor:pointer; font-weight:bold; display:inline-block; text-align:center; }
        textarea { min-height:70px; resize:vertical; }
        .form-grid { display:grid; grid-template-columns:repeat(auto-fit,minmax(180px,1fr)); gap:8px; align-items:end; }
        table { width:100%; border-collapse:collapse; font-size:13px; }
        th, td { border-bottom:1px solid var(--line); padding:8px; text-align:left; vertical-align:top; }
        th { color:#dbe9fa; font-size:12px; }
        .table-wrap { overflow:auto; }
        pre { white-space:pre-wrap; overflow:auto; max-height:220px; }
        @media(max-width:860px){ header{grid-template-columns:1fr;} .logo{width:88px;height:88px;} h1{font-size:28px;} }
    </style>
</head>
<body>
<header>
    <div class="brand">
        <img class="logo" src="/logo.png?v={{ logo_version }}" alt="PMO BOT">
        <div>
            <h1>PMO Bot Subscription Center</h1>
            <div class="tagline">PRECISION. MOMENTUM. OPPORTUNITY.</div>
            <div class="muted">PMO Bot subscriptions, installer access, purchase requests, and payment setup.</div>
        </div>
    </div>
    <div>
        <a class="pill" href="/control">PMO Terminal</a>
        <a class="pill" href="/api/install/windows">Windows Installer</a>
        <span class="pill {{ 'ok' if subscription_hub.configured_count else 'bad' }}">Checkout {{ subscription_hub.configured_count }}/{{ subscription_hub.total_count }}</span>
    </div>
</header>
<main>
    <section class="card">
        <h2>PMO Bot Shop</h2>
        <div class="muted">Request PMO Bot access, setup support, and installer access. Trading results are not guaranteed and live trading remains controlled by PMO safety gates.</div>
    </section>

    <section class="grid">
        {% for tier in subscription_hub.tiers %}
        <div class="card tier-card">
            <h3>{{ tier.name }}</h3>
            <div class="metric green">${{ tier.price }}<span class="muted"> / month</span></div>
            <div class="muted">Setup: ${{ tier.setup }} | {{ tier.notes }}</div>
            <div>
                {% for feature in tier.features %}
                <span class="pill">{{ feature }}</span>
                {% endfor %}
            </div>
            <div class="muted">Route: {{ tier.payment_route }}</div>
            {% if tier.checkout_url %}
            <a class="button-link" href="{{ tier.checkout_url }}" target="_blank" rel="noopener">Subscribe Now</a>
            {% elif tier.paypal_plan_id and subscription_hub.paypal_client_id %}
            <div id="paypal-button-{{ tier.slug }}"></div>
            {% else %}
            <button class="requestTierButton" data-tier="{{ tier.slug }}">Request Purchase Setup</button>
            {% endif %}
        </div>
        {% endfor %}
    </section>

    <section class="wide-grid">
        <div class="card">
            <h3>Purchase Request</h3>
            <div class="form-grid">
                <select id="leadTier">{% for tier in subscription_hub.tiers %}<option value="{{ tier.slug }}">{{ tier.name }} - ${{ tier.price }}/mo</option>{% endfor %}</select>
                <input id="leadName" placeholder="Name">
                <input id="leadEmail" placeholder="Email">
                <input id="leadPhone" placeholder="Phone optional">
            </div>
            <textarea id="leadNotes" style="width:100%; margin-top:8px;" placeholder="Setup notes, preferred payment route, or install request"></textarea>
            <div class="row" style="margin-top:8px;"><button id="submitLeadButton">Send PMO Purchase Request</button></div>
            <pre id="leadOut">Purchase request output will appear here.</pre>
        </div>
        <div class="card">
            <h3>PMO Auto Install Center</h3>
            <div class="muted">Customers can download the Windows installer helper after purchase. It is transparent, user-run, and does not perform hidden installs.</div>
            <div class="row" style="margin-top:10px;">
                <a class="button-link" href="/api/install/windows">Download Windows Installer</a>
                <a class="button-link" href="/api/install/manifest" target="_blank" rel="noopener">View Install Manifest</a>
            </div>
            <div class="table-wrap" style="margin-top:10px;"><table>
                <tr><th>Item</th><th>Status</th></tr>
                <tr><td>Release ZIP URL</td><td class="{{ 'green' if installer.release_zip_url_configured else 'yellow' }}">{{ 'CONFIGURED' if installer.release_zip_url_configured else 'SET PMO_RELEASE_ZIP_URL' }}</td></tr>
                <tr><td>Installer Mode</td><td>User-approved Windows helper</td></tr>
                <tr><td>Control URL</td><td>{{ installer.control_url }}</td></tr>
            </table></div>
        </div>
    </section>

    <section class="card">
        <h3>Recent Purchase Requests</h3>
        <div class="table-wrap"><table>
            <tr><th>Time</th><th>Tier</th><th>Name</th><th>Email</th><th>Status</th></tr>
            {% for lead in subscription_hub.latest_leads %}
            <tr><td>{{ lead.timestamp }}</td><td>{{ lead.tier }}</td><td>{{ lead.name }}</td><td>{{ lead.email }}</td><td>{{ lead.status }}</td></tr>
            {% else %}
            <tr><td colspan="5">No purchase requests logged yet.</td></tr>
            {% endfor %}
        </table></div>
    </section>
</main>
<script>
async function postJson(url, body) {
    const response = await fetch(url, {method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify(body || {})});
    const payload = await response.json();
    if (!response.ok || !payload.ok) throw new Error(payload.message || payload.error || 'PMO request failed');
    return payload;
}
async function submitLead(source) {
    const out = document.getElementById('leadOut');
    try {
        const payload = await postJson('/api/subscription-leads', {
            tier: document.getElementById('leadTier').value,
            name: document.getElementById('leadName').value,
            email: document.getElementById('leadEmail').value,
            phone: document.getElementById('leadPhone').value,
            notes: document.getElementById('leadNotes').value,
            source
        });
        out.textContent = JSON.stringify(payload.lead, null, 2);
    } catch (err) { out.textContent = err.message; }
}
document.getElementById('submitLeadButton').onclick = () => submitLead('subscription_page_form');
document.querySelectorAll('.requestTierButton').forEach(btn => {
    btn.onclick = () => {
        document.getElementById('leadTier').value = btn.dataset.tier;
        document.getElementById('leadNotes').focus();
        submitLead('tier_request_button');
    };
});
const pmoSubscriptionTiers = {{ subscription_hub.tiers|tojson }};
if (window.paypal) {
    pmoSubscriptionTiers.filter(t => t.paypal_plan_id).forEach(tier => {
        const target = document.getElementById('paypal-button-' + tier.slug);
        if (!target) return;
        paypal.Buttons({
            style: { shape:'rect', color:'gold', layout:'vertical', label:'subscribe' },
            createSubscription: function(data, actions) {
                return actions.subscription.create({ plan_id: tier.paypal_plan_id });
            },
            onApprove: async function(data) {
                document.getElementById('leadTier').value = tier.slug;
                document.getElementById('leadNotes').value = 'PayPal subscription approved: ' + data.subscriptionID;
                await submitLead('paypal_subscription_approved');
            }
        }).render(target);
    });
}
</script>
</body>
</html>
"""


