def pmo_realtime_stream_snapshot() -> Dict[str, Any]:
    settings = load_settings()
    bot.settings = settings
    paper_proof = pmo_fast_paper_proof_snapshot(settings)
    account = pmo_fast_account_snapshot(settings)
    return {
        "ok": True,
        "stream": True,
        "updated": now_et().isoformat(),
        "settings": settings,
        "account": account,
        "market_data_status": getattr(bot, "market_data_status", {}) or {},
        "execution": {
            "broker_order_executor_installed": True,
            "broker_order_execution_enabled": bool(settings.get("ENABLE_ALPACA_ORDER_EXECUTOR")),
            "mode": settings.get("PMO_ORDER_EXECUTION_MODE"),
            "ready": bool(settings.get("ENABLE_ALPACA_ORDER_EXECUTOR")) and str(settings.get("PMO_ORDER_EXECUTION_MODE", "")).upper() in {"PAPER_ALPACA", "PAPER_ONLY", "PAPER"},
        },
        "paper_proof": paper_proof,
    }


@app.route("/api/stream")
def api_stream():
    def generate():
        while True:
            try:
                payload = pmo_realtime_stream_snapshot()
            except Exception as exc:
                payload = {"ok": False, "stream": True, "error": str(exc), "updated": now_et().isoformat()}
            yield f"data: {json.dumps(payload, default=str)}\n\n"
            time.sleep(1)

    return Response(
        generate(),
        mimetype="text/event-stream",
        headers={
            "Cache-Control": "no-cache",
            "Connection": "keep-alive",
            "X-Accel-Buffering": "no",
        },
    )




