@app.route("/api/owner-command", methods=["POST"])
def api_owner_command():
    payload = request.get_json(force=True, silent=True) or {}
    locked = pmo_require_admin(payload)
    if locked:
        return locked, 403
    action = str(payload.get("action") or "owner_note").strip().lower()
    target = str(payload.get("target") or "").strip()
    notes = str(payload.get("notes") or "").strip()
    if payment_text_has_sensitive_terms(target, notes):
        return jsonify({"ok": False, "message": "Do not store passwords, SSNs, card numbers, CVV codes, routing/account numbers, seed phrases, or private keys in PMO owner commands."}), 400
    settings = load_settings()
    result: Dict[str, Any] = {"status": "LOGGED", "message": "Owner note logged."}
    if action == "switchboard_audit":
        health = bot.connection_check()
        account = bot.account_snapshot()
        regime = bot.market_regime()
        positions = open_positions()
        reconciliation = broker_reconciliation_snapshot(settings, account, positions)
        live_readiness = live_readiness_snapshot(settings, account, health, regime, reconciliation)
        feature_audit = pmo_feature_integrity_audit(settings, health, live_readiness, record=False)
        result = {"status": "COMPLETE", "audit": pmo_switchboard_audit(settings, health, live_readiness, feature_audit, record=True)}
    elif action == "refresh_connections":
        result = {"status": "COMPLETE", "health": bot.connection_check()}
    elif action == "safe_mode":
        preset = pmo_apply_switchboard_preset(settings, "pmo_safe_mode")
        write_settings(settings)
        bot.reload()
        result = {"status": "COMPLETE", "preset": preset}
    elif action == "system_review":
        result = {"status": "COMPLETE", "review": run_system_review_scan(notes or SYSTEM_REVIEW_PROMPT)}
    elif action == "refresh_watchlist":
        result = {"status": "COMPLETE", "auto_watchlist": bot.build_auto_watchlist(apply_to_settings=False)}
    elif action == "paper_proof":
        result = {"status": "COMPLETE", "paper_proof": pmo_paper_proof_snapshot(settings, record=True), "v112_proof": pmo_v112_proof_report(settings, record=True)}
    csv_append(PMO_BOT_OWNER_COMMANDS_FILE, {
        "timestamp": now_et().isoformat(),
        "action": action,
        "target": target,
        "notes": notes,
        "status": result.get("status", ""),
        "safe_note": "Owner command route cannot arm live trading.",
    })
    return jsonify({"ok": True, "action": action, "target": target, "result": result, "file": str(PMO_BOT_OWNER_COMMANDS_FILE)})


@app.route("/api/providers/setup", methods=["GET", "POST"])
def api_providers_setup():
    if request.method == "GET":
        providers = load_pmo_provider_setup()
        return jsonify({
            "ok": True,
            "providers": providers,
            "summary": {
                "count": len(providers),
                "ready": sum(1 for row in providers if "READY" in str(row.get("api_status", "")).upper() or "READY" in str(row.get("connection_status", "")).upper()),
                "file": str(PMO_BOT_PROVIDER_SETUP_FILE),
            },
        })
    payload = request.get_json(force=True, silent=True) or {}
    locked = pmo_require_admin(payload)
    if locked:
        return locked, 403
    providers = payload.get("providers")
    if not isinstance(providers, list):
        return jsonify({"ok": False, "message": "providers must be a list"}), 400
    for row in providers:
        if isinstance(row, dict) and payment_text_has_sensitive_terms(row.get("notes"), row.get("instructions")):
            return jsonify({"ok": False, "message": "Do not store passwords, card numbers, routing/account numbers, seed phrases, or private keys in provider setup notes."}), 400
    save_pmo_provider_setup(providers)
    providers = load_pmo_provider_setup()
    return jsonify({"ok": True, "providers": providers, "file": str(PMO_BOT_PROVIDER_SETUP_FILE)})


