@app.route("/api/cms/module/update", methods=["POST"])
def api_cms_module_update():
    payload = request.get_json(force=True, silent=True) or {}
    module_id = str(payload.get("id", "")).strip()
    if not module_id:
        return jsonify({"ok": False, "message": "module id is required"}), 400
    allowed = {"notes", "dashboard_section", "category", "module"}
    updates = {key: str(payload.get(key) or "").strip() for key in allowed if key in payload}
    if not updates:
        return jsonify({"ok": False, "message": "No editable CMS module fields were supplied."}), 400
    if payment_text_has_sensitive_terms(json.dumps(updates, default=str)):
        return jsonify({"ok": False, "message": "CMS module text cannot store passwords, private keys, card data, account numbers, or bank data."}), 400
    modules = pmo_cms_manual_modules()
    before = dict(modules.get(module_id, {})) if isinstance(modules.get(module_id, {}), dict) else {}
    modules[module_id] = {**before, **updates, "updated": now_et().isoformat()}
    write_json_file(PMO_CMS_MODULES_FILE, modules)
    pmo_cms_audit("module_update", module=module_id, old_value=before, new_value=modules[module_id], notes="CMS module label/notes update")
    return jsonify({"ok": True, "module": modules[module_id], "modules": pmo_cms_module_registry(load_settings()), "file": str(PMO_CMS_MODULES_FILE)})


@app.route("/api/cms/layout", methods=["GET", "POST"])
def api_cms_layout():
    if request.method == "GET":
        layout = load_pmo_dashboard_layout()
        cms_layout = read_json_file(PMO_CMS_LAYOUT_FILE, {})
        if not isinstance(cms_layout, dict):
            cms_layout = {}
        return jsonify({"ok": True, "layout": layout, "cms_layout": cms_layout, "file": str(PMO_BOT_DASHBOARD_LAYOUT_FILE), "cms_file": str(PMO_CMS_LAYOUT_FILE)})
    payload = request.get_json(force=True, silent=True) or {}
    if bool(payload.get("reset", False)):
        saved = default_dashboard_layout()
        write_json_file(PMO_BOT_DASHBOARD_LAYOUT_FILE, saved)
        write_json_file(PMO_CMS_LAYOUT_FILE, {"updated": now_et().isoformat(), "layout": saved, "reset": True})
        pmo_cms_audit("layout_reset", module="Dashboard Layout", new_value={"sections": len(saved.get("sections", {}))}, notes="CMS layout reset to defaults")
        return jsonify({"ok": True, "layout": saved, "file": str(PMO_BOT_DASHBOARD_LAYOUT_FILE), "cms_file": str(PMO_CMS_LAYOUT_FILE), "message": "Dashboard layout reset to defaults."})
    layout = payload.get("layout")
    if not isinstance(layout, dict):
        return jsonify({"ok": False, "message": "layout must be an object"}), 400
    saved = save_pmo_dashboard_layout(layout)
    write_json_file(PMO_CMS_LAYOUT_FILE, {"updated": now_et().isoformat(), "layout": saved})
    pmo_cms_audit("layout_save", module="Dashboard Layout", new_value={"sections": len(saved.get("sections", {}))}, notes="CMS layout save through existing dashboard layout system")
    return jsonify({"ok": True, "layout": saved, "file": str(PMO_BOT_DASHBOARD_LAYOUT_FILE), "cms_file": str(PMO_CMS_LAYOUT_FILE)})


@app.route("/api/cms/content", methods=["GET", "POST"])
def api_cms_content():
    if request.method == "GET":
        return jsonify({"ok": True, "content": pmo_cms_content(), "file": str(PMO_CMS_CONTENT_FILE)})
    payload = request.get_json(force=True, silent=True) or {}
    reset = bool(payload.get("reset", False))
    content = pmo_cms_default_content() if reset else payload.get("content")
    if not isinstance(content, dict):
        return jsonify({"ok": False, "message": "content must be an object"}), 400
    content = pmo_cms_sanitize_content(content)
    if payment_text_has_sensitive_terms(json.dumps(content, default=str)):
        return jsonify({"ok": False, "message": "CMS content cannot store passwords, private keys, card data, account numbers, or bank data."}), 400
    before = pmo_cms_content()
    write_json_file(PMO_CMS_CONTENT_FILE, content)
    pmo_cms_audit("content_reset" if reset else "content_save", module="Content/Text CMS", old_value={"sections": len(before.get("sections", {}))}, new_value={"sections": len(content.get("sections", {}))}, notes="CMS content text save")
    return jsonify({"ok": True, "content": content, "file": str(PMO_CMS_CONTENT_FILE)})


