@app.route("/api/reports/open", methods=["GET"])
def api_reports_open():
    raw = request.args.get("path", "")
    path = Path(raw).resolve(strict=False)
    allowed_roots = (REPORT_DIR, CSV_DIR, PINE_DIR)
    root_pine_file = path.suffix.lower() == ".pine" and path.parent.resolve(strict=False) == PMO_ROOT.resolve(strict=False)
    root_log_file = path.suffix.lower() == ".log" and path.parent.resolve(strict=False) == PMO_DIR.resolve(strict=False)
    allowed_suffixes = {".csv", ".html", ".jpeg", ".jpg", ".json", ".log", ".pdf", ".pine", ".png", ".svg", ".txt", ".xlsx"}
    blocked_names = {".env", "pmo_settings.py", "pmo_bot.py"}
    if (
        not path.exists()
        or path.name in blocked_names
        or path.name.startswith(".")
        or path.suffix.lower() not in allowed_suffixes
        or not (root_pine_file or root_log_file or any(is_path_inside(path, root) for root in allowed_roots))
    ):
        return jsonify({"ok": False, "message": "report path is outside the approved PMO report areas or is not a report file"}), 404
    if path.suffix.lower() in {".json", ".csv", ".log", ".txt", ".pine"}:
        return send_file(path, mimetype="text/plain")
    return send_file(path)


@app.route("/api/dashboard/button-audit", methods=["POST"])
def api_dashboard_button_audit():
    payload = request.get_json(force=True, silent=True) or {}
    buttons = payload.get("buttons") if isinstance(payload.get("buttons"), list) else []
    for button in buttons:
        if not isinstance(button, dict):
            continue
        csv_append(PMO_BOT_BUTTON_AUDIT_FILE, {
            "timestamp": now_et().isoformat(),
            "button_id": button.get("id", ""),
            "text": button.get("text", ""),
            "classes": button.get("classes", ""),
            "bound": button.get("bound", ""),
            "disabled": button.get("disabled", ""),
            "section": button.get("section", ""),
        })
    dead = [button for button in buttons if isinstance(button, dict) and not button.get("bound")]
    return jsonify({
        "ok": True,
        "summary": {"total": len(buttons), "unbound": len(dead), "file": str(PMO_BOT_BUTTON_AUDIT_FILE)},
        "unbound_buttons": dead[:50],
    })


