def pmo_asset_universe_payload(settings: Dict[str, Any], account: Optional[Dict[str, Any]] = None, record: bool = False) -> Dict[str, Any]:
    account = account or {}
    snapshot = build_asset_universe_snapshot(settings, account)
    matrix = build_market_capability_matrix(settings, account)
    unsupported = {
        "ok": True,
        "unsupported": snapshot.get("unsupported", []),
        "needs_data": snapshot.get("needs_data", []),
        "missing_integrations": [
            "Futures broker missing",
            "Forex broker missing",
            "Fixed-income broker missing",
            "Mutual fund trading API missing",
            "Tokenized asset provider missing",
            "Event contract provider missing",
        ],
    }
    proof_report = {
        "ok": True,
        "proof_by_asset_class": {
            row["asset_class"]: row.get("proof_requirements", {})
            for row in snapshot.get("rows", [])
            if row["asset_class"] in {"STOCK", "ETF", "CRYPTO_SPOT", "STOCK_OPTION", "ETF_OPTION", "INDEX_OPTION", "EQUITY_INDEX_FUTURE", "FOREX_SPOT", "LEVERAGED_ETF"}
        },
    }
    if record:
        write_json_file(PMO_ASSET_UNIVERSE_SNAPSHOT_FILE, snapshot)
        write_json_file(PMO_MARKET_CAPABILITY_MATRIX_FILE, matrix)
        write_json_file(PMO_UNSUPPORTED_ASSET_REPORT_FILE, unsupported)
        write_json_file(PMO_ASSET_CLASS_PROOF_REPORT_FILE, proof_report)
        csv_append(PMO_ASSET_UNIVERSE_EVENTS_FILE, {
            "timestamp": now_et().isoformat(),
            "event": "ASSET_UNIVERSE_REFRESH",
            "mode": snapshot.get("mode"),
            "total_asset_classes": snapshot.get("total_asset_classes"),
            "paper_ready": len(snapshot.get("paper_ready", [])),
            "scan_only": len(snapshot.get("scan_only", [])),
            "unsupported": len(snapshot.get("unsupported", [])),
            "safe_note": snapshot.get("safety_note"),
        })
    return {
        "ok": True,
        "asset_universe": snapshot,
        "capability_matrix": matrix,
        "unsupported_report": unsupported,
        "proof_report": proof_report,
        "reports": {
            "snapshot": str(PMO_ASSET_UNIVERSE_SNAPSHOT_FILE),
            "capability_matrix": str(PMO_MARKET_CAPABILITY_MATRIX_FILE),
            "proof_report": str(PMO_ASSET_CLASS_PROOF_REPORT_FILE),
            "unsupported_report": str(PMO_UNSUPPORTED_ASSET_REPORT_FILE),
            "events": str(PMO_ASSET_UNIVERSE_EVENTS_FILE),
            "blockers": str(PMO_ASSET_BLOCKERS_FILE),
            "order_attempts": str(PMO_UNIVERSAL_ORDER_ATTEMPTS_FILE),
            "paper_journal": str(PMO_ASSET_CLASS_PAPER_JOURNAL_FILE),
        },
    }


