def pmo_preview_or_apply_mode(payload: Dict[str, Any], mode_name: str, phrase: str, apply_func) -> Dict[str, Any]:
    confirm_text = str(payload.get("confirm_text", "")).strip().upper()
    if confirm_text != phrase:
        raise ValueError(f"Type {phrase} to continue.")
    settings = load_settings()
    before = dict(settings)
    result = apply_func(settings)
    apply_change = bool(payload.get("apply", False))
    audit = {"ok": True, "mode": mode_name, "diff": result.get("diff", [])}
    if apply_change:
        write_settings(settings)
        bot.reload()
        audit = pmo_save_mode_change(mode_name, before, settings)
    return {
        "ok": True,
        "applied": apply_change,
        "mode": mode_name,
        "result": result,
        "audit": audit,
        "settings_preview": {row["setting"]: row["after"] for row in result.get("diff", [])},
    }


