@app.route("/api/fvg", methods=["GET", "POST"])
@app.route("/api/fair-value-gap", methods=["GET", "POST"])
def api_fvg():
    payload = request.get_json(force=True, silent=True) or {} if request.method == "POST" else {}
    settings = load_settings()
    symbol = str(payload.get("symbol") or request.args.get("symbol") or "SPY").strip().upper()
    timeframe = str(payload.get("timeframe") or request.args.get("timeframe") or "5Min").strip() or "5Min"
    market = str(payload.get("market") or request.args.get("market") or "AUTO").strip() or "AUTO"
    limit = int(max(20, min(500, safe_float(payload.get("limit") or request.args.get("limit"), settings.get("PMO_FVG_LOOKBACK_BARS", 80)))))
    fetch = str(payload.get("fetch") if "fetch" in payload else request.args.get("fetch", "true")).strip().lower() not in {"0", "false", "no", "off"}
    direction = str(payload.get("direction") or request.args.get("direction") or "").strip().lower()
    rows = pmo_edge_load_ohlcv_rows(symbol, intraday=True, limit=limit)
    source = "local_intraday_csv"
    if fetch and len(rows) < max(3, int(safe_float(settings.get("PMO_PATTERN_ENGINE_MIN_INTRADAY_ROWS", 20), 20))):
        chart = pmo_alpaca_chart_bars(symbol=symbol, timeframe=timeframe, limit=max(limit, 80), market=market)
        if chart.get("ok") and isinstance(chart.get("bars"), list):
            rows = chart.get("bars", [])
            source = "alpaca_chart_bars"
    if not direction:
        try:
            first_close = safe_float(rows[0].get("close"), 0) if rows else 0
            last_close = safe_float(rows[-1].get("close"), 0) if rows else 0
            direction = "long" if last_close >= first_close else "short"
        except Exception:
            direction = "long"
    report = pmo_fvg_for_chart_rows(rows, direction, settings)
    return jsonify({
        "ok": True,
        "engine": "PMO FVG Detector",
        "mode": "READ_ONLY_RESEARCH",
        "symbol": symbol,
        "timeframe": timeframe,
        "source": source,
        "rows": len(rows),
        "direction": direction,
        "fvg": report,
        "live_unlocked": False,
        "orders_placed": False,
        "settings_changed": False,
    })


@app.route("/api/edge-engines", methods=["GET", "POST"])
@app.route("/api/intraday-edge-engines", methods=["GET", "POST"])
def api_edge_engines():
    payload = request.get_json(force=True, silent=True) or {} if request.method == "POST" else {}
    settings = load_settings()
    symbol = str(payload.get("symbol") or request.args.get("symbol") or "SPY").strip().upper()
    timeframe = str(payload.get("timeframe") or request.args.get("timeframe") or "5Min").strip() or "5Min"
    market = str(payload.get("market") or request.args.get("market") or "AUTO").strip() or "AUTO"
    limit = int(max(20, min(500, safe_float(payload.get("limit") or request.args.get("limit"), settings.get("PMO_INTRADAY_BARS_LOOKBACK", 80)))))
    fetch = str(payload.get("fetch") if "fetch" in payload else request.args.get("fetch", "true")).strip().lower() not in {"0", "false", "no", "off"}
    direction = str(payload.get("direction") or request.args.get("direction") or "").strip().lower()
    rows = pmo_edge_load_ohlcv_rows(symbol, intraday=True, limit=limit)
    source = "local_intraday_csv"
    if fetch and len(rows) < max(10, int(safe_float(settings.get("PMO_PATTERN_ENGINE_MIN_INTRADAY_ROWS", 20), 20))):
        chart = pmo_alpaca_chart_bars(symbol=symbol, timeframe=timeframe, limit=max(limit, 80), market=market)
        if chart.get("ok") and isinstance(chart.get("bars"), list):
            rows = chart.get("bars", [])
            source = "alpaca_chart_bars"
    if not direction:
        try:
            first_close = safe_float(rows[0].get("close"), 0) if rows else 0
            last_close = safe_float(rows[-1].get("close"), 0) if rows else 0
            direction = "long" if last_close >= first_close else "short"
        except Exception:
            direction = "long"
    report = pmo_analyze_edge_engines(symbol, direction, settings, intraday_rows=rows)
    return jsonify({
        "ok": True,
        "engine": "PMO Intraday Edge Engines",
        "mode": "READ_ONLY_RESEARCH",
        "symbol": symbol,
        "timeframe": timeframe,
        "source": source,
        "rows": len(rows),
        "direction": direction,
        "edge_engines": report,
        "live_unlocked": False,
        "orders_placed": False,
        "settings_changed": False,
    })


