@app.route("/api/crypto/ws/restart", methods=["POST"])
def api_crypto_ws_restart():
    payload = request.get_json(force=True, silent=True) or {}
    locked = pmo_require_admin(payload)
    if locked:
        return locked, 403
    settings = load_settings()
    symbols = [
        normalize_crypto_symbol(symbol)
        for symbol in unique_symbols(settings.get("PMO_CRYPTO_WATCHLIST", []), settings.get("PMO_CRYPTO_DISCOVERY_UNIVERSE", []))
        if detect_market(str(symbol), "AUTO") == "CRYPTO"
    ]
    provider_order = payload.get("provider_order")
    replacement_settings = dict(settings)
    if provider_order:
        replacement_settings["PMO_CRYPTO_WS_PROVIDER_ORDER"] = provider_order
    try:
        bot.crypto_ws.stop()
    except Exception:
        pass
    bot.crypto_ws = PMOCryptoWebSocketFeed(replacement_settings)
    bot.crypto_ws.start(symbols)
    return jsonify({"ok": True, "symbols": symbols, "websocket_feeds": pmo_crypto_ws_monitor(replacement_settings, restart_if_needed=False)})


