@app.route("/api/intelligence/bundle", methods=["GET", "POST"])
def api_intelligence_bundle():
    settings = load_settings()
    payload = request.get_json(force=True, silent=True) or {} if request.method == "POST" else {}
    symbol = str(payload.get("symbol") or request.args.get("symbol") or "").strip().upper()
    if symbol:
        direction = str(payload.get("trade_direction") or payload.get("side") or request.args.get("trade_direction") or "long").lower()
        result = pmo_analyze_intelligence_bundle(
            symbol,
            direction,
            settings,
            score=safe_float(payload.get("score") or request.args.get("score"), 0),
            rvol=safe_float(payload.get("rvol") or payload.get("relative_volume") or request.args.get("rvol"), 1.0),
            regime=str(payload.get("regime") or request.args.get("regime") or "MIXED"),
            pattern=payload.get("pattern") if isinstance(payload.get("pattern"), dict) else None,
            refresh_journal=bool(payload.get("refresh_journal") or request.args.get("refresh_journal") in {"1", "true", "yes"}),
        )
    else:
        if request.method == "POST" and bool(payload.get("refresh_journal")):
            pmo_ensure_intelligence_bundle_loaded(force=True)
        result = pmo_latest_intelligence_bundle_snapshot(settings)
    result.update({
        "live_unlocked": False,
        "orders_placed": False,
        "settings_changed": False,
        "read_only": True,
        "score_influence": False,
    })
    return jsonify(result)


