@app.route("/api/custom-model/train", methods=["POST"])
def api_custom_model_train():
    if not PMO_CUSTOM_MODEL_ENGINE_AVAILABLE or train_custom_ai_model is None:
        return jsonify({
            "ok": False,
            "error": PMO_CUSTOM_MODEL_ENGINE_ERROR or "Custom model engine is not available.",
            "orders_placed": False,
            "live_unlocked": False,
        }), 503
    payload = request.get_json(force=True, silent=True) or {}
    locked = pmo_require_admin(payload)
    if locked:
        return locked, 403
    settings = load_settings()
    if not bool(settings.get("ENABLE_PMO_CUSTOM_MODEL_LAB", True)):
        return jsonify({"ok": False, "error": "ENABLE_PMO_CUSTOM_MODEL_LAB is disabled.", "orders_placed": False, "live_unlocked": False}), 400
    if bool(settings.get("PMO_CUSTOM_MODEL_EXCLUDE_BLOCKLIST", True)) and not bool(payload.get("include_blocklisted_symbols", False)):
        payload = dict(payload)
        existing = pmo_profile_list(payload.get("exclude_symbols", []))
        payload["exclude_symbols"] = sorted({*existing, *pmo_symbol_blocklist(settings)})
    result = train_custom_ai_model(REPORT_DIR, TRADE_JOURNAL_FILE, payload)
    return jsonify(result)


