def pmo_onesignal_web_sdk_config(settings: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    settings = settings or load_settings()
    app_id = str(
        first_env("ONESIGNAL_WEB_APP_ID", "PMO_ONESIGNAL_WEB_APP_ID", "ONESIGNAL_APP_ID", "PMO_ONESIGNAL_APP_ID")
        or settings.get("PMO_ONESIGNAL_WEB_APP_ID")
        or settings.get("PMO_ONESIGNAL_APP_ID")
        or PMO_ONESIGNAL_WEB_SDK_APP_ID
    ).strip()
    return {
        "ok": True,
        "provider": "OneSignal",
        "enabled": bool(settings.get("PMO_ONESIGNAL_WEB_SDK_ENABLED", True)),
        "app_id": app_id,
        "app_id_configured": bool(app_id),
        "allow_localhost_as_secure_origin": bool(settings.get("PMO_ONESIGNAL_ALLOW_LOCALHOST_AS_SECURE_ORIGIN", True)),
        "sdk_script": "https://cdn.onesignal.com/sdks/web/v16/OneSignalSDK.page.js",
        "worker_path": "/OneSignalSDKWorker.js",
        "updater_worker_path": "/OneSignalSDKUpdaterWorker.js",
        "safe_note": "Browser Web SDK subscriptions only. Server-side notification sending still requires a OneSignal REST API key.",
        "orders_placed": False,
        "live_unlocked": False,
        "settings_changed": False,
    }


@app.route("/OneSignalSDKWorker.js", methods=["GET"])
@app.route("/OneSignalSDKUpdaterWorker.js", methods=["GET"])
def onesignal_sdk_worker():
    response = Response(PMO_ONESIGNAL_SERVICE_WORKER_JS, mimetype="application/javascript")
    response.headers["Service-Worker-Allowed"] = "/"
    response.headers["Cache-Control"] = "no-cache, no-store, must-revalidate"
    return response


