@app.route("/api/onesignal/test", methods=["POST"])
def api_onesignal_test():
    payload = request.get_json(force=True, silent=True) or {}
    locked = pmo_require_admin(payload)
    if locked:
        return locked, 403
    settings = load_settings()
    target_url = str(payload.get("url") or public_base_url() or terminal_base_url(settings)).rstrip("/")
    if not target_url.endswith("/control"):
        target_url = f"{target_url}/control"
    if build_pmo_alert_payload is not None:
        test_payload = build_pmo_alert_payload(
            "Notification Test",
            "PMO Bot OneSignal test alert. Notification only. No orders placed.",
            level="TEST",
            url=target_url,
        )
    else:
        test_payload = {
            "title": "PMO TEST: Notification Test",
            "message": "PMO Bot OneSignal test alert. Notification only. No orders placed.",
        }
    test_payload.update({k: v for k, v in payload.items() if k in {"included_segments", "segment", "external_ids", "subscription_ids", "filters", "dry_run"}})
    result = send_onesignal_notification(settings, test_payload, PMO_ONESIGNAL_EVENTS_FILE)
    return jsonify(result), 200 if result.get("ok") else 400


