def pmo_claude_codex_status(settings: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    settings = settings or load_settings()
    key_present = bool(first_env("ANTHROPIC_API_KEY", "PMO_ANTHROPIC_API_KEY", "CLAUDE_API_KEY"))
    return {
        "ok": True,
        "enabled": bool(settings.get("PMO_CLAUDE_CODEX_ENABLED", True)),
        "available": bool(PMO_CLAUDE_CODEX_AVAILABLE),
        "error": PMO_CLAUDE_CODEX_ERROR,
        "key_present": key_present,
        "model": str(settings.get("PMO_CLAUDE_CODEX_MODEL") or settings.get("PMO_AI_MODEL") or PMO_AI_MODEL),
        "roles": CLAUDE_CODEX_ROLES,
        "endpoints": {role: meta.get("endpoint") for role, meta in CLAUDE_CODEX_ROLES.items()},
        "admin_required": bool(settings.get("PMO_CLAUDE_CODEX_REQUIRE_ADMIN", True)),
        "log_file": str(PMO_CLAUDE_CODEX_LOG_FILE),
        **pmo_cc_safety_fields(),
    }


def pmo_claude_codex_require_admin(payload: Dict[str, Any], settings: Dict[str, Any]) -> Optional[Response]:
    if not bool(settings.get("PMO_CLAUDE_CODEX_REQUIRE_ADMIN", True)):
        return None
    return pmo_require_admin(payload)


def pmo_claude_codex_context(settings: Dict[str, Any], deep: bool = False) -> Dict[str, Any]:
    try:
        context = pmo_ai_context_snapshot(settings) if deep else pmo_ai_quick_context_snapshot(settings)
    except Exception as exc:
        context = {"ok": False, "context_error": str(exc)[:240], "fallback": pmo_ai_quick_context_snapshot(settings)}
    context["claude_codex_safety"] = pmo_cc_safety_fields()
    context["secrets_included"] = False
    context["admin_token_included"] = False
    return context


def pmo_claude_codex_call(
    role: str,
    *,
    question: str = "",
    code: str = "",
    description: str = "",
    context: Optional[Dict[str, Any]] = None,
    settings: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    settings = settings or load_settings()
    if not settings.get("PMO_CLAUDE_CODEX_ENABLED", True):
        return {
            "ok": False,
            "role": role,
            "error": "PMO_CLAUDE_CODEX_ENABLED is false.",
            **pmo_cc_safety_fields(),
        }
    if not PMO_CLAUDE_CODEX_AVAILABLE or not pmo_cc_build_user_prompt:
        return {
            "ok": False,
            "role": role,
            "error": PMO_CLAUDE_CODEX_ERROR or "pmo_claude_codex.py is not available.",
            **pmo_cc_safety_fields(),
        }
    if role not in PMO_CLAUDE_CODEX_SYSTEM_PROMPTS:
        return {"ok": False, "role": role, "error": f"Unknown Claude/Codex role: {role}", **pmo_cc_safety_fields()}
    role_meta = CLAUDE_CODEX_ROLES.get(role, {})
    max_tokens_key = str(role_meta.get("max_tokens_key") or "PMO_CLAUDE_CODEX_MAX_TOKENS")
    max_tokens = int(safe_float(settings.get(max_tokens_key), safe_float(settings.get("PMO_CLAUDE_CODEX_MAX_TOKENS"), 1500)))
    max_tokens = max(100, min(max_tokens, 12000))
    prompt = pmo_cc_build_user_prompt(
        role,
        question=question,
        code=code,
        description=description,
        pmo_context=context or {},
        context_max_chars=int(safe_float(settings.get("PMO_CLAUDE_CODEX_CONTEXT_MAX_CHARS"), 12000)),
        code_max_chars=int(safe_float(settings.get("PMO_CLAUDE_CODEX_CODE_MAX_CHARS"), 20000)),
    )
    call_settings = dict(settings)
    call_settings["PMO_AI_MODEL"] = str(settings.get("PMO_CLAUDE_CODEX_MODEL") or settings.get("PMO_AI_MODEL") or PMO_AI_MODEL)
    ai = pmo_claude_call(
        str(PMO_CLAUDE_CODEX_SYSTEM_PROMPTS.get(role) or ""),
        prompt,
        max_tokens=max_tokens,
        expect_json=False,
        settings=call_settings,
    )
    response = {
        "ok": bool(ai.get("ok")),
        "role": role,
        "role_kind": role_meta.get("kind", ""),
        "text": str(ai.get("text") or "").strip(),
        "error": str(ai.get("error") or ""),
        "model": ai.get("model", call_settings.get("PMO_AI_MODEL")),
        "usage": ai.get("usage", {}),
        "prompt_cache": ai.get("prompt_cache", {}),
        **pmo_cc_safety_fields(),
    }
    try:
        if pmo_cc_append_jsonl and pmo_cc_safe_log_entry:
            pmo_cc_append_jsonl(PMO_CLAUDE_CODEX_LOG_FILE, pmo_cc_safe_log_entry(role, prompt, response))
    except Exception:
        pass
    return response


