@app.route("/api/ask", methods=["POST"])
def api_ask():
    payload = request.get_json(force=True, silent=True) or {}
    settings = load_settings()
    question = str(payload.get("question") or payload.get("q") or "").strip()
    max_len = int(safe_float(settings.get("PMO_AI_CHAT_MAX_QUESTION_LEN", 500), 500))
    max_len = max(100, min(max_len, 2000))
    if not settings.get("PMO_AI_CHAT_ENABLED", True):
        return jsonify({
            "ok": False,
            "error": "PMO_AI_CHAT_ENABLED is false.",
            "answer": "PMO AI chat is disabled in settings.",
            "live_unlocked": False,
            "orders_placed": False,
            "settings_changed": False,
        })
    if not question:
        return jsonify({
            "ok": False,
            "error": "No question provided.",
            "answer": "Ask a PMO question first.",
            "live_unlocked": False,
            "orders_placed": False,
            "settings_changed": False,
        })
    if len(question) > max_len:
        return jsonify({
            "ok": False,
            "error": f"Question too long. Max {max_len} characters.",
            "answer": f"Question too long. Keep it under {max_len} characters.",
            "live_unlocked": False,
            "orders_placed": False,
            "settings_changed": False,
        })
    if not pmo_ai_provider_ready(settings):
        answer = "PMO AI chat is not connected to Claude yet. Check ANTHROPIC_API_KEY in .env, then restart PMO."
        return jsonify({
            "ok": False,
            "error": "Claude provider not ready.",
            "answer": answer,
            "live_unlocked": False,
            "orders_placed": False,
            "settings_changed": False,
        })
    clean_history: List[Dict[str, str]] = []
    for item in list(payload.get("history") or [])[-6:]:
        if not isinstance(item, dict):
            continue
        role = str(item.get("role", "user")).lower()
        content = str(item.get("content", "")).strip()[:400]
        if role in {"user", "assistant"} and content:
            clean_history.append({"role": role, "content": content})
    clean_history.append({"role": "user", "content": question})
    system_prompt = pmo_ai_build_elite_system_prompt(settings)
    user_prompt = (
        pmo_ai_xml_block("conversation_history", clean_history[:-1])
        + "\n\n"
        + pmo_ai_xml_block("newest_user_message", question)
        + "\n\n"
        + pmo_ai_xml_block("task", "Answer the newest user message using PMO's live state, ground truth, and safety constraints.")
    )
    ai = pmo_claude_call(
        system_prompt,
        user_prompt,
        max_tokens=420,
        expect_json=False,
        settings=settings,
    )
    if ai.get("ok") and ai.get("text"):
        answer = str(ai.get("text", "")).strip()
        model = str(ai.get("model") or settings.get("PMO_AI_MODEL") or PMO_AI_MODEL)
        pmo_ai_save_chat_exchange(question, answer, model=model, ok=True)
        return jsonify({
            "ok": True,
            "answer": answer,
            "model": model,
            "usage": ai.get("usage", {}),
            "prompt_cache": ai.get("prompt_cache", {}),
            "live_unlocked": False,
            "orders_placed": False,
            "settings_changed": False,
        })
    answer = "PMO AI could not answer right now. The chat made no trades and changed no settings."
    pmo_ai_save_chat_exchange(question, answer, model=str(ai.get("model") or PMO_AI_MODEL), ok=False)
    return jsonify({
        "ok": False,
        "error": ai.get("error", "Claude chat unavailable"),
        "answer": answer,
        "live_unlocked": False,
        "orders_placed": False,
        "settings_changed": False,
    })


