@app.route("/api/level5/review", methods=["POST"])
def api_level5_review():
    payload = request.get_json(force=True, silent=True) or {}
    bot.settings = load_settings()
    ai_provider_call = (
        bool(bot.settings.get("PMO_AI_WARP_ENABLED", False))
        and str(bot.settings.get("PMO_WARP_AI_PROVIDER", "rule_based")).lower() == "claude"
        and bool(payload.get("record", False))
    )
    if ai_provider_call:
        locked = pmo_require_admin(payload)
        if locked:
            return locked, 403
    account = bot.account_snapshot()
    health = bot.connection_check()
    regime = bot.market_regime()
    positions = open_positions()
    reconciliation = broker_reconciliation_snapshot(bot.settings, account, positions)
    live_readiness = live_readiness_snapshot(bot.settings, account, health, regime, reconciliation)
    feature_audit = pmo_feature_integrity_audit(bot.settings, health, live_readiness, record=False)
    executor = bot.executor_status()
    paper_proof = pmo_paper_proof_snapshot(bot.settings, record=False)
    quantum_matrix = load_pmo_quantum_matrix()
    operations = pmo_operations_readiness_snapshot(bot.settings, account, health, regime, reconciliation, live_readiness)
    warp_context = pmo_warp_context_snapshot(bot.settings, account, health, regime, executor, paper_proof, quantum_matrix, operations)
    warp_result = pmo_warp_review(
        "PMO_BOT",
        "run PMO Level 5 review",
        warp_context,
        speed=str(payload.get("speed") or bot.settings.get("PMO_WARP_SPEED", "SMART")),
        settings=bot.settings,
        record=bool(payload.get("record", False)),
    )
    review = pmo_level5_review_snapshot(bot.settings, account, health, regime, live_readiness, feature_audit, warp_result)
    if bool(payload.get("record", True)):
        csv_append(CSV_DIR / "pmo_level5_reviews.csv", {
            "timestamp": review["timestamp"],
            "mode": review["mode"],
            "next_action": review["next_action"],
            "risk_notes": " | ".join(review["risk_notes"]),
            "performance_notes": " | ".join(review["performance_notes"]),
        })
    return jsonify({
        "ok": True,
        "level5_review": review,
        "warp_result": warp_result,
    })


