    if not voice.get("realtime_configured"):
        result = {
            "ok": True,
            "configured": False,
            "voice": voice,
            "message": "OpenAI Realtime is not enabled/configured. Browser Web Speech fallback should be used.",
            "safety_note": "No provider call was made and no secret was exposed.",
        }
        pmo_ai_log_event("REALTIME_SESSION", "LOCAL_FALLBACK", payload, result)
        return jsonify(result)
    result = {
        "ok": True,
        "configured": False,
        "voice": voice,
        "message": "Realtime provider key is present, but PMO is keeping this local route in fallback mode until owner enables external AI calls.",
        "safety_note": "External calls remain disabled by PMO_LIVE_AI_ALLOW_EXTERNAL_PROVIDER_CALLS.",
    }
    pmo_ai_log_event("REALTIME_SESSION", "LOCAL_FALLBACK", payload, result)
    return jsonify(result)


