@app.route("/api/why-not", methods=["GET", "POST"])
def api_why_not():
    payload = request.get_json(force=True, silent=True) or {}
    settings = load_settings()
    account = bot.account_snapshot()
    health = bot.connection_check()
    regime = pmo_market_regime_snapshot(bot, fresh=True)
    auto_watchlist = load_auto_watchlist()
    positions = open_positions()
    reconciliation = broker_reconciliation_snapshot(settings, account, positions)
    live_readiness = live_readiness_snapshot(settings, account, health, regime, reconciliation)
    executor = bot.executor_status()
    paper_proof = pmo_paper_proof_snapshot(settings, record=False)
    record = bool(payload.get("record", settings.get("PMO_WHY_NOT_RECORD_AUDIT", True))) if request.method == "POST" else False
    ai_explain = bool(payload.get("ai_explain") or payload.get("claude_explain") or payload.get("explain_with_claude"))
    if ai_explain and bool(settings.get("PMO_WHY_NOT_AI_EXPLAIN", True)):
        locked = pmo_require_admin(payload)
        if locked:
            return locked, 403
    why_not = pmo_why_not_snapshot_with_ai(
        auto_watchlist,
        settings,
        account,
        health,
        regime,
        live_readiness,
        executor,
        reconciliation,
        paper_proof,
        record=record,
        ai_explain=ai_explain,
    )
    return jsonify({
        "ok": True,
        "why_not": why_not,
        "signal_timeline": signal_decision_timeline(auto_watchlist, settings, regime, account, health, live_readiness, executor, reconciliation, paper_proof),
        "events_file": str(PMO_WHY_NOT_EVENTS_FILE),
    })


