@app.route("/api/deck/snapshot", methods=["GET"])
def api_deck_snapshot():
    """Fast dashboard snapshot for high-frequency deck polling.

    Keep this much lighter than /api/status. It reports only nav/status,
    journal health, proof health, and missing data flags.
    """
    settings = load_settings()
    journal_summary = trade_journal_summary(limit=20)
    account = pmo_fast_account_snapshot(settings)
    paper_proof = pmo_fast_paper_proof_snapshot(settings)

    trade_rows = recent_csv_rows(TRADE_JOURNAL_FILE, 5000)
    trade_status_counts: Dict[str, int] = {}
    for row in trade_rows:
        status = str(row.get("status") or row.get("result") or row.get("outcome") or "UNKNOWN").strip().upper()
        if not status:
            status = "UNKNOWN"
        trade_status_counts[status] = trade_status_counts.get(status, 0) + 1

    def journal_trade_key(row: Dict[str, Any]) -> str:
        for field in ("source_order_id", "order_id", "client_order_id", "trade_plan_id", "sync_key"):
            value = str(row.get(field) or "").strip()
            if value:
                return value.split(":")[0]
        return "|".join(str(row.get(field) or "").strip().upper() for field in ("symbol", "side", "entry_price"))

    terminal_trade_keys = {
        journal_trade_key(row)
        for row in trade_rows
        if str(row.get("status") or row.get("result") or row.get("outcome") or "").upper().startswith(("CLOSED", "VOID_"))
    }
    unresolved_trade_rows = [
        row for row in trade_rows
        if journal_trade_key(row) not in terminal_trade_keys
    ]

    v112_report = paper_proof.get("v112") if isinstance(paper_proof.get("v112"), dict) else {}
    if not v112_report:
        v112_report = read_json_file(PMO_V112_PROOF_REPORT_FILE, {})
    if not isinstance(v112_report, dict):
        v112_report = {"ok": False, "status": "UNKNOWN", "summary": {}}
    v112_summary = v112_report.get("summary") or {}

    auto_watchlist = load_auto_watchlist()
    auto_symbols = auto_watchlist.get("symbols") if isinstance(auto_watchlist, dict) else []
    if not isinstance(auto_symbols, list):
        auto_symbols = []
    configured_symbols = settings.get("PMO_WATCHLIST") or []
    micro_symbols = (settings.get("PMO_MICRO_SAFE_WATCHLIST") or []) if bool(settings.get("ENABLE_PMO_MICRO_ACCOUNT_MODE", False)) else []
    watchlist_symbols = [
        str(symbol).upper().strip()
        for symbol in dict.fromkeys(list(configured_symbols) + list(micro_symbols) + list(auto_symbols))
        if str(symbol).strip()
    ]
    scan_only_symbols = {
        str(row.get("symbol") or "").upper().strip()
        for row in pmo_international_quality_rows(settings)
        if "SCAN_ONLY" in str(row.get("execution_mode") or "").upper()
    }
    backtest_required_symbols = [
        symbol for symbol in watchlist_symbols
        if detect_market(symbol, "AUTO") == "STOCK" and symbol not in scan_only_symbols
    ]

    backtest_dirs = [CSV_DIR / "backtest_daily_bars", PMO_DIR / "pmo_backtest_data"]
    backtest_symbols: set[str] = set()
    intraday_available = False
    for backtest_dir in backtest_dirs:
        if not backtest_dir.exists():
            continue
        for path in backtest_dir.glob("*.csv"):
            stem = path.stem.upper().strip()
            if not stem:
                continue
            if stem.endswith("_1M") or stem.endswith("_5M"):
                intraday_available = True
                stem = stem.rsplit("_", 1)[0]
            backtest_symbols.add(stem)
    missing_symbols = [symbol for symbol in backtest_required_symbols if symbol.upper() not in backtest_symbols]

    md_status = getattr(bot, "market_data_status", {}) or {}
    md_age_seconds: Optional[float] = None
    last_md = md_status.get("updated") or md_status.get("timestamp") or md_status.get("last_updated") or md_status.get("watchlist_refresh_updated")
    if last_md:
        try:
            parsed = datetime.fromisoformat(str(last_md).replace("Z", "+00:00"))
            if parsed.tzinfo is None:
                parsed = parsed.replace(tzinfo=ET)
            md_age_seconds = max(0.0, (now_et() - parsed.astimezone(ET)).total_seconds())
        except Exception:
            md_age_seconds = None

    paper_safe = bool(settings.get("ALPACA_PAPER", True)) and bool(settings.get("PMO_DRY_RUN_ORDERS", True))
    execution_mode = str(settings.get("PMO_ORDER_EXECUTION_MODE", "SIGNAL_ONLY")).upper()
    why_not_on = bool(settings.get("ENABLE_PMO_WHY_NOT_ENGINE", True))
    why_not_event_rows = [
        row for row in recent_csv_rows(PMO_WHY_NOT_EVENTS_FILE, 5000)
        if str(row.get("symbol") or row.get("ticker") or "").strip()
    ]

    regime = pmo_fast_regime_snapshot(settings)
    regime_label = str(regime.get("regime") or regime.get("label") or "UNKNOWN").upper()

    vix_price = pmo_regime_cached_price(regime, "VXX")
    spy_price = pmo_regime_cached_price(regime, "SPY")

    bg_state = getattr(bot, "background_paper_state", {}) or {}
    crypto_ws = pmo_crypto_ws_monitor(settings, restart_if_needed=True)
    latest_why_not = read_json_file(PMO_WHY_NOT_FILE, {})
    if not isinstance(latest_why_not, dict):
        latest_why_not = {}

    closed = int(safe_float(journal_summary.get("closed_trades"), 0))
    open_filled = sum(1 for row in unresolved_trade_rows if str(row.get("status") or "").upper() == "OPEN_FILLED")
    stop_open = sum(1 for row in unresolved_trade_rows if str(row.get("status") or "").upper() == "STOP_REACHED_OPEN")
    target_open = sum(1 for row in unresolved_trade_rows if str(row.get("status") or "").upper() == "TARGET_REACHED_OPEN")
    not_yet_closed = stop_open + target_open

    dq_issues: List[Dict[str, Any]] = []
    if closed == 0:
        dq_issues.append({
            "code": "NO_CLOSED_TRADES",
            "severity": "CRITICAL",
            "msg": f"0 broker-confirmed closed trades. {not_yet_closed} stops/targets reached but still OPEN.",
            "fix": "Run /api/trade-journal/sync with close_hits=true, or wait for Alpaca to confirm paper close fills.",
        })
    elif closed < 20:
        dq_issues.append({
            "code": "FEW_CLOSED_TRADES",
            "severity": "WARN",
            "msg": f"Only {closed} closed trades. Need 20+ clean outcomes before win-rate is meaningful.",
            "fix": "Let paper mode complete more entry -> stop/target -> confirmed close cycles.",
        })
    if not_yet_closed > 0:
        dq_issues.append({
            "code": "EXITS_UNCONFIRMED",
            "severity": "WARN",
            "msg": f"{stop_open} stop-reached + {target_open} target-reached rows still marked OPEN.",
            "fix": "Sync or submit paper close orders so these become CLOSED_WIN/CLOSED_LOSS rows.",
        })
    if missing_symbols:
        preview = ", ".join(missing_symbols[:8])
        suffix = "..." if len(missing_symbols) > 8 else ""
        dq_issues.append({
            "code": "MISSING_BACKTEST_SYMBOLS",
            "severity": "WARN",
            "msg": f"{len(missing_symbols)}/{len(watchlist_symbols)} watchlist symbols have no backtest history: {preview}{suffix}",
            "fix": "Fetch daily history for missing symbols before trusting strategy research.",
        })
    if md_age_seconds is not None and md_age_seconds > 300:
        dq_issues.append({
            "code": "STALE_MARKET_DATA",
            "severity": "WARN",
            "msg": f"Market data last updated {int(md_age_seconds)}s ago (>300s threshold).",
            "fix": "POST /api/watchlist/refresh to pull fresh prices.",
        })
    if bool(settings.get("ENABLE_PMO_CRYPTO_WEBSOCKET_FEEDS", True)):
        crypto_age = crypto_ws.get("age_seconds")
        if not crypto_ws.get("connected"):
            dq_issues.append({
                "code": "CRYPTO_WS_DISCONNECTED",
                "severity": "WARN",
                "msg": f"Crypto WebSocket feed is disconnected. Active provider: {crypto_ws.get('active_provider') or 'NONE'}.",
                "fix": "POST /api/crypto/ws/restart or wait for the background paper health check to restart it.",
            })
        elif crypto_ws.get("stale"):
            age_text = "unknown" if crypto_age is None else f"{int(safe_float(crypto_age, 0))}s"
            dq_issues.append({
                "code": "CRYPTO_WS_STALE",
                "severity": "WARN",
                "msg": f"Crypto WebSocket cache is stale. Last update age: {age_text}.",
                "fix": "POST /api/crypto/ws/restart; PMO will fall back to Alpaca REST until the cache is fresh.",
            })
    if not why_not_on:
        dq_issues.append({
            "code": "WHY_NOT_OFF",
            "severity": "WARN",
            "msg": "Why-Not engine is OFF. Signal rejection reasons are not being recorded or explained.",
            "fix": "Set ENABLE_PMO_WHY_NOT_ENGINE=true in settings.",
        })
    v112_closed = int(safe_float(
        v112_summary.get("closed_paper_trades", v112_summary.get("closed_trades", v112_report.get("closed_trades", 0))),
        0,
    ))
    if v112_closed < 5:
        dq_issues.append({
            "code": "SCORE_UNCALIBRATED",
            "severity": "WARN",
            "msg": f"PMO score has only {v112_closed} closed v112 outcomes. Score bands cannot be trusted yet.",
            "fix": "Collect 20+ clean closed paper replay outcomes before trusting 70/85/93 score bands.",
        })
    if not intraday_available:
        dq_issues.append({
            "code": "NO_INTRADAY_DATA",
            "severity": "INFO",
            "msg": "No 1m/5m intraday bars found. Execution accuracy relies mostly on daily/live snapshots.",
            "fix": "Fetch 1m or 5m bars for watchlist symbols to improve stop/target simulation.",
        })
    if regime_label in {"", "UNKNOWN"}:
        dq_issues.append({
            "code": "NO_REGIME",
            "severity": "INFO",
            "msg": "Market regime is UNKNOWN. Regime-filtered backtests and trade tags are weaker.",
            "fix": "Ensure SPY/QQQ/VIX market data is fresh before trusting regime labels.",
        })

    trust_level = (
        "DO_NOT_TRUST" if closed == 0
        else "LOW_TRUST" if closed < 10
        else "BUILDING" if closed < 30
        else "MODERATE" if closed < 60
        else "HIGH"
    )
    ai_engines_fast = pmo_ai_engine_candidate_snapshot(settings, score=70, rvol=1.5)
    trade_edge_six_snapshot = pmo_trade_edge_six_status(settings, record=False)
    tier_ab17_snapshot = trade_edge_six_snapshot.get("tier_ab17") if isinstance(trade_edge_six_snapshot, dict) else {}
    if not isinstance(tier_ab17_snapshot, dict) or not tier_ab17_snapshot:
        tier_ab17_snapshot = pmo_tier_ab17_status(settings, record=False)
    dashboard_polish = pmo_dashboard_polish_snapshot(settings, journal_summary, paper_proof, regime)
    meta_strategy = pmo_meta_strategy_report(
        settings,
        current_state={"regime": regime_label, "score": 70, "rvol": 1.5},
        record=False,
    )
    vault_intelligence = pmo_vault_intelligence_report(
        settings,
        current_state={"regime": regime_label, "score": 70, "rvol": 1.5},
        record=False,
    )

    return jsonify({
        "ok": True,
        "updated": now_et().isoformat(),
        "mode": "SNAPSHOT",
        "account": account,
        "paper_safe": paper_safe,
        "execution_mode": execution_mode,
        "why_not_on": why_not_on,
        "env_badge": "LIVE" if bool(settings.get("PMO_LIVE_TRADING_ENABLED")) else "PAPER",
        "bot_mode": str(settings.get("BOT_MODE", settings.get("PMO_BOT_MODE", "UNKNOWN"))).upper(),
        "bg_scheduler_running": bool(bg_state.get("running")),
        "bg_last_status": str(bg_state.get("last_status", "")),
        "regime": regime_label,
        "regime_reason": regime.get("reason", ""),
        "vix": vix_price,
        "spy": spy_price,
        "market_data_status": md_status,
        "md_age_seconds": md_age_seconds,
        "crypto_ws": crypto_ws,
        "paper_proof": paper_proof,
        "why_not": {
            "enabled": why_not_on,
            "summary": latest_why_not.get("summary", {}) if isinstance(latest_why_not.get("summary"), dict) else {},
            "rows": latest_why_not.get("rows", [])[:10] if isinstance(latest_why_not.get("rows"), list) else [],
            "timestamp": latest_why_not.get("timestamp", ""),
            "file": str(PMO_WHY_NOT_FILE),
        },
        "journal": {
            "rows": journal_summary.get("journal_rows", 0),
            "closed": closed,
            "wins": journal_summary.get("wins", 0),
            "losses": journal_summary.get("losses", 0),
            "win_rate": journal_summary.get("win_rate", 0),
            "profit_factor": journal_summary.get("profit_factor", 0),
            "net_pnl": journal_summary.get("net_pnl", 0),
            "open_filled": open_filled,
            "stop_reached_open": stop_open,
            "target_reached_open": target_open,
        },
        "v112": {
            "closed": v112_closed,
            "win_rate": v112_summary.get("win_rate", v112_report.get("win_rate", 0)),
            "profit_factor": v112_summary.get("profit_factor", v112_report.get("profit_factor", 0)),
            "proof_score": v112_report.get("proof_score", 0),
            "status": v112_report.get("status", ""),
        },
        "watchlist_count": len(watchlist_symbols),
        "backtest_symbols_count": len(backtest_symbols),
        "missing_backtest_count": len(missing_symbols),
        "missing_backtest_symbols": missing_symbols[:20],
        "trust_level": trust_level,
        "data_quality_issues": dq_issues,
        "data_quality_issue_count": len(dq_issues),
        "critical_issues": sum(1 for item in dq_issues if item.get("severity") == "CRITICAL"),
        "ai_engines": ai_engines_fast,
        "intelligence_bundle": pmo_latest_intelligence_bundle_snapshot(settings),
        "trade_edge_six": trade_edge_six_snapshot,
        "tier_ab17": tier_ab17_snapshot,
        "barchart_context": pmo_barchart_index_context(settings),
        "dashboard_polish": dashboard_polish,
        "meta_strategy": meta_strategy,
        "vault_intelligence": vault_intelligence,
    })


@app.route("/api/trade-truth", methods=["GET", "POST"])
def api_trade_truth():
    """Grade PMO against the 10 trade-improvement data requirements."""
    settings = load_settings()
    journal = trade_journal_summary(limit=500)
    rows = [
        row for row in recent_csv_rows(TRADE_JOURNAL_FILE, 5000)
        if str(row.get("symbol", "")).upper() not in {"SYSTEM", ""}
        and str(row.get("status", "")).upper() not in {"JOURNAL_READY", "SYSTEM", "INIT", "INITIALIZED"}
    ]

    def truth_status(ok: bool, warn: bool = False) -> str:
        if ok:
            return "PASS"
        if warn:
            return "WARN"
        return "MISSING"

    def row_status(row: Dict[str, Any]) -> str:
        return str(row.get("status") or row.get("result") or row.get("outcome") or "").upper()

    def has_any(row: Dict[str, Any], fields: Iterable[str]) -> bool:
        return any(str(row.get(field, "")).strip() not in {"", "None", "null"} for field in fields)

    def closed_row(row: Dict[str, Any]) -> bool:
        status = row_status(row)
        if status.endswith("_OPEN"):
            return False
        if status.startswith("VOID_"):
            return False
        if status.startswith("CLOSED") or status in {"WIN", "LOSS", "COMPLETE", "COMPLETED"}:
            return True
        return has_any(row, ("pnl", "pnl_usd", "realized_pnl", "net_pnl")) and has_any(row, ("exit_price", "close_price"))

    def journal_trade_key(row: Dict[str, Any]) -> str:
        for field in ("source_order_id", "order_id", "client_order_id", "trade_plan_id", "sync_key"):
            value = str(row.get(field) or "").strip()
            if value:
                return value.split(":")[0]
        return "|".join(str(row.get(field) or "").strip().upper() for field in ("symbol", "side", "entry_price"))

    def score_band(score: Any) -> str:
        return pmo_score_range_label(score, settings)

    def row_sort_time(row: Dict[str, Any]) -> float:
        dt = parse_pmo_timestamp(row.get("timestamp"))
        return dt.timestamp() if dt else 0.0

    closed_rows = [row for row in rows if closed_row(row)]
    terminal_keys = {
        journal_trade_key(row)
        for row in rows
        if row_status(row).startswith(("CLOSED", "VOID_"))
    }
    unresolved_by_key: Dict[str, Dict[str, Any]] = {}
    for row in rows:
        key = journal_trade_key(row)
        if key in terminal_keys:
            continue
        current = unresolved_by_key.get(key)
        if current is None or row_sort_time(row) >= row_sort_time(current):
            unresolved_by_key[key] = row
    unresolved_rows = list(unresolved_by_key.values())
    open_rows = [row for row in unresolved_rows if "OPEN" in row_status(row)]
    stop_target_open = [row for row in unresolved_rows if row_status(row) in {"STOP_REACHED_OPEN", "TARGET_REACHED_OPEN"}]
    scored_rows = [row for row in rows if has_any(row, ("score", "pmo_score"))]
    scored_closed_rows = [row for row in closed_rows if has_any(row, ("score", "pmo_score"))]
    score_band_counts: Dict[str, Dict[str, int]] = {}
    for row in scored_closed_rows:
        band = score_band(row.get("score") or row.get("pmo_score"))
        bucket = score_band_counts.setdefault(band, {"closed": 0, "wins": 0, "losses": 0})
        bucket["closed"] += 1
        status = row_status(row)
        pnl = safe_float(row.get("pnl") or row.get("pnl_usd") or row.get("realized_pnl") or 0, 0)
        if "WIN" in status or pnl > 0:
            bucket["wins"] += 1
        elif "LOSS" in status or pnl < 0:
            bucket["losses"] += 1

    try:
        regime = bot.market_regime()
    except Exception as exc:
        regime = {"regime": "UNKNOWN", "reason": str(exc)}
    regime_label = str(regime.get("regime") or "UNKNOWN").upper()

    backtest_dirs = [CSV_DIR / "backtest_daily_bars", PMO_DIR / "pmo_backtest_data"]
    intraday_files = []
    for backtest_dir in backtest_dirs:
        if backtest_dir.exists():
            intraday_files.extend(list(backtest_dir.glob("*_1m.csv")))
            intraday_files.extend(list(backtest_dir.glob("*_5m.csv")))

    why_not_on = bool(settings.get("ENABLE_PMO_WHY_NOT_ENGINE", True))
    why_not_event_rows = [
        row for row in recent_csv_rows(PMO_WHY_NOT_EVENTS_FILE, 5000)
        if str(row.get("symbol") or row.get("ticker") or "").strip()
    ]
    asset_class_rows = [row for row in rows if has_any(row, ("asset_class", "market"))]
    market_counts: Dict[str, int] = {}
    for row in rows:
        market = str(row.get("market") or detect_market(row.get("symbol", ""), "AUTO")).upper()
        market_counts[market] = market_counts.get(market, 0) + 1

    sector_rows = [row for row in rows if has_any(row, ("sector", "sector_etf", "sector_confirmation"))]
    setup_rows = [row for row in rows if has_any(row, ("setup_type", "strategy", "entry_logic"))]
    volume_rows = [row for row in rows if has_any(row, ("relative_volume", "rvol", "volume_quality", "volume"))]
    late_entry_rows = [row for row in rows if has_any(row, ("entry_distance_vwap", "vwap_distance", "change_pct", "recent_move_pct", "chase_penalty"))]
    excursion_rows = [row for row in rows if has_any(row, ("mfe", "mae", "max_favorable_excursion", "max_adverse_excursion"))]
    regime_rows = [row for row in rows if has_any(row, ("regime", "market_regime", "score_regime"))]
    do_not_trade_rows = [
        row for row in rows
        if "BLOCK" in row_status(row) or "REJECT" in row_status(row) or has_any(row, ("why_not", "blocker", "blocked_reason"))
    ] + why_not_event_rows

    closed_count = len(closed_rows)
    checklist = [
        {
            "id": 1,
            "name": "Close every paper trade properly",
            "status": truth_status(closed_count >= 20, closed_count > 0),
            "metric": f"{closed_count} closed / {len(open_rows)} open / {len(stop_target_open)} stop-target-open",
            "why": "Win rate and profit factor only mean something after broker-confirmed closed outcomes.",
            "next_action": "Fix exit sync until every stop/target hit becomes CLOSED_WIN or CLOSED_LOSS.",
        },
        {
            "id": 2,
            "name": "Track score bands honestly",
            "status": truth_status(len(scored_closed_rows) >= 20, len(scored_closed_rows) > 0),
            "metric": f"{len(scored_closed_rows)} scored closed trades",
            "bands": score_band_counts,
            "why": "PMO must prove whether 70/85/93 scores predict better outcomes.",
            "next_action": "Show win rate/profit factor by score band after 20+ closed scored trades.",
        },
        {
            "id": 3,
            "name": "Add market regime filter",
            "status": truth_status(regime_label not in {"", "UNKNOWN"} and len(regime_rows) >= 20, regime_label not in {"", "UNKNOWN"}),
            "metric": f"current regime {regime_label}; {len(regime_rows)} journal rows tagged",
            "why": "A strategy can work in bullish regimes and fail in defensive/choppy regimes.",
            "next_action": "Write regime to every trade row at entry and close.",
        },
        {
            "id": 4,
            "name": "Add sector confirmation",
            "status": truth_status(len(sector_rows) >= 20, len(sector_rows) > 0),
            "metric": f"{len(sector_rows)} rows with sector confirmation fields",
            "why": "Stock trades need sector agreement; weak sector context should reduce confidence.",
            "next_action": "Record sector, sector ETF, and sector trend on every stock/ETF trade.",
        },
        {
            "id": 5,
            "name": "Add late-entry detection",
            "status": truth_status(len(late_entry_rows) >= 20, len(late_entry_rows) > 0),
            "metric": f"{len(late_entry_rows)} rows with chase/VWAP/distance fields",
            "why": "High scores can mean PMO is buying after the move already happened.",
            "next_action": "Log VWAP distance, candle extension, and chase penalty at entry.",
        },
        {
            "id": 6,
            "name": "Add volume quality, not just volume size",
            "status": truth_status(len(volume_rows) >= 20, len(volume_rows) > 0),
            "metric": f"{len(volume_rows)} rows with volume fields",
            "why": "Relative volume alone does not separate clean accumulation from exhaustion.",
            "next_action": "Log RVOL plus candle spread, direction, and volume-quality label.",
        },
        {
            "id": 7,
            "name": "Add setup type labels",
            "status": truth_status(len(setup_rows) >= 20, len(setup_rows) > 0),
            "metric": f"{len(setup_rows)} rows tagged with setup/strategy",
            "why": "PMO needs to learn which setup type wins: breakout, pullback, reversal, continuation, gap-fill, or mean reversion.",
            "next_action": "Require setup_type on every generated trade plan.",
        },
        {
            "id": 8,
            "name": "Track max favorable/adverse excursion",
            "status": truth_status(len(excursion_rows) >= 20, len(excursion_rows) > 0 and bool(intraday_files)),
            "metric": f"{len(excursion_rows)} rows with MFE/MAE; {len(intraday_files)} intraday files",
            "why": "MFE/MAE tells whether stops are too tight, targets too far, or entries too late.",
            "next_action": "Fetch 1m/5m bars and calculate MFE/MAE for every closed paper trade.",
        },
        {
            "id": 9,
            "name": "Separate stock, ETF, crypto, options, leveraged ETF logic",
            "status": truth_status(len(asset_class_rows) >= 20, len(market_counts) > 1),
            "metric": f"market counts {market_counts}",
            "why": "Crypto, stocks, ETFs, options, and leveraged ETFs should not share one scoring brain.",
            "next_action": "Write asset_class and strategy_family to each trade row and score each family separately.",
        },
        {
            "id": 10,
            "name": "Create a do-not-trade model",
            "status": truth_status(why_not_on and len(do_not_trade_rows) >= 20, why_not_on or len(do_not_trade_rows) > 0),
            "metric": f"why_not_on={why_not_on}; {len(do_not_trade_rows)} blocked/rejected rows",
            "why": "The best improvement may be blocking bad-looking-good setups before entry.",
            "next_action": "Turn Why-Not on and train block reasons against closed outcomes.",
        },
    ]

    for item in checklist:
        next_action = item.get("next_action")
        if next_action:
            item.setdefault("next_step", next_action)
            item.setdefault("action", next_action)

    pass_count = sum(1 for item in checklist if item["status"] == "PASS")
    warn_count = sum(1 for item in checklist if item["status"] == "WARN")
    missing_count = sum(1 for item in checklist if item["status"] == "MISSING")
    readiness_score = round((pass_count * 10 + warn_count * 4) / 100, 3)

    return jsonify({
        "ok": True,
        "updated": now_et().isoformat(),
        "engine": "PMO Trade Truth Engine",
        "readiness_score": readiness_score,
        "pass": pass_count,
        "warn": warn_count,
        "missing": missing_count,
        "verdict": (
            "DO_NOT_TRUST_LIVE" if checklist[0]["status"] != "PASS"
            else "RESEARCH_ONLY" if missing_count >= 4
            else "PAPER_PROOF_BUILDING" if pass_count < 8
            else "FORWARD_TEST_READY"
        ),
        "journal": {
            "rows": journal.get("journal_rows", 0),
            "closed": closed_count,
            "wins": journal.get("wins", 0),
            "losses": journal.get("losses", 0),
            "win_rate": journal.get("win_rate", 0),
            "profit_factor": journal.get("profit_factor", 0),
            "net_pnl": journal.get("net_pnl", 0),
        },
        "checklist": checklist,
        "next_best_actions": [
            item["next_action"] for item in checklist
            if item["status"] in {"MISSING", "WARN"}
        ][:5],
    })


