def pmo_edge_safe_symbol(symbol: str) -> str:
    return str(symbol or "").strip().upper().replace("/", "_").replace("\\", "_")


def pmo_edge_load_ohlcv_rows(symbol: str, intraday: bool = False, limit: int = 260) -> List[Dict[str, Any]]:
    safe_symbol = pmo_edge_safe_symbol(symbol)
    if not safe_symbol:
        return []
    candidates: List[Path] = []
    for base_dir in (CSV_DIR / "backtest_daily_bars", PMO_DIR / "pmo_backtest_data"):
        if intraday:
            candidates.extend([base_dir / f"{safe_symbol}_5m.csv", base_dir / f"{safe_symbol}_1m.csv"])
        else:
            candidates.append(base_dir / f"{safe_symbol}.csv")
    for path in candidates:
        if not path.exists() or path.stat().st_size <= 0:
            continue
        rows = recent_csv_rows(path, max(1, limit))
        cleaned = []
        for row in rows:
            close = safe_float(row.get("close") or row.get("c"), 0)
            if close <= 0:
                continue
            cleaned.append({
                "date": row.get("date") or row.get("timestamp") or row.get("time") or row.get("t") or "",
                "open": safe_float(row.get("open") or row.get("o"), close),
                "high": safe_float(row.get("high") or row.get("h"), close),
                "low": safe_float(row.get("low") or row.get("l"), close),
                "close": close,
                "volume": safe_float(row.get("volume") or row.get("v"), 0),
            })
        if cleaned:
            return cleaned[-max(1, limit):]
    return []


def pmo_trade_quality_from_intraday(
    symbol: str,
    side: str = "LONG",
    entry_price: float = 0.0,
    exit_price: float = 0.0,
    entry_timestamp: Any = None,
    exit_timestamp: Any = None,
    limit: int = 500,
) -> Dict[str, Any]:
    """Calculate honest trade-quality fields from local 1m/5m files when matching bars exist."""
    entry_price = safe_float(entry_price, 0)
    if entry_price <= 0:
        return {}
    rows = pmo_edge_load_ohlcv_rows(symbol, intraday=True, limit=limit)
    if not rows:
        return {}
    parsed_rows: List[Dict[str, Any]] = []
    for row in rows:
        ts = parse_pmo_timestamp(row.get("date") or row.get("timestamp") or row.get("time"))
        close = safe_float(row.get("close"), 0)
        if ts is None or close <= 0:
            continue
        parsed_rows.append({
            "timestamp": ts,
            "open": safe_float(row.get("open"), close),
            "high": safe_float(row.get("high"), close),
            "low": safe_float(row.get("low"), close),
            "close": close,
            "volume": safe_float(row.get("volume"), 0),
        })
    if not parsed_rows:
        return {}
    parsed_rows.sort(key=lambda row: row["timestamp"])
    entry_dt = parse_pmo_timestamp(entry_timestamp)
    exit_dt = parse_pmo_timestamp(exit_timestamp)
    if entry_dt is not None:
        same_session_rows = [row for row in parsed_rows if row["timestamp"].date() == entry_dt.date()]
        if not same_session_rows:
            return {}
        parsed_rows = same_session_rows
        entry_index = next((idx for idx, row in enumerate(parsed_rows) if row["timestamp"] >= entry_dt), len(parsed_rows) - 1)
    else:
        entry_index = len(parsed_rows) - 1
    entry_index = max(0, min(entry_index, len(parsed_rows) - 1))
    entry_row = parsed_rows[entry_index]
    vwap_rows = parsed_rows[: entry_index + 1]
    volume_sum = sum(max(0.0, safe_float(row.get("volume"), 0)) for row in vwap_rows)
    if volume_sum > 0:
        vwap = sum(safe_float(row.get("close"), 0) * max(0.0, safe_float(row.get("volume"), 0)) for row in vwap_rows) / volume_sum
    else:
        vwap = sum(safe_float(row.get("close"), 0) for row in vwap_rows) / max(1, len(vwap_rows))
    vwap_distance = round(((entry_price - vwap) / vwap) * 100, 4) if vwap > 0 else ""
    prior_rows = parsed_rows[max(0, entry_index - 20): entry_index]
    avg_prior_volume = sum(safe_float(row.get("volume"), 0) for row in prior_rows) / len(prior_rows) if prior_rows else 0
    relative_volume = round(safe_float(entry_row.get("volume"), 0) / avg_prior_volume, 4) if avg_prior_volume > 0 else ""
    rv = safe_float(relative_volume, 0)
    volume_quality = "RVOL_HIGH" if rv >= 2.0 else "RVOL_OK" if rv >= 1.5 else "RVOL_LOW" if rv > 0 else ""
    direction = str(side or "LONG").upper()
    if direction in {"SHORT", "SELL", "PUT", "PUT_BIAS"}:
        if isinstance(vwap_distance, (int, float)) and vwap_distance < -1.0:
            late_entry_flag = "SHORT_CHASED_BELOW_VWAP"
        elif isinstance(vwap_distance, (int, float)) and vwap_distance < -0.5:
            late_entry_flag = "SHORT_EXTENDED"
        else:
            late_entry_flag = "OK"
    else:
        if isinstance(vwap_distance, (int, float)) and vwap_distance > 1.0:
            late_entry_flag = "LONG_CHASED_ABOVE_VWAP"
        elif isinstance(vwap_distance, (int, float)) and vwap_distance > 0.5:
            late_entry_flag = "LONG_EXTENDED"
        else:
            late_entry_flag = "OK"
    trade_rows = parsed_rows[entry_index:]
    if exit_dt is not None and exit_dt.date() == parsed_rows[entry_index]["timestamp"].date():
        trade_rows = [row for row in trade_rows if row["timestamp"] <= exit_dt] or trade_rows[:1]
    max_high = max(safe_float(row.get("high"), entry_price) for row in trade_rows)
    min_low = min(safe_float(row.get("low"), entry_price) for row in trade_rows)
    if direction in {"SHORT", "SELL", "PUT", "PUT_BIAS"}:
        mfe_pct = round(((entry_price - min_low) / entry_price) * 100, 4)
        mae_pct = round(((entry_price - max_high) / entry_price) * 100, 4)
    else:
        mfe_pct = round(((max_high - entry_price) / entry_price) * 100, 4)
        mae_pct = round(((min_low - entry_price) / entry_price) * 100, 4)
    return {
        "entry_distance_vwap": vwap_distance,
        "vwap_distance": vwap_distance,
        "vwap_distance_pct": vwap_distance,
        "relative_volume": relative_volume,
        "volume_quality": volume_quality,
        "late_entry_flag": late_entry_flag,
        "mfe": mfe_pct,
        "mae": mae_pct,
        "max_favorable_excursion": mfe_pct,
        "max_adverse_excursion": mae_pct,
    }


def pmo_pattern_empty(status: str = "NO_PATTERN", note: str = "") -> Dict[str, Any]:
    return {
        "pattern_name": "None",
        "pattern_direction": "None",
        "pattern_confidence": 0.0,
        "pattern_score_mod": 0,
        "pattern_found": False,
        "pattern_status": status,
        "pattern_note": note,
    }


def pmo_pattern_result_dict(result: Any, status: str = "MATCH", note: str = "") -> Dict[str, Any]:
    if result is None:
        return pmo_pattern_empty(status, note)
    try:
        data = result.get_journal_dict()
    except Exception:
        return pmo_pattern_empty("ERROR", "pattern result could not be serialized")
    found = bool(getattr(result, "pattern_found", False))
    data.update({
        "pattern_found": found,
        "pattern_status": status if found else "NO_PATTERN",
        "pattern_note": note,
    })
    return data


def pmo_pattern_prepare_rows(rows: Iterable[Dict[str, Any]]) -> List[Dict[str, Any]]:
    prepared: List[Dict[str, Any]] = []
    for row in rows or []:
        close = safe_float(row.get("close") or row.get("c"), 0)
        if close <= 0:
            continue
        timestamp = row.get("datetime") or row.get("date") or row.get("timestamp") or row.get("time") or row.get("t") or ""
        prepared.append({
            "datetime": timestamp,
            "open": safe_float(row.get("open") or row.get("o"), close),
            "high": safe_float(row.get("high") or row.get("h"), close),
            "low": safe_float(row.get("low") or row.get("l"), close),
            "close": close,
            "volume": safe_float(row.get("volume") or row.get("v"), 0),
        })
    return prepared


def pmo_apply_pattern_modifier(base_score: float, symbol: str, trade_direction: str, settings: Dict[str, Any]) -> tuple:
    if not settings.get("ENABLE_PMO_PATTERN_ENGINE", True):
        return base_score, pmo_pattern_empty("OFF", "pattern engine disabled")
    if not PMO_PATTERN_ENGINE_AVAILABLE or _PATTERN_ENGINE is None or apply_pattern_to_score is None:
        return base_score, pmo_pattern_empty("UNAVAILABLE", PMO_PATTERN_ENGINE_ERROR or "pattern engine unavailable")
    min_rows = int(max(10, safe_float(settings.get("PMO_PATTERN_ENGINE_MIN_INTRADAY_ROWS", 20), 20)))
    lookback = max(min_rows, int(max(40, safe_float(settings.get("PMO_INTRADAY_BARS_LOOKBACK", 78), 78))))
    rows = pmo_pattern_prepare_rows(pmo_edge_load_ohlcv_rows(symbol, intraday=True, limit=lookback))
    if len(rows) < min_rows:
        return base_score, pmo_pattern_empty("DATA_REQUIRED", f"pattern engine needs {min_rows} intraday rows; found {len(rows)}")
    try:
        adjusted_score, result = apply_pattern_to_score(base_score, rows, trade_direction, engine=_PATTERN_ENGINE)
        data = pmo_pattern_result_dict(result)
        data["pattern_rows"] = len(rows)
        return adjusted_score, data
    except Exception as exc:
        return base_score, pmo_pattern_empty("ERROR", f"pattern engine error: {str(exc)[:120]}")


def pmo_pattern_for_chart_rows(rows: Iterable[Dict[str, Any]], trade_direction: str, settings: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    settings = settings or load_settings()
    if not settings.get("ENABLE_PMO_PATTERN_ENGINE", True):
        return pmo_pattern_empty("OFF", "pattern engine disabled")
    if not PMO_PATTERN_ENGINE_AVAILABLE or _PATTERN_ENGINE is None:
        return pmo_pattern_empty("UNAVAILABLE", PMO_PATTERN_ENGINE_ERROR or "pattern engine unavailable")
    min_rows = int(max(10, safe_float(settings.get("PMO_PATTERN_ENGINE_MIN_INTRADAY_ROWS", 20), 20)))
    prepared = pmo_pattern_prepare_rows(rows)
    if len(prepared) < min_rows:
        return pmo_pattern_empty("DATA_REQUIRED", f"pattern engine needs {min_rows} rows; found {len(prepared)}")
    try:
        result = _PATTERN_ENGINE.detect(prepared, trade_direction)
        data = pmo_pattern_result_dict(result)
        data["pattern_rows"] = len(prepared)
        return data
    except Exception as exc:
        return pmo_pattern_empty("ERROR", f"pattern engine error: {str(exc)[:120]}")


def pmo_fvg_empty(status: str = "NO_FVG", note: str = "") -> Dict[str, Any]:
    return {
        "fvg_found": False,
        "fvg_signal": "NONE",
        "fvg_confluence": "NONE",
        "fvg_score_mod": 0,
        "fvg_gap_low": "",
        "fvg_gap_high": "",
        "fvg_gap_pct": "",
        "fvg_price_in_zone": False,
        "fvg_total_active": 0,
        "fvg_status": status,
        "fvg_note": note,
        "fvg_score_influence": False,
        "fvg_zones": [],
    }


def pmo_fvg_detector_from_settings(settings: Dict[str, Any]) -> Any:
    if not PMO_FVG_AVAILABLE or FVGDetector is None:
        return None
    return FVGDetector(
        min_gap_pct=safe_float(settings.get("PMO_FVG_MIN_GAP_PCT", 0.10), 0.10),
        zone_proximity_pct=safe_float(settings.get("PMO_FVG_ZONE_PROXIMITY_PCT", 0.50), 0.50),
        lookback=int(max(3, safe_float(settings.get("PMO_FVG_LOOKBACK_BARS", 50), 50))),
        score_modifier=int(safe_float(settings.get("PMO_FVG_SCORE_MODIFIER", 5), 5)),
        against_modifier=int(safe_float(settings.get("PMO_FVG_AGAINST_MODIFIER", -3), -3)),
    )


def pmo_fvg_result_dict(result: Any, status: str = "MATCH", note: str = "", score_influence: bool = False) -> Dict[str, Any]:
    if result is None:
        return pmo_fvg_empty(status, note)
    try:
        data = result.get_journal_dict()
    except Exception:
        return pmo_fvg_empty("ERROR", "FVG result could not be serialized")
    found = bool(data.get("fvg_found"))
    try:
        dashboard = result.get_dashboard_dict()
    except Exception:
        dashboard = {}
    data.update({
        "fvg_status": status if found else "NO_FVG",
        "fvg_note": note,
        "fvg_score_influence": bool(score_influence),
        "fvg_zones": dashboard.get("zones", []),
    })
    return data


def pmo_apply_fvg_modifier(base_score: float, symbol: str, trade_direction: str, settings: Dict[str, Any]) -> tuple:
    if not settings.get("PMO_FVG_ENABLED", True):
        return base_score, pmo_fvg_empty("OFF", "FVG detector disabled")
    detector = pmo_fvg_detector_from_settings(settings)
    if detector is None:
        return base_score, pmo_fvg_empty("UNAVAILABLE", PMO_FVG_ERROR or "FVG detector unavailable")
    min_rows = int(max(3, safe_float(settings.get("PMO_PATTERN_ENGINE_MIN_INTRADAY_ROWS", 20), 20)))
    lookback = int(max(min_rows, safe_float(settings.get("PMO_FVG_LOOKBACK_BARS", 50), 50)))
    rows = pmo_pattern_prepare_rows(pmo_edge_load_ohlcv_rows(symbol, intraday=True, limit=lookback))
    if len(rows) < min_rows:
        return base_score, pmo_fvg_empty("DATA_REQUIRED", f"FVG detector needs {min_rows} intraday rows; found {len(rows)}")
    try:
        result = detector.detect(rows, trade_direction)
        score_influence = bool(settings.get("PMO_FVG_SCORE_INFLUENCE_ENABLED", False))
        data = pmo_fvg_result_dict(result, score_influence=score_influence)
        data["fvg_rows"] = len(rows)
        if not score_influence:
            if data.get("fvg_found"):
                data["fvg_note"] = "FVG detected; score influence disabled"
            return base_score, data
        delta = safe_float(data.get("fvg_score_mod"), 0)
        cap = int(max(0, safe_float(settings.get("PMO_FVG_COMBINED_CAP", 12), 12)))
        if cap:
            delta = max(-cap, min(cap, delta))
        return base_score + delta, data
    except Exception as exc:
        return base_score, pmo_fvg_empty("ERROR", f"FVG detector error: {str(exc)[:120]}")


def pmo_fvg_for_chart_rows(rows: Iterable[Dict[str, Any]], trade_direction: str, settings: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    settings = settings or load_settings()
    if not settings.get("PMO_FVG_ENABLED", True):
        return pmo_fvg_empty("OFF", "FVG detector disabled")
    detector = pmo_fvg_detector_from_settings(settings)
    if detector is None:
        return pmo_fvg_empty("UNAVAILABLE", PMO_FVG_ERROR or "FVG detector unavailable")
    min_rows = int(max(3, safe_float(settings.get("PMO_PATTERN_ENGINE_MIN_INTRADAY_ROWS", 20), 20)))
    prepared = pmo_pattern_prepare_rows(rows)
    if len(prepared) < min_rows:
        return pmo_fvg_empty("DATA_REQUIRED", f"FVG detector needs {min_rows} rows; found {len(prepared)}")
    try:
        result = detector.detect(prepared, trade_direction)
        data = pmo_fvg_result_dict(
            result,
            score_influence=bool(settings.get("PMO_FVG_SCORE_INFLUENCE_ENABLED", False)),
        )
        data["fvg_rows"] = len(prepared)
        return data
    except Exception as exc:
        return pmo_fvg_empty("ERROR", f"FVG detector error: {str(exc)[:120]}")


def pmo_edge_engines_empty(status: str = "NO_EDGE_ENGINE", note: str = "") -> Dict[str, Any]:
    return {
        "edge_engine_status": status,
        "edge_engine_note": note,
        "edge_signal": "NEUTRAL",
        "edge_combined_mod": 0,
        "edge_bull_count": 0,
        "edge_bear_count": 0,
        "edge_score_influence": False,
        "orb_signal": "NONE",
        "orb_mod": 0,
        "orb_high": "",
        "orb_low": "",
        "rs_signal": "NONE",
        "rs_mod": 0,
        "rs_delta_pct": "",
        "poc_signal": "NONE",
        "poc_mod": 0,
        "poc_price": "",
        "gap_signal": "NONE",
        "gap_mod": 0,
        "gap_pct": "",
        "sec_signal": "NONE",
        "sec_mod": 0,
        "sec_index": "",
        "dashboard": {},
    }


def pmo_edge_engine_sector_context(symbol: str, settings: Dict[str, Any]) -> Dict[str, Any]:
    clean = str(symbol or "").strip().upper()
    sector_index = ""
    sector_change = 0.0
    try:
        import pmo_edge_engines as edge_module

        sector_index = edge_module.SECTOR_MAP.get(clean, "")
    except Exception:
        sector_index = ""
    if sector_index:
        try:
            rows = pmo_barchart_index_context(settings).get("rows", [])
        except Exception:
            rows = []
        for row in rows:
            if str(row.get("symbol", "")).upper() == sector_index.upper():
                sector_change = safe_float(row.get("change_pct"), 0)
                break
    return {"sector_index": sector_index, "sector_change_pct": sector_change}


def pmo_edge_engine_prev_close(symbol: str) -> float:
    rows = pmo_edge_load_ohlcv_rows(symbol, intraday=False, limit=5)
    closes = [safe_float(row.get("close"), 0) for row in rows if safe_float(row.get("close"), 0) > 0]
    if len(closes) >= 2:
        return closes[-2]
    if closes:
        return closes[0]
    return 0.0


def pmo_edge_engines_result_dict(result: Any, status: str = "READY", note: str = "", score_influence: bool = False) -> Dict[str, Any]:
    if result is None:
        return pmo_edge_engines_empty(status, note)
    try:
        journal = result.get_journal_dict()
    except Exception:
        return pmo_edge_engines_empty("ERROR", "edge engine result could not be serialized")
    try:
        dashboard = result.get_dashboard_dict()
    except Exception:
        dashboard = {}
    journal.update({
        "edge_engine_status": status,
        "edge_engine_note": note,
        "edge_score_influence": bool(score_influence),
        "dashboard": dashboard,
    })
    return journal


def pmo_analyze_edge_engines(symbol: str, trade_direction: str, settings: Dict[str, Any], intraday_rows: Optional[List[Dict[str, Any]]] = None) -> Dict[str, Any]:
    if not settings.get("PMO_EDGE_ENGINES_ENABLED", True):
        return pmo_edge_engines_empty("OFF", "edge engines disabled")
    if not PMO_EDGE_ENGINES_AVAILABLE or _EDGE_ENGINE_BUNDLE is None:
        return pmo_edge_engines_empty("UNAVAILABLE", PMO_EDGE_ENGINES_ERROR or "edge engines unavailable")
    min_rows = int(max(10, safe_float(settings.get("PMO_PATTERN_ENGINE_MIN_INTRADAY_ROWS", 20), 20)))
    lookback = int(max(min_rows, safe_float(settings.get("PMO_INTRADAY_BARS_LOOKBACK", 78), 78)))
    rows = pmo_pattern_prepare_rows(intraday_rows if intraday_rows is not None else pmo_edge_load_ohlcv_rows(symbol, intraday=True, limit=lookback))
    if len(rows) < min_rows:
        return pmo_edge_engines_empty("DATA_REQUIRED", f"edge engines need {min_rows} intraday rows; found {len(rows)}")
    spy_rows = pmo_pattern_prepare_rows(pmo_edge_load_ohlcv_rows("SPY", intraday=True, limit=lookback))
    sector = pmo_edge_engine_sector_context(symbol, settings)
    prev_close = pmo_edge_engine_prev_close(symbol)
    try:
        result = _EDGE_ENGINE_BUNDLE.analyze(
            ticker=symbol,
            bars=rows,
            spy_bars=spy_rows,
            sector_index=sector.get("sector_index") or None,
            sector_change_pct=safe_float(sector.get("sector_change_pct"), 0),
            prev_close=prev_close,
            trade_direction=trade_direction,
            orb_minutes=int(max(5, safe_float(settings.get("PMO_ORB_MINUTES", 15), 15))),
            target_pct=safe_float(settings.get("PMO_DEFAULT_TAKE_PROFIT_PCT", 6.0), 6.0),
            rs_threshold_pct=safe_float(settings.get("PMO_RS_THRESHOLD_PCT", 0.5), 0.5),
            poc_buckets=int(max(5, safe_float(settings.get("PMO_POC_BUCKETS", 20), 20))),
            gap_threshold_pct=safe_float(settings.get("PMO_GAP_THRESHOLD_PCT", 0.5), 0.5),
            sector_threshold_pct=safe_float(settings.get("PMO_SECTOR_THRESHOLD_PCT", 0.3), 0.3),
            combined_cap=int(max(0, safe_float(settings.get("PMO_EDGE_COMBINED_CAP", 15), 15))),
        )
        score_influence = bool(settings.get("PMO_EDGE_SCORE_INFLUENCE_ENABLED", False)) and not bool(settings.get("PMO_EDGE_READ_ONLY", True))
        data = pmo_edge_engines_result_dict(result, status="READY", score_influence=score_influence)
        data["edge_rows"] = len(rows)
        data["spy_rows"] = len(spy_rows)
        if not score_influence:
            data["edge_engine_note"] = "edge engines are read-only; score influence disabled"
        return data
    except Exception as exc:
        return pmo_edge_engines_empty("ERROR", f"edge engine error: {str(exc)[:120]}")


def pmo_intraday_market_window_open(ts: Optional[datetime] = None) -> bool:
    current = ts or now_et()
    if current.weekday() >= 5:
        return False
    market_open = current.replace(hour=9, minute=0, second=0, microsecond=0)
    market_close = current.replace(hour=16, minute=30, second=0, microsecond=0)
    return market_open <= current <= market_close


def pmo_fetch_intraday_bars(
    symbol: str,
    lookback_bars: int = 78,
    settings: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    settings = settings or load_settings()
    clean_symbol = str(symbol or "").strip().upper()
    if not clean_symbol:
        return {"ok": False, "symbol": "", "rows": 0, "error": "missing symbol"}
    if detect_market(clean_symbol, "AUTO") != "STOCK":
        return {"ok": True, "symbol": clean_symbol, "rows": 0, "skipped": True, "reason": "non-stock symbol"}
    if not pmo_intraday_market_window_open():
        return {
            "ok": True,
            "symbol": clean_symbol,
            "rows": 0,
            "skipped": True,
            "market_hours_skip": True,
            "reason": "outside market hours",
        }
    if ALPACA_IMPORT_ERROR or StockBarsRequest is None or TimeFrame is None:
        return {"ok": False, "symbol": clean_symbol, "rows": 0, "error": "Alpaca stock bars client unavailable"}
    if bot.stock_client is None:
        return {"ok": False, "symbol": clean_symbol, "rows": 0, "error": "stock_client not initialized"}

    lookback = int(max(20, min(200, safe_float(lookback_bars, 78))))
    end = now_et()
    start = end - timedelta(minutes=(lookback * 5) + 90)

    try:
        try:
            from alpaca.data.timeframe import TimeFrameUnit
            timeframe = TimeFrame(5, TimeFrameUnit.Minute)
        except Exception:
            timeframe = TimeFrame.Minute

        last_error = ""
        df = None
        feed_used = ""
        for feed_name in bot.feed_sequence():
            try:
                req = StockBarsRequest(
                    symbol_or_symbols=clean_symbol,
                    timeframe=timeframe,
                    start=start,
                    end=end,
                    feed=bot.feed_enum(feed_name),
                )
                candidate = bot.stock_client.get_stock_bars(req).df
                if candidate is not None and not candidate.empty:
                    df = candidate
                    feed_used = str(feed_name)
                    break
            except Exception as exc:
                last_error = str(exc)
        if df is None or df.empty:
            return {"ok": False, "symbol": clean_symbol, "rows": 0, "error": last_error or "no bars returned"}

        frame = df.reset_index() if hasattr(df, "reset_index") else df
        if "symbol" in frame.columns:
            frame = frame[frame["symbol"].astype(str).str.upper() == clean_symbol].copy()
        if frame.empty:
            return {"ok": False, "symbol": clean_symbol, "rows": 0, "error": "bars returned for different symbol"}

        rename = {}
        for target, candidates in {
            "timestamp": ("timestamp", "date", "time", "t"),
            "open": ("open", "o"),
            "high": ("high", "h"),
            "low": ("low", "l"),
            "close": ("close", "c"),
            "volume": ("volume", "v", "vol"),
        }.items():
            if target not in frame.columns:
                for candidate in candidates:
                    if candidate in frame.columns:
                        rename[candidate] = target
                        break
        if rename:
            frame = frame.rename(columns=rename)
        required = ["open", "high", "low", "close", "volume"]
        missing = [name for name in required if name not in frame.columns]
        if missing:
            return {"ok": False, "symbol": clean_symbol, "rows": 0, "error": f"missing bar columns: {', '.join(missing)}"}
        if "timestamp" not in frame.columns:
            frame["timestamp"] = ""

        output = frame[["timestamp", "open", "high", "low", "close", "volume"]].tail(lookback).copy()
        for column in ["open", "high", "low", "close", "volume"]:
            output[column] = output[column].map(lambda value: safe_float(value, 0))
        output = output[output["close"] > 0]
        if output.empty:
            return {"ok": False, "symbol": clean_symbol, "rows": 0, "error": "no usable close prices"}

        out_dir = PMO_DIR / "pmo_backtest_data"
        out_dir.mkdir(parents=True, exist_ok=True)
        out_path = out_dir / f"{pmo_edge_safe_symbol(clean_symbol)}_5m.csv"
        output.to_csv(out_path, index=False)
        return {
            "ok": True,
            "symbol": clean_symbol,
            "rows": int(len(output)),
            "path": str(out_path),
            "feed": feed_used,
            "last_bar": str(output.iloc[-1].get("timestamp", "")),
            "market_hours_skip": False,
        }
    except Exception as exc:
        return {"ok": False, "symbol": clean_symbol, "rows": 0, "error": str(exc)[:240]}


def pmo_alpaca_chart_timeframe(value: str) -> tuple[Any, str, int]:
    raw = str(value or "5Min").strip().lower()
    try:
        from alpaca.data.timeframe import TimeFrameUnit
    except Exception:
        TimeFrameUnit = None
    minute_unit = getattr(TimeFrameUnit, "Minute", None) if TimeFrameUnit is not None else None
    hour_unit = getattr(TimeFrameUnit, "Hour", None) if TimeFrameUnit is not None else None
    day_unit = getattr(TimeFrameUnit, "Day", None) if TimeFrameUnit is not None else None

    def make_tf(amount: int, unit: Any, fallback: Any) -> Any:
        if TimeFrame is None:
            return None
        try:
            if unit is not None:
                return TimeFrame(amount, unit)
        except Exception:
            pass
        return fallback

    if raw in {"1", "1m", "1min", "minute"}:
        return make_tf(1, minute_unit, getattr(TimeFrame, "Minute", None)), "1Min", 7
    if raw in {"15", "15m", "15min"}:
        return make_tf(15, minute_unit, getattr(TimeFrame, "Minute", None)), "15Min", 21
    if raw in {"60", "1h", "1hour", "hour"}:
        return make_tf(1, hour_unit, getattr(TimeFrame, "Hour", getattr(TimeFrame, "Minute", None))), "1Hour", 90
    if raw in {"240", "4h", "4hour", "4hours"}:
        return make_tf(1, hour_unit, getattr(TimeFrame, "Hour", getattr(TimeFrame, "Minute", None))), "1Hour", 120
    if raw in {"d", "1d", "day", "1day"}:
        return make_tf(1, day_unit, getattr(TimeFrame, "Day", None)), "1Day", 420
    if raw in {"w", "1w", "week", "1week"}:
        return make_tf(1, day_unit, getattr(TimeFrame, "Day", None)), "1Day", 900
    return make_tf(5, minute_unit, getattr(TimeFrame, "Minute", None)), "5Min", 14


def pmo_chart_ema(values: List[float], period: int) -> List[Optional[float]]:
    if not values or period <= 1:
        return [safe_float(v, 0) for v in values]
    alpha = 2 / (period + 1)
    out: List[Optional[float]] = []
    ema: Optional[float] = None
    for value in values:
        price = safe_float(value, 0)
        ema = price if ema is None else ((price - ema) * alpha) + ema
        out.append(round(ema, 4))
    return out


def pmo_chart_rsi(values: List[float], period: int = 14) -> List[Optional[float]]:
    out: List[Optional[float]] = [None for _ in values]
    if len(values) <= period:
        return out
    gains: List[float] = []
    losses: List[float] = []
    for idx in range(1, len(values)):
        change = safe_float(values[idx], 0) - safe_float(values[idx - 1], 0)
        gains.append(max(change, 0))
        losses.append(abs(min(change, 0)))
        if idx >= period:
            recent_gains = gains[idx - period:idx]
            recent_losses = losses[idx - period:idx]
            avg_gain = sum(recent_gains) / period if recent_gains else 0
            avg_loss = sum(recent_losses) / period if recent_losses else 0
            if avg_loss <= 0:
                out[idx] = 100.0
            else:
                rs = avg_gain / avg_loss
                out[idx] = round(100 - (100 / (1 + rs)), 2)
    return out


def pmo_chart_vwap(highs: List[float], lows: List[float], closes: List[float], volumes: List[float]) -> List[Optional[float]]:
    out: List[Optional[float]] = []
    pv_total = 0.0
    volume_total = 0.0
    for high, low, close, volume in zip(highs, lows, closes, volumes):
        vol = max(0.0, safe_float(volume, 0))
        typical = (safe_float(high, 0) + safe_float(low, 0) + safe_float(close, 0)) / 3
        pv_total += typical * vol
        volume_total += vol
        out.append(round(pv_total / volume_total, 4) if volume_total > 0 else None)
    return out


def pmo_extract_alpaca_bar_rows(df: Any, symbol: str, limit: int) -> List[Dict[str, Any]]:
    if df is None:
        return []
    frame = df.reset_index() if hasattr(df, "reset_index") else df
    try:
        if "symbol" in frame.columns:
            frame = frame[frame["symbol"].astype(str).str.upper() == symbol.upper()].copy()
    except Exception:
        pass
    if getattr(frame, "empty", False):
        return []
    rename = {}
    for target, candidates in {
        "timestamp": ("timestamp", "date", "time", "t"),
        "open": ("open", "o"),
        "high": ("high", "h"),
        "low": ("low", "l"),
        "close": ("close", "c"),
        "volume": ("volume", "v", "vol"),
    }.items():
        if target not in frame.columns:
            for candidate in candidates:
                if candidate in frame.columns:
                    rename[candidate] = target
                    break
    if rename:
        frame = frame.rename(columns=rename)
    required = ["open", "high", "low", "close", "volume"]
    if any(name not in frame.columns for name in required):
        return []
    if "timestamp" not in frame.columns:
        frame["timestamp"] = ""
    try:
        frame = frame.sort_values("timestamp")
    except Exception:
        pass
    output = frame[["timestamp", "open", "high", "low", "close", "volume"]].tail(max(20, min(500, int(limit)))).copy()
    rows: List[Dict[str, Any]] = []
    for _, row in output.iterrows():
        close = safe_float(row.get("close"), 0)
        if close <= 0:
            continue
        ts_value = row.get("timestamp", "")
        try:
            ts_text = ts_value.isoformat()
        except Exception:
            ts_text = str(ts_value)
        rows.append({
            "time": ts_text,
            "open": round(safe_float(row.get("open"), close), 4),
            "high": round(safe_float(row.get("high"), close), 4),
            "low": round(safe_float(row.get("low"), close), 4),
            "close": round(close, 4),
            "volume": round(safe_float(row.get("volume"), 0), 2),
        })
    return rows


def pmo_alpaca_chart_bars(symbol: str, timeframe: str = "5Min", limit: int = 160, market: str = "AUTO") -> Dict[str, Any]:
    clean_symbol = str(symbol or "SPY").strip().upper()
    clean_symbol = re.sub(r"[^A-Z0-9./_-]", "", clean_symbol)[:24] or "SPY"
    market_type = detect_market(clean_symbol, market)
    row_limit = max(40, min(500, int(safe_float(limit, 160))))
    timeframe_obj, timeframe_label, lookback_days = pmo_alpaca_chart_timeframe(timeframe)
    if ALPACA_IMPORT_ERROR or TimeFrame is None or timeframe_obj is None:
        return {"ok": False, "symbol": clean_symbol, "rows": 0, "error": "Alpaca chart data client unavailable", "live_unlocked": False, "orders_placed": False}
    end = now_et()
    start = end - timedelta(days=lookback_days)
    last_error = ""
    feed_used = ""
    rows: List[Dict[str, Any]] = []
    try:
        if market_type == "CRYPTO":
            if bot.crypto_client is None or CryptoBarsRequest is None:
                return {"ok": False, "symbol": clean_symbol, "market": market_type, "rows": 0, "error": "crypto chart client unavailable", "live_unlocked": False, "orders_placed": False}
            crypto_symbol = normalize_crypto_symbol(clean_symbol)
            req = CryptoBarsRequest(symbol_or_symbols=crypto_symbol, timeframe=timeframe_obj, start=start, end=end)
            df = bot.crypto_client.get_crypto_bars(req).df
            rows = pmo_extract_alpaca_bar_rows(df, crypto_symbol, row_limit)
            feed_used = "ALPACA_CRYPTO"
        elif market_type == "OPTION":
            return {"ok": False, "symbol": clean_symbol, "market": market_type, "rows": 0, "error": "option chart bars are not enabled in dashboard chart", "live_unlocked": False, "orders_placed": False}
        else:
            if bot.stock_client is None or StockBarsRequest is None:
                return {"ok": False, "symbol": clean_symbol, "market": "STOCK", "rows": 0, "error": "stock chart client unavailable", "live_unlocked": False, "orders_placed": False}
            for feed_name in bot.feed_sequence():
                try:
                    req = StockBarsRequest(
                        symbol_or_symbols=clean_symbol,
                        timeframe=timeframe_obj,
                        start=start,
                        end=end,
                        feed=bot.feed_enum(feed_name),
                    )
                    df = bot.stock_client.get_stock_bars(req).df
                    rows = pmo_extract_alpaca_bar_rows(df, clean_symbol, row_limit)
                    if rows:
                        feed_used = str(feed_name)
                        break
                except Exception as exc:
                    last_error = str(exc)
    except Exception as exc:
        return {"ok": False, "symbol": clean_symbol, "market": market_type, "rows": 0, "error": str(exc)[:240], "live_unlocked": False, "orders_placed": False}
    if not rows:
        return {"ok": False, "symbol": clean_symbol, "market": market_type, "timeframe": timeframe_label, "rows": 0, "error": last_error or "no Alpaca bars returned", "live_unlocked": False, "orders_placed": False}

    closes = [safe_float(row["close"], 0) for row in rows]
    highs = [safe_float(row["high"], 0) for row in rows]
    lows = [safe_float(row["low"], 0) for row in rows]
    volumes = [safe_float(row["volume"], 0) for row in rows]
    ema9 = pmo_chart_ema(closes, 9)
    ema21 = pmo_chart_ema(closes, 21)
    vwap = pmo_chart_vwap(highs, lows, closes, volumes)
    rsi = pmo_chart_rsi(closes, 14)
    for idx, row in enumerate(rows):
        row["ema9"] = ema9[idx]
        row["ema21"] = ema21[idx]
        row["vwap"] = vwap[idx]
        row["rsi"] = rsi[idx]
    latest = rows[-1]
    first_close = safe_float(rows[0].get("close"), 0)
    last_close = safe_float(latest.get("close"), 0)
    change_pct = ((last_close - first_close) / first_close * 100) if first_close else 0.0
    settings = load_settings()
    chart_direction = "long" if change_pct >= 0 else "short"
    pattern = pmo_pattern_for_chart_rows(rows, chart_direction, settings)
    fvg = pmo_fvg_for_chart_rows(rows, chart_direction, settings)
    edge_engines = pmo_analyze_edge_engines(clean_symbol, chart_direction, settings, intraday_rows=rows)
    return {
        "ok": True,
        "symbol": clean_symbol,
        "market": market_type,
        "timeframe": timeframe_label,
        "rows": len(rows),
        "feed": feed_used,
        "change_pct": round(change_pct, 3),
        "latest": latest,
        "bars": rows,
        "pattern": pattern,
        "fvg": fvg,
        "edge_engines": edge_engines,
        "safety_note": "Read-only Alpaca market-data chart. No orders submitted and no live settings changed.",
        "live_unlocked": False,
        "orders_placed": False,
    }


def pmo_refresh_intraday_watchlist(settings: Optional[Dict[str, Any]] = None, force: bool = False) -> Dict[str, Any]:
    global _intraday_last_refresh
    settings = settings or load_settings()
    if not bool(settings.get("PMO_INTRADAY_REFRESH_ENABLED", True)):
        return {"ok": True, "skipped": True, "reason": "PMO_INTRADAY_REFRESH_ENABLED=False", "fetched": 0}

    interval = int(max(60, safe_float(settings.get("PMO_INTRADAY_REFRESH_INTERVAL_SECONDS", 600), 600)))
    now_mono = time.monotonic()
    if not force and _intraday_last_refresh is not None:
        elapsed = now_mono - _intraday_last_refresh
        if elapsed < interval:
            return {
                "ok": True,
                "skipped": True,
                "reason": f"rate_limited; {int(interval - elapsed)}s until next refresh",
                "fetched": 0,
            }

    auto_watchlist = load_auto_watchlist()
    selected_symbols = []
    for item in auto_watchlist.get("selected", []):
        if isinstance(item, dict):
            selected_symbols.append(item.get("symbol"))
        else:
            selected_symbols.append(item)
    symbols = unique_symbols(
        settings.get("PMO_WATCHLIST", []),
        auto_watchlist.get("symbols", []),
        selected_symbols,
        settings.get("PMO_AUTO_WATCHLIST_UNIVERSE", []),
    )
    max_symbols = int(max(1, min(150, safe_float(settings.get("PMO_INTRADAY_REFRESH_MAX_SYMBOLS", 40), 40))))
    stock_symbols = [sym for sym in symbols if detect_market(str(sym), "AUTO") == "STOCK"][:max_symbols]
    if not stock_symbols:
        return {"ok": True, "skipped": True, "reason": "empty stock watchlist", "fetched": 0}

    lookback = int(max(20, min(200, safe_float(settings.get("PMO_INTRADAY_BARS_LOOKBACK", 78), 78))))
    fetched = 0
    skipped = 0
    errors: List[str] = []
    results: List[Dict[str, Any]] = []
    market_hours_skip = False
    for sym in stock_symbols:
        result = pmo_fetch_intraday_bars(sym, lookback_bars=lookback, settings=settings)
        results.append({
            "symbol": sym,
            "ok": bool(result.get("ok")),
            "rows": result.get("rows", 0),
            "skipped": bool(result.get("skipped")),
            "reason": result.get("reason", result.get("error", "")),
        })
        if result.get("market_hours_skip"):
            market_hours_skip = True
            break
        if result.get("ok") and int(safe_float(result.get("rows", 0), 0)) > 0:
            fetched += 1
        elif result.get("skipped"):
            skipped += 1
        else:
            errors.append(f"{sym}: {str(result.get('error', 'unknown error'))[:80]}")

    _intraday_last_refresh = now_mono
    return {
        "ok": True,
        "timestamp": now_et().isoformat(),
        "fetched": fetched,
        "skipped": skipped,
        "symbols_attempted": 0 if market_hours_skip else len(results),
        "symbols_available": len(stock_symbols),
        "market_hours_skip": market_hours_skip,
        "lookback_bars": lookback,
        "data_dir": str(PMO_DIR / "pmo_backtest_data"),
        "errors": errors[:8],
        "results": results[:12],
    }


def pmo_edge_sma(values: List[float], period: int) -> Optional[float]:
    period = int(max(1, period))
    vals = [safe_float(value, 0) for value in values if safe_float(value, 0) > 0]
    if len(vals) < period:
        return None
    return sum(vals[-period:]) / period


def pmo_edge_rsi(closes: List[float], period: int = 14) -> Optional[float]:
    vals = [safe_float(value, 0) for value in closes if safe_float(value, 0) > 0]
    if len(vals) <= period:
        return None
    gains: List[float] = []
    losses: List[float] = []
    for idx in range(len(vals) - period, len(vals)):
        delta = vals[idx] - vals[idx - 1]
        gains.append(max(0.0, delta))
        losses.append(abs(min(0.0, delta)))
    avg_gain = sum(gains) / period
    avg_loss = sum(losses) / period
    if avg_loss <= 0:
        return 100.0
    rs = avg_gain / avg_loss
    return round(100 - (100 / (1 + rs)), 2)


def pmo_edge_atr(rows: List[Dict[str, Any]], period: int = 14) -> Optional[float]:
    if len(rows) <= period:
        return None
    true_ranges: List[float] = []
    for idx in range(1, len(rows)):
        high = safe_float(rows[idx].get("high"), 0)
        low = safe_float(rows[idx].get("low"), 0)
        prev_close = safe_float(rows[idx - 1].get("close"), 0)
        if high <= 0 or low <= 0 or prev_close <= 0:
            continue
        true_ranges.append(max(high - low, abs(high - prev_close), abs(low - prev_close)))
    if len(true_ranges) < period:
        return None
    return sum(true_ranges[-period:]) / period


def pmo_edge_result(edge_id: str, status: str, direction: str = "NONE", reason: str = "", **extra: Any) -> Dict[str, Any]:
    definition = next((item for item in pmo_edge_library_definitions() if item["id"] == edge_id), {"id": edge_id, "name": edge_id})
    return {
        "id": edge_id,
        "name": definition.get("name", edge_id),
        "family": definition.get("family", "UNKNOWN"),
        "status": status,
        "direction": direction,
        "reason": reason,
        "signal_only": True,
        **extra,
    }


def pmo_evaluate_edge_library(
    settings: Dict[str, Any],
    symbol: str,
    latest: Optional[Dict[str, Any]] = None,
    bars: Optional[Dict[str, Any]] = None,
    daily_rows: Optional[List[Dict[str, Any]]] = None,
    intraday_rows: Optional[List[Dict[str, Any]]] = None,
    score: Any = None,
    record: bool = False,
) -> Dict[str, Any]:
    symbol = str(symbol or "").strip().upper()
    latest = latest if isinstance(latest, dict) else {}
    bars = bars if isinstance(bars, dict) else {}
    daily_rows = daily_rows if isinstance(daily_rows, list) else pmo_edge_load_ohlcv_rows(symbol, intraday=False, limit=280)
    intraday_rows = intraday_rows if isinstance(intraday_rows, list) else pmo_edge_load_ohlcv_rows(symbol, intraday=True, limit=390)
    closes = [safe_float(row.get("close"), 0) for row in daily_rows if safe_float(row.get("close"), 0) > 0]
    highs = [safe_float(row.get("high"), 0) for row in daily_rows if safe_float(row.get("high"), 0) > 0]
    lows = [safe_float(row.get("low"), 0) for row in daily_rows if safe_float(row.get("low"), 0) > 0]
    volumes = [safe_float(row.get("volume"), 0) for row in daily_rows if safe_float(row.get("volume"), 0) >= 0]
    latest_price = safe_float(latest.get("price") or (closes[-1] if closes else 0), 0)
    edge_rows: List[Dict[str, Any]] = []

    if len(closes) >= 21 and len(volumes) >= 21:
        prev_high = max(highs[-21:-1] or closes[-21:-1])
        avg_volume = sum(volumes[-21:-1]) / max(1, len(volumes[-21:-1]))
        last_volume = volumes[-1]
        breakout = latest_price > prev_high
        volume_ok = last_volume > avg_volume * 1.5 if avg_volume > 0 else False
        status = "READY" if breakout and volume_ok else "WATCH" if breakout else "WAIT"
        edge_rows.append(pmo_edge_result(
            "momentum_breakout",
            status,
            "LONG" if breakout else "NONE",
            f"price {latest_price:.4g} vs 20-day high {prev_high:.4g}; volume {last_volume:.4g} vs avg {avg_volume:.4g}",
            stop_pct=3.0,
        ))
    else:
        edge_rows.append(pmo_edge_result("momentum_breakout", "DATA_REQUIRED", reason="needs 21+ daily OHLCV rows"))

    sma50 = pmo_edge_sma(closes, 50)
    rsi14 = pmo_edge_rsi(closes, 14)
    if sma50 and rsi14 is not None and latest_price > 0:
        long_signal = latest_price < sma50 * 0.98 and rsi14 < 30
        short_signal = latest_price > sma50 * 1.02 and rsi14 > 70
        status = "READY" if long_signal or short_signal else "WAIT"
        direction = "LONG" if long_signal else "SHORT" if short_signal else "NONE"
        edge_rows.append(pmo_edge_result(
            "mean_reversion_ma",
            status,
            direction,
            f"price {latest_price:.4g}, SMA50 {sma50:.4g}, RSI14 {rsi14:.2f}",
            stop_pct=3.0,
        ))
    else:
        edge_rows.append(pmo_edge_result("mean_reversion_ma", "DATA_REQUIRED", reason="needs 50+ daily/intraday rows for SMA and RSI"))

    if len(intraday_rows) >= 40:
        intraday_closes = [safe_float(row.get("close"), 0) for row in intraday_rows if safe_float(row.get("close"), 0) > 0]
        intraday_volumes = [safe_float(row.get("volume"), 0) for row in intraday_rows if safe_float(row.get("volume"), 0) >= 0]
        total_volume = sum(intraday_volumes)
        vwap = sum(close * volume for close, volume in zip(intraday_closes, intraday_volumes)) / total_volume if total_volume > 0 else 0
        recent_avg = sum(intraday_volumes[-20:]) / 20 if len(intraday_volumes) >= 20 else 0
        prior_avg = sum(intraday_volumes[-40:-20]) / 20 if len(intraday_volumes) >= 40 else 0
        last_intraday = intraday_closes[-1] if intraday_closes else latest_price
        rising_volume = recent_avg > prior_avg if prior_avg > 0 else False
        long_signal = vwap > 0 and last_intraday < vwap and rising_volume
        short_signal = vwap > 0 and last_intraday > vwap and not rising_volume
        edge_rows.append(pmo_edge_result(
            "vwap_intraday",
            "WATCH" if long_signal or short_signal else "WAIT",
            "LONG" if long_signal else "SHORT" if short_signal else "NONE",
            f"last {last_intraday:.4g}, VWAP {vwap:.4g}, recent volume avg {recent_avg:.4g}, prior {prior_avg:.4g}",
        ))
    else:
        edge_rows.append(pmo_edge_result("vwap_intraday", "DATA_REQUIRED", reason="needs 40+ 1m/5m intraday rows"))

    if not settings.get("PMO_FVG_ENABLED", True):
        edge_rows.append(pmo_edge_result("fair_value_gap", "OFF", reason="PMO_FVG_ENABLED=False"))
    elif len(intraday_rows) >= 20:
        fvg_direction = "long"
        try:
            first_intraday_close = safe_float(intraday_rows[0].get("close"), 0)
            last_intraday_close = safe_float(intraday_rows[-1].get("close"), latest_price)
            fvg_direction = "long" if last_intraday_close >= first_intraday_close else "short"
        except Exception:
            pass
        fvg_report = pmo_fvg_for_chart_rows(intraday_rows, fvg_direction, settings)
        confluence = str(fvg_report.get("fvg_confluence", "NONE")).upper()
        in_zone = bool(fvg_report.get("fvg_price_in_zone"))
        fvg_status = "READY" if confluence == "ALIGNED" and in_zone else "WATCH" if fvg_report.get("fvg_found") else "WAIT"
        edge_rows.append(pmo_edge_result(
            "fair_value_gap",
            fvg_status,
            str(fvg_report.get("fvg_signal") or "NONE"),
            str(fvg_report.get("fvg_note") or f"FVG {fvg_report.get('fvg_signal', 'NONE')} confluence {confluence}; in zone {in_zone}"),
            fvg=fvg_report,
        ))
    else:
        edge_rows.append(pmo_edge_result("fair_value_gap", "DATA_REQUIRED", reason="needs 20+ 1m/5m intraday rows"))

    data_required_edges = {
        "order_flow_tape": "needs trade-by-trade aggressor feed",
        "liquidity_stop_run": "needs tick/orderbook wick and sweep data",
        "pairs_stat_arb": "needs paired symbol history, hedge beta, and cointegration test",
        "order_book_imbalance": "needs L2 book snapshots",
        "news_sentiment": "needs low-latency news and sentiment model",
        "latency_arb": "requires direct exchange feed and colocated execution; PMO keeps this research-only",
        "option_flow_bias": "needs options sweep/feed data",
        "ml_pattern_risk": "needs trained model, feature store, and out-of-sample proof",
        "risk_premia_carry": "needs futures/yield curve term-structure data",
    }
    for edge_id, reason in data_required_edges.items():
        edge_rows.append(pmo_edge_result(edge_id, "DATA_REQUIRED", reason=reason))

    if len(daily_rows) >= 35 and len(highs) >= 21:
        atr14 = pmo_edge_atr(daily_rows, 14)
        atr_values = []
        for idx in range(max(15, len(daily_rows) - 35), len(daily_rows)):
            value = pmo_edge_atr(daily_rows[:idx], 14)
            if value:
                atr_values.append(value)
        atr_mean = sum(atr_values) / len(atr_values) if atr_values else 0
        prev_high = max(highs[-21:-1])
        breakout = latest_price > prev_high and bool(atr14 and atr_mean and atr14 > atr_mean * 1.1)
        edge_rows.append(pmo_edge_result(
            "volatility_breakout",
            "READY" if breakout else "WAIT",
            "LONG" if breakout else "NONE",
            f"ATR14 {safe_float(atr14, 0):.4g}, ATR mean {atr_mean:.4g}, prior 20-day high {prev_high:.4g}",
            stop_atr_mult=1.5,
        ))
    else:
        edge_rows.append(pmo_edge_result("volatility_breakout", "DATA_REQUIRED", reason="needs 35+ daily OHLCV rows"))

    minutes = now_et().hour * 60 + now_et().minute
    open_window = 9 * 60 + 30 <= minutes <= 10 * 60 + 30
    close_window = 15 * 60 + 15 <= minutes <= 16 * 60
    edge_rows.append(pmo_edge_result(
        "time_of_day",
        "WATCH" if open_window or close_window else "WAIT",
        "CONFIRM_REQUIRED" if open_window or close_window else "NONE",
        "open/close window active; require another PMO confirmation" if open_window or close_window else "outside primary time-of-day windows",
    ))

    score_value = safe_float(score if score is not None else bars.get("score"), 0)
    full_size_score = safe_float(settings.get("PMO_SMART_LIMIT_FULL_SIZE_SCORE", 88), 88)
    base_notional = safe_float(settings.get("PMO_ORDER_NOTIONAL_USD", 40), 40)
    max_notional = safe_float(settings.get("PMO_MAX_ORDER_NOTIONAL_USD", 60), 60)
    if score_value > 0 and full_size_score > 0:
        notional_scale = round(max(0.5, min(1.0, score_value / full_size_score)), 3)
    else:
        notional_scale = 0.5
    edge_rows.append(pmo_edge_result(
        "adaptive_sizing",
        "SIZING_ONLY",
        "NONE",
        f"score {score_value:.2f}, full-size threshold {full_size_score:.2f}, scale {notional_scale:.3f}",
        base_notional=base_notional,
        max_notional=max_notional,
        scaled_notional=round(min(base_notional, max_notional) * notional_scale, 2),
        notional_scale=notional_scale,
    ))

    ready = [row for row in edge_rows if row.get("status") == "READY"]
    watch = [row for row in edge_rows if row.get("status") == "WATCH"]
    data_required = [row for row in edge_rows if row.get("status") == "DATA_REQUIRED"]
    consensus = "RESEARCH_READY" if ready else "WATCH" if watch else "NO_EDGE"
    report = {
        "ok": True,
        "engine": "PMO Edge Library",
        "updated": now_et().isoformat(),
        "symbol": symbol,
        "mode": "SIGNAL_ONLY_RESEARCH",
        "live_order_allowed": False,
        "edge_count": len(edge_rows),
        "ready_count": len(ready),
        "watch_count": len(watch),
        "data_required_count": len(data_required),
        "consensus": consensus,
        "best_edges": [row.get("id") for row in ready[:5]] or [row.get("id") for row in watch[:5]],
        "edges": edge_rows,
        "definitions": pmo_edge_library_definitions(),
        "data": {
            "daily_rows": len(daily_rows),
            "intraday_rows": len(intraday_rows),
            "latest_price": latest_price,
        },
        "report_file": str(PMO_EDGE_LIBRARY_REPORT_FILE),
    }
    if record:
        write_json_file(PMO_EDGE_LIBRARY_REPORT_FILE, report)
    return report


def pmo_backtest_symbols(settings: Dict[str, Any], symbols: Optional[Any] = None) -> List[str]:
    raw = symbols if symbols is not None else settings.get("PMO_BACKTEST_DEFAULT_SYMBOLS", [])
    if isinstance(raw, str):
        raw_items = [item.strip() for item in raw.replace(";", ",").split(",")]
    elif isinstance(raw, (list, tuple, set)):
        raw_items = list(raw)
    else:
        raw_items = []
    max_symbols = int(max(1, safe_float(settings.get("PMO_BACKTEST_MAX_SYMBOLS", 8), 8)))
    return unique_symbols(raw_items)[:max_symbols]


def pmo_rows_vwap(rows: List[Dict[str, Any]]) -> float:
    weighted_sum = 0.0
    total_volume = 0.0
    for row in rows:
        close = safe_float(row.get("close"), 0)
        high = safe_float(row.get("high"), close)
        low = safe_float(row.get("low"), close)
        volume = safe_float(row.get("volume"), 0)
        if close <= 0 or volume <= 0:
            continue
        weighted_sum += ((high + low + close) / 3) * volume
        total_volume += volume
    return weighted_sum / total_volume if total_volume > 0 else 0.0


def pmo_backtest_simulator(
    settings: Optional[Dict[str, Any]] = None,
    symbols: Optional[Any] = None,
    rows_by_symbol: Optional[Dict[str, List[Dict[str, Any]]]] = None,
    record: bool = False,
    lookahead_bars: Optional[Any] = None,
) -> Dict[str, Any]:
    settings = settings or load_settings()
    if not settings.get("ENABLE_PMO_BACKTEST_SIMULATOR", True):
        return {
            "ok": False,
            "engine": "PMO Backtest Simulator",
            "mode": "DISABLED",
            "live_order_allowed": False,
            "paper_order_allowed": False,
            "error": "ENABLE_PMO_BACKTEST_SIMULATOR is off",
        }
    rows_by_symbol = rows_by_symbol or {}
    selected_symbols = pmo_backtest_symbols(settings, symbols)
    use_intraday = bool(settings.get("PMO_BACKTEST_USE_INTRADAY", True))
    min_rows = int(max(10, safe_float(settings.get("PMO_BACKTEST_MIN_INTRADAY_ROWS", 40), 40)))
    lookahead = int(max(1, safe_float(lookahead_bars if lookahead_bars is not None else settings.get("PMO_BACKTEST_LOOKAHEAD_BARS", 12), 12)))
    stop_pct = max(0.1, safe_float(settings.get("PMO_DEFAULT_STOP_LOSS_PCT", 4.0), 4.0))
    target_pct = max(0.1, safe_float(settings.get("PMO_DEFAULT_TAKE_PROFIT_PCT", 6.0), 6.0))
    events: List[Dict[str, Any]] = []
    symbol_summaries: Dict[str, Dict[str, Any]] = {}

    for symbol in selected_symbols:
        safe_symbol = pmo_edge_safe_symbol(symbol)
        rows = rows_by_symbol.get(safe_symbol) or rows_by_symbol.get(symbol) or pmo_edge_load_ohlcv_rows(safe_symbol, intraday=use_intraday, limit=390)
        clean_rows = [row for row in rows if safe_float(row.get("close"), 0) > 0]
        if len(clean_rows) < min_rows + lookahead + 1:
            symbol_summaries[safe_symbol] = {
                "symbol": safe_symbol,
                "status": "DATA_REQUIRED",
                "rows": len(clean_rows),
                "reason": f"needs at least {min_rows + lookahead + 1} OHLCV rows",
            }
            continue
        last_signal_idx = -lookahead
        symbol_events: List[Dict[str, Any]] = []
        for idx in range(min_rows, len(clean_rows) - lookahead):
            if idx - last_signal_idx < lookahead:
                continue
            window = clean_rows[max(0, idx - min_rows):idx + 1]
            vwap = pmo_rows_vwap(window)
            entry_row = clean_rows[idx]
            prev_close = safe_float(clean_rows[idx - 1].get("close"), 0)
            entry = safe_float(entry_row.get("close"), 0)
            if vwap <= 0 or entry <= 0 or prev_close <= 0:
                continue
            direction = ""
            if entry > vwap and entry > prev_close:
                direction = "LONG"
                stop_price = entry * (1 - stop_pct / 100)
                target_price = entry * (1 + target_pct / 100)
            elif entry < vwap and entry < prev_close:
                direction = "SHORT"
                stop_price = entry * (1 + stop_pct / 100)
                target_price = entry * (1 - target_pct / 100)
            else:
                continue

            outcome = "TIME_EXIT"
            exit_price = safe_float(clean_rows[idx + lookahead].get("close"), entry)
            pnl_pct = ((exit_price - entry) / entry) * 100 if direction == "LONG" else ((entry - exit_price) / entry) * 100
            for future in clean_rows[idx + 1:idx + lookahead + 1]:
                high = safe_float(future.get("high"), safe_float(future.get("close"), entry))
                low = safe_float(future.get("low"), safe_float(future.get("close"), entry))
                if direction == "LONG":
                    if low <= stop_price:
                        outcome = "STOP_HIT"
                        exit_price = stop_price
                        pnl_pct = -stop_pct
                        break
                    if high >= target_price:
                        outcome = "TARGET_HIT"
                        exit_price = target_price
                        pnl_pct = target_pct
                        break
                else:
                    if high >= stop_price:
                        outcome = "STOP_HIT"
                        exit_price = stop_price
                        pnl_pct = -stop_pct
                        break
                    if low <= target_price:
                        outcome = "TARGET_HIT"
                        exit_price = target_price
                        pnl_pct = target_pct
                        break
            event = {
                "timestamp": entry_row.get("date") or entry_row.get("timestamp") or entry_row.get("time") or "",
                "symbol": safe_symbol,
                "strategy": "VWAP_DIRECTIONAL_SIM",
                "direction": direction,
                "entry": round(entry, 4),
                "exit": round(exit_price, 4),
                "vwap": round(vwap, 4),
                "stop_pct": stop_pct,
                "target_pct": target_pct,
                "outcome": outcome,
                "pnl_pct": round(pnl_pct, 3),
                "rules_followed": True,
            }
            events.append(event)
            symbol_events.append(event)
            last_signal_idx = idx

        wins = [item for item in symbol_events if safe_float(item.get("pnl_pct"), 0) > 0]
        losses = [item for item in symbol_events if safe_float(item.get("pnl_pct"), 0) < 0]
        gross_profit = sum(safe_float(item.get("pnl_pct"), 0) for item in wins)
        gross_loss = abs(sum(safe_float(item.get("pnl_pct"), 0) for item in losses))
        symbol_summaries[safe_symbol] = {
            "symbol": safe_symbol,
            "status": "SIMULATED" if symbol_events else "NO_SIGNALS",
            "rows": len(clean_rows),
            "trades": len(symbol_events),
            "wins": len(wins),
            "losses": len(losses),
            "win_rate": round(len(wins) / len(symbol_events), 4) if symbol_events else 0.0,
            "profit_factor": round(gross_profit / gross_loss, 4) if gross_loss else (round(gross_profit, 4) if gross_profit else 0.0),
            "net_pnl_pct": round(sum(safe_float(item.get("pnl_pct"), 0) for item in symbol_events), 3),
        }

    wins = [item for item in events if safe_float(item.get("pnl_pct"), 0) > 0]
    losses = [item for item in events if safe_float(item.get("pnl_pct"), 0) < 0]
    gross_profit = sum(safe_float(item.get("pnl_pct"), 0) for item in wins)
    gross_loss = abs(sum(safe_float(item.get("pnl_pct"), 0) for item in losses))
    cumulative = 0.0
    peak = 0.0
    max_drawdown = 0.0
    for item in events:
        cumulative += safe_float(item.get("pnl_pct"), 0)
        peak = max(peak, cumulative)
        max_drawdown = min(max_drawdown, cumulative - peak)
    simulated = [row for row in symbol_summaries.values() if row.get("status") == "SIMULATED"]
    best_symbols = sorted(simulated, key=lambda row: safe_float(row.get("net_pnl_pct"), 0), reverse=True)[:5]
    worst_symbols = sorted(simulated, key=lambda row: safe_float(row.get("net_pnl_pct"), 0))[:5]
    report = {
        "ok": True,
        "engine": "PMO Backtest Simulator",
        "mode": "RESEARCH_ONLY_BACKTEST",
        "updated": now_et().isoformat(),
        "live_order_allowed": False,
        "paper_order_allowed": False,
        "symbols": selected_symbols,
        "strategy": "VWAP_DIRECTIONAL_SIM",
        "settings": {
            "use_intraday": use_intraday,
            "min_rows": min_rows,
            "lookahead_bars": lookahead,
            "stop_pct": stop_pct,
            "target_pct": target_pct,
        },
        "summary": {
            "trades": len(events),
            "wins": len(wins),
            "losses": len(losses),
            "win_rate": round(len(wins) / len(events), 4) if events else 0.0,
            "avg_win_pct": round(gross_profit / len(wins), 3) if wins else 0.0,
            "avg_loss_pct": round(gross_loss / len(losses), 3) if losses else 0.0,
            "profit_factor": round(gross_profit / gross_loss, 4) if gross_loss else (round(gross_profit, 4) if gross_profit else 0.0),
            "net_pnl_pct": round(sum(safe_float(item.get("pnl_pct"), 0) for item in events), 3),
            "max_drawdown_pct": round(abs(max_drawdown), 3),
        },
        "best_symbols": best_symbols,
        "worst_symbols": worst_symbols,
        "symbols_detail": list(symbol_summaries.values()),
        "events": events[:250],
        "report_file": str(PMO_BACKTEST_SIMULATOR_REPORT_FILE),
        "events_file": str(PMO_BACKTEST_SIMULATOR_EVENTS_FILE),
        "safety_note": "Simulation only. Results do not submit orders, unlock live trading, or change PMO readiness.",
    }
    if record:
        write_json_file(PMO_BACKTEST_SIMULATOR_REPORT_FILE, report)
        for event in events[:1000]:
            csv_append(PMO_BACKTEST_SIMULATOR_EVENTS_FILE, {**event, "recorded_at": report["updated"]})
    return report


def pmo_cobr_research_snapshot(record: bool = False, duration_ms: Any = 1200, step_ms: Any = 20) -> Dict[str, Any]:
    duration = int(max(200, min(10000, safe_float(duration_ms, 1200))))
    step = int(max(5, min(250, safe_float(step_ms, 20))))
    try:
        import cobr_signal
        import market_simulator

        if hasattr(cobr_signal, "reset_state"):
            cobr_signal.reset_state()
        sim_result = market_simulator.run_synthetic_cobr_replay(duration_ms=duration, step_ms=step)
        report = {
            "ok": True,
            "updated": now_et().isoformat(),
            "engine": "PMO COBR Research Pack",
            "mode": "RESEARCH_ONLY_SIMULATION",
            "live_order_allowed": False,
            "paper_order_allowed": False,
            "advanced_edge_count": len(pmo_advanced_microstructure_edge_definitions()),
            "advanced_definitions": pmo_advanced_microstructure_edge_definitions(),
            "module_files": {
                "cobr_signal": str(PMO_DIR / "cobr_signal.py"),
                "market_simulator": str(PMO_DIR / "market_simulator.py"),
                "sample_real_data_adapter": str(PMO_DIR / "sample_real_data_adapter.py"),
                "notebook": str(PMO_DIR / "notebook.ipynb"),
            },
            "simulation": sim_result,
            "report_file": str(PMO_COBR_RESEARCH_REPORT_FILE),
            "safety_note": "COBR signals are research-only and cannot arm live or paper execution from this endpoint.",
        }
    except Exception as exc:
        report = {
            "ok": False,
            "updated": now_et().isoformat(),
            "engine": "PMO COBR Research Pack",
            "mode": "RESEARCH_ONLY_SIMULATION",
            "live_order_allowed": False,
            "paper_order_allowed": False,
            "error": str(exc),
            "report_file": str(PMO_COBR_RESEARCH_REPORT_FILE),
        }
    if record:
        write_json_file(PMO_COBR_RESEARCH_REPORT_FILE, report)
    return report


