@app.route("/api/receiving-accounts", methods=["GET", "POST"])
def api_receiving_accounts():
    if request.method == "GET":
        return jsonify({"ok": True, "accounts": load_receiving_accounts(), "file": str(RECEIVING_ACCOUNTS_FILE)})
    payload = request.get_json(force=True, silent=True) or {}
    locked = pmo_require_admin(payload)
    if locked:
        return locked, 403
    destination = str(payload.get("destination", "")).strip()
    nickname = str(payload.get("nickname", "")).strip()
    notes = str(payload.get("notes", "")).strip()
    if not destination:
        return jsonify({"ok": False, "message": "payment handle or link is required"}), 400
    if payment_text_has_sensitive_terms(destination, nickname, notes):
        return jsonify({"ok": False, "message": "do not store passwords, SSNs, card numbers, CVV codes, routing/account numbers, seed phrases, or private keys in PMO"}), 400
    accounts = load_receiving_accounts()
    account = {
        "id": str(int(time.time() * 1000)),
        "account_type": str(payload.get("account_type", "Other")).strip() or "Other",
        "nickname": nickname,
        "destination": destination,
        "notes": notes,
        "priority": max(1, min(10, int(safe_float(payload.get("priority", 5), 5)))),
        "active": bool(payload.get("active", True)),
        "created_at": now_et().isoformat(),
    }
    accounts.append(account)
    save_receiving_accounts(accounts)
    return jsonify({"ok": True, "account": account, "accounts": accounts})


@app.route("/api/receiving-accounts/delete", methods=["POST"])
def api_receiving_accounts_delete():
    payload = request.get_json(force=True, silent=True) or {}
    locked = pmo_require_admin(payload)
    if locked:
        return locked, 403
    account_id = str(payload.get("id", "")).strip()
    if not account_id:
        return jsonify({"ok": False, "message": "missing receiving account id"}), 400
    accounts = load_receiving_accounts()
    kept = [account for account in accounts if str(account.get("id", "")) != account_id]
    save_receiving_accounts(kept)
    return jsonify({"ok": True, "removed": len(accounts) - len(kept), "accounts": kept})


