@app.route("/api/payments/webhook/paypal", methods=["POST"])
def api_paypal_webhook():
    event = request.get_json(force=True, silent=True) or {}
    event_type = str(event.get("event_type", "PAYPAL_WEBHOOK")).strip() or "PAYPAL_WEBHOOK"
    resource = event.get("resource", {}) if isinstance(event.get("resource", {}), dict) else {}
    reference = str(resource.get("id", event.get("id", "")))
    try:
        verification = verify_paypal_webhook(event, request.headers)
    except Exception as exc:
        verification = {"ok": False, "status": "VERIFY_FAILED", "message": str(exc)}
    log_payment_event(
        "PAYPAL",
        event_type,
        str(resource.get("status", event.get("status", "RECEIVED"))),
        amount=resource.get("amount", {}).get("value", "") if isinstance(resource.get("amount", {}), dict) else "",
        reference=reference,
        detail=str(event)[:300],
        verified=verification.get("status", verification.get("ok")),
    )
    return jsonify({"ok": True, "verified": verification})


