@app.route("/api/settings", methods=["POST"])
def api_settings():
    payload = request.get_json(force=True, silent=True) or {}
    locked = pmo_require_admin(payload)
    if locked:
        return locked, 403
    name = str(payload.get("name", "")).strip()
    if name not in EDITABLE_SETTINGS:
        return jsonify({"ok": False, "message": "setting is not editable"}), 400
    settings = load_settings()
    meta = EDITABLE_SETTINGS[name]
    raw = payload.get("value")
    if meta["type"] == "bool":
        value = str(raw).strip().lower() in {"true", "1", "yes", "on"}
    elif meta["type"] == "int":
        value = max(meta.get("min", 0), min(meta.get("max", 999), int(raw)))
    elif meta["type"] == "float":
        value = max(meta.get("min", 0), min(meta.get("max", 999), float(raw)))
    elif meta["type"] == "select":
        value = str(raw)
        if value not in meta["options"]:
            return jsonify({"ok": False, "message": "invalid option"}), 400
    else:
        value = raw
    settings[name] = value
    if name == "PMO_LIVE_TRADING_ENABLED" and value:
        return jsonify({"ok": False, "message": "Use the PMO live signal master switch to arm signal approval."}), 400
    sync_setting_aliases(settings, name)
    write_settings(settings)
    bot.reload()
    return jsonify({"ok": True, "setting": {"name": name, "value": value}})


@app.route("/api/live-master", methods=["POST"])
def api_live_master():
    payload = request.get_json(force=True, silent=True) or {}
    locked = pmo_require_admin(payload)
    if locked:
        return locked, 403
    enable = bool(payload.get("enable"))
    phrase = str(payload.get("confirm_text", "")).strip().upper()
    settings = load_settings()
    if enable:
        if phrase != "PMO GO LIVE":
            return jsonify({"ok": False, "message": "Type PMO GO LIVE to arm live signal approval."}), 400
        account = bot.account_snapshot()
        drawdown_governor = pmo_day_drawdown_governor(settings, account, action="LIVE_ARM", record=True)
        if not drawdown_governor.get("live_ready_allowed"):
            return jsonify({
                "ok": False,
                "message": "PMO live master is blocked by the day hard-stop governor.",
                "drawdown_governor": drawdown_governor,
            }), 400
        required = {
            "PMO_ALLOW_LIVE_TRADING": settings.get("PMO_ALLOW_LIVE_TRADING"),
            "ORDER_AUTOMATION_ENABLED": settings.get("ORDER_AUTOMATION_ENABLED"),
            "PMO_DRY_RUN_ORDERS_FALSE": not settings.get("PMO_DRY_RUN_ORDERS"),
            "ALPACA_PAPER_FALSE": not settings.get("ALPACA_PAPER"),
        }
        if not all(required.values()):
            return jsonify({"ok": False, "message": "Live signal approval is still locked by safety switches.", "required": required}), 400
        settings["PMO_LIVE_TRADING_ENABLED"] = True
        sync_setting_aliases(settings)
    else:
        if phrase not in {"PMO PAPER SAFE", "PMO GO SAFE"}:
            return jsonify({"ok": False, "message": "Type PMO PAPER SAFE to return to safe mode."}), 400
        settings["PMO_LIVE_TRADING_ENABLED"] = False
        settings["ORDER_AUTOMATION_ENABLED"] = False
        settings["PMO_DRY_RUN_ORDERS"] = True
        settings["ALPACA_PAPER"] = True
        sync_setting_aliases(settings, "ORDER_AUTOMATION_ENABLED")
        sync_setting_aliases(settings, "PMO_DRY_RUN_ORDERS")
        sync_setting_aliases(settings, "ALPACA_PAPER")
    write_settings(settings)
    bot.reload()
    return jsonify({"ok": True, "live_master": {
        "enabled": settings["PMO_LIVE_TRADING_ENABLED"],
        "paper": settings.get("ALPACA_PAPER"),
        "automation": settings.get("ORDER_AUTOMATION_ENABLED"),
        "dry_run": settings.get("PMO_DRY_RUN_ORDERS"),
    }})


@app.route("/tradingview", methods=["GET", "POST"])
@app.route("/api/tv-alert", methods=["GET", "POST"])
def tradingview_webhook():
    if request.method == "GET":
        return jsonify({
            "ok": True,
            "message": "PMO BOT TradingView webhook is online.",
            "routes": ["/tradingview", "/api/tv-alert"],
            "required_trigger": "Once Per Bar Close",
        })
    raw_payload = request.get_json(force=True, silent=True) or {}
    payload = normalize_tv_webhook_payload(raw_payload)
    bot.settings = load_settings()
    secret = str(payload.get("secret", "")).strip()
    expected = str(bot.settings.get("TRADINGVIEW_WEBHOOK_SECRET", "CHANGE_ME_SECRET")).strip()
    if not expected or expected == "CHANGE_ME_SECRET":
        return jsonify({"ok": False, "message": "TradingView webhook secret is not configured. Change TRADINGVIEW_WEBHOOK_SECRET before accepting alerts."}), 403
    if not secret or not secrets.compare_digest(secret, expected):
        return jsonify({"ok": False, "message": "bad webhook secret"}), 403
    valid, errors, warnings = validate_tv_payload(payload)
    if not valid:
        csv_append(CSV_DIR / "pmo_tradingview_alerts.csv", {
            "timestamp": now_et().isoformat(),
            "symbol": payload.get("symbol", ""),
            "side": payload.get("side", payload.get("action", "")),
            "price": payload.get("price", payload.get("close", "")),
            "timeframe": payload.get("timeframe", payload.get("interval", "")),
            "strategy": payload.get("strategy") or payload.get("source") or "TradingView",
            "approved": False,
            "live_signal_allowed": False,
            "live_order_allowed": False,
            "broker_order_submitted": False,
            "execution_status": "INVALID_PAYLOAD",
            "reason": " ; ".join(errors + warnings),
            "score_band": "NO_TRADE",
            "score_action": "REJECT",
            "market_data_result": "NOT_REQUESTED",
            "payload": json.dumps(payload, sort_keys=True),
        })
        return jsonify({
            "ok": False,
            "action": "rejected",
            "reason": "invalid_payload",
            "errors": errors,
            "warnings": warnings,
            "orders_placed": False,
            "live_unlocked": False,
            "settings_changed": False,
        }), 200
    dedup = pmo_webhook_dedup_check(payload)
    if dedup.get("duplicate"):
        csv_append(CSV_DIR / "pmo_tradingview_alerts.csv", {
            "timestamp": now_et().isoformat(),
            "symbol": payload.get("symbol", ""),
            "side": payload.get("side", payload.get("action", "")),
            "price": payload.get("price", payload.get("close", "")),
            "timeframe": payload.get("timeframe", payload.get("interval", "")),
            "strategy": payload.get("strategy") or payload.get("source") or "TradingView",
            "approved": False,
            "live_signal_allowed": False,
            "live_order_allowed": False,
            "broker_order_submitted": False,
            "execution_status": "DUPLICATE_WEBHOOK",
            "reason": f"duplicate webhook same bar: {dedup.get('key')}",
            "score_band": "NO_TRADE",
            "score_action": "DUPLICATE",
            "market_data_result": "NOT_REQUESTED",
            "payload": json.dumps(payload, sort_keys=True),
        })
        return jsonify({
            "ok": False,
            "action": "ignored",
            "reason": "duplicate_webhook",
            "dedup": dedup,
            "warnings": warnings,
            "orders_placed": False,
            "live_unlocked": False,
            "settings_changed": False,
        }), 200
    decision = bot.evaluate_tradingview_alert(payload)
    return jsonify({
        "ok": True,
        "action": "queued",
        "decision": decision,
        "validation": {"valid": valid, "warnings": warnings},
        "dedup": dedup,
        "orders_placed": bool(decision.get("broker_order_submitted")),
        "live_unlocked": False,
        "settings_changed": False,
    })


