def run_once() -> None:
    account = bot.account_snapshot()
    health = bot.connection_check()
    pine = ensure_master_pine()
    print("=" * 62)
    print("PMO BOT one-time health run")
    print(f"Account: {'OK' if account.get('ok') else account.get('error')}")
    print(f"Connections: {health['online']}/{health['total']} online")
    print(f"Master Pine: {pine}")
    print("Watchlist:")
    for item in bot.refresh_watchlist():
        price = item.get("price")
        status = price if price else item.get("error", "missing")
        print(f"  {item.get('symbol')} [{item.get('market')}] {status}")
    print("=" * 62)


def run_loop(seconds: int = 60) -> None:
    print("=" * 62)
    print("PMO BOT safe auto loop started")
    print("Press Ctrl+C to stop.")
    print("=" * 62)
    while True:
        run_once()
        time.sleep(max(10, int(seconds)))


def main() -> None:
    parser = argparse.ArgumentParser(description="PMO BOT restored command runner")
    parser.add_argument("--webhook", action="store_true", help="Run TradingView webhook-focused server on the configured PMO webhook/terminal port")
    parser.add_argument("--once", action="store_true", help="Run one PMO health/watchlist pass")
    parser.add_argument("--loop", action="store_true", help="Run repeated PMO health/watchlist passes")
    parser.add_argument("--interval", type=int, default=60, help="Loop interval in seconds")
    args = parser.parse_args()

    settings = load_settings()
    ml_startup = pmo_init_ml_engine(settings, force=False)
    try:
        dep = pmo_v2055_dependency_check(PMO_DIR)
        mod = v206_module_report(PMO_DIR)
        print(f"PMO BOT v205.5 dependency check: {dep.get('ready_count', 0)}/{dep.get('total_count', 0)} ready")
        print(f"PMO BOT v206 modular core: {mod.get('ready_count', 0)}/{mod.get('total_count', 0)} modules ready")
        print(f"PMO ML engine: trained={ml_startup.get('trained')} trades={ml_startup.get('training_trades', 0)}")
    except Exception as _pmo_startup_check_error:
        print(f"PMO BOT v205.5/v206 startup check warning: {_pmo_startup_check_error}")
    if args.once:
        run_once()
        return
    if args.loop:
        run_loop(args.interval)
        return

    host = str(settings.get("PMO_TERMINAL_HOST", "127.0.0.1"))
    if args.webhook:
        port = int(settings.get("PMO_TRADINGVIEW_WEBHOOK_PORT") or settings.get("PMO_TERMINAL_PORT", 8090))
    else:
        port = int(settings.get("PMO_TERMINAL_PORT", 8090))
    print("=" * 62)
    print("PMO BOT API server" if not args.webhook else "PMO BOT TradingView webhook server")
    print(f"Root: {PMO_ROOT}")
    print(f"Python: {PMO_DIR}")
    print(f"API health: http://{host}:{port}/api/health")
    print(f"TradingView webhook: http://{host}:{port}/tradingview")
    print(f"Master Pine: {master_pine_path()}")
    print("=" * 62)
    if settings.get("ENABLE_PMO_BACKGROUND_PAPER_SCHEDULER", False):
        start_result = pmo_start_background_paper_scheduler(force=False)
        print(f"Background paper scheduler: {start_result.get('state', {}).get('last_status') or start_result.get('blockers', '')}")
    app.run(host=host, port=port, debug=False, threaded=True)


if __name__ == "__main__":
    main()
